window.WebDevGymCurriculumData={"version":"2026-07-21","locale":"ru","sections":[{"id":"sec-calendar","lessons":[{"id":"block-calendar-main","title":"План обучения до 31.12.2026 🔗","html":"<div class=\"block\" id=\"block-calendar-main\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-calendar-main')\">План обучения <span class=\"badge good\">до 31.12.2026</span><span class=\"anchor-icon\">🔗</span></div>\n\n      <div class=\"wdg-cal-toolbar\">\n        <button class=\"wdg-cal-btn\" onclick=\"wdgCalMoveDay(-1)\">← День</button>\n        <button class=\"wdg-cal-btn primary\" onclick=\"wdgCalGoToday()\">Сегодня</button>\n        <button class=\"wdg-cal-btn\" onclick=\"wdgCalMoveDay(1)\">День →</button>\n        <button class=\"wdg-cal-btn\" onclick=\"wdgCalAddTask()\">Добавить</button>\n        <button class=\"wdg-cal-btn\" onclick=\"wdgCalExport()\">Экспорт календаря</button>\n        <button class=\"wdg-cal-btn\" onclick=\"wdgCalImport()\">Импорт календаря</button>\n        <button class=\"wdg-cal-btn danger\" onclick=\"wdgCalResetPlan()\">Сбросить календарь</button>\n      </div>\n\n      <div class=\"wdg-cal-hero\">\n        <div class=\"wdg-cal-card\">\n          <p class=\"wdg-cal-kicker\" id=\"wdgCalDateLabel\">Сегодня</p>\n          <h2 class=\"wdg-cal-title\" id=\"wdgCalTodayTitle\">Загрузка...</h2>\n          <p class=\"wdg-cal-desc\" id=\"wdgCalTodayDesc\">Календарь готовит следующий шаг.</p>\n          <div class=\"wdg-cal-stats\">\n            <div class=\"wdg-cal-stat\"><strong id=\"wdgCalDoneLessons\">0</strong><span>учебных дней закрыто</span></div>\n            <div class=\"wdg-cal-stat\"><strong id=\"wdgCalDaysLeft\">0</strong><span>дней до 31 декабря</span></div>\n            <div class=\"wdg-cal-stat\"><strong id=\"wdgCalNextLessons\">0</strong><span>тем впереди</span></div>\n          </div>\n        </div>\n        <div class=\"wdg-cal-card\">\n          <p class=\"wdg-cal-kicker\">Заметка</p>\n          <textarea class=\"wdg-cal-note\" id=\"wdgCalNote\" placeholder=\"Что важно помнить по учебе, Kwork или проектам?\"></textarea>\n        </div>\n      </div>\n\n      <div class=\"wdg-cal-layout\">\n        <div class=\"wdg-cal-card\">\n          <div class=\"wdg-cal-month-head\">\n            <button class=\"wdg-cal-btn\" onclick=\"wdgCalMoveMonth(-1)\">←</button>\n            <h3 id=\"wdgCalMonthTitle\">Месяц</h3>\n            <button class=\"wdg-cal-btn\" onclick=\"wdgCalMoveMonth(1)\">→</button>\n          </div>\n          <div class=\"wdg-cal-grid\" style=\"margin-bottom:7px;\">\n            <div class=\"wdg-cal-weekday\">Пн</div>\n            <div class=\"wdg-cal-weekday\">Вт</div>\n            <div class=\"wdg-cal-weekday\">Ср</div>\n            <div class=\"wdg-cal-weekday\">Чт</div>\n            <div class=\"wdg-cal-weekday\">Пт</div>\n            <div class=\"wdg-cal-weekday\">Сб</div>\n            <div class=\"wdg-cal-weekday\">Вс</div>\n          </div>\n          <div class=\"wdg-cal-grid\" id=\"wdgCalGrid\"></div>\n        </div>\n\n        <div class=\"wdg-cal-card\">\n          <div class=\"wdg-cal-month-head\">\n            <h3>Задачи дня</h3>\n            <div style=\"display:flex;gap:8px;flex-wrap:wrap;justify-content:flex-end;\">\n              <span class=\"wdg-cal-pill\" id=\"wdgCalDayType\">План</span>\n              <button class=\"wdg-cal-btn primary\" id=\"wdgCalCompleteDayBtn\" onclick=\"wdgCalToggleSelectedDay()\">Засчитать день</button>\n            </div>\n          </div>\n          <div class=\"wdg-cal-task-list\" id=\"wdgCalTaskList\"></div>\n        </div>\n      </div>\n    </div>\n\n    "},{"id":"block-calendar-route","title":"Ближайший маршрут следующие шаги 🔗","html":"<div class=\"block\" id=\"block-calendar-route\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-calendar-route')\">Ближайший маршрут <span class=\"badge good\">следующие шаги</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"wdg-cal-route\" id=\"wdgCalRoute\"></div>\n    </div>\n  "}]},{"id":"sec-html","lessons":[{"id":"block-semantic","title":"Семантические теги важно 🔗","html":"<div class=\"block\" id=\"block-semantic\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-semantic')\">Семантические теги <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">&lt;header&gt;  — шапка сайта (лого, навигация)\n&lt;nav&gt;     — меню / навигация\n&lt;main&gt;    — ОСНОВНОЙ контент (один на странице!)\n&lt;section&gt; — тематический раздел\n&lt;article&gt; — самостоятельный блок (статья, пост)\n&lt;aside&gt;   — боковая панель\n&lt;footer&gt;  — подвал (копирайт, контакты)</div>\n      <div class=\"explain\">\n        Раньше всё делали через <code>&lt;div class=\"header\"&gt;</code>. Теперь есть <code>&lt;header&gt;</code> — браузер и поисковики <em>понимают</em> структуру.<br><br>\n        <strong>section vs article — новички путают:</strong><br>\n        <strong>&lt;article&gt;</strong> — самостоятельный блок, который можно вырезать и вставить на другой сайт и он сохранит смысл (пост в блоге, новость, карточка товара).<br>\n        <strong>&lt;section&gt;</strong> — просто тематическая часть страницы, не претендующая на самостоятельность (раздел \"О нас\", блок \"Отзывы\" на лендинге).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb18\" onchange=\"updateProgress(this)\"><span>header, nav, main, section, article, aside, footer — вместо div</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb19\" onchange=\"updateProgress(this)\"><span>main — только один на странице. В нём — главный контент</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb20\" onchange=\"updateProgress(this)\"><span>article — самостоятельный блок, section — просто раздел страницы</span></label>\n      </div>\n    </div>\n    "},{"id":"block-page-structure","title":"Структура страницы основа 🔗","html":"<div class=\"block\" id=\"block-page-structure\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-page-structure')\">Структура страницы <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">HTML — это скелет любого сайта. Он не отвечает за красоту, а говорит браузеру: «это заголовок», «это картинка», «это ссылка».</div>\n      <div class=\"code\">&lt;!DOCTYPE html&gt;\n&lt;html lang=\"ru\"&gt;\n  &lt;head&gt;\n    &lt;meta charset=\"UTF-8\"&gt;\n    &lt;title&gt;Мой сайт&lt;/title&gt;\n  &lt;/head&gt;\n  &lt;body&gt;\n    &lt;h1&gt;Привет, мир!&lt;/h1&gt;\n  &lt;/body&gt;\n&lt;/html&gt;</div>\n      <div class=\"explain\">\n        <strong>&lt;!DOCTYPE html&gt;</strong> — говорит браузеру: «это современный HTML5». Пиши всегда первой строкой.<br>\n        <strong>&lt;html lang=\"ru\"&gt;</strong> — корень страницы. <code>lang</code> подсказывает браузеру и поисковикам язык.<br>\n        <strong>&lt;head&gt;</strong> — «голова» сайта. Тут настройки, которые <em>не видны</em> на странице: кодировка, заголовок вкладки, подключение CSS.<br>\n        <strong>&lt;meta charset=\"UTF-8\"&gt;</strong> — чтобы русские буквы отображались нормально. Без этого будут «кракозябры».<br>\n        <strong>&lt;body&gt;</strong> — «тело» сайта. Всё, что ты тут напишешь, <em>увидит пользователь</em>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb1\" onchange=\"updateProgress(this)\"><span>Понимаю, зачем нужен DOCTYPE</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb2\" onchange=\"updateProgress(this)\"><span>Знаю разницу между &lt;head&gt; (настройки) и &lt;body&gt; (видимый контент)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb3\" onchange=\"updateProgress(this)\"><span>Не забываю charset=\"UTF-8\" — иначе будут «??» вместо русских букв</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb4\" onchange=\"updateProgress(this)\"><span>&lt;title&gt; — это текст во вкладке браузера, а не на странице</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-headings","title":"Заголовки и текст основа 🔗","html":"<div class=\"block\" id=\"block-headings\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-headings')\">Заголовки и текст <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">&lt;h1&gt;Самый главный&lt;/h1&gt;     ← только один на странице!\n&lt;h2&gt;Раздел&lt;/h2&gt;\n&lt;h3&gt;Подраздел&lt;/h3&gt;\n&lt;p&gt;Это абзац текста.&lt;/p&gt;\n&lt;p&gt;А тут &lt;strong&gt;жирный&lt;/strong&gt; и &lt;em&gt;курсив&lt;/em&gt; текст.&lt;/p&gt;</div>\n      <div class=\"explain\">\n        <strong>h1–h6</strong> — заголовки. h1 — самый важный (название страницы), h6 — самый мелкий. Используй по порядку: h1 → h2 → h3. <em>Не перепрыгивай!</em><br>\n        <strong>&lt;p&gt;</strong> — абзац (paragraph). Браузер автоматически добавляет отступы между абзацами.<br>\n        <strong>&lt;strong&gt;</strong> — жирный, означает <em>важный</em> текст.<br>\n        <strong>&lt;em&gt;</strong> — курсив, означает <em>акцент</em> (ударение).<br>\n        <strong>&lt;br&gt;</strong> — перенос строки. Не используй для отступов! Для этого есть CSS.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb5\" onchange=\"updateProgress(this)\"><span>На странице только один h1 — остальные h2, h3...</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb6\" onchange=\"updateProgress(this)\"><span>&lt;p&gt; для текста, не &lt;div&gt;</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb7\" onchange=\"updateProgress(this)\"><span>&lt;strong&gt; = важно, &lt;em&gt; = акцент (ударение)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-links","title":"Ссылки и изображения ОСНОВА #","html":"<div class=\"block wdg-quality-block\" id=\"block-links\"><div class=\"block-title\" onclick=\"scrollToBlock('block-links')\">Ссылки и изображения <span class=\"badge must\">ОСНОВА</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Ссылка ведёт пользователя на страницу или к разделу. Кнопка выполняет действие. Не вкладывай <code>&lt;button&gt;</code> внутрь <code>&lt;a&gt;</code>: это два интерактивных элемента друг в друге и невалидная разметка.</div><div class=\"code\">&lt;!-- Внешняя ссылка --&gt;\n&lt;a href=\"https://example.com\" target=\"_blank\" rel=\"noopener noreferrer\"&gt;\n  Открыть документацию\n&lt;/a&gt;\n\n&lt;!-- Страница и раздел текущего сайта --&gt;\n&lt;a href=\"settings.html\"&gt;Настройки&lt;/a&gt;\n&lt;a href=\"#contacts\"&gt;Перейти к контактам&lt;/a&gt;\n\n&lt;!-- Ссылка может выглядеть как кнопка без вложенного button --&gt;\n&lt;a href=\"settings.html\" class=\"btn\"&gt;Настройки&lt;/a&gt;\n\n&lt;img src=\"team.jpg\" alt=\"Команда проекта за рабочим столом\" width=\"640\"&gt;</div><div class=\"explain\"><code>href</code> хранит адрес. <code>#contacts</code> ищет элемент с <code>id=\"contacts\"</code>. Для новой вкладки добавляй <code>rel=\"noopener noreferrer\"</code>. <code>alt</code> описывает смысл изображения; у чисто декоративного изображения допустим <code>alt=\"\"</code>. Класс <code>.btn</code> меняет внешний вид ссылки, но её смысл остаётся ссылкой.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-links-1\" onchange=\"updateProgress(this)\"><span>Ссылка для перехода, кнопка для действия</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-links-2\" onchange=\"updateProgress(this)\"><span>Не вкладываю интерактивные элементы</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-links-3\" onchange=\"updateProgress(this)\"><span>Пишу осмысленный alt</span></label></div></div>"},{"id":"block-lists","title":"Списки основа 🔗","html":"<div class=\"block\" id=\"block-lists\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-lists')\">Списки <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">&lt;!-- Маркированный (точки) — когда порядок не важен --&gt;\n&lt;ul&gt;\n  &lt;li&gt;Молоко&lt;/li&gt;\n  &lt;li&gt;Хлеб&lt;/li&gt;\n&lt;/ul&gt;\n\n&lt;!-- Нумерованный (1, 2, 3) — когда порядок важен --&gt;\n&lt;ol&gt;\n  &lt;li&gt;Открыть редактор&lt;/li&gt;\n  &lt;li&gt;Написать код&lt;/li&gt;\n  &lt;li&gt;Сохранить файл&lt;/li&gt;\n&lt;/ol&gt;</div>\n      <div class=\"explain\">\n        <strong>&lt;ul&gt;</strong> — список с точками. Порядок элементов <em>не важен</em> (список покупок).<br>\n        <strong>&lt;ol&gt;</strong> — список с номерами 1, 2, 3... Порядок <em>важен</em> (инструкция, рецепт).<br>\n        <strong>&lt;li&gt;</strong> — элемент списка. Всегда внутри &lt;ul&gt; или &lt;ol&gt;.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb13\" onchange=\"updateProgress(this)\"><span>ul = порядок не важен, ol = порядок важен</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb14\" onchange=\"updateProgress(this)\"><span>li — всегда внутри ul или ol, не сам по себе</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-forms","title":"Формы: данные, которые действительно отправятся ВАЖНО #","html":"<div class=\"block wdg-quality-block\" id=\"block-forms\"><div class=\"block-title\" onclick=\"scrollToBlock('block-forms')\">Формы: данные, которые действительно отправятся <span class=\"badge good\">ВАЖНО</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">У каждого отправляемого поля должен быть атрибут <code>name</code>. Без него значение видно в браузере, но оно не попадёт в <code>FormData</code>, Server Action или обычный серверный обработчик.</div><div class=\"code\">&lt;form action=\"/api/contact\" method=\"post\"&gt;\n  &lt;label for=\"contact-name\"&gt;Имя&lt;/label&gt;\n  &lt;input id=\"contact-name\" name=\"name\" autocomplete=\"name\" required&gt;\n\n  &lt;label for=\"contact-email\"&gt;Email&lt;/label&gt;\n  &lt;input id=\"contact-email\" name=\"email\" type=\"email\" autocomplete=\"email\" required&gt;\n\n  &lt;label for=\"contact-message\"&gt;Сообщение&lt;/label&gt;\n  &lt;textarea id=\"contact-message\" name=\"message\" rows=\"5\" required&gt;&lt;/textarea&gt;\n\n  &lt;label&gt;\n    &lt;input name=\"consent\" type=\"checkbox\" value=\"yes\" required&gt;\n    Согласен на обработку данных\n  &lt;/label&gt;\n\n  &lt;button type=\"submit\"&gt;Отправить&lt;/button&gt;\n&lt;/form&gt;\n\nconst data = new FormData(document.querySelector(\"form\"));\nconsole.log(data.get(\"email\"));</div><div class=\"explain\"><code>label for</code> связывается с <code>id</code> поля. <code>name</code> становится ключом отправляемых данных. <code>type=\"email\"</code> включает базовую браузерную проверку, а <code>required</code> блокирует пустую отправку. Сервер обязан проверить данные повторно. Поля с <code>disabled</code> вообще не отправляются.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-forms-1\" onchange=\"updateProgress(this)\"><span>У каждого нужного поля есть name</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-forms-2\" onchange=\"updateProgress(this)\"><span>Связываю label с полем</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-forms-3\" onchange=\"updateProgress(this)\"><span>Проверяю данные на сервере</span></label></div></div>"},{"id":"block-tables","title":"Таблицы: только для табличных данных ПРАКТИКА #","html":"<div class=\"block wdg-quality-block\" id=\"block-tables\"><div class=\"block-title\" onclick=\"scrollToBlock('block-tables')\">Таблицы: только для табличных данных <span class=\"badge good\">ПРАКТИКА</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Таблицы не устарели: они нужны для отчётов, тарифов, статистики и админ-панелей. Устарело использовать таблицу для раскладки всей страницы.</div><div class=\"code\">&lt;table&gt;\n  &lt;caption&gt;Результаты курса&lt;/caption&gt;\n  &lt;thead&gt;\n    &lt;tr&gt;&lt;th scope=\"col\"&gt;Ученик&lt;/th&gt;&lt;th scope=\"col\"&gt;Баллы&lt;/th&gt;&lt;/tr&gt;\n  &lt;/thead&gt;\n  &lt;tbody&gt;\n    &lt;tr&gt;&lt;th scope=\"row\"&gt;Анна&lt;/th&gt;&lt;td&gt;92&lt;/td&gt;&lt;/tr&gt;\n    &lt;tr&gt;&lt;th scope=\"row\"&gt;Макс&lt;/th&gt;&lt;td&gt;87&lt;/td&gt;&lt;/tr&gt;\n  &lt;/tbody&gt;\n&lt;/table&gt;</div><div class=\"explain\"><code>caption</code> даёт таблице название. <code>thead</code> содержит заголовки, <code>tbody</code> - данные. <code>th</code> обозначает заголовочную ячейку, а <code>scope</code> связывает её со строкой или колонкой. Для карточек и макета страницы используй Grid или Flexbox.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tables-1\" onchange=\"updateProgress(this)\"><span>Table только для строк и колонок данных</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tables-2\" onchange=\"updateProgress(this)\"><span>Добавляю caption и th</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tables-3\" onchange=\"updateProgress(this)\"><span>Не строю макет таблицей</span></label></div></div>"},{"id":"block-meta","title":"Meta-теги — SEO и соцсети важно 🔗","html":"<div class=\"block\" id=\"block-meta\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-meta')\">Meta-теги — SEO и соцсети <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Meta-теги не видны на странице, но влияют на то, как сайт выглядит в поиске и при репосте в соцсетях.</div>\n      <div class=\"code\">&lt;head&gt;\n  &lt;meta charset=\"UTF-8\"&gt;\n  &lt;meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"&gt;\n\n  &lt;!-- SEO --&gt;\n  &lt;title&gt;Мой магазин — купить онлайн&lt;/title&gt;\n  &lt;meta name=\"description\" content=\"Лучший магазин в интернете. Доставка 1 день.\"&gt;\n  &lt;meta name=\"keywords\" content=\"магазин, покупки, доставка\"&gt;\n\n  &lt;!-- Open Graph — как выглядит при шеринге (ВКонтакте, Telegram) --&gt;\n  &lt;meta property=\"og:title\" content=\"Мой магазин\"&gt;\n  &lt;meta property=\"og:description\" content=\"Лучший магазин!\"&gt;\n  &lt;meta property=\"og:image\" content=\"https://myshop.ru/preview.jpg\"&gt;\n  &lt;meta property=\"og:url\" content=\"https://myshop.ru\"&gt;\n\n  &lt;!-- Запрет индексации (например, для страницы входа) --&gt;\n  &lt;meta name=\"robots\" content=\"noindex, nofollow\"&gt;\n&lt;/head&gt;</div>\n      <div class=\"explain\">\n        <strong>viewport</strong> — обязателен для мобильных! Без него мобильный браузер уменьшает страницу.<br>\n        <strong>description</strong> — описание, которое показывает Google под ссылкой (160 символов).<br>\n        <strong>og:image</strong> — картинка при репосте в мессенджерах и соцсетях. Размер: 1200×630 px.<br>\n        <strong>robots: noindex</strong> — страница не попадёт в поиск.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb25\" onchange=\"updateProgress(this)\"><span>viewport — обязателен для адаптивного сайта</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb26\" onchange=\"updateProgress(this)\"><span>description — до 160 символов, видна в Google</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb27\" onchange=\"updateProgress(this)\"><span>og:image — картинка при репосте (1200×630 px)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-video-audio","title":"Видео, аудио и iframe важно 🔗","html":"<div class=\"block\" id=\"block-video-audio\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-video-audio')\">Видео, аудио и iframe <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">HTML5 позволяет встраивать медиа прямо на страницу — без Flash и сторонних плагинов.</div>\n      <div class=\"code-wrap\"><div class=\"code\">&lt;!-- Видео --&gt;\n&lt;video src=\"movie.mp4\" controls width=\"640\"&gt;\n  Твой браузер не поддерживает video.\n&lt;/video&gt;\n\n&lt;!-- Несколько форматов (fallback) --&gt;\n&lt;video controls width=\"640\" poster=\"preview.jpg\"&gt;\n  &lt;source src=\"movie.webm\" type=\"video/webm\"&gt;\n  &lt;source src=\"movie.mp4\"  type=\"video/mp4\"&gt;\n&lt;/video&gt;\n\n&lt;!-- Аудио --&gt;\n&lt;audio src=\"song.mp3\" controls&gt;&lt;/audio&gt;\n\n&lt;!-- YouTube / Google Maps / любой сайт через iframe --&gt;\n&lt;iframe\n  src=\"https://www.youtube.com/embed/dQw4w9WgXcQ\"\n  width=\"560\" height=\"315\"\n  allowfullscreen&gt;\n&lt;/iframe&gt;</div><button class=\"copy-btn\" onclick=\"copyCode(this)\">Копировать</button></div>\n      <div class=\"explain\">\n        <strong>controls</strong> — показывает стандартные кнопки плеера (play, пауза, громкость).<br>\n        <strong>poster</strong> — картинка-превью видео до нажатия play.<br>\n        <strong>&lt;source&gt;</strong> — несколько форматов: браузер берёт первый, который поддерживает.<br>\n        <strong>autoplay muted loop</strong> — автозапуск без звука (фоновые видео). Без <code>muted</code> браузер заблокирует autoplay.<br>\n        <strong>&lt;iframe&gt;</strong> — вставляет другой сайт или видео. allowfullscreen — разрешает полноэкранный режим.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb28\" onchange=\"updateProgress(this)\"><span>controls — обязателен, иначе плеер не будет видно</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb29\" onchange=\"updateProgress(this)\"><span>autoplay требует muted, иначе браузер заблокирует</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb30\" onchange=\"updateProgress(this)\"><span>&lt;source&gt; — несколько форматов (mp4 + webm) для кроссбраузерности</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb31\" onchange=\"updateProgress(this)\"><span>&lt;iframe&gt; — вставка YouTube, карт или любого внешнего контента</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-data-attrs","title":"Data-атрибуты и доступность (ARIA) важно 🔗","html":"<div class=\"block\" id=\"block-data-attrs\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-data-attrs')\">Data-атрибуты и доступность (ARIA) <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">data-* позволяют хранить любые данные прямо в HTML. ARIA помогает людям, которые используют скринридеры.</div>\n      <div class=\"code-wrap\"><div class=\"code\">&lt;!-- data-* — храним произвольные данные в HTML --&gt;\n&lt;button data-user-id=\"42\" data-role=\"admin\"\n        onclick=\"handleClick(this)\"&gt;\n  Открыть профиль\n&lt;/button&gt;\n\n&lt;!-- В JS читаем через dataset --&gt;\n&lt;script&gt;\nfunction handleClick(btn) {\n  console.log(btn.dataset.userId);  // \"42\"\n  console.log(btn.dataset.role);    // \"admin\"\n}\n&lt;/script&gt;\n\n&lt;!-- ARIA — подсказки для скринридеров --&gt;\n&lt;button aria-label=\"Закрыть меню\"&gt;✕&lt;/button&gt;\n&lt;input aria-required=\"true\" aria-describedby=\"hint\"&gt;\n&lt;p id=\"hint\"&gt;Минимум 8 символов&lt;/p&gt;\n\n&lt;!-- role — указывает роль элемента --&gt;\n&lt;div role=\"alert\"&gt;Ошибка! Проверьте форму.&lt;/div&gt;\n&lt;nav aria-label=\"Основная навигация\"&gt;...&lt;/nav&gt;</div><button class=\"copy-btn\" onclick=\"copyCode(this)\">Копировать</button></div>\n      <div class=\"explain\">\n        <strong>data-имя-атрибута</strong> — имя пишется через дефис. В JS читается через <code>dataset.имяАтрибута</code> (camelCase).<br>\n        <strong>aria-label</strong> — объясняет элемент для скринридеров (когда видимого текста нет, например кнопка «✕»).<br>\n        <strong>aria-required</strong> — сообщает, что поле обязательно (в дополнение к <code>required</code>).<br>\n        <strong>role=\"alert\"</strong> — скринридер сразу объявляет этот текст при его появлении.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb32\" onchange=\"updateProgress(this)\"><span>data-* — хранить данные в HTML, читать через dataset.name</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb33\" onchange=\"updateProgress(this)\"><span>aria-label — обязателен для иконочных кнопок без текста</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb34\" onchange=\"updateProgress(this)\"><span>role=\"alert\" — скринридер зачитает текст немедленно</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-images","title":"Картинки — img, srcset, picture основа 🔗","html":"<div class=\"block\" id=\"block-images\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-images')\">Картинки — img, srcset, picture <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">&lt;img&gt; — самый частый медиа-тег. От него зависит и скорость сайта, и SEO, и доступность для незрячих.</div>\n      <div class=\"code\">&lt;!-- Базовая картинка --&gt;\n&lt;img src=\"cat.jpg\" alt=\"Рыжий кот спит на диване\" width=\"600\" height=\"400\"&gt;\n\n&lt;!-- alt=\"\" — декоративная (узор, иконка). Иначе описание --&gt;\n\n&lt;!-- Ленивая загрузка — не грузить, пока не видно --&gt;\n&lt;img src=\"photo.jpg\" alt=\"Закат\" loading=\"lazy\"&gt;\n\n&lt;!-- Разные размеры для разных экранов --&gt;\n&lt;img src=\"photo-800.jpg\"\n     srcset=\"photo-400.jpg  400w,\n             photo-800.jpg  800w,\n             photo-1600.jpg 1600w\"\n     sizes=\"(max-width: 600px) 100vw, 800px\"\n     alt=\"Горы\"&gt;\n\n&lt;!-- &lt;picture&gt; — разные форматы (avif/webp/jpg) --&gt;\n&lt;picture&gt;\n  &lt;source srcset=\"photo.avif\" type=\"image/avif\"&gt;\n  &lt;source srcset=\"photo.webp\" type=\"image/webp\"&gt;\n  &lt;img    src=\"photo.jpg\"     alt=\"Закат\"&gt;   &lt;!-- запасной --&gt;\n&lt;/picture&gt;</div>\n      <div class=\"explain\">\n        <strong>alt</strong> — текст вместо картинки, если она не загрузилась. Читают скринридеры и Google. Декоративная — <code>alt=\"\"</code>, важная — описание.<br>\n        <strong>width / height</strong> — указывай в HTML! Это резервирует место и убирает «прыжки» при загрузке (улучшает CLS в Lighthouse).<br>\n        <strong>loading=\"lazy\"</strong> — браузер загрузит картинку, только когда она появится в зоне видимости. Ставь всем, <em>кроме первой на странице</em>.<br>\n        <strong>srcset + sizes</strong> — браузер сам выберет нужный размер под экран. Экономит трафик на телефонах.<br>\n        <strong>&lt;picture&gt;</strong> — нужен для разных форматов (avif/webp/jpg) или совсем разных кадров на десктопе и телефоне.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb35\" onchange=\"updateProgress(this)\"><span>alt всегда заполняю — текст или alt=\"\" для декоративных</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb36\" onchange=\"updateProgress(this)\"><span>width / height в HTML — чтобы не было «прыжков» контента</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb37\" onchange=\"updateProgress(this)\"><span>loading=\"lazy\" — для всех картинок ниже первого экрана</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb38\" onchange=\"updateProgress(this)\"><span>srcset — разные размеры для телефона и десктопа</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb39\" onchange=\"updateProgress(this)\"><span>&lt;picture&gt; + webp/avif → меньше вес, jpg как запасной</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-html-core-web-vitals","title":"Core Web Vitals — скорость глазами пользователя важно 🔗","html":"<div class=\"block\" id=\"block-html-core-web-vitals\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-html-core-web-vitals')\">Core Web Vitals — скорость глазами пользователя <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Core Web Vitals — метрики Google про то, как пользователь ощущает страницу: быстро ли появился главный контент, не прыгает ли layout, быстро ли сайт реагирует.</div>\n      <div class=\"code\">&lt;!-- LCP: главный элемент первого экрана должен загрузиться быстро --&gt;\n&lt;img src=\"hero.webp\"\n     alt=\"Главный экран проекта\"\n     width=\"1200\"\n     height=\"700\"\n     fetchpriority=\"high\"&gt;\n\n&lt;!-- CLS: всегда резервируй место под медиа --&gt;\n&lt;img src=\"card.webp\" alt=\"Карточка\" width=\"360\" height=\"240\" loading=\"lazy\"&gt;\n\n&lt;!-- INP: не вешай тяжёлую работу прямо на клик --&gt;\n&lt;button&gt;Открыть меню&lt;/button&gt;</div>\n      <div class=\"explain\">\n        <strong>LCP</strong> — как быстро загрузился главный видимый контент: hero-картинка, большой заголовок, первый блок.<br>\n        <strong>CLS</strong> — прыгает ли страница при загрузке. Лечится <code>width/height</code>, стабильными контейнерами и аккуратной загрузкой шрифтов.<br>\n        <strong>INP</strong> — насколько быстро страница реагирует на действия. Не делай тяжёлые циклы и большие расчёты прямо в обработчиках клика.<br>\n        <strong>Lighthouse</strong> в Chrome DevTools показывает эти метрики и подсказывает, что исправить.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-html-cwv-1\" onchange=\"updateProgress(this)\"><span>LCP — главный контент первого экрана должен грузиться быстро</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-html-cwv-2\" onchange=\"updateProgress(this)\"><span>CLS — задаю размеры картинкам и не допускаю прыжков layout</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-html-cwv-3\" onchange=\"updateProgress(this)\"><span>INP — не блокирую интерфейс тяжёлым JS в кликах</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-inputs","title":"Инпуты — все типы полей формы основа 🔗","html":"<div class=\"block\" id=\"block-inputs\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-inputs')\">Инпуты — все типы полей формы <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">У &lt;input&gt; больше 20 типов. Правильный type включает удобную клавиатуру на телефоне, валидацию и нужный пикер.</div>\n      <div class=\"code\">&lt;!-- Текстовые --&gt;\n&lt;input type=\"text\"     name=\"name\"   placeholder=\"Имя\"&gt;\n&lt;input type=\"email\"    name=\"email\"  required&gt;       &lt;!-- @ на телефоне --&gt;\n&lt;input type=\"tel\"      name=\"phone\"  pattern=\"[0-9]{11}\"&gt;\n&lt;input type=\"password\" name=\"pass\"   minlength=\"8\"&gt;\n&lt;input type=\"url\"      name=\"site\"&gt;\n&lt;input type=\"search\"   name=\"q\"&gt;\n\n&lt;!-- Числа и диапазоны --&gt;\n&lt;input type=\"number\" min=\"1\" max=\"99\" step=\"1\" value=\"18\"&gt;\n&lt;input type=\"range\"  min=\"0\" max=\"100\" value=\"50\"&gt;   &lt;!-- ползунок --&gt;\n\n&lt;!-- Даты и время --&gt;\n&lt;input type=\"date\"&gt;          &lt;!-- календарь --&gt;\n&lt;input type=\"time\"&gt;\n&lt;input type=\"datetime-local\"&gt;\n&lt;input type=\"month\"&gt;\n&lt;input type=\"week\"&gt;\n\n&lt;!-- Выбор --&gt;\n&lt;input type=\"checkbox\" id=\"ok\"&gt; &lt;label for=\"ok\"&gt;Согласен&lt;/label&gt;\n&lt;input type=\"radio\" name=\"size\" value=\"s\"&gt; S\n&lt;input type=\"radio\" name=\"size\" value=\"m\" checked&gt; M\n\n&lt;!-- Файл и цвет --&gt;\n&lt;input type=\"file\"  accept=\"image/*\" multiple&gt;\n&lt;input type=\"color\" value=\"#6366f1\"&gt;\n\n&lt;!-- &lt;textarea&gt; — длинный текст, &lt;select&gt; — выпадающий список --&gt;\n&lt;textarea rows=\"4\" maxlength=\"500\"&gt;&lt;/textarea&gt;\n&lt;select&gt;\n  &lt;option value=\"\"&gt;Выбери...&lt;/option&gt;\n  &lt;option value=\"ru\"&gt;Русский&lt;/option&gt;\n  &lt;option value=\"en\"&gt;English&lt;/option&gt;\n&lt;/select&gt;</div>\n      <div class=\"explain\">\n        <strong>Зачем правильный type?</strong> На телефоне <code>type=\"email\"</code> покажет клавиатуру с @, <code>type=\"tel\"</code> — цифровую, <code>type=\"number\"</code> — только цифры. Без этого пользователю неудобно.<br>\n        <strong>required, min, max, pattern, minlength</strong> — браузер сам не даст отправить форму с ошибкой, без единой строки JS.<br>\n        <strong>&lt;label for=\"id\"&gt;</strong> — клик по тексту фокусирует поле (а у чекбокса — переключает). Делает форму удобнее и доступнее.<br>\n        <strong>name=\"...\"</strong> — обязателен! Без него поле не отправится на сервер.<br>\n        <strong>placeholder ≠ label</strong> — placeholder исчезает при вводе. Всегда дублируй его лейблом.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb40\" onchange=\"updateProgress(this)\"><span>type=\"email\" / \"tel\" / \"number\" — удобная клавиатура на телефоне</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb41\" onchange=\"updateProgress(this)\"><span>required, min/max, pattern — валидация без JS</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb42\" onchange=\"updateProgress(this)\"><span>&lt;label for=\"id\"&gt; — клик по тексту фокусирует поле</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb43\" onchange=\"updateProgress(this)\"><span>name=\"...\" обязателен — иначе поле не уйдёт на сервер</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb44\" onchange=\"updateProgress(this)\"><span>type=\"date\" / \"color\" / \"file\" — встроенные пикеры браузера</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-iframe","title":"iframe — встраиваем YouTube, карты, виджеты важно 🔗","html":"<div class=\"block\" id=\"block-iframe\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-iframe')\">iframe — встраиваем YouTube, карты, виджеты <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">&lt;iframe&gt; вставляет «страницу внутри страницы». Так встраивают видео, карты, формы Google, виджеты соцсетей.</div>\n      <div class=\"code\">&lt;!-- YouTube --&gt;\n&lt;iframe width=\"560\" height=\"315\"\n        src=\"https://www.youtube.com/embed/dQw4w9WgXcQ\"\n        title=\"Видео\"\n        frameborder=\"0\"\n        allow=\"autoplay; encrypted-media; picture-in-picture\"\n        allowfullscreen&gt;&lt;/iframe&gt;\n\n&lt;!-- Google Maps (готовый embed-код) --&gt;\n&lt;iframe src=\"https://www.google.com/maps/embed?pb=...\"\n        width=\"600\" height=\"450\"\n        loading=\"lazy\"\n        referrerpolicy=\"no-referrer-when-downgrade\"&gt;&lt;/iframe&gt;\n\n&lt;!-- Адаптивный iframe (16:9) — оборачиваем --&gt;\n&lt;style&gt;\n  .embed { position: relative; aspect-ratio: 16 / 9; }\n  .embed iframe { position: absolute; inset: 0; width: 100%; height: 100%; border: 0; }\n&lt;/style&gt;\n\n&lt;div class=\"embed\"&gt;\n  &lt;iframe src=\"https://www.youtube.com/embed/...\" allowfullscreen&gt;&lt;/iframe&gt;\n&lt;/div&gt;\n\n&lt;!-- sandbox — ограничения для чужого контента (безопасность) --&gt;\n&lt;iframe src=\"https://untrusted.com\"\n        sandbox=\"allow-scripts allow-same-origin\"&gt;&lt;/iframe&gt;</div>\n      <div class=\"explain\">\n        <strong>src=\"...embed...\"</strong> — у YouTube/Maps есть отдельный embed-URL. Обычная ссылка <code>youtube.com/watch?v=...</code> не сработает — нужен <code>youtube.com/embed/ID</code>.<br>\n        <strong>aspect-ratio + position:absolute</strong> — стандартный приём адаптивного видео. Без него iframe ломает вёрстку на телефонах.<br>\n        <strong>loading=\"lazy\"</strong> — для iframe тоже работает! Очень полезно для карт и видео — они тяжёлые.<br>\n        <strong>sandbox</strong> — ограничивает чужой контент (нельзя выполнять JS, открывать поп-апы и т.д.). Используй, когда встраиваешь не свой сайт.<br>\n        <strong>title</strong> — обязателен для скринридеров. Объясняет, что внутри iframe.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb45\" onchange=\"updateProgress(this)\"><span>YouTube → копирую «Поделиться → Embed», беру URL из src</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb46\" onchange=\"updateProgress(this)\"><span>aspect-ratio + position:absolute — адаптивный iframe</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb47\" onchange=\"updateProgress(this)\"><span>loading=\"lazy\" — карта и видео грузятся только при скролле</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb48\" onchange=\"updateProgress(this)\"><span>title=\"...\" — нужен для скринридеров</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb49\" onchange=\"updateProgress(this)\"><span>sandbox — для непроверенного контента</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-details-dialog","title":"<details> и <dialog> — спойлеры и модалки без JS важно 🔗","html":"<div class=\"block\" id=\"block-details-dialog\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-details-dialog')\">&lt;details&gt; и &lt;dialog&gt; — спойлеры и модалки без JS <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Современный HTML умеет делать раскрывающиеся блоки и модальные окна сам. Не нужно писать JS, как 5 лет назад.</div>\n      <div class=\"code\">&lt;!-- Спойлер / FAQ --&gt;\n&lt;details&gt;\n  &lt;summary&gt;Как сделать заказ?&lt;/summary&gt;\n  &lt;p&gt;Положи товар в корзину и нажми «Купить». Мы перезвоним.&lt;/p&gt;\n&lt;/details&gt;\n\n&lt;details open&gt;     &lt;!-- сразу раскрытый --&gt;\n  &lt;summary&gt;Состав&lt;/summary&gt;\n  &lt;ul&gt;&lt;li&gt;мука&lt;/li&gt;&lt;li&gt;молоко&lt;/li&gt;&lt;/ul&gt;\n&lt;/details&gt;\n\n&lt;!-- Модальное окно --&gt;\n&lt;dialog id=\"myModal\"&gt;\n  &lt;form method=\"dialog\"&gt;\n    &lt;h2&gt;Подтверждение&lt;/h2&gt;\n    &lt;p&gt;Удалить файл?&lt;/p&gt;\n    &lt;button value=\"cancel\"&gt;Отмена&lt;/button&gt;\n    &lt;button value=\"ok\"&gt;Удалить&lt;/button&gt;   &lt;!-- закроет dialog --&gt;\n  &lt;/form&gt;\n&lt;/dialog&gt;\n\n&lt;button onclick=\"myModal.showModal()\"&gt;Удалить&lt;/button&gt;\n\n&lt;script&gt;\n  const dlg = document.getElementById('myModal');\n  dlg.addEventListener('close', () =&gt; {\n    if (dlg.returnValue === 'ok') {\n      console.log('Подтверждено!');\n    }\n  });\n&lt;/script&gt;</div>\n      <div class=\"explain\">\n        <strong>&lt;details&gt; / &lt;summary&gt;</strong> — нативный спойлер. Идеален для FAQ, «подробнее», скрытого описания. Работает без JS, доступен с клавиатуры.<br>\n        <strong>&lt;dialog&gt;</strong> — нативная модалка. <code>.showModal()</code> — открыть с фоном (затемнением), <code>.show()</code> — без фона.<br>\n        <strong>method=\"dialog\"</strong> — особый тип формы. Любая её кнопка автоматически закрывает диалог, а <code>value</code> кнопки попадает в <code>dialog.returnValue</code>.<br>\n        <strong>Esc закрывает dialog</strong> — встроенно. Не нужно ничего писать.<br>\n        <strong>Стили</strong>: фон затемнения настраивается через <code>dialog::backdrop { background: rgba(0,0,0,.5); }</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb50\" onchange=\"updateProgress(this)\"><span>&lt;details&gt; / &lt;summary&gt; — спойлер без JS, для FAQ</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb51\" onchange=\"updateProgress(this)\"><span>open — атрибут раскрытого по умолчанию состояния</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb52\" onchange=\"updateProgress(this)\"><span>&lt;dialog&gt; + showModal() — нативная модалка с фоном</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb53\" onchange=\"updateProgress(this)\"><span>Esc закрывает dialog автоматически</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb54\" onchange=\"updateProgress(this)\"><span>::backdrop — стилизуем затемнение под dialog</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-html-popover","title":"Popover API — попапы и подсказки без JS modern 🔗","html":"<div class=\"block\" id=\"block-html-popover\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-html-popover')\">Popover API — попапы и подсказки без JS <span class=\"badge good\">modern</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Popover API — нативный способ открыть маленькую панель, меню или подсказку. Браузер сам умеет закрывать её по Esc и клику снаружи.</div>\n      <div class=\"code\">&lt;button popovertarget=\"menu\"&gt;Открыть меню&lt;/button&gt;\n\n&lt;div id=\"menu\" popover&gt;\n  &lt;a href=\"/profile\"&gt;Профиль&lt;/a&gt;\n  &lt;a href=\"/settings\"&gt;Настройки&lt;/a&gt;\n&lt;/div&gt;\n\n&lt;style&gt;\n  [popover] {\n    border: 0;\n    border-radius: 10px;\n    padding: 12px;\n    box-shadow: 0 16px 40px rgba(0,0,0,.18);\n  }\n&lt;/style&gt;</div>\n      <div class=\"explain\">\n        <strong>popover</strong> — делает элемент всплывающей панелью. Он скрыт, пока его не откроют.<br>\n        <strong>popovertarget</strong> — связывает кнопку с popover-элементом по id, без обработчика click.<br>\n        <strong>Когда использовать:</strong> выпадающее меню, тултип, фильтр, быстрые настройки. Для полноценного подтверждения действия чаще лучше <code>&lt;dialog&gt;</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-html-popover-1\" onchange=\"updateProgress(this)\"><span>Понимаю popover и popovertarget</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-html-popover-2\" onchange=\"updateProgress(this)\"><span>Знаю отличие popover от dialog</span></label>\n      </div>\n    </div>\n\n    "}]},{"id":"sec-css","lessons":[{"id":"block-css-connect","title":"Как подключить CSS основа 🔗","html":"<div class=\"block\" id=\"block-css-connect\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-css-connect')\">Как подключить CSS <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">CSS — это «одежда» сайта. HTML = скелет, CSS = внешний вид: цвета, размеры, расположение.</div>\n      <div class=\"code\">&lt;!DOCTYPE html&gt;\n&lt;html&gt;\n&lt;head&gt;\n  &lt;!-- ЭТА СТРОКА подключает style.css --&gt;\n  &lt;link rel=\"stylesheet\" href=\"style.css\"&gt;\n&lt;/head&gt;\n&lt;body&gt;\n  &lt;h1&gt;Привет&lt;/h1&gt;\n&lt;/body&gt;\n&lt;/html&gt;\n\n/* А это — файл style.css */\nh1 {\n  color: red;\n  text-align: center;\n}</div>\n      <div class=\"explain\">\n        <strong>Без &lt;link&gt;</strong> браузер <em>не знает</em> про style.css. Стили не применятся.<br>\n        <strong>rel=\"stylesheet\"</strong> — говорит браузеру: «это таблица стилей».<br>\n        <strong>href=\"style.css\"</strong> — путь к файлу. Если в папке: <code>href=\"css/style.css\"</code>.<br>\n        <strong>Частая ошибка:</strong> написал CSS, но не подключил &lt;link&gt; — ничего не изменилось!\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb55\" onchange=\"updateProgress(this)\"><span>&lt;link rel=\"stylesheet\" href=\"style.css\"&gt; — внутри &lt;head&gt;</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb56\" onchange=\"updateProgress(this)\"><span>Без &lt;link&gt; стили НЕ применятся</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb57\" onchange=\"updateProgress(this)\"><span>href — путь к файлу: \"style.css\", \"css/style.css\", \"../style.css\"</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-selectors","title":"Селекторы — к чему применять стили основа 🔗","html":"<div class=\"block\" id=\"block-selectors\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-selectors')\">Селекторы — к чему применять стили <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">p            { }   /* Все &lt;p&gt; — по тегу */\n.card        { }   /* class=\"card\" — по классу (самый частый!) */\n#header      { }   /* id=\"header\" — по id (один на странице) */\na:hover      { }   /* ссылка при наведении мыши */\ndiv &gt; p      { }   /* &lt;p&gt; — прямой потомок &lt;div&gt; */</div>\n      <div class=\"explain\">\n        <strong>Класс (.)</strong> — можно использовать на множестве элементов.<br>\n        <strong>Id (#)</strong> — только <em>один</em> элемент на странице.<br>\n        <strong>Специфичность</strong>: <code>#id</code> &gt; <code>.класс</code> &gt; <code>тег</code>.<br>\n        <strong>:hover</strong> — стиль при наведении. :focus — при клике на поле. :active — в момент нажатия.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb58\" onchange=\"updateProgress(this)\"><span>Класс (.) — для множества элементов. Id (#) — для одного</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb59\" onchange=\"updateProgress(this)\"><span>:hover — наведение, :focus — фокус</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-css-responsive-2026","title":"Адаптивная раскладка: Flexbox + Grid ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-css-responsive-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-css-responsive-2026')\">Адаптивная раскладка: Flexbox + Grid <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Flexbox выравнивает элементы по одной оси, Grid строит полноценную сетку. Современный CSS часто адаптируется без отдельного медиазапроса.</div><div class=\"code\">.page {\n  display: grid;\n  grid-template-columns: 16rem minmax(0, 1fr);\n  gap: 24px;\n}\n\n.cards {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));\n  gap: 16px;\n}\n\n.toolbar {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 12px;\n  flex-wrap: wrap;\n}\n\n@media (max-width: 48rem) {\n  .page { grid-template-columns: 1fr; }\n}</div><div class=\"explain\"><strong>Flexbox</strong> подходит для меню, строки кнопок и выравнивания. <strong>Grid</strong> одновременно управляет строками и колонками. <code>minmax(0, 1fr)</code> не даёт длинному контенту растянуть страницу, а <code>auto-fit</code> сам переносит карточки.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-responsive-2026-1\" onchange=\"updateProgress(this)\"><span>Выбираю Flexbox для ряда, а Grid для сетки</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-responsive-2026-2\" onchange=\"updateProgress(this)\"><span>Использую repeat(), minmax() и auto-fit</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-responsive-2026-3\" onchange=\"updateProgress(this)\"><span>Проверяю 360 px, 768 px и широкий экран</span></label></div></div>"},{"id":"block-flexbox","title":"Flexbox — расположение в ряд основа 🔗","html":"<div class=\"block\" id=\"block-flexbox\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-flexbox')\">Flexbox — расположение в ряд <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">.container {\n  display: flex;\n  justify-content: center;   /* По горизонтали */\n  align-items: center;       /* По вертикали */\n  gap: 16px;                 /* Расстояние между элементами */\n  flex-wrap: wrap;           /* Перенос на новую строку */\n}\n.item { flex: 1; }</div>\n      <div class=\"explain\">\n        <strong>display: flex</strong> — все прямые потомки контейнера встают в ряд.<br>\n        <strong>justify-content</strong> — по горизонтали. <strong>align-items</strong> — по вертикали.<br>\n        <strong>gap</strong> — промежуток между элементами.<br>\n        <strong>flex-wrap: wrap</strong> — если не влезают, переносятся на следующую строку.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb81\" onchange=\"updateProgress(this)\"><span>justify-content — по горизонтали, align-items — по вертикали</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb82\" onchange=\"updateProgress(this)\"><span>gap — расстояние между элементами</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb83\" onchange=\"updateProgress(this)\"><span>flex-wrap: wrap — перенос на новую строку</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-grid","title":"Grid — сетка / таблица важно 🔗","html":"<div class=\"block\" id=\"block-grid\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-grid')\">Grid — сетка / таблица <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">.grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr); /* 3 колонки */\n  gap: 20px;\n}\n@media (max-width: 768px) {\n  .grid { grid-template-columns: 1fr; } /* На телефоне — 1 колонка */\n}\n.span-2 { grid-column: span 2; } /* На 2 колонки */</div>\n      <div class=\"explain\">\n        <strong>repeat(3, 1fr)</strong> — «повтори 3 раза по 1 доле». Получится 3 равных колонки.<br>\n        <strong>grid-column: span 2</strong> — эта ячейка займёт 2 колонки.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb84\" onchange=\"updateProgress(this)\"><span>repeat(3, 1fr) — 3 равных колонки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb85\" onchange=\"updateProgress(this)\"><span>Grid для сетки страницы, Flexbox для элементов внутри</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-css-tailwind-mobile-2026","title":"Tailwind CSS и Mobile First ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-css-tailwind-mobile-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-css-tailwind-mobile-2026')\">Tailwind CSS и Mobile First <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Сначала напиши удобный вариант для телефона. Префиксы md: и lg: добавляют изменения для более широких экранов.</div><div class=\"code\">&lt;section class=\"grid grid-cols-1 gap-4 p-4 md:grid-cols-2 md:p-6 lg:grid-cols-3\"&gt;\n  &lt;article class=\"rounded-lg border border-slate-700 bg-slate-900 p-4\"&gt;\n    &lt;h2 class=\"text-lg font-semibold text-white\"&gt;Project&lt;/h2&gt;\n    &lt;p class=\"mt-2 text-sm text-slate-300\"&gt;Responsive by default.&lt;/p&gt;\n    &lt;button class=\"mt-4 w-full bg-violet-600 px-4 py-2 text-white md:w-auto\"&gt;\n      Open\n    &lt;/button&gt;\n  &lt;/article&gt;\n&lt;/section&gt;</div><div class=\"explain\">Классы без префикса создают мобильную основу. <code>md:grid-cols-2</code> включается с md. Tailwind не отменяет CSS: он даёт короткие имена правилам. Повторяющийся интерфейс выноси в компонент, а не копируй длинную строку классов.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-tailwind-mobile-2026-1\" onchange=\"updateProgress(this)\"><span>Начинаю с мобильной версии</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-tailwind-mobile-2026-2\" onchange=\"updateProgress(this)\"><span>Понимаю CSS за utility-классами</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-tailwind-mobile-2026-3\" onchange=\"updateProgress(this)\"><span>Выношу повторяющийся UI в компоненты</span></label></div></div>"},{"id":"block-tailwind-product-card-2026","title":"Карточка товара на Tailwind CSS ПРАКТИКА #","html":"<div class=\"block wdg-quality-block\" id=\"block-tailwind-product-card-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-tailwind-product-card-2026')\">Карточка товара на Tailwind CSS <span class=\"badge good\">ПРАКТИКА</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Карточка - хороший пример композиции utility-классов. Семантика остаётся HTML, а Tailwind отвечает за внешний вид и адаптивные состояния.</div><div class=\"code\">&lt;article class=\"overflow-hidden rounded-lg border border-slate-700 bg-slate-900\"&gt;\n  &lt;img class=\"aspect-[4/3] w-full object-cover\"\n       src=\"keyboard.jpg\" alt=\"Механическая клавиатура Key Pro\"&gt;\n  &lt;div class=\"p-4\"&gt;\n    &lt;h2 class=\"text-lg font-semibold text-white\"&gt;Key Pro&lt;/h2&gt;\n    &lt;p class=\"mt-1 text-sm text-slate-300\"&gt;Тихие переключатели, RGB&lt;/p&gt;\n    &lt;div class=\"mt-4 flex items-center justify-between gap-3\"&gt;\n      &lt;strong class=\"text-xl text-white\"&gt;7 990 ?&lt;/strong&gt;\n      &lt;button class=\"rounded-md bg-violet-600 px-4 py-2 text-white hover:bg-violet-500\"&gt;\n        В корзину\n      &lt;/button&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n&lt;/article&gt;</div><div class=\"explain\"><code>aspect-[4/3]</code> резервирует стабильное место для изображения, поэтому карточка не прыгает при загрузке. <code>object-cover</code> заполняет область без искажения пропорций. Повторяющиеся карточки генерируй из массива данных в компоненте, а не копируй вручную.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tailwind-product-card-2026-1\" onchange=\"updateProgress(this)\"><span>Сохраняю semantic article</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tailwind-product-card-2026-2\" onchange=\"updateProgress(this)\"><span>Фиксирую aspect ratio</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tailwind-product-card-2026-3\" onchange=\"updateProgress(this)\"><span>Выношу повторения в компонент</span></label></div></div>"},{"id":"block-tailwind-basics","title":"Tailwind CSS — utility-first стек 2026 🔗","html":"<div class=\"block\" id=\"block-tailwind-basics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-tailwind-basics')\">Tailwind CSS — utility-first стек <span class=\"badge must\">2026</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">В новых React-проектах Tailwind часто выбирают вместо ручного SCSS: стили собираются из маленьких utility-классов прямо в JSX, а дизайн-система живёт в конфиге.</div>\n      <div class=\"code\"><span class=\"cm\">// Пример компонента на Tailwind</span>\n&lt;<span class=\"tag\">button</span>\n  <span class=\"attr\">className</span>=<span class=\"str\">\"rounded-lg bg-indigo-600 px-4 py-2 text-sm font-semibold text-white hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-500\"</span>\n&gt;\n  Сохранить\n&lt;/<span class=\"tag\">button</span>&gt;\n\n<span class=\"cm\">// tailwind.config.ts — дизайн-токены команды</span>\n<span class=\"kw\">export default</span> {\n  theme: {\n    extend: {\n      colors: { brand: <span class=\"str\">'#6366f1'</span> },\n      borderRadius: { card: <span class=\"str\">'8px'</span> }\n    }\n  }\n}</div>\n      <div class=\"explain\">\n        <strong>Utility-first</strong> — класс описывает одно CSS-свойство: <code>px-4</code>, <code>flex</code>, <code>text-sm</code>.<br>\n        <strong>Плюс для команд:</strong> меньше случайных CSS-файлов и конфликтов имён, проще держать единые отступы, цвета и состояния.<br>\n        <strong>Важно:</strong> Tailwind не отменяет CSS. Нужно понимать каскад, flex/grid, адаптивность и доступность, иначе классы превращаются в хаос.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb152a\" onchange=\"updateProgress(this)\"><span>Понимаю utility-first подход Tailwind CSS</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb152b\" onchange=\"updateProgress(this)\"><span>Знаю где в Tailwind задаются цвета, отступы и радиусы</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-div","title":"<div> — универсальный контейнер основа 🔗","html":"<div class=\"block\" id=\"block-div\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-div')\">&lt;div&gt; — универсальный контейнер <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">&lt;div&gt; — это «коробка» без смысла. Она не говорит браузеру что внутри. Просто контейнер, в который ты кладёшь элементы.</div>\n      <div class=\"code\">&lt;!-- Группируем элементы вместе --&gt;\n&lt;div class=\"card\"&gt;\n  &lt;img src=\"photo.jpg\" alt=\"Фото\"&gt;\n  &lt;h3&gt;Заголовок карточки&lt;/h3&gt;\n  &lt;p&gt;Описание карточки&lt;/p&gt;\n  &lt;button&gt;Подробнее&lt;/button&gt;\n&lt;/div&gt;\n\n/* CSS: стилизуем всю карточку */\n.card {\n  background: white;\n  border-radius: 12px;\n  padding: 20px;\n  margin: 10px;\n}</div>\n      <div class=\"explain\">\n        <strong>&lt;div&gt;</strong> — просто контейнер. Он не значит «карточка», «заголовок», «ссылка». Он значит «тут что-то сгруппировано».<br>\n        <strong>Зачем:</strong> чтобы применить стили ко всему сразу. Например: сделать рамку вокруг картинки + текста + кнопки.<br>\n        <strong>class=\"card\"</strong> — даём имя. В CSS: <code>.card { background: white; padding: 20px; }</code>.<br><br>\n        <strong>Когда использовать &lt;div&gt;:</strong> когда нужно сгруппировать элементы для стилизации.<br>\n        <strong>Когда НЕ использовать:</strong> вместо &lt;p&gt; для текста, вместо &lt;button&gt; для кнопки. Если есть смысловой тег — используй его.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb60\" onchange=\"updateProgress(this)\"><span>&lt;div&gt; — контейнер-«коробка», группирует элементы</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb61\" onchange=\"updateProgress(this)\"><span>class=\"имя\" — даём имя, стилизуем в CSS через .имя</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb62\" onchange=\"updateProgress(this)\"><span>Используй &lt;div&gt; для группировки, не вместо смысловых тегов</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-span","title":"<span> — строчный контейнер важно 🔗","html":"<div class=\"block\" id=\"block-span\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-span')\">&lt;span&gt; — строчный контейнер <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">&lt;span&gt; — как &lt;div&gt;, но НЕ создаёт новую строку. Для части текста внутри &lt;p&gt;.</div>\n      <div class=\"code\">&lt;p&gt;Цена: &lt;span class=\"price\"&gt;999 руб&lt;/span&gt;&lt;/p&gt;\n&lt;p&gt;Это &lt;span class=\"highlight\"&gt;очень&lt;/span&gt; важно!&lt;/p&gt;\n\n/* CSS */\n.price { color: red; font-weight: bold; }\n.highlight {\n  background-color: yellow;\n  padding: 2px 4px;\n  border-radius: 4px;\n}</div>\n      <div class=\"explain\">\n        <strong>&lt;span&gt;</strong> — строчный контейнер. Не переносит на новую строку. Работает <em>внутри</em> текста.<br>\n        <strong>Отличие от &lt;div&gt;:</strong> &lt;div&gt; = блок, новая строка. &lt;span&gt; = внутри строки, не ломает текст.<br>\n        Используй &lt;span&gt; когда нужно покрасить часть текста, выделить кусок слова, и т.д.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb63\" onchange=\"updateProgress(this)\"><span>&lt;span&gt; — контейнер внутри строки, не создаёт новую строку</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb64\" onchange=\"updateProgress(this)\"><span>&lt;div&gt; = блочный (новая строка), &lt;span&gt; = строчный (внутри текста)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-nested-selectors","title":"Вложенные селекторы — стили внутри страницы основа 🔗","html":"<div class=\"block\" id=\"block-nested-selectors\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nested-selectors')\">Вложенные селекторы — стили внутри страницы <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Один CSS-файл, но на каждой странице — свои цвета текста, кнопок и ссылок. Как? Ставь пробел между классом страницы и элементом.</div>\n      <div class=\"code\">/* h1 — разный на каждой странице */\n.page-home h1 {\n  color: black;\n}\n.page-recipe h1 {\n  color: white;\n}\n.page-settings h1 {\n  color: yellow;\n}\n\n/* p, button, a — тоже разные */\n.page-home p { color: gray; }\n.page-home button { background-color: red; }\n\n.page-recipe p { color: lightgreen; }\n.page-recipe button { background-color: green; }\n\n.page-settings button { background-color: blue; }</div>\n      <div class=\"explain\">\n        <strong>Пробел = «внутри»:</strong> <code>.page-home h1</code> читается как «найди все h1 <em>внутри</em> элемента с классом page-home».<br>\n        Так можно стилизовать <strong>любой</strong> элемент на конкретной странице, не затрагивая остальные.<br>\n        <strong>.page-home button</strong> — только кнопки на главной. <strong>.page-recipe p</strong> — только абзацы на странице рецепта.<br>\n        Это работает для всего: <code>.page-home img</code>, <code>.page-settings a</code>, <code>.page-recipe ul</code> — для любого тега внутри класса.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb65\" onchange=\"updateProgress(this)\"><span>.page-home h1 — «пробел» значит «внутри». Только h1 на главной</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb66\" onchange=\"updateProgress(this)\"><span>Можно стилизовать любой тег: p, a, button, img, ul, li — всё</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb67\" onchange=\"updateProgress(this)\"><span>Один CSS-файл → разные стили на разных страницах</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-center-button","title":"Центрирование кнопки без костылей ОСНОВА #","html":"<div class=\"block wdg-quality-block\" id=\"block-center-button\"><div class=\"block-title\" onclick=\"scrollToBlock('block-center-button')\">Центрирование кнопки без костылей <span class=\"badge must\">ОСНОВА</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Центрируй элемент через контейнер или автоматические внешние отступы. Большие фиксированные <code>margin-left</code> ломают адаптивность.</div><div class=\"code\">/* Вариант 1: контейнер управляет расположением */\n.actions {\n  display: flex;\n  justify-content: center;\n}\n\n/* Вариант 2: одна блочная кнопка */\n.save-button {\n  display: block;\n  margin-inline: auto;\n}\n\n&lt;div class=\"actions\"&gt;\n  &lt;button type=\"button\"&gt;Сохранить&lt;/button&gt;\n&lt;/div&gt;</div><div class=\"explain\"><code>justify-content</code> работает вдоль главной оси flex-контейнера. <code>margin-inline: auto</code> делит свободное место поровну. Не оборачивай кнопку ссылкой ради центрирования или внешнего вида.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-center-button-1\" onchange=\"updateProgress(this)\"><span>Центрирую через layout</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-center-button-2\" onchange=\"updateProgress(this)\"><span>Понимаю роль контейнера</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-center-button-3\" onchange=\"updateProgress(this)\"><span>Не смешиваю ссылку и кнопку</span></label></div></div>"},{"id":"block-boxmodel","title":"Блочная модель (Box Model) основа 🔗","html":"<div class=\"block\" id=\"block-boxmodel\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-boxmodel')\">Блочная модель (Box Model) <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">  ┌─────── margin (внешний отступ) ──────┐\n  │  ┌────── border (рамка) ─────────┐   │\n  │  │  ┌─── padding (внутр. отступ) ─┐  │\n  │  │  │        width / height       │  │\n  │  │  └─────────────────────────────┘  │\n  │  └────────────────────────────────────┘\n  └──────────────────────────────────────────┘\n\ndiv {\n  width: 200px;\n  padding: 20px;   /* расширяет блок изнутри */\n  border: 2px solid black;\n  margin: 30px;    /* отступ от соседних элементов */\n  box-sizing: border-box; /* padding НЕ увеличивает ширину */\n}</div>\n      <div class=\"explain\">\n        <strong>margin</strong> — снаружи. Расстояние от соседних элементов.<br>\n        <strong>border</strong> — рамка вокруг элемента.<br>\n        <strong>padding</strong> — внутри. Расстояние между содержимым и рамкой.<br>\n        <strong>box-sizing: border-box</strong> — ставь всегда! Тогда width включает padding и border.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb79\" onchange=\"updateProgress(this)\"><span>margin — снаружи, padding — внутри, border — рамка</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb80\" onchange=\"updateProgress(this)\"><span>box-sizing: border-box — первая строка любого CSS</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-scroll-anim","title":"Анимация при скролле (Intersection Observer) анимации 🔗","html":"<div class=\"block\" id=\"block-scroll-anim\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-scroll-anim')\">Анимация при скролле (Intersection Observer) <span class=\"badge anim\">анимации</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Элементы появляются плавно, когда пользователь доскролливает до них — как на современных сайтах.</div>\n      <div class=\"code\">/* CSS — скрыт по умолчанию */\n.fade-in {\n  opacity: 0;\n  transform: translateY(30px);\n  transition: all 0.6s ease;\n}\n/* Класс добавляется JS'ом */\n.fade-in.visible {\n  opacity: 1;\n  transform: translateY(0);\n}\n\n// JS — следим за появлением элементов\nconst observer = new IntersectionObserver((entries) =&gt; {\n  entries.forEach(entry =&gt; {\n    if (entry.isIntersecting) {\n      entry.target.classList.add('visible');\n    }\n  });\n}, { threshold: 0.1 });\n\ndocument.querySelectorAll('.fade-in').forEach(el =&gt; {\n  observer.observe(el);\n});</div>\n      <div class=\"explain\">\n        <strong>IntersectionObserver</strong> — браузерное API. Следит: вошёл ли элемент в видимую зону экрана.<br>\n        <strong>threshold: 0.1</strong> — «сработай, когда 10% элемента видно».<br>\n        <strong>entry.isIntersecting</strong> — true, если элемент сейчас виден на экране.<br>\n        Это лучше, чем слушать событие <code>scroll</code> — не тормозит страницу!\n      </div>\n      <div class=\"live-example\">\n        <div class=\"live-example-header\">▶ ЖИВОЙ ПРИМЕР — нажми кнопку, имитируя скролл</div>\n        <div class=\"live-example-body\" style=\"flex-direction: column; align-items: stretch; padding: 12px;\">\n          <div class=\"demo-scroll-box\" id=\"scrollDemo\">\n            <div class=\"scroll-item\">🚀 Блок 1 — появляется первым</div>\n            <div class=\"scroll-item\">🎨 Блок 2 — плавно выезжает</div>\n            <div class=\"scroll-item\">⚡ Блок 3 — один за другим</div>\n          </div>\n          <button onclick=\"triggerScrollAnim()\" style=\"margin-top:8px; padding:8px 16px; border-radius:8px; background:#6366f1; color:white; border:none; cursor:pointer; font-family:inherit; font-size:13px;\">▶ Запустить анимацию</button>\n        </div>\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb89\" onchange=\"updateProgress(this)\"><span>IntersectionObserver — следим за появлением в экране</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb90\" onchange=\"updateProgress(this)\"><span>opacity + transform — основная пара для плавного появления</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-vars","title":"CSS-переменные продвинуто 🔗","html":"<div class=\"block\" id=\"block-vars\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vars')\">CSS-переменные <span class=\"badge pro\">продвинуто</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">/* Определяем переменные один раз */\n:root {\n  --color-main: #6366f1;\n  --radius: 8px;\n  --font: 'Segoe UI', sans-serif;\n}\n.btn {\n  background: var(--color-main);\n  border-radius: var(--radius);\n  transition: all 0.2s ease;\n}\n/* Тёмная тема — меняем одну переменную! */\n[data-theme=\"dark\"] {\n  --color-main: #818cf8;\n}</div>\n      <div class=\"explain\">\n        <strong>--имя</strong> — так создаётся CSS-переменная. <strong>var(--имя)</strong> — так используется.<br>\n        <strong>:root</strong> — переменные доступны на всей странице.<br>\n        Смена темы: меняешь 5 переменных → весь сайт перекрашивается!\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb93\" onchange=\"updateProgress(this)\"><span>CSS-переменные: определил один раз — используешь везде</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb94\" onchange=\"updateProgress(this)\"><span>transition = плавность. Без него изменения мгновенные</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-toggle-guide","title":"Тумблер (Toggle Switch) — как сделать анимации 🔗","html":"<div class=\"block\" id=\"block-toggle-guide\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-toggle-guide')\">Тумблер (Toggle Switch) — как сделать <span class=\"badge anim\">анимации</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Тумблер — это стилизованный чекбокс. Делается через &lt;input type=\"checkbox\"&gt; + CSS псевдоэлементы.</div>\n      <div class=\"code\">/* HTML */\n&lt;label class=\"toggle-wrap\"&gt;\n  &lt;input type=\"checkbox\" id=\"myToggle\"&gt;\n  &lt;span class=\"slider\"&gt;&lt;/span&gt;\n&lt;/label&gt;\n\n/* CSS */\n.toggle-wrap {\n  position: relative;\n  width: 52px;\n  height: 28px;\n  cursor: pointer;\n}\n.toggle-wrap input { opacity: 0; width:0; height:0; } /* Скрываем */\n\n.slider {\n  position: absolute;\n  inset: 0;\n  background: #d1d5db;\n  border-radius: 99px;\n  transition: background 0.3s ease;\n}\n.slider::before {          /* Шарик */\n  content: '';\n  position: absolute;\n  width: 20px;\n  height: 20px;\n  background: white;\n  border-radius: 50%;\n  bottom: 4px;\n  left: 4px;\n  transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);\n  box-shadow: 0 1px 4px rgba(0,0,0,.2);\n}\n/* Когда включено */\ninput:checked + .slider { background: #6366f1; }\ninput:checked + .slider::before { transform: translateX(24px); }\n\n// Читаем состояние в JS:\nconst toggle = document.getElementById('myToggle');\ntoggle.addEventListener('change', () =&gt; {\n  if (toggle.checked) {\n    console.log('Включено!');\n    document.body.classList.add('dark-theme');\n  } else {\n    console.log('Выключено!');\n    document.body.classList.remove('dark-theme');\n  }\n});</div>\n      <div class=\"live-example\">\n        <div class=\"live-example-header\">▶ ЖИВОЙ ПРИМЕР — нажми на тумблеры</div>\n        <div class=\"live-example-body\" style=\"gap: 24px;\">\n          <div class=\"demo-toggle-wrap\">\n            <div class=\"toggle-label\">Тёмная тема</div>\n            <button class=\"toggle\" id=\"t1\" onclick=\"toggleSwitch('t1', 'toggleStatus1')\"></button>\n            <div class=\"toggle-status\" id=\"toggleStatus1\">Выключено</div>\n          </div>\n          <div class=\"demo-toggle-wrap\">\n            <div class=\"toggle-label\">Уведомления</div>\n            <button class=\"toggle on\" id=\"t2\" onclick=\"toggleSwitch('t2', 'toggleStatus2')\"></button>\n            <div class=\"toggle-status\" id=\"toggleStatus2\">Включено</div>\n          </div>\n          <div class=\"demo-toggle-wrap\">\n            <div class=\"toggle-label\">Wi-Fi</div>\n            <button class=\"toggle\" id=\"t3\" onclick=\"toggleSwitch('t3', 'toggleStatus3')\"></button>\n            <div class=\"toggle-status\" id=\"toggleStatus3\">Выключено</div>\n          </div>\n        </div>\n      </div>\n      <div class=\"explain\">\n        <strong>input:checked + .slider</strong> — CSS-селектор «когда чекбокс включён, стилизуй следующий элемент .slider».<br>\n        <strong>::before</strong> — псевдоэлемент, он создаёт «шарик» тумблера без лишнего HTML.<br>\n        <strong>transform: translateX(24px)</strong> — двигает шарик вправо при включении.<br>\n        В JS читаешь <code>toggle.checked</code> — это <code>true</code> или <code>false</code>.\n      </div>\n      <div class=\"items\">\n      <!-- МИНИ-ТЕСТ ДЛЯ ТУМБЛЕРА -->\n      <div class=\"quiz-block\" id=\"quiz-toggle\">\n        <div class=\"quiz-title\">🧪 Мини-тест — Тумблер</div>\n        <div class=\"quiz-question\">1. На чём основан тумблер-переключатель в CSS?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-1\" value=\"a\"> <span>На &lt;div&gt; с JavaScript-обработчиком</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-1\" value=\"b\"> <span>На скрытом &lt;input type=\"checkbox\"&gt; со стилизованным span</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-1\" value=\"c\"> <span>На &lt;button&gt; с toggle-классом</span></label>\n        </div>\n        <div class=\"quiz-question\">2. Какой CSS-селектор отслеживает состояние чекбокса?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-2\" value=\"a\"> <span>input.active + .slider</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-2\" value=\"b\"> <span>input:checked + .slider</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-2\" value=\"c\"> <span>input[on] ~ .slider</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Практика</div>\n          <div class=\"practice-task\">Напиши CSS-правило, которое меняет фон <code>.slider</code> на зелёный, когда связанный чекбокс отмечен.</div>\n          <textarea class=\"practice-input\" id=\"practice-toggle\" placeholder=\"input:checked + .slider { ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('toggle')\">✓ Проверить</button>\n        <div class=\"quiz-result\" id=\"result-toggle\"></div>\n      </div>\n        <div class=\"items\" id=\"items-toggle\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb609\" onchange=\"updateProgress(this)\" disabled><span>🔒 Тумблер = скрытый чекбокс + стилизованный span</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb95\" onchange=\"updateProgress(this)\"><span>input:checked + .slider — стиль когда включено</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb96\" onchange=\"updateProgress(this)\"><span>toggle.checked в JS — true/false состояние</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-gradient-text\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-gradient-text')\">Градиентный текст и эффекты <span class=\"badge anim\">анимации</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">/* Градиентный текст */\n.gradient-text {\n  background: linear-gradient(135deg, #6366f1, #ec4899, #f59e0b);\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n  background-size: 200% 200%;\n  animation: gradientShift 3s ease infinite;\n}\n@keyframes gradientShift {\n  0%, 100% { background-position: 0% 50%; }\n  50%       { background-position: 100% 50%; }\n}\n\n/* Glassmorphism (стекло) */\n.glass {\n  background: rgba(255, 255, 255, 0.1);\n  backdrop-filter: blur(10px);\n  border: 1px solid rgba(255, 255, 255, 0.2);\n  border-radius: 16px;\n}</div>\n      <div class=\"live-example\">\n        <div class=\"live-example-header\">▶ ЖИВОЙ ПРИМЕР</div>\n        <div class=\"live-example-body\">\n          <div class=\"demo-gradient-text\">Привет!</div>\n        </div>\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb97\" onchange=\"updateProgress(this)\"><span>background-clip: text — применяет фон к тексту</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb98\" onchange=\"updateProgress(this)\"><span>backdrop-filter: blur() — эффект стекла</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-position\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-position')\">Position — позиционирование элементов <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">position — одно из самых часто используемых свойств. Без него не сделать модалку, выпадающее меню, кнопку поверх картинки.</div>\n      <div class=\"code\">/* static — по умолчанию (в потоке документа) */\n.box { position: static; }\n\n/* relative — смещается относительно своего места */\n.box { position: relative; top: 10px; left: 20px; }\n\n/* absolute — вырывается из потока, позиционируется\n   относительно ближайшего предка с position != static */\n.parent { position: relative; }\n.child  { position: absolute; top: 0; right: 0; }\n\n/* fixed — прибивается к окну браузера (шапка, кнопка \"наверх\") */\n.header { position: fixed; top: 0; left: 0; width: 100%; z-index: 100; }\n\n/* sticky — прилипает при скролле */\n.sidebar { position: sticky; top: 20px; }</div>\n      <div class=\"explain\">\n        <strong>static</strong> — все элементы по умолчанию. top/left/right/bottom не работают.<br>\n        <strong>relative</strong> — смещается, но место в потоке <em>сохраняется</em>. Часто используется как «якорь» для absolute-детей.<br>\n        <strong>absolute</strong> — ищет ближайшего предка с <code>position: relative/absolute/fixed</code>. Если не нашёл — позиционируется по &lt;html&gt;.<br>\n        <strong>fixed</strong> — не реагирует на скролл. Идеально для шапки и всплывающих кнопок.<br>\n        <strong>z-index</strong> — кто рисуется поверх. Большее число = выше.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb99\" onchange=\"updateProgress(this)\"><span>relative — якорь для absolute-детей</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb100\" onchange=\"updateProgress(this)\"><span>absolute позиционируется по ближайшему relative-предку</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb101\" onchange=\"updateProgress(this)\"><span>fixed прибит к экрану, не скроллится</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb102\" onchange=\"updateProgress(this)\"><span>z-index управляет порядком слоёв</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb103\" onchange=\"updateProgress(this)\"><span>sticky — прилипает при достижении края</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-pseudo\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pseudo')\">Псевдоклассы и псевдоэлементы <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Псевдоклассы реагируют на состояние элемента (:hover, :focus). Псевдоэлементы добавляют контент без лишнего HTML (::before, ::after).</div>\n      <div class=\"code\">/* === ПСЕВДОКЛАССЫ === */\na:hover  { color: #6366f1; }          /* при наведении мыши */\na:active { opacity: .7; }             /* при клике */\ninput:focus { border-color: #6366f1; } /* при фокусе */\n\nli:first-child { font-weight: bold; }  /* первый элемент */\nli:last-child  { color: gray; }        /* последний */\nli:nth-child(2) { background: #f0f; }  /* второй */\nli:nth-child(odd) { background: #f9f9f9; } /* нечётные */\n\n/* === ПСЕВДОЭЛЕМЕНТЫ === */\n/* Добавляют контент ДО и ПОСЛЕ элемента */\n.badge::before {\n  content: \"★ \";   /* обязательное свойство */\n  color: gold;\n}\n\n.card::after {\n  content: \"\";      /* пустой контент — для декора */\n  display: block;\n  width: 100%;\n  height: 3px;\n  background: linear-gradient(to right, #6366f1, #ec4899);\n}\n\n/* Выделение текста */\n::selection { background: #6366f1; color: white; }</div>\n      <div class=\"explain\">\n        <strong>:hover</strong> — стиль при наведении. Работает на любом элементе, не только на ссылках.<br>\n        <strong>:focus</strong> — стиль при фокусе (Tab или клик). Важен для доступности.<br>\n        <strong>:nth-child(n)</strong> — выбирает n-й элемент среди братьев. <code>odd</code> = нечётные, <code>even</code> = чётные.<br>\n        <strong>::before / ::after</strong> — «виртуальные» элементы. Нужен <code>content</code> (хотя бы пустой <code>\"\"</code>).<br>\n        <strong>Разница</strong>: один двоеточие <code>:</code> — псевдокласс, два <code>::</code> — псевдоэлемент.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb104\" onchange=\"updateProgress(this)\"><span>:hover / :focus / :active — три состояния интерактивности</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb105\" onchange=\"updateProgress(this)\"><span>:nth-child(odd/even) — зебра-стили для таблиц и списков</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb106\" onchange=\"updateProgress(this)\"><span>::before / ::after — декор без HTML, нужен content: \"\"</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb107\" onchange=\"updateProgress(this)\"><span>: — псевдокласс, :: — псевдоэлемент</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-media\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-media')\">Медиа-запросы — адаптивность <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Медиа-запросы позволяют применять разные стили для разных размеров экрана. Mobile-first — сначала пишем для мобильных, потом расширяем.</div>\n      <div class=\"code\">/* === Mobile-first подход === */\n/* Базовые стили — для мобильных (&lt; 768px) */\n.container { padding: 0 16px; }\n.nav { display: none; }               /* меню скрыто на мобильном */\n.visually-hidden {\n  position: absolute;\n  width: 1px; height: 1px;\n  overflow: hidden;\n  clip: rect(0 0 0 0);\n}\n\n/* Планшет — от 768px */\n@media (min-width: 768px) {\n  .container { max-width: 960px; margin: 0 auto; }\n  .nav { display: flex; }             /* меню появляется */\n}\n\n/* Десктоп — от 1024px */\n@media (min-width: 1024px) {\n  .container { max-width: 1200px; }\n  .grid { grid-template-columns: repeat(3, 1fr); }\n}\n\n/* === Типичные брейкпоинты === */\n/* 480px  — большие телефоны         */\n/* 768px  — планшеты                 */\n/* 1024px — ноутбуки                 */\n/* 1280px — десктопы                 */\n\n/* === Ориентация экрана === */\n@media (orientation: landscape) {\n  .hero { min-height: 60vh; }\n}\n\n/* === Тёмная тема системы === */\n@media (prefers-color-scheme: dark) {\n  body { background: #0f1117; color: #e2e8f0; }\n}</div>\n      <div class=\"explain\">\n        <strong>min-width</strong> — «от X пикселей и шире» (mobile-first). Чаще всего именно так.<br>\n        <strong>max-width</strong> — «до X пикселей» (desktop-first). Старый подход, но иногда удобен.<br>\n        <strong>Брейкпоинт</strong> — ширина, при которой дизайн меняется (768px, 1024px...).<br>\n        <strong>display: none</strong> полностью убирает элемент из дерева доступности. Если текст должен остаться для скринридеров, используй паттерн <code>.visually-hidden</code>, а не просто скрытие через display.<br>\n        <strong>prefers-color-scheme</strong> — определяет, включена ли тёмная тема в ОС.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb108\" onchange=\"updateProgress(this)\"><span>Mobile-first: сначала стили для мобильного, потом @media (min-width)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb109\" onchange=\"updateProgress(this)\"><span>768px — планшет, 1024px — десктоп</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb110\" onchange=\"updateProgress(this)\"><span>Проверяю сайт в DevTools (F12 → иконка телефона)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb111\" onchange=\"updateProgress(this)\"><span>prefers-color-scheme — авто-тёмная тема</span></label>\n      </div>\n    </div>\n\n\n    <div class=\"block\" id=\"block-container-queries\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-container-queries')\">Container Queries — адаптивность по контейнеру <span class=\"badge good\">изучи после</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Медиа-запросы реагируют на размер ВСЕГО окна браузера. Но что если одна и та же карточка лежит и в узком сайдбаре, и в широком центре страницы? Container Queries решают именно это.</div>\n      <div class=\"code\">/* Объявляем элемент контейнером для запросов */\n.card-wrapper {\n  container-type: inline-size;\n  container-name: card;\n}\n\n/* Стили карточки меняются от ширины КОНТЕЙНЕРА, не экрана */\n.card { display: block; }\n\n@container card (min-width: 400px) {\n  .card { display: flex; gap: 16px; }   /* широкий контейнер — flex */\n}\n\n@container card (max-width: 399px) {\n  .card { display: block; }              /* узкий контейнер — блок */\n}\n\n/* Одна и та же карточка автоматически адаптируется\n   и в сайдбаре (узко), и в основном контенте (широко) */</div>\n      <div class=\"explain\">\n        <strong>Обычный @media</strong> — смотрит на ширину окна браузера целиком.<br>\n        <strong>@container</strong> — смотрит на ширину родительского контейнера элемента, независимо от размера экрана.<br>\n        <strong>container-type: inline-size</strong> — обязательное объявление родителя как контейнера, иначе @container не сработает.<br>\n        <strong>Где использовать:</strong> переиспользуемые компоненты (карточки, виджеты) которые могут оказаться в разных по ширине местах — сайдбар, грид, модалка.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb112\" onchange=\"updateProgress(this)\"><span>container-type: inline-size — объявление контейнера</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb113\" onchange=\"updateProgress(this)\"><span>@container (min-width: ...) — запрос по ширине контейнера, не экрана</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb114\" onchange=\"updateProgress(this)\"><span>Понимаю разницу @media vs @container</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-typography\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-typography')\">Типографика — шрифты и текст <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Правильный шрифт делает сайт профессиональным. Google Fonts — бесплатно, 1000+ шрифтов, подключается одной строкой.</div>\n      <div class=\"code-wrap\"><div class=\"code\">&lt;!-- В &lt;head&gt; подключаем Google Fonts --&gt;\n&lt;link href=\"https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700&amp;display=swap\" rel=\"stylesheet\"&gt;\n\n/* В CSS применяем */\nbody {\n  font-family: 'Inter', sans-serif; /* основной шрифт */\n  font-size: 16px;                  /* базовый размер */\n  line-height: 1.6;                 /* межстрочный интервал */\n  color: #1a1a2e;\n}\n\nh1 { font-size: 2.5rem;  font-weight: 700; }\nh2 { font-size: 1.75rem; font-weight: 600; }\np  { font-size: 1rem;    font-weight: 400; }\n\n/* Обрезать текст многоточием */\n.truncate {\n  white-space: nowrap;\n  overflow: hidden;\n  text-overflow: ellipsis;  /* \"длинный те...\" */\n}\n\n/* Полезные утилиты */\n.uppercase { text-transform: uppercase; letter-spacing: 0.08em; }\n.center    { text-align: center; }\n.muted     { color: #9ca3af; font-size: 0.875rem; }</div><button class=\"copy-btn\" onclick=\"copyCode(this)\">Копировать</button></div>\n      <div class=\"explain\">\n        <strong>font-family: 'Inter', sans-serif</strong> — если Inter не загрузился, браузер возьмёт системный sans-serif.<br>\n        <strong>rem</strong> — относительная единица. 1rem = 16px. Лучше px, потому что масштабируется с настройками браузера.<br>\n        <strong>line-height: 1.6</strong> — без единицы! Это множитель. 1.6 = 1.6 × font-size. Идеал для текста: 1.5–1.7.<br>\n        <strong>text-overflow: ellipsis</strong> — обрезает текст многоточием. Нужны три свойства одновременно: white-space + overflow + text-overflow.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb115\" onchange=\"updateProgress(this)\"><span>Подключаю Google Fonts через &lt;link&gt; в &lt;head&gt;</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb116\" onchange=\"updateProgress(this)\"><span>rem вместо px — масштабируется с настройками браузера</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb117\" onchange=\"updateProgress(this)\"><span>line-height без единиц (1.5–1.7) — идеально для читаемости</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb118\" onchange=\"updateProgress(this)\"><span>text-overflow: ellipsis — нужен white-space:nowrap + overflow:hidden</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-transition\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-transition')\">Transition — плавные переходы <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Transition делает изменения CSS-свойств плавными. Самый простой способ добавить «жизнь» в интерфейс.</div>\n      <div class=\"code-wrap\"><div class=\"code\">/* Синтаксис: transition: свойство длительность функция задержка */\n.btn {\n  background: #6366f1;\n  color: white;\n  padding: 12px 24px;\n  border-radius: 8px;\n  transition: background 0.25s ease;  /* плавная смена фона */\n}\n.btn:hover { background: #4f46e5; }\n\n/* Несколько свойств */\n.card {\n  box-shadow: 0 1px 4px rgba(0,0,0,.08);\n  transform: translateY(0);\n  transition: box-shadow 0.2s ease,\n              transform   0.2s ease;\n}\n.card:hover {\n  box-shadow: 0 8px 24px rgba(0,0,0,.15);\n  transform: translateY(-4px);  /* «всплывает» */\n}\n\n/* Функции времени */\n/* ease      — медленно → быстро → медленно (по умолчанию) */\n/* linear    — равномерно                                   */\n/* ease-in   — медленно → быстро                            */\n/* ease-out  — быстро → медленно (хорошо для появления)     */\n/* cubic-bezier(0.34,1.56,0.64,1) — пружинный эффект        */</div><button class=\"copy-btn\" onclick=\"copyCode(this)\">Копировать</button></div>\n      <div class=\"explain\">\n        <strong>transition: background 0.25s ease</strong> — три части: что меняется, как долго, какая функция.<br>\n        <strong>ease-out</strong> — лучший вариант для появления элементов (быстро появился, плавно остановился).<br>\n        <strong>transition: all</strong> — удобно, но осторожно: анимирует всё подряд, включая width/height — это дорого для браузера.<br>\n        Предпочитай анимировать <code>transform</code> и <code>opacity</code> — они работают на GPU и не вызывают перерисовку страницы.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb119\" onchange=\"updateProgress(this)\"><span>transition: свойство 0.25s ease — ставлю на исходный элемент, не на :hover</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb120\" onchange=\"updateProgress(this)\"><span>ease-out — для появления. ease-in — для исчезновения</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb121\" onchange=\"updateProgress(this)\"><span>transform + opacity быстрее, чем width/height/margin</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb122\" onchange=\"updateProgress(this)\"><span>Можно перечислить несколько свойств через запятую</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-transform\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-transform')\">Transform — сдвиг, поворот, масштаб <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Transform двигает, вращает и масштабирует элемент без изменения потока документа. Работает через GPU — не вызывает reflow.</div>\n      <div class=\"code-wrap\"><div class=\"code\">/* Основные функции transform */\n\n/* Сдвиг */\ntransform: translateX(50px);        /* вправо на 50px          */\ntransform: translateY(-20px);       /* вверх на 20px           */\ntransform: translate(50px, -20px);  /* оба сразу               */\ntransform: translateX(50%);         /* 50% от своей ширины     */\n\n/* Масштаб */\ntransform: scale(1.2);   /* увеличить на 20% */\ntransform: scale(0.8);   /* уменьшить на 20% */\n\n/* Поворот */\ntransform: rotate(45deg);   /* по часовой       */\ntransform: rotate(-90deg);  /* против часовой   */\n\n/* Комбинация — слева направо! */\ntransform: translate(-50%, -50%) scale(1.1);\n\n/* Реальный пример — центрирование абсолютного блока */\n.popup {\n  position: absolute;\n  top: 50%;  left: 50%;\n  transform: translate(-50%, -50%);  /* идеальное центрирование */\n}\n\n/* Иконка разворачивается при открытии */\n.arrow { transition: transform 0.3s ease; }\n.open .arrow { transform: rotate(180deg); }\n\n/* Карточка «всплывает» при hover */\n.card {\n  transition: transform 0.2s ease-out;\n}\n.card:hover { transform: translateY(-6px) scale(1.02); }</div><button class=\"copy-btn\" onclick=\"copyCode(this)\">Копировать</button></div>\n      <div class=\"explain\">\n        <strong>translate(-50%, -50%)</strong> — классический трюк центрирования: сдвигает на половину <em>собственного</em> размера.<br>\n        <strong>Порядок важен!</strong> <code>translate() scale()</code> ≠ <code>scale() translate()</code> — трансформации применяются справа налево.<br>\n        <strong>transform-origin</strong> — точка, вокруг которой происходит поворот/масштаб. По умолчанию <code>center center</code>.<br>\n        Всегда комбинируй <code>transform</code> с <code>transition</code> — иначе изменение будет мгновенным, без анимации.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb123\" onchange=\"updateProgress(this)\"><span>translate(-50%,-50%) + position:absolute — идеальное центрирование</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb124\" onchange=\"updateProgress(this)\"><span>scale(1.05) при hover — популярный эффект увеличения карточки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb125\" onchange=\"updateProgress(this)\"><span>rotate(180deg) — разворот стрелки при открытии меню</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb126\" onchange=\"updateProgress(this)\"><span>transform + transition вместе = плавная анимация</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-shadows\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-shadows')\">Тени — box-shadow, text-shadow, drop-shadow <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Тени делают интерфейс «объёмным». Главное — не перебарщивать. Хорошая тень мягкая и едва заметная.</div>\n      <div class=\"code\">/* box-shadow: x-сдвиг y-сдвиг размытие распространение цвет */\n.card {\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);   /* мягкая, как у Material */\n}\n\n/* Эффект «парения» при hover */\n.card:hover {\n  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.15);\n  transform: translateY(-3px);\n}\n\n/* Несколько теней через запятую */\n.fancy {\n  box-shadow:\n    0 1px 2px rgba(0, 0, 0, 0.1),\n    0 4px 12px rgba(0, 0, 0, 0.08);\n}\n\n/* Внутренняя тень (inset) */\n.input {\n  box-shadow: inset 0 2px 4px rgba(0, 0, 0, 0.08);\n}\n\n/* Светящаяся обводка вокруг кнопки */\n.btn:focus {\n  box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.4);\n}\n\n/* text-shadow — тень текста */\nh1 {\n  text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.3);\n}\n\n/* Неоновое свечение */\n.neon {\n  color: #fff;\n  text-shadow:\n    0 0 5px  #6366f1,\n    0 0 10px #6366f1,\n    0 0 20px #6366f1;\n}\n\n/* drop-shadow — тень по форме (для картинок и SVG) */\n.icon {\n  filter: drop-shadow(0 4px 6px rgba(0, 0, 0, 0.2));\n}</div>\n      <div class=\"explain\">\n        <strong>Параметры box-shadow</strong>: x — горизонтальный сдвиг, y — вертикальный, размытие, распространение, цвет. Чем больше размытие — тем мягче.<br>\n        <strong>rgba(0,0,0,0.08)</strong> — почти всегда лучше, чем сплошной серый. Прозрачность хорошо ложится на любой фон.<br>\n        <strong>inset</strong> — тень <em>внутрь</em> элемента. Эффект «вдавленности» (поля ввода, прогресс-бары).<br>\n        <strong>filter: drop-shadow()</strong> ≠ box-shadow. drop-shadow повторяет реальную форму элемента — нужна для PNG/SVG с прозрачностью.<br>\n        <strong>0 0 0 3px цвет</strong> — фокус-кольцо для кнопок и инпутов вместо некрасивого браузерного outline.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb127\" onchange=\"updateProgress(this)\"><span>0 2px 8px rgba(0,0,0,.08) — стандартная мягкая тень карточки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb128\" onchange=\"updateProgress(this)\"><span>:hover — тень больше + translateY(-3px) → эффект парения</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb129\" onchange=\"updateProgress(this)\"><span>inset — внутренняя тень (поля, переключатели)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb130\" onchange=\"updateProgress(this)\"><span>filter: drop-shadow() — для иконок и SVG, повторяет форму</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb131\" onchange=\"updateProgress(this)\"><span>Фокус-кольцо: box-shadow + outline: 3px solid transparent для доступности</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-zindex\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-zindex')\">z-index и stacking context — кто над кем <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">z-index управляет порядком наложения элементов. Самый запутанный момент — почему z-index: 9999 иногда не работает. Дело в stacking context.</div>\n      <div class=\"code\">/* z-index работает ТОЛЬКО у позиционированных элементов */\n.modal {\n  position: fixed;       /* обязательно! */\n  z-index: 1000;\n  inset: 0;\n}\n\n/* Без position: ... → z-index игнорируется */\n.broken {\n  z-index: 999;          /* НЕ работает! */\n}\n\n/* Стандартная иерархия слоёв */\n.dropdown   { z-index: 100; }\n.sticky-nav { z-index: 200; }\n.modal      { z-index: 1000; }\n.toast      { z-index: 2000; }   /* всегда сверху */\n\n/* Stacking context — «отдельный мир» наложения */\n.parent {\n  position: relative;\n  z-index: 1;            /* создаёт контекст */\n  /* ИЛИ: opacity &lt; 1, transform, filter, isolation: isolate */\n}\n\n.parent .child {\n  z-index: 9999;         /* всё равно не «вылезет» из родителя! */\n}\n\n/* Решение — поднять родителя или вынести child в body */\n.parent { isolation: isolate; }   /* явный stacking context */</div>\n      <div class=\"explain\">\n        <strong>z-index работает только при position</strong> ≠ static. Без <code>position: relative/absolute/fixed/sticky</code> — игнорируется.<br>\n        <strong>Stacking context</strong> — «параллельный мир» наложения. Внутри него z-index считается отдельно. Любой <code>z-index</code> у потомка не «вылезет» наружу контекста родителя.<br>\n        <strong>Что создаёт контекст</strong>: position + z-index (любой), <code>opacity &lt; 1</code>, <code>transform</code>, <code>filter</code>, <code>will-change</code>, <code>isolation: isolate</code>.<br>\n        <strong>«z-index: 9999 не работает!»</strong> — почти всегда виноват родитель с opacity/transform. Найди его DevTools → Layers, либо добавь модалке <code>position: fixed</code> и помести в &lt;body&gt;.<br>\n        <strong>Не лепи большие числа.</strong> 1, 10, 100, 1000 — система. 9999 — признак того, что что-то идёт не так.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb132\" onchange=\"updateProgress(this)\"><span>z-index работает только при position: relative/absolute/fixed/sticky</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb133\" onchange=\"updateProgress(this)\"><span>Понимаю, что такое stacking context</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb134\" onchange=\"updateProgress(this)\"><span>Использую систему: 100/200/1000/2000, а не 9999</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb135\" onchange=\"updateProgress(this)\"><span>opacity / transform у родителя = ловушка для z-index</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb136\" onchange=\"updateProgress(this)\"><span>isolation: isolate — явно создать свой stacking context</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-filter\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-filter')\">filter и backdrop-filter — размытие, glassmorphism <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">filter применяет к элементу графический эффект (как в Photoshop). backdrop-filter размывает то, что <em>под</em> элементом — отсюда «стеклянные» панели.</div>\n      <div class=\"code\">/* filter — эффекты к самому элементу */\n.img-blur     { filter: blur(4px); }\n.img-bw       { filter: grayscale(100%); }\n.img-bright   { filter: brightness(1.2); }\n.img-contrast { filter: contrast(1.4); }\n.img-hue      { filter: hue-rotate(90deg); }   /* меняет оттенок */\n.img-invert   { filter: invert(1); }            /* негатив */\n.img-saturate { filter: saturate(2); }\n\n/* Несколько эффектов через пробел */\n.cool {\n  filter: brightness(1.1) contrast(1.2) saturate(1.3);\n}\n\n/* hover — раскрашиваем чёрно-белое фото */\n.gallery img {\n  filter: grayscale(100%);\n  transition: filter 0.4s;\n}\n.gallery img:hover { filter: grayscale(0); }\n\n/* backdrop-filter — размывает ФОН под элементом (glassmorphism) */\n.glass {\n  background: rgba(255, 255, 255, 0.15);\n  backdrop-filter: blur(12px) saturate(1.5);\n  -webkit-backdrop-filter: blur(12px) saturate(1.5);  /* Safari */\n  border: 1px solid rgba(255, 255, 255, 0.2);\n  border-radius: 16px;\n}\n\n/* Затемнение при модалке */\n.modal-bg {\n  background: rgba(0, 0, 0, 0.4);\n  backdrop-filter: blur(8px);\n}</div>\n      <div class=\"explain\">\n        <strong>filter</strong> применяется к элементу целиком (включая контент). <strong>backdrop-filter</strong> — к тому, что <em>под</em> ним сквозь полупрозрачный фон.<br>\n        <strong>Glassmorphism</strong> — модный эффект «матового стекла». Рецепт: полупрозрачный фон + <code>backdrop-filter: blur()</code> + тонкая светлая граница.<br>\n        <strong>-webkit-backdrop-filter</strong> — обязателен для Safari (включая iPhone). Без префикса — не работает.<br>\n        <strong>Производительность.</strong> blur и backdrop-filter тяжёлые. Не вешай на крупные элементы и не анимируй radius блюра — будут лаги на мобилках.<br>\n        <strong>Серый кадр галереи + цветной при hover</strong> — приём, который любят дизайнеры. Делается одним <code>filter: grayscale()</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb137\" onchange=\"updateProgress(this)\"><span>filter: blur, grayscale, brightness, contrast — основные эффекты</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb138\" onchange=\"updateProgress(this)\"><span>Можно комбинировать через пробел: filter: brightness(1.1) saturate(1.3)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb139\" onchange=\"updateProgress(this)\"><span>backdrop-filter: blur — glassmorphism (рецепт стекла)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb140\" onchange=\"updateProgress(this)\"><span>-webkit-backdrop-filter обязателен для Safari</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb141\" onchange=\"updateProgress(this)\"><span>Большие blur тормозят на мобилках — экономно</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-object-fit\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-object-fit')\">object-fit и aspect-ratio — картинки без растяжения <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Самая частая боль вёрстки — картинки разных размеров в одинаковых рамках. object-fit и aspect-ratio решают это в две строки.</div>\n      <div class=\"code\">/* Карточка товара — все картинки одинакового размера */\n.card-img {\n  width: 100%;\n  height: 240px;\n  object-fit: cover;       /* заполняет, обрезая лишнее */\n  object-position: center; /* что показывать (по умолчанию центр) */\n}\n\n/* Значения object-fit */\nimg.fit-cover    { object-fit: cover;    }  /* заполнить, обрезать */\nimg.fit-contain  { object-fit: contain;  }  /* вместить целиком */\nimg.fit-fill     { object-fit: fill;     }  /* растянуть (искажая!) */\nimg.fit-none     { object-fit: none;     }  /* как есть */\nimg.fit-scale    { object-fit: scale-down; }  /* contain, но не увеличивать */\n\n/* aspect-ratio — задать пропорцию без хаков с padding */\n.video-frame {\n  width: 100%;\n  aspect-ratio: 16 / 9;    /* высота = ширина × 9/16 */\n  background: #000;\n}\n\n.avatar {\n  width: 80px;\n  aspect-ratio: 1;          /* квадрат, что бы ни случилось */\n  border-radius: 50%;\n  object-fit: cover;\n}\n\n/* Адаптивная сетка карточек одной высоты */\n.grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));\n  gap: 16px;\n}\n.grid img {\n  width: 100%;\n  aspect-ratio: 4 / 3;\n  object-fit: cover;\n  border-radius: 8px;\n}</div>\n      <div class=\"explain\">\n        <strong>object-fit: cover</strong> — главный спаситель. Картинка заполнит контейнер, лишнее обрежется. Никаких чёрных полос и искажений.<br>\n        <strong>object-fit: contain</strong> — наоборот, вмещает целиком. Полезно для логотипов разной формы — ничего не обрежется.<br>\n        <strong>object-position: top / 50% 30%</strong> — какая часть будет видна при <code>cover</code>. По умолчанию — центр. Для портретов часто нужно <code>top</code>.<br>\n        <strong>aspect-ratio: 16/9</strong> — задать пропорцию. Раньше делали через <code>padding-top: 56.25%</code> — забудь этот хак.<br>\n        <strong>Работает у video и iframe тоже.</strong> Для видео и YouTube-iframe это идеальный способ адаптивности.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb142\" onchange=\"updateProgress(this)\"><span>object-fit: cover — заполнить, обрезать (карточки товаров)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb143\" onchange=\"updateProgress(this)\"><span>object-fit: contain — вместить целиком (логотипы)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb144\" onchange=\"updateProgress(this)\"><span>object-position — какую часть показывать при cover</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb145\" onchange=\"updateProgress(this)\"><span>aspect-ratio: 16/9 / 1/1 / 4/3 — пропорции в одну строку</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb146\" onchange=\"updateProgress(this)\"><span>aspect-ratio + object-fit:cover — готовый рецепт для галерей</span></label>\n      </div>\n    </div>\n\n    <button class=\"try-btn\" onclick=\"sendPrompt('Дай мне задание по CSS-анимациям для новичка с примером кода')\">Получить задание по CSS ↗</button>\n  </div>\n\n    "},{"id":"block-scss-basics","title":"SCSS — переменные и вложенность основа 🔗","html":"<div class=\"block\" id=\"block-scss-basics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-scss-basics')\">SCSS — переменные и вложенность <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">SCSS — это CSS с суперспособностями. Компилируется в обычный CSS. Используется в 80%+ коммерческих проектов.</div>\n      <div class=\"code\"><span class=\"cm\">// Переменные</span>\n<span class=\"kw\">$primary:</span> <span class=\"str\">#6366f1</span>;\n<span class=\"kw\">$font-size-base:</span> <span class=\"num\">16px</span>;\n<span class=\"kw\">$radius:</span> <span class=\"num\">8px</span>;\n\n<span class=\"cm\">// Вложенность — не нужно повторять селекторы</span>\n<span class=\"kw\">.card</span> {\n  padding: <span class=\"num\">20px</span>;\n  border-radius: <span class=\"kw\">$radius</span>;\n\n  <span class=\"kw\">&amp;__title</span> { font-size: <span class=\"num\">18px</span>; }    <span class=\"cm\">// .card__title</span>\n  <span class=\"kw\">&amp;__body</span>  { color: <span class=\"str\">#666</span>; }       <span class=\"cm\">// .card__body</span>\n\n  <span class=\"kw\">&amp;:hover</span>  { box-shadow: <span class=\"num\">0 4px 20px</span> rgba(<span class=\"num\">0,0,0,.1</span>); }\n  <span class=\"kw\">&amp;--dark</span>  { background: <span class=\"str\">#1a1a2e</span>; }  <span class=\"cm\">// .card--dark (БЭМ)</span>\n}\n\n<span class=\"cm\">// Миксины — переиспользуемые блоки стилей</span>\n<span class=\"kw\">@mixin</span> <span class=\"fn\">flex-center</span> {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n<span class=\"kw\">.hero</span> {\n  <span class=\"kw\">@include</span> <span class=\"fn\">flex-center</span>;\n  min-height: <span class=\"num\">100vh</span>;\n}</div>\n      <div class=\"explain\">\n        <strong>$переменная</strong> — цвета, размеры, шрифты. Меняешь в одном месте — меняется везде.<br>\n        <strong>&amp;</strong> — ссылка на родительский селектор. &amp; + __element = БЭМ без повторений.<br>\n        <strong>@mixin + @include</strong> — как функции в CSS. Вынеси повторяющиеся стили один раз.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb147\" onchange=\"updateProgress(this)\"><span>$переменные — цвета, размеры, отступы</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb148\" onchange=\"updateProgress(this)\"><span>Вложенность и &amp; — ссылка на родителя</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb149\" onchange=\"updateProgress(this)\"><span>@mixin и @include — переиспользование стилей</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-scss-advanced","title":"SCSS — функции, циклы и @extend важно 🔗","html":"<div class=\"block\" id=\"block-scss-advanced\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-scss-advanced')\">SCSS — функции, циклы и @extend <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Функции</span>\n<span class=\"kw\">@function</span> <span class=\"fn\">rem</span>(px) {\n  <span class=\"kw\">@return</span> #{px / 16}rem;\n}\n<span class=\"kw\">.title</span> { font-size: <span class=\"fn\">rem</span>(<span class=\"num\">24</span>); } <span class=\"cm\">// → 1.5rem</span>\n\n<span class=\"cm\">// Цикл @each</span>\n<span class=\"kw\">$colors:</span> (primary: <span class=\"str\">#6366f1</span>, success: <span class=\"str\">#22c55e</span>, danger: <span class=\"str\">#ef4444</span>);\n\n<span class=\"kw\">@each</span> $name, $color <span class=\"kw\">in</span> <span class=\"kw\">$colors</span> {\n  <span class=\"kw\">.btn-#{$name}</span> {\n    background: <span class=\"kw\">$color</span>;\n    color: white;\n  }\n}\n<span class=\"cm\">// Генерирует: .btn-primary, .btn-success, .btn-danger</span>\n\n<span class=\"cm\">// @extend — наследование стилей</span>\n<span class=\"kw\">%btn-base</span> {\n  padding: <span class=\"num\">8px 16px</span>;\n  border-radius: <span class=\"num\">6px</span>;\n  border: none;\n  cursor: pointer;\n}\n<span class=\"kw\">.btn-primary</span> { <span class=\"kw\">@extend</span> %btn-base; background: <span class=\"str\">#6366f1</span>; }\n<span class=\"kw\">.btn-danger</span>  { <span class=\"kw\">@extend</span> %btn-base; background: <span class=\"str\">#ef4444</span>; }</div>\n      <div class=\"explain\">\n        <strong>@function</strong> — возвращает значение. Удобно для конвертации px → rem.<br>\n        <strong>@each</strong> — цикл по списку или map. Генерирует множество классов из одного кода.<br>\n        <strong>%placeholder + @extend</strong> — не создаёт лишнего HTML-класса, только объединяет CSS-правила.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb150\" onchange=\"updateProgress(this)\"><span>@function — своя функция возвращающая значение</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb151\" onchange=\"updateProgress(this)\"><span>@each — генерация классов из списка</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb152\" onchange=\"updateProgress(this)\"><span>@extend и %placeholder — наследование стилей</span></label>\n      </div>\n    </div>\n\n\n    "},{"id":"block-css-modern-layer-nesting","title":"Современный CSS: @layer и nesting изучи после CSS 🔗","html":"<div class=\"block\" id=\"block-css-modern-layer-nesting\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-css-modern-layer-nesting')\">Современный CSS: @layer и nesting <span class=\"badge good\">изучи после CSS</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">/* Каскадные слои — управляют порядком важности без !important */</span>\n<span class=\"kw\">@layer</span> reset, base, components, utilities;\n\n<span class=\"kw\">@layer</span> components {\n  <span class=\"tag\">.card</span> {\n    padding: <span class=\"num\">16px</span>;\n\n    <span class=\"cm\">/* Нативная вложенность CSS */</span>\n    &amp;:hover { box-shadow: <span class=\"num\">0 8px 24px</span> rgba(<span class=\"num\">0,0,0,.12</span>); }\n    &amp; .title { font-size: <span class=\"num\">18px</span>; }\n  }\n}</div>\n      <div class=\"explain\">\n        <strong>@layer</strong> помогает заранее договориться, что важнее: reset, база, компоненты или utilities. Это снижает потребность в <code>!important</code>.<br>\n        <strong>CSS Nesting</strong> уже поддерживается современными браузерами: простую вложенность можно писать без SCSS, если проектный стек это позволяет.<br>\n        <strong>SCSS всё ещё полезен</strong> для функций, mixin и сложных циклов, но вложенность больше не является его уникальной суперсилой.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb152c\" onchange=\"updateProgress(this)\"><span>@layer — управляю каскадом без войн за !important</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb152d\" onchange=\"updateProgress(this)\"><span>CSS Nesting — понимаю нативную вложенность без SCSS</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-css-2026-native-apis","title":"CSS 2026: @scope, scroll-driven и View Transitions modern 🔗","html":"<div class=\"block\" id=\"block-css-2026-native-apis\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-css-2026-native-apis')\">CSS 2026: @scope, scroll-driven и View Transitions <span class=\"badge must\">modern</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Современный CSS всё чаще заменяет маленькие JS-библиотеки: локальные стили, анимации от прокрутки и переходы между экранами можно делать нативно.</div>\n      <div class=\"code\"><span class=\"cm\">/* @scope — стили живут только внутри .profile-card */</span>\n<span class=\"kw\">@scope</span> (.profile-card) {\n  <span class=\"tag\">.title</span> { color: <span class=\"str\">#6366f1</span>; }\n  <span class=\"tag\">button</span> { border-radius: <span class=\"num\">8px</span>; }\n}\n\n<span class=\"cm\">/* Scroll-driven animation — прогресс зависит от прокрутки */</span>\n<span class=\"tag\">.progress-line</span> {\n  transform-origin: left;\n  animation: grow linear;\n  animation-timeline: scroll();\n}\n\n<span class=\"kw\">@keyframes</span> grow {\n  from { transform: scaleX(<span class=\"num\">0</span>); }\n  to   { transform: scaleX(<span class=\"num\">1</span>); }\n}\n\n<span class=\"cm\">/* View Transitions — плавная смена экранов/страниц */</span>\n<span class=\"kw\">::view-transition-old</span>(root),\n<span class=\"kw\">::view-transition-new</span>(root) {\n  animation-duration: <span class=\"num\">220ms</span>;\n}</div>\n      <div class=\"explain\">\n        <strong>@scope</strong> ограничивает область действия селекторов. Это похоже на локальные стили компонента, но без CSS Modules.<br>\n        <strong>Scroll-driven animations</strong> привязывают анимацию к прокрутке страницы. Для прогресс-баров и мягких эффектов часто не нужен Intersection Observer.<br>\n        <strong>View Transitions API</strong> помогает делать плавные переходы между состояниями интерфейса. Отлично подходит для SPA и небольших интерактивных страниц.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-css-modern-1\" onchange=\"updateProgress(this)\"><span>@scope — локальная область CSS-селекторов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-css-modern-2\" onchange=\"updateProgress(this)\"><span>Scroll-driven animations — анимации от прокрутки без JS</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-css-modern-3\" onchange=\"updateProgress(this)\"><span>View Transitions — плавные переходы между состояниями UI</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-js","lessons":[{"id":"block-vars-js","title":"Переменные — где храним данные основа 🔗","html":"<div class=\"block\" id=\"block-vars-js\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vars-js')\">Переменные — где храним данные <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Переменная — это «коробочка» с именем, в которой лежит значение.</div>\n      <div class=\"code\">// const — значение НЕЛЬЗЯ изменить (постоянная)\nconst PI = 3.14;\nconst name = \"Алекс\";\n\n// let — значение МОЖНО изменить\nlet age = 25;\nage = 26;  // нормально, age теперь 26\n\n// Типы данных:\nlet text = \"Привет\";    // string (строка)\nlet number = 42;        // number (число)\nlet isOnline = true;    // boolean (да/нет)\nlet nothing = null;     // пусто (специально)\nlet notSet;             // undefined (не задано)</div>\n      <div class=\"explain\">\n        <strong>const</strong> — используй в 90% случаев. Нельзя переназначить.<br>\n        <strong>let</strong> — когда значение точно будет меняться (счётчик, флаг).<br>\n        <strong>var</strong> — <em>забудь</em>. В современном коде только const и let.<br>\n        <strong>null vs undefined</strong>: null = мы специально положили пустоту. undefined = никто ещё не положил значение.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb153\" onchange=\"updateProgress(this)\"><span>const по умолчанию, let только если нужно менять</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb154\" onchange=\"updateProgress(this)\"><span>var — устарел! Только const и let</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-functions","title":"Функции — обычные, стрелочные, параметры основа 🔗","html":"<div class=\"block\" id=\"block-functions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-functions')\">Функции — обычные, стрелочные, параметры <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Функция — это «рецепт». Один раз написал — пользуешься сколько угодно раз. В JS их две основные формы: function и стрелочные.</div>\n      <div class=\"code\">// Обычная функция (function declaration)\nfunction greet(name) {\n  return \"Привет, \" + name + \"!\";\n}\n\ngreet(\"Мир\");   // \"Привет, Мир!\"\n\n// Стрелочная (arrow function) — короче, без своего this\nconst greet2 = (name) =&gt; \"Привет, \" + name + \"!\";\n\n// Если параметр один — скобки можно убрать\nconst square = n =&gt; n * n;\n\n// Если тело — одно выражение, return и {} не нужны\nconst sum = (a, b) =&gt; a + b;\n\n// Несколько строк — нужны фигурные скобки и return\nconst greet3 = (name) =&gt; {\n  const upper = name.toUpperCase();\n  return \"Привет, \" + upper + \"!\";\n};\n\n// Параметры по умолчанию\nfunction order(item, quantity = 1, price = 100) {\n  return `${item} × ${quantity} = ${quantity * price}₽`;\n}\norder(\"кофе\");              // \"кофе × 1 = 100₽\"\norder(\"чай\", 3);            // \"чай × 3 = 300₽\"\norder(\"сок\", 2, 80);        // \"сок × 2 = 160₽\"\n\n// Rest-параметр — собирает «всё остальное» в массив\nfunction sumAll(...numbers) {\n  return numbers.reduce((s, n) =&gt; s + n, 0);\n}\nsumAll(1, 2, 3, 4, 5);   // 15\n\n// Колбэк — функция, которую передаёшь как аргумент\n[1, 2, 3].map(n =&gt; n * 2);   // [2, 4, 6]\nsetTimeout(() =&gt; console.log(\"через секунду\"), 1000);</div>\n      <div class=\"explain\">\n\n<strong>Как читать функцию:</strong> функция — это именованный кусок логики. Параметры в скобках — это данные, которые функция получает снаружи.<br>\n        <strong>return</strong> — результат функции. Если return нет, функция вернет <code>undefined</code>. <code>console.log</code> только печатает, но не возвращает значение.<br>\n        <strong>function greet(name)</strong> удобно читать как “создай действие greet, которому нужен name”. Вызов <code>greet(\"Мир\")</code> подставляет строку вместо параметра.<br>\n        <strong>Стрелочная функция</strong> часто короче: <code>n =&gt; n * n</code> значит “возьми n и верни n * n”. Если тело в одну строку, <code>return</code> пишется неявно.<br>\n        <strong>Если есть фигурные скобки</strong> в стрелочной функции, <code>return</code> снова нужен: <code>() =&gt; { return value; }</code>.<br>\n        <strong>Параметры по умолчанию</strong> спасают, если аргумент не передали: <code>quantity = 1</code>.<br>\n        <strong>Callback</strong> — функция, которую передали в другую функцию. Именно так работают <code>map</code>, <code>filter</code>, <code>addEventListener</code>, <code>setTimeout</code>.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb184\" onchange=\"updateProgress(this)\"><span>const f = () =&gt; ... — стрелочная по умолчанию</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb185\" onchange=\"updateProgress(this)\"><span>n =&gt; n * 2 — короткая запись с одним выражением</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb186\" onchange=\"updateProgress(this)\"><span>function name() — нужна для методов и hoisting</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb187\" onchange=\"updateProgress(this)\"><span>Параметры по умолчанию: function f(x = 10)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb188\" onchange=\"updateProgress(this)\"><span>...rest собирает аргументы в массив</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-arrays","title":"Массивы — список элементов основа 🔗","html":"<div class=\"block\" id=\"block-arrays\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-arrays')\">Массивы — список элементов <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">const fruits = [\"яблоко\", \"банан\", \"груша\"];\n\nfruits[0];           // \"яблоко\" — нумерация с 0!\nfruits.length;       // 3\n\nfruits.push(\"манго\");      // Добавить в конец\nfruits.pop();              // Удалить последний\nfruits.unshift(\"апельсин\"); // Добавить в начало\nfruits.shift();            // Удалить первый\n\nconst numbers = [1, 2, 3, 4, 5];\nconst doubled = numbers.map(n =&gt; n * 2);  // [2,4,6,8,10]\nconst big = numbers.filter(n =&gt; n &gt; 3);   // [4, 5]\nconst sum = numbers.reduce((t, n) =&gt; t + n, 0); // 15</div>\n      <div class=\"explain\">\n\n<strong>Как читать массив:</strong> массив — это список значений в одном порядке. Индексы начинаются с 0, поэтому <code>fruits[0]</code> — первый элемент, а не “нулевой по смыслу”.<br>\n        <strong>.length</strong> показывает количество элементов. Последний индекс всегда <code>length - 1</code>.<br>\n        <strong>push / pop</strong> работают с концом массива. <code>push</code> добавляет, <code>pop</code> удаляет последний и возвращает удаленный элемент.<br>\n        <strong>unshift / shift</strong> работают с началом массива. Их лучше не злоупотреблять на больших списках, потому что элементы приходится сдвигать.<br>\n        <strong>map</strong> — когда нужно получить новый массив такой же длины, но с измененными элементами: числа умножить, объекты превратить в HTML, имена привести к виду.<br>\n        <strong>filter</strong> — когда нужно оставить только часть элементов: только выполненные задачи, товары дороже 1000, карточки по поиску.<br>\n        <strong>reduce</strong> — когда из массива нужно получить одно значение: сумму, максимум, объект группировки, статистику.<br>\n        <strong>Как читать reduce:</strong> <code>t</code> — накопитель, <code>n</code> — текущий элемент, <code>0</code> — стартовое значение. На каждом шаге возвращается новый накопитель.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb159\" onchange=\"updateProgress(this)\"><span>Нумерация с 0: fruits[0] — первый элемент</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb160\" onchange=\"updateProgress(this)\"><span>map — трансформирует, filter — фильтрует, reduce — сворачивает</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-destructuring","title":"Деструктуризация и spread — современный синтаксис важно 🔗","html":"<div class=\"block\" id=\"block-destructuring\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-destructuring')\">Деструктуризация и spread — современный синтаксис <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Деструктуризация — короткий способ «вытащить» поля из объекта или массива. Spread — «разложить» массив или объект.</div>\n      <div class=\"code\">// === Деструктуризация объекта ===\nconst user = { name: \"Алекс\", age: 25, city: \"Москва\" };\n\n// Старый способ\nconst name1 = user.name;\nconst age1  = user.age;\n\n// Новый способ\nconst { name, age } = user;\nconsole.log(name, age);     // \"Алекс\" 25\n\n// Переименование + значение по умолчанию\nconst { name: userName, role = \"guest\" } = user;\nconsole.log(userName, role);   // \"Алекс\" \"guest\"\n\n// === Деструктуризация массива ===\nconst colors = [\"red\", \"green\", \"blue\"];\nconst [first, second] = colors;     // \"red\"  \"green\"\nconst [, , third] = colors;         // только третий: \"blue\"\n\n// Обмен переменными\nlet a = 1, b = 2;\n[a, b] = [b, a];   // теперь a=2, b=1\n\n// === В параметрах функции ===\nfunction showUser({ name, age }) {\n  console.log(`${name}, ${age} лет`);\n}\nshowUser(user);   // \"Алекс, 25 лет\"\n\n// === Spread (...) — «разложить» ===\nconst arr1 = [1, 2, 3];\nconst arr2 = [...arr1, 4, 5];          // [1,2,3,4,5]\nconst copy = [...arr1];                // полная копия\n\nconst obj1 = { a: 1, b: 2 };\nconst obj2 = { ...obj1, c: 3 };        // {a:1, b:2, c:3}\nconst updated = { ...user, age: 26 };  // копия + обновлённое поле\n\n// Передать массив как аргументы\nconst nums = [5, 8, 1, 9, 2];\nMath.max(...nums);                     // 9</div>\n      <div class=\"explain\">\n        <strong>{ name } = user</strong> — берём поле <code>name</code> из объекта и сразу создаём переменную с таким же именем.<br>\n        <strong>: переименование</strong> — <code>{ name: userName }</code> создаёт переменную <code>userName</code>.<br>\n        <strong>= значение</strong> — если поля нет, подставится дефолт. Часто комбинируют оба: <code>{ role = \"guest\" }</code>.<br>\n        <strong>...spread</strong> «раскрывает» массив или объект. Идеален для копирования и обновления (а не для мутации!).<br>\n        <strong>Обновить объект, не меняя оригинал</strong>: <code>{ ...user, age: 26 }</code>. Фундамент для React и Redux.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb194\" onchange=\"updateProgress(this)\"><span>const { name, age } = user — достаём поля одной строкой</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb195\" onchange=\"updateProgress(this)\"><span>const [first, second] = arr — то же для массива</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb196\" onchange=\"updateProgress(this)\"><span>function f({ name, age }) — деструктуризация в параметрах</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb197\" onchange=\"updateProgress(this)\"><span>[...arr1, 4, 5] — копия + добавление, без мутаций</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb198\" onchange=\"updateProgress(this)\"><span>{...user, age: 26} — обновить поле, не трогая оригинал</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-js-modern-2026","title":"Современный JavaScript: работа с данными ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-js-modern-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-js-modern-2026')\">Современный JavaScript: работа с данными <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Стрелочные функции, деструктуризация, Rest/Spread и методы массивов - ежедневные инструменты, а не трюки.</div><div class=\"code\">const users = [\n  { id: 1, name: \"Mira\", active: true, score: 12 },\n  { id: 2, name: \"Leo\", active: false, score: 7 },\n  { id: 3, name: \"Nika\", active: true, score: 18 }\n];\n\nconst activeNames = users\n  .filter(({ active }) =&gt; active)\n  .map(({ name }) =&gt; name);\n\nconst total = users.reduce((sum, { score }) =&gt; sum + score, 0);\nconst updateUser = (user, changes) =&gt; ({ ...user, ...changes });\nconst [first, ...rest] = users;</div><div class=\"explain\"><code>filter</code> отбирает, <code>map</code> преобразует, <code>reduce</code> собирает массив в один результат. Деструктуризация достаёт поля по имени. Spread создаёт новый объект без мутации, Rest собирает оставшиеся значения. <code>var</code> здесь не нужен.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-modern-2026-1\" onchange=\"updateProgress(this)\"><span>Применяю arrow, destructuring и Rest/Spread</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-modern-2026-2\" onchange=\"updateProgress(this)\"><span>Отличаю map, filter и reduce</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-modern-2026-3\" onchange=\"updateProgress(this)\"><span>Не использую var и лишние мутации</span></label></div></div>"},{"id":"block-async","title":"Promise и async/await — асинхронность по-человечески важно 🔗","html":"<div class=\"block\" id=\"block-async\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-async')\">Promise и async/await — асинхронность по-человечески <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Когда код «ждёт» (запрос к серверу, таймер) — он работает асинхронно. Promise — обещание дать результат «потом». async/await — синтаксис, чтобы это выглядело как обычный код.</div>\n      <div class=\"code\">// Promise — «обещание» результата в будущем\nconst promise = new Promise((resolve, reject) =&gt; {\n  setTimeout(() =&gt; {\n    const ok = Math.random() &gt; 0.3;\n    if (ok) resolve(\"Данные пришли!\");\n    else    reject(\"Сервер отвалился\");\n  }, 1000);\n});\n\n// .then().catch() — старый стиль\npromise\n  .then(data =&gt; console.log(data))      // успех\n  .catch(err =&gt; console.error(err))     // ошибка\n  .finally(() =&gt; console.log(\"Готово\")); // всегда\n\n// async/await — современный стиль (читается как обычный код)\nasync function loadUser(id) {\n  try {\n    const res  = await fetch(`/api/users/${id}`);\n    if (!res.ok) throw new Error(\"HTTP \" + res.status);\n\n    const user = await res.json();      // ждём парсинг\n    console.log(user.name);\n    return user;\n  } catch (err) {\n    console.error(\"Не загрузилось:\", err.message);\n    return null;\n  }\n}\n\n// Запускаем\nloadUser(42).then(u =&gt; console.log(u));\n\n// await работает только внутри async функции!\n// Чтобы дождаться нескольких параллельно — Promise.all\nasync function loadAll() {\n  const [users, posts] = await Promise.all([\n    fetch(\"/api/users\").then(r =&gt; r.json()),\n    fetch(\"/api/posts\").then(r =&gt; r.json())\n  ]);   // запросы идут параллельно — быстрее\n  return { users, posts };\n}</div>\n      <div class=\"explain\">\n        <strong>Promise</strong> — объект, который <em>когда-нибудь</em> выдаст результат (resolve) или ошибку (reject). Чаще всего ты их не создаёшь сам — их возвращают <code>fetch</code>, <code>fs</code>, библиотеки.<br>\n        <strong>async</strong> перед функцией → она автоматически возвращает Promise.<br>\n        <strong>await</strong> «ставит на паузу» функцию, пока промис не выполнится. Под капотом — те же <code>.then()</code>, но читается как синхронный код.<br>\n        <strong>try / catch</strong> с async/await — работает! Любая ошибка из await ловится в catch.<br>\n        <strong>Promise.all([...])</strong> — запустить промисы параллельно. Намного быстрее, чем <code>await</code> по очереди.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb189\" onchange=\"updateProgress(this)\"><span>Promise — «обещание» результата в будущем</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb190\" onchange=\"updateProgress(this)\"><span>.then(ok).catch(err) — старый, но рабочий способ</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb191\" onchange=\"updateProgress(this)\"><span>async/await — современный, читается как обычный код</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb192\" onchange=\"updateProgress(this)\"><span>await — только внутри async функции!</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb193\" onchange=\"updateProgress(this)\"><span>Promise.all — параллельные запросы, ждём все сразу</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-fetch","title":"Fetch: HTTP-ошибки, JSON и отмена ВАЖНО #","html":"<div class=\"block wdg-quality-block\" id=\"block-fetch\"><div class=\"block-title\" onclick=\"scrollToBlock('block-fetch')\">Fetch: HTTP-ошибки, JSON и отмена <span class=\"badge good\">ВАЖНО</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\"><code>fetch()</code> отклоняет Promise при сетевой ошибке, но ответы 404 и 500 всё равно дают обычный <code>Response</code>. Поэтому всегда проверяй <code>response.ok</code>.</div><div class=\"code\">async function loadProjects(signal) {\n  const response = await fetch(\"/api/projects\", { signal });\n  if (!response.ok) {\n    throw new Error(\"HTTP \" + response.status);\n  }\n  return response.json();\n}\n\nconst controller = new AbortController();\ntry {\n  const projects = await loadProjects(controller.signal);\n  console.log(projects);\n} catch (error) {\n  if (error.name !== \"AbortError\") console.error(error);\n}\n\n// controller.abort(); // отменить устаревший запрос</div><div class=\"explain\">Сначала проверь статус, затем разбирай тело через <code>json()</code>. <code>try/catch</code> ловит сетевые ошибки, собственный <code>throw</code> и ошибки разбора. <code>AbortController</code> отменяет запрос, когда пользователь ушёл со страницы или ввёл новый поиск.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-fetch-1\" onchange=\"updateProgress(this)\"><span>Проверяю response.ok</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-fetch-2\" onchange=\"updateProgress(this)\"><span>Показываю ошибку пользователю</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-fetch-3\" onchange=\"updateProgress(this)\"><span>Отменяю устаревшие запросы</span></label></div></div>"},{"id":"block-trycatch","title":"try / catch — обработка ошибок важно 🔗","html":"<div class=\"block\" id=\"block-trycatch\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-trycatch')\">try / catch — обработка ошибок <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Ошибки случаются: сервер не ответил, пользователь ввёл невалидные данные. try/catch позволяет обработать их без «падения» всего скрипта.</div>\n      <div class=\"code\">// Базовый try / catch\ntry {\n  const data = JSON.parse(\"не JSON строка\");  // ошибка!\n  console.log(data);\n} catch (err) {\n  console.log(\"Ошибка:\", err.message);  // перехватываем\n} finally {\n  console.log(\"Выполнится всегда\");   // и при успехе, и при ошибке\n}\n\n// С fetch (async/await + try/catch)\nasync function loadUser(id) {\n  try {\n    const res = await fetch(`/api/users/${id}`);\n\n    if (!res.ok) {\n      throw new Error(`Сервер вернул ${res.status}`);  // сами бросаем ошибку\n    }\n\n    const user = await res.json();\n    return user;\n\n  } catch (err) {\n    console.error(\"Не удалось загрузить пользователя:\", err.message);\n    return null;  // возвращаем null вместо краша\n  }\n}\n\n// Своя ошибка\nfunction divide(a, b) {\n  if (b === 0) throw new Error(\"Делить на ноль нельзя!\");\n  return a / b;\n}\n\ntry {\n  console.log(divide(10, 0));\n} catch (e) {\n  console.warn(e.message);  // \"Делить на ноль нельзя!\"\n}</div>\n      <div class=\"explain\">\n        <strong>try</strong> — код, который может упасть с ошибкой.<br>\n        <strong>catch (err)</strong> — сюда попадаем при ошибке. <code>err.message</code> — текст ошибки.<br>\n        <strong>finally</strong> — выполняется всегда (закрыть соединение, скрыть лоадер).<br>\n        <strong>throw new Error(\"...\")</strong> — ты сам создаёшь ошибку (например, при невалидных данных).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb179\" onchange=\"updateProgress(this)\"><span>try { } catch (err) { } — обязательная пара</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb180\" onchange=\"updateProgress(this)\"><span>err.message — читаем текст ошибки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb181\" onchange=\"updateProgress(this)\"><span>finally — закрывать ресурсы, скрывать спиннер</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb182\" onchange=\"updateProgress(this)\"><span>throw new Error() — сам бросаю ошибку при невалидных данных</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb183\" onchange=\"updateProgress(this)\"><span>Оборачиваю fetch / JSON.parse в try/catch</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-js-network-2026","title":"Реальный запрос: fetch + async/await ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-js-network-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-js-network-2026')\">Реальный запрос: fetch + async/await <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">У запроса есть загрузка, успех, пустой ответ и ошибка. Обработай все состояния, а не только удачный console.log.</div><div class=\"code\">async function loadProjects() {\n  renderStatus(\"loading\");\n\n  try {\n    const response = await fetch(\"/api/projects\");\n    if (!response.ok) throw new Error(\"HTTP \" + response.status);\n\n    const projects = await response.json();\n    renderProjects(projects);\n    renderStatus(projects.length ? \"success\" : \"empty\");\n  } catch (error) {\n    console.error(error);\n    renderStatus(\"error\");\n  }\n}</div><div class=\"explain\"><code>await</code> ждёт Promise внутри async-функции и не замораживает страницу. HTTP 404/500 не всегда бросает исключение, поэтому проверяй <code>response.ok</code>. <code>try/catch</code> обрабатывает сбой, а отдельные render-функции не смешивают сеть и DOM.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-network-2026-1\" onchange=\"updateProgress(this)\"><span>Проверяю response.ok</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-network-2026-2\" onchange=\"updateProgress(this)\"><span>Обрабатываю ошибку через try/catch</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-network-2026-3\" onchange=\"updateProgress(this)\"><span>Разделяю загрузку данных и DOM</span></label></div></div>"},{"id":"block-strings","title":"Строки — работа с текстом основа 🔗","html":"<div class=\"block\" id=\"block-strings\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-strings')\">Строки — работа с текстом <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">const name = \"Мир\";\nconst age = 25;\n\n// Шаблоны — подставляем переменные в текст\nconst msg = `Привет, ${name}! Тебе ${age} лет.`;\n\nmsg.length;               // Длина строки\nmsg.toUpperCase();        // \"ПРИВЕТ, МИР!\"\nmsg.toLowerCase();        // \"привет, мир!\"\nmsg.includes(\"Мир\");      // true\nmsg.replace(\"Мир\", \"друг\"); // \"Привет, друг!\"\nmsg.trim();               // Убрать пробелы по краям\nmsg.split(\", \");          // [\"Привет\", \"Мир!\"]</div>\n      <div class=\"explain\">\n\n<strong>Как читать этот код:</strong> строка — это текст. Если текст лежит в переменной, с ним можно работать методами: проверять длину, искать кусок текста, менять регистр, заменять часть строки.<br>\n        <strong>Шаблонная строка</strong> пишется через обратные кавычки <code>`</code>. Внутри <code>${name}</code> означает: возьми значение переменной <code>name</code> и вставь его прямо в текст.<br>\n        <strong>Важно:</strong> методы строк обычно <em>не меняют старую строку</em>, а возвращают новый результат. Например <code>msg.toUpperCase()</code> вернет текст большими буквами, но сам <code>msg</code> останется прежним.<br>\n        <strong>.length</strong> — это не функция, поэтому без скобок. Она просто хранит число символов.<br>\n        <strong>.includes(\"Мир\")</strong> задает вопрос: “есть ли внутри такой кусок текста?” Ответ будет <code>true</code> или <code>false</code>.<br>\n        <strong>.trim()</strong> почти всегда полезен перед проверкой формы: пользователь мог ввести только пробелы, а <code>trim()</code> превратит это в пустую строку.<br>\n        <strong>.split(\", \")</strong> режет строку по разделителю и делает массив. Если разделитель не найден, получится массив из одной строки.<br>\n        <strong>Когда применять:</strong> формы, поиск по странице, сообщения пользователю, форматирование имени, проверка email/логина перед отправкой.\n\n      </div>\n      <!-- МИНИ-ТЕСТ ДЛЯ СТРОК -->\n      <div class=\"quiz-block\" id=\"quiz-strings\">\n        <div class=\"quiz-title\">🧪 Мини-тест — Строки</div>\n        <div class=\"quiz-question\">1. Какой метод убирает пробелы в начале и конце строки?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-1\" value=\"a\"> <span>.clean()</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-1\" value=\"b\"> <span>.trim()</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-1\" value=\"c\"> <span>.strip()</span></label>\n        </div>\n        <div class=\"quiz-question\">2. Как подставить переменную в строку через шаблон?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-2\" value=\"a\"> <span>\"Привет, \" + name</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-2\" value=\"b\"> <span>`Привет, ${name}`</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-2\" value=\"c\"> <span>f\"Привет, {name}\"</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Практика</div>\n          <div class=\"practice-task\">Напиши функцию <code>trimAndUpper</code>, которая принимает строку, убирает пробелы по краям и возвращает её в верхнем регистре.</div>\n          <textarea class=\"practice-input\" id=\"practice-strings\" placeholder=\"function trimAndUpper(str) { ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('strings')\">✓ Проверить</button>\n        <div class=\"quiz-result\" id=\"result-strings\"></div>\n      </div>\n      <div class=\"items\" id=\"items-strings\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb610\" onchange=\"updateProgress(this)\" disabled><span>🔒 Шаблоны: `${переменная}` внутри обратных кавычек</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb611\" onchange=\"updateProgress(this)\" disabled><span>🔒 .trim() — убрать пробелы, .includes() — есть ли подстрока</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Пройди тест и практику, чтобы разблокировать чекбоксы</div>\n    </div>\n\n    "},{"id":"block-conditions","title":"Условия — если... то... основа 🔗","html":"<div class=\"block\" id=\"block-conditions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-conditions')\">Условия — если... то... <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">const age = 20;\n\nif (age &gt;= 18) {\n  console.log(\"Взрослый\");\n} else if (age &gt;= 14) {\n  console.log(\"Подросток\");\n} else {\n  console.log(\"Ребёнок\");\n}\n\n// Тернарный оператор — короткая запись if/else\nconst status = age &gt;= 18 ? \"взрослый\" : \"ребёнок\";\n\n// ===  строго равно (5 === \"5\" → false!)\n// !==  строго НЕ равно\n// &amp;&amp;   И (оба условия верны)\n// ||   ИЛИ (хотя бы одно верно)</div>\n      <div class=\"explain\">\n\n<strong>Как читать if:</strong> браузер идет сверху вниз и выполняет первый блок, где условие стало <code>true</code>. Остальные ветки после этого пропускаются.<br>\n        <strong>if</strong> — первая проверка. <strong>else if</strong> — запасная проверка, если первая не подошла. <strong>else</strong> — вариант “иначе”, когда ничего выше не подошло.<br>\n        <strong>Где ставить ===:</strong> когда сравниваешь “это значение равно тому значению?”. Например <code>role === \"admin\"</code>, <code>score === 0</code>, <code>theme === \"dark\"</code>.<br>\n        <strong>Где ставить &gt;=:</strong> когда проверяешь границу: возраст, цена, количество, ширина экрана, число кликов. <code>age &gt;= 18</code> значит “18 или больше”.<br>\n        <strong>&amp;&amp;</strong> — нужно, чтобы выполнились оба условия: <code>age &gt;= 18 &amp;&amp; hasTicket</code>.<br>\n        <strong>||</strong> — достаточно одного условия: <code>role === \"admin\" || role === \"moderator\"</code>.<br>\n        <strong>Тернарный оператор</strong> удобен для короткого выбора значения. Если внутри уже много действий, лучше обычный <code>if/else</code>, так код легче читать.<br>\n        <strong>Частая ошибка:</strong> <code>=</code> присваивает, <code>===</code> сравнивает. В условиях почти всегда нужен именно <code>===</code>.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb155\" onchange=\"updateProgress(this)\"><span>Всегда используй === (строгое), а не == (нестрогое)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb156\" onchange=\"updateProgress(this)\"><span>Тернарный: условие ? да : нет</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-loops","title":"Циклы — повторяем действие основа 🔗","html":"<div class=\"block\" id=\"block-loops\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-loops')\">Циклы — повторяем действие <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">// for — когда знаем, сколько раз\nfor (let i = 0; i &lt; 5; i++) {\n  console.log(i);  // 0, 1, 2, 3, 4\n}\n\n// while — когда НЕ знаем, сколько раз\nlet count = 3;\nwhile (count &gt; 0) {\n  console.log(count);\n  count--;\n}\n\n// for...of — перебор массива\nconst fruits = [\"яблоко\", \"банан\", \"груша\"];\nfor (const fruit of fruits) {\n  console.log(fruit);\n}</div>\n      <div class=\"explain\">\n\n<strong>Как читать цикл for:</strong> <code>let i = 0</code> — откуда начинаем, <code>i &lt; 5</code> — пока продолжаем, <code>i++</code> — что делаем после каждого круга.<br>\n        <strong>Почему вывод 0..4:</strong> цикл стартует с 0, а условие <code>i &lt; 5</code> останавливает его до 5. Когда <code>i</code> станет 5, условие уже false.<br>\n        <strong>while</strong> нужен, когда заранее неизвестно точное число повторений. Например ждать, пока пользователь введет правильные данные.<br>\n        <strong>Опасность while:</strong> если внутри не менять значение, условие может всегда оставаться true, и получится бесконечный цикл.<br>\n        <strong>for...of</strong> используй, когда тебе нужен сам элемент массива: фрукт, карточка, задача, пользователь. Это проще, чем доставать элемент по индексу.<br>\n        <strong>Когда применять:</strong> вывести список карточек, пройтись по кнопкам, посчитать сумму, найти нужный элемент, создать HTML для каждого объекта.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb157\" onchange=\"updateProgress(this)\"><span>for — когда знаю сколько раз, while — пока условие верно</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb158\" onchange=\"updateProgress(this)\"><span>for...of — перебор элементов массива</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-dom","title":"DOM — управляем страницей основа 🔗","html":"<div class=\"block\" id=\"block-dom\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-dom')\">DOM — управляем страницей <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">// НАЙТИ элемент\nconst btn = document.querySelector(\".btn\");       // Первый\nconst all = document.querySelectorAll(\"li\");      // Все\n\n// ИЗМЕНИТЬ\nbtn.textContent = \"Нажато!\";       // Изменить текст\nbtn.style.color = \"red\";           // Изменить стиль\nbtn.classList.add(\"active\");       // Добавить класс\nbtn.classList.remove(\"active\");    // Убрать класс\nbtn.classList.toggle(\"open\");      // Переключить\n\n// СОЗДАТЬ и ДОБАВИТЬ\nconst div = document.createElement(\"div\");\ndiv.textContent = \"Новый блок\";\ndocument.body.appendChild(div);\n\n// УДАЛИТЬ\nbtn.remove();</div>\n      <div class=\"explain\">\n\n<strong>Как читать DOM-код:</strong> сначала ты находишь элемент на странице, потом меняешь его текст, стиль, классы или вешаешь события.<br>\n        <strong>querySelector</strong> берет первый подходящий элемент. Внутри пишется CSS-селектор: <code>\".btn\"</code> для класса, <code>\"#title\"</code> для id, <code>\"button\"</code> для тега.<br>\n        <strong>querySelectorAll</strong> берет список элементов. По нему обычно проходят через <code>forEach</code>, потому что это не один элемент, а коллекция.<br>\n        <strong>textContent</strong> меняет текст внутри элемента. Это безопаснее для обычного текста, чем <code>innerHTML</code>.<br>\n        <strong>classList</strong> лучше, чем постоянно менять <code>style</code>. Логика остается в JS, внешний вид — в CSS.<br>\n        <strong>createElement + append</strong> нужны, когда элемент должен появиться на странице после действия пользователя: новая задача, сообщение, карточка, ошибка формы.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb161\" onchange=\"updateProgress(this)\"><span>querySelector — один, querySelectorAll — все</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb162\" onchange=\"updateProgress(this)\"><span>classList.add / remove / toggle / contains</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-events","title":"События — реагируем на действия основа 🔗","html":"<div class=\"block\" id=\"block-events\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-events')\">События — реагируем на действия <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">const btn = document.querySelector(\".btn\");\n\nbtn.addEventListener(\"click\", (e) =&gt; {\n  console.log(\"Кликнули!\");\n  e.preventDefault(); // Отменить стандартное поведение\n});\n\nconst input = document.querySelector(\"input\");\ninput.addEventListener(\"input\", (e) =&gt; {\n  console.log(\"Ввели:\", e.target.value);\n});\n\n// Частые события:\n// click, dblclick — клик / двойной клик\n// input, change — ввод / изменение поля\n// submit — отправка формы\n// keydown, keyup — клавиатура\n// mouseover, mouseout — мышь\n// scroll — прокрутка</div>\n      <div class=\"explain\">\n\n<strong>Как читать событие:</strong> <code>addEventListener(\"click\", ...)</code> значит “когда произойдет click, запусти эту функцию”. Код внутри не запускается сразу, он ждет действия пользователя.<br>\n        <strong>Первый аргумент</strong> — название события строкой: <code>\"click\"</code>, <code>\"input\"</code>, <code>\"submit\"</code>, <code>\"keydown\"</code>.<br>\n        <strong>Второй аргумент</strong> — функция, которая выполнится потом. Поэтому пишем функцию без немедленного вызова. <code>handleClick</code> — передать функцию, <code>handleClick()</code> — вызвать сразу.<br>\n        <strong>e</strong> или <strong>event</strong> — объект события. В нем браузер дает детали: где кликнули, какая клавиша нажата, что лежит в input.<br>\n        <strong>e.target</strong> — конкретный элемент, на котором произошло событие. <code>e.target.value</code> — текст внутри input.<br>\n        <strong>e.preventDefault()</strong> нужен в форме, чтобы браузер не перезагрузил страницу после submit.<br>\n        <strong>Как выбрать событие:</strong> кнопка — <code>click</code>, поле ввода в реальном времени — <code>input</code>, отправка формы — <code>submit</code>, клавиатура — <code>keydown</code>.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb163\" onchange=\"updateProgress(this)\"><span>addEventListener — слушаем событие</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb164\" onchange=\"updateProgress(this)\"><span>e.target.value — значение поля ввода</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb165\" onchange=\"updateProgress(this)\"><span>e.preventDefault() — отменить перезагрузку</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-localstorage","title":"localStorage: строки, null и безопасный разбор ВАЖНО #","html":"<div class=\"block wdg-quality-block\" id=\"block-localstorage\"><div class=\"block-title\" onclick=\"scrollToBlock('block-localstorage')\">localStorage: строки, null и безопасный разбор <span class=\"badge good\">ВАЖНО</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\"><code>localStorage.getItem()</code> возвращает строку или <code>null</code>. Сначала обработай отсутствие значения, затем преобразуй тип. Не храни здесь пароли, токены и другие секреты.</div><div class=\"code\">localStorage.setItem(\"theme\", \"dark\");\nconst theme = localStorage.getItem(\"theme\") ?? \"light\";\n\nconst rawScore = localStorage.getItem(\"score\");\nconst parsedScore = rawScore === null ? 0 : Number(rawScore);\nconst score = Number.isFinite(parsedScore) ? parsedScore : 0;\n\nconst user = { id: 7, name: \"Mira\" };\nlocalStorage.setItem(\"user\", JSON.stringify(user));\n\nconst rawUser = localStorage.getItem(\"user\");\nconst savedUser = rawUser === null ? null : JSON.parse(rawUser);\nlocalStorage.removeItem(\"theme\");</div><div class=\"explain\"><code>??</code> берёт запасное значение только для <code>null</code> и <code>undefined</code>, сохраняя корректные <code>0</code> и пустую строку. Запись <code>Number(localStorage.getItem(\"score\")) ?? 0</code> бесполезна: после <code>Number()</code> значение уже не бывает <code>null</code>. Объекты сохраняй через <code>JSON.stringify</code>; при чтении учитывай повреждённые данные.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-1\" onchange=\"updateProgress(this)\"><span>Помню про string | null</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-2\" onchange=\"updateProgress(this)\"><span>Проверяю NaN после Number()</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-3\" onchange=\"updateProgress(this)\"><span>Не храню секреты</span></label></div></div>"},{"id":"block-localstorage-counter","title":"Счётчик с сохранением состояния ПРАКТИКА #","html":"<div class=\"block wdg-quality-block\" id=\"block-localstorage-counter\"><div class=\"block-title\" onclick=\"scrollToBlock('block-localstorage-counter')\">Счётчик с сохранением состояния <span class=\"badge good\">ПРАКТИКА</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Приложение сначала восстанавливает состояние, затем отображает его. После каждого реального изменения новое значение записывается обратно.</div><div class=\"code\">const count = document.querySelector(\".count\");\nconst plus = document.querySelector(\".plus\");\nconst reset = document.querySelector(\".reset\");\n\nconst rawScore = localStorage.getItem(\"score\");\nlet score = rawScore === null ? 0 : Number(rawScore);\nif (!Number.isFinite(score)) score = 0;\n\nfunction render() { count.textContent = score; }\nfunction save() { localStorage.setItem(\"score\", String(score)); }\n\nplus.addEventListener(\"click\", () =&gt; {\n  score += 1;\n  save();\n  render();\n});\n\nreset.addEventListener(\"click\", () =&gt; {\n  score = 0;\n  save();\n  render();\n});\n\nrender();</div><div class=\"explain\"><code>score</code> - состояние, <code>render()</code> синхронизирует DOM, а <code>save()</code> отвечает только за хранилище. Первый <code>render()</code> обязателен: без него восстановленное значение не появится до клика. Не объявляй <code>score</code> повторно после чтения хранилища.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-counter-1\" onchange=\"updateProgress(this)\"><span>Восстанавливаю до render()</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-counter-2\" onchange=\"updateProgress(this)\"><span>Разделяю state, save и render</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-counter-3\" onchange=\"updateProgress(this)\"><span>Не объявляю score дважды</span></label></div></div>"},{"id":"block-objects","title":"Объекты — структурированные данные основа 🔗","html":"<div class=\"block\" id=\"block-objects\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-objects')\">Объекты — структурированные данные <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Объект — это набор «ключ: значение». Идеально для описания сущностей: пользователь, товар, задача.</div>\n      <div class=\"code\">// Создаём объект\nconst user = {\n  name: \"Алекс\",\n  age: 25,\n  isAdmin: false,\n  greet() {\n    return `Привет, я ${this.name}!`;\n  }\n};\n\n// Читаем свойства\nconsole.log(user.name);       // \"Алекс\"\nconsole.log(user[\"age\"]);     // 25  (второй способ)\n\n// Меняем / добавляем свойства\nuser.age = 26;\nuser.city = \"Москва\";         // добавили новое поле\n\n// Вызов метода\nconsole.log(user.greet());    // \"Привет, я Алекс!\"\n\n// Деструктуризация (вытащить поля в переменные)\nconst { name, age } = user;\nconsole.log(name, age);       // \"Алекс\" 26\n\n// Перебрать все ключи\nfor (const key in user) {\n  console.log(key, user[key]);\n}\n\n// Массив объектов\nconst products = [\n  { id: 1, name: \"Ноутбук\", price: 50000 },\n  { id: 2, name: \"Мышь\",    price: 1200 },\n];\nproducts.forEach(p =&gt; console.log(p.name, p.price));\n\n// Копия объекта (spread)\nconst copy = { ...user, role: \"editor\" };</div>\n      <div class=\"explain\">\n        <strong>Точечная нотация</strong>: <code>user.name</code> — самый частый способ.<br>\n        <strong>Скобочная нотация</strong>: <code>user[\"name\"]</code> — нужна, когда ключ в переменной.<br>\n        <strong>this</strong> — внутри метода ссылается на сам объект.<br>\n        <strong>Деструктуризация</strong>: <code>const {name, age} = user</code> — короткий способ достать несколько полей.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb175\" onchange=\"updateProgress(this)\"><span>Объект = { ключ: значение }, читаем через точку</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb176\" onchange=\"updateProgress(this)\"><span>Деструктуризация: const { name, age } = user</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb177\" onchange=\"updateProgress(this)\"><span>Spread: { ...obj } — копирует объект</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb178\" onchange=\"updateProgress(this)\"><span>Массив объектов — типичная структура данных с сервера</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-timers","title":"setTimeout, setInterval, debounce важно 🔗","html":"<div class=\"block\" id=\"block-timers\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-timers')\">setTimeout, setInterval, debounce <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Таймеры запускают код «через сколько-то» или «каждые сколько-то». На них построено всё: тосты, тултипы, поиск-по-вводу, анимации, опросы сервера.</div>\n      <div class=\"code\">// setTimeout — выполнить ОДИН раз через N мс\nsetTimeout(() =&gt; {\n  console.log(\"Прошла секунда\");\n}, 1000);\n\n// Сохраняем id, чтобы можно было отменить\nconst id = setTimeout(() =&gt; alert(\"Не появится!\"), 5000);\nclearTimeout(id);   // отменяем\n\n// setInterval — повторять КАЖДЫЕ N мс\nconst tick = setInterval(() =&gt; {\n  console.log(new Date().toLocaleTimeString());\n}, 1000);\n\n// Через 10 секунд останавливаем\nsetTimeout(() =&gt; clearInterval(tick), 10000);\n\n// === Реальный пример: автоскрытие тоста ===\nfunction showToast(text) {\n  const t = document.querySelector(\".toast\");\n  t.textContent = text;\n  t.classList.add(\"show\");\n  setTimeout(() =&gt; t.classList.remove(\"show\"), 3000);\n}\n\n// === Debounce — «выполнить не сразу, а когда успокоится» ===\n// Полезно для поиска по вводу: ждём, пока пользователь перестанет печатать\nfunction debounce(fn, ms = 300) {\n  let timer;\n  return (...args) =&gt; {\n    clearTimeout(timer);\n    timer = setTimeout(() =&gt; fn(...args), ms);\n  };\n}\n\nconst searchInput = document.querySelector(\"#search\");\nconst search = debounce((value) =&gt; {\n  console.log(\"ищем:\", value);\n  // fetch(`/api/search?q=${value}`)\n}, 400);\n\nsearchInput.addEventListener(\"input\", e =&gt; search(e.target.value));</div>\n      <div class=\"explain\">\n        <strong>setTimeout(fn, ms)</strong> — один раз через N миллисекунд. <strong>setInterval</strong> — каждые N мс.<br>\n        <strong>clearTimeout / clearInterval</strong> — отменить по сохранённому id. Обязательно вызывай при удалении компонента / уходе со страницы — иначе утечки памяти.<br>\n        <strong>0 мс</strong> — <code>setTimeout(fn, 0)</code> — НЕ мгновенно. Откладывает на «после текущего кода». Часто используется, чтобы дождаться рендера DOM.<br>\n        <strong>Debounce</strong> — паттерн «жди тишины». Пользователь печатает → запрос идёт только после паузы 400мс. Защищает сервер от тысяч запросов.<br>\n        <strong>Throttle</strong> — «не чаще раза в N мс». Используется для скролла и ресайза.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb199\" onchange=\"updateProgress(this)\"><span>setTimeout(fn, ms) — один раз через N мс</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb200\" onchange=\"updateProgress(this)\"><span>setInterval(fn, ms) — каждые N мс. clearInterval — стоп</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb201\" onchange=\"updateProgress(this)\"><span>Сохраняю id и вызываю clear при unmount</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb202\" onchange=\"updateProgress(this)\"><span>Debounce — для input поиска (запрос после паузы)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb203\" onchange=\"updateProgress(this)\"><span>Throttle — для scroll и resize (раз в N мс)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-classes","title":"Классы — class, extends, this продвинуто 🔗","html":"<div class=\"block\" id=\"block-classes\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-classes')\">Классы — class, extends, this <span class=\"badge pro\">продвинуто</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Классы — это «шаблоны» для создания однотипных объектов. Под капотом — обычные функции и прототипы, но синтаксис привычнее.</div>\n      <div class=\"code\">class User {\n  // Конструктор — вызывается при new User(...)\n  constructor(name, age) {\n    this.name = name;\n    this.age  = age;\n  }\n\n  // Метод\n  greet() {\n    return `Привет, я ${this.name}!`;\n  }\n\n  // Геттер — вызывается БЕЗ скобок\n  get isAdult() {\n    return this.age &gt;= 18;\n  }\n\n  // Сеттер\n  set newName(value) {\n    this.name = value.trim();\n  }\n\n  // Статический метод — у класса, не у объекта\n  static fromString(str) {\n    const [name, age] = str.split(\",\");\n    return new User(name, Number(age));\n  }\n}\n\nconst u = new User(\"Алекс\", 25);\nconsole.log(u.greet());      // \"Привет, я Алекс!\"\nconsole.log(u.isAdult);      // true (без скобок!)\n\nconst u2 = User.fromString(\"Иван,30\");   // статический\n\n// === Наследование ===\nclass Admin extends User {\n  constructor(name, age, role) {\n    super(name, age);   // вызов конструктора родителя\n    this.role = role;\n  }\n\n  greet() {\n    return super.greet() + ` Я ${this.role}.`;   // переопределяем\n  }\n}\n\nconst a = new Admin(\"Маша\", 30, \"админ\");\nconsole.log(a.greet());   // \"Привет, я Маша! Я админ.\"\n\n// Приватные поля (с #)\nclass Account {\n  #balance = 0;            // приватное! недоступно снаружи\n\n  deposit(sum) { this.#balance += sum; }\n  get balance() { return this.#balance; }\n}</div>\n      <div class=\"explain\">\n        <strong>constructor</strong> — особый метод, вызывается один раз при <code>new ClassName()</code>. Здесь задаём начальные поля.<br>\n        <strong>this</strong> внутри методов — текущий объект. <em>Стрелочные функции внутри класса не имеют своего this</em>, обычные методы — имеют.<br>\n        <strong>get / set</strong> — свойства, которые на самом деле функции. Снаружи — <code>obj.isAdult</code> без скобок.<br>\n        <strong>static</strong> — метод, который вызывается у класса, а не у объекта. Часто это «фабрики»: <code>User.fromString(...)</code>.<br>\n        <strong>extends + super</strong> — наследование. <code>super(...)</code> в constructor обязателен <em>до</em> использования this.<br>\n        <strong>#field</strong> — приватные поля (новый синтаксис). Снаружи их не достать.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb204\" onchange=\"updateProgress(this)\"><span>class + constructor + методы — базовая форма</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb205\" onchange=\"updateProgress(this)\"><span>this — ссылка на текущий объект</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb206\" onchange=\"updateProgress(this)\"><span>get / set — свойства-функции (без скобок снаружи)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb207\" onchange=\"updateProgress(this)\"><span>static — метод у самого класса (фабрики)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb208\" onchange=\"updateProgress(this)\"><span>extends + super(...) — наследование</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-js-eventloop","title":"Event Loop — как работает асинхронность топ собесов 🔗","html":"<div class=\"block\" id=\"block-js-eventloop\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-js-eventloop')\">Event Loop — как работает асинхронность <span class=\"badge must\">топ собесов</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Самый частый вопрос на собеседовании: \"Почему этот код выводит именно в таком порядке?\" Без Event Loop невозможно понять асинхронный JS.</div>\n      <div class=\"code\"><span class=\"cm\">// JavaScript выполняет код в таком порядке:</span>\n<span class=\"cm\">// 1. Весь СИНХРОННЫЙ код</span>\n<span class=\"cm\">// 2. Все МИКРОЗАДАЧИ (Promise.then, async/await)</span>\n<span class=\"cm\">// 3. Одна МАКРОЗАДАЧА (setTimeout, setInterval)</span>\n<span class=\"cm\">// 4. Повтор пункта 2-3</span>\n\nconsole.<span class=\"fn\">log</span>(<span class=\"str\">'1: синхронно'</span>);\n\n<span class=\"fn\">setTimeout</span>(() =&gt; console.<span class=\"fn\">log</span>(<span class=\"str\">'4: макрозадача'</span>), <span class=\"num\">0</span>);\n\nPromise.<span class=\"fn\">resolve</span>().<span class=\"fn\">then</span>(() =&gt; console.<span class=\"fn\">log</span>(<span class=\"str\">'3: микрозадача'</span>));\n\nconsole.<span class=\"fn\">log</span>(<span class=\"str\">'2: синхронно'</span>);\n\n<span class=\"cm\">// Вывод: 1, 2, 3, 4</span>\n<span class=\"cm\">// Хотя setTimeout(fn, 0) — таймер 0мс, он выполнится ПОСЛЕ Promise!</span></div>\n      <div class=\"explain\">\n        <strong>Стек вызовов (Call Stack)</strong> — выполняет синхронный код сверху вниз, один за другим.<br>\n        <strong>Микрозадачи</strong> (Promise, async/await) — имеют приоритет выше макрозадач. Очередь микрозадач опустошается ПОЛНОСТЬЮ перед каждой макрозадачей.<br>\n        <strong>Макрозадачи</strong> (setTimeout, setInterval, события) — выполняются по одной за \"тик\" Event Loop.<br>\n        <strong>Главный вывод:</strong> <code>setTimeout(fn, 0)</code> не означает \"сразу\" — это означает \"после того как весь текущий синхронный код и все микрозадачи закончатся\".\n      </div>\n      <div class=\"eventloop-lab\">\n        <div class=\"tool-row\">\n          <button class=\"try-btn\" style=\"margin:0;\" onclick=\"runEventLoopDemo()\">Запустить код</button>\n          <span style=\"font-size:12px;color:#6b7280;\">Смотри, куда попадают sync, Promise и setTimeout.</span>\n        </div>\n        <div class=\"eventloop-board\">\n          <div class=\"event-col\"><h4>Call Stack</h4><div id=\"elStack\"></div></div>\n          <div class=\"event-col\"><h4>Microtasks</h4><div id=\"elMicro\"></div></div>\n          <div class=\"event-col\"><h4>Macrotasks</h4><div id=\"elMacro\"></div></div>\n        </div>\n        <div class=\"tool-result\" id=\"elLog\">Нажми «Запустить код».</div>\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb209\" onchange=\"updateProgress(this)\"><span>Порядок выполнения: синхронный код → микрозадачи → макрозадачи</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb210\" onchange=\"updateProgress(this)\"><span>Promise.then — микрозадача, выполняется раньше setTimeout</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb211\" onchange=\"updateProgress(this)\"><span>Могу объяснить почему setTimeout(fn, 0) не выполняется мгновенно</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-js-closures","title":"Замыкания (Closures) топ собесов 🔗","html":"<div class=\"block\" id=\"block-js-closures\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-js-closures')\">Замыкания (Closures) <span class=\"badge must\">топ собесов</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Любимый вопрос интервьюеров №1. Замыкание — это функция, которая \"помнит\" переменные из окружения, в котором она была создана, даже после того как это окружение завершило работу.</div>\n      <div class=\"code\"><span class=\"cm\">// Простой пример — счётчик</span>\n<span class=\"kw\">function</span> <span class=\"fn\">createCounter</span>() {\n  <span class=\"kw\">let</span> count = <span class=\"num\">0</span>; <span class=\"cm\">// эта переменная \"захватывается\" замыканием</span>\n\n  <span class=\"kw\">return function</span>() {\n    count++; <span class=\"cm\">// внутренняя функция помнит count из внешней</span>\n    <span class=\"kw\">return</span> count;\n  };\n}\n\n<span class=\"kw\">const</span> counter = <span class=\"fn\">createCounter</span>();\ncounter(); <span class=\"cm\">// 1</span>\ncounter(); <span class=\"cm\">// 2</span>\ncounter(); <span class=\"cm\">// 3 — count не сбрасывается между вызовами!</span>\n\n<span class=\"cm\">// Каждый вызов createCounter создаёт СВОЁ замыкание</span>\n<span class=\"kw\">const</span> counter2 = <span class=\"fn\">createCounter</span>();\ncounter2(); <span class=\"cm\">// 1 — у counter2 свой собственный count</span>\n\n<span class=\"cm\">// Практичный пример — приватные переменные</span>\n<span class=\"kw\">function</span> <span class=\"fn\">createBankAccount</span>(initialBalance) {\n  <span class=\"kw\">let</span> balance = initialBalance; <span class=\"cm\">// \"приватная\" переменная</span>\n  <span class=\"kw\">return</span> {\n    deposit: amount =&gt; balance += amount,\n    getBalance: () =&gt; balance\n  };\n} <span class=\"cm\">// снаружи нет прямого доступа к balance — только через методы</span></div>\n      <div class=\"explain\">\n        <strong>Замыкание создаётся всегда</strong> когда функция объявлена внутри другой функции и использует её переменные.<br>\n        <strong>Зачем нужно:</strong> создание приватных переменных, счётчиков, кэширования результатов (мемоизация), обработчиков событий которые помнят контекст.<br>\n        <strong>Частая ловушка собеседований:</strong> замыкания в циклах с <code>var</code> — все функции будут видеть финальное значение переменной, а не то что было при создании. С <code>let</code> такой проблемы нет.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb212\" onchange=\"updateProgress(this)\"><span>Понимаю что функция \"запоминает\" переменные внешнего окружения</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb213\" onchange=\"updateProgress(this)\"><span>Написал свой счётчик через замыкание</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb214\" onchange=\"updateProgress(this)\"><span>Знаю ловушку var в циклах с замыканиями (и почему let её решает)</span></label>\n      </div>\n    </div>\n\n\n    "},{"id":"block-js-architecture","title":"Архитектура JS-кода до React важно 🔗","html":"<div class=\"block\" id=\"block-js-architecture\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-js-architecture')\">Архитектура JS-кода до React <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">До компонентов важно научиться делить обычный JavaScript на модули: данные отдельно, бизнес-логика отдельно, отображение отдельно.</div>\n      <div class=\"code\"><span class=\"cm\">// api/users.js — слой данных</span>\n<span class=\"kw\">export async function</span> <span class=\"fn\">loadUsers</span>() {\n  <span class=\"kw\">const</span> res = <span class=\"kw\">await</span> <span class=\"fn\">fetch</span>(<span class=\"str\">'/api/users'</span>);\n  <span class=\"kw\">return</span> res.<span class=\"fn\">json</span>();\n}\n\n<span class=\"cm\">// domain/users.js — бизнес-логика</span>\n<span class=\"kw\">export function</span> <span class=\"fn\">getActiveUsers</span>(users) {\n  <span class=\"kw\">return</span> users.<span class=\"fn\">filter</span>(user =&gt; user.active);\n}\n\n<span class=\"cm\">// ui/renderUsers.js — отображение</span>\n<span class=\"kw\">export function</span> <span class=\"fn\">renderUsers</span>(users, root) {\n  root.innerHTML = users.<span class=\"fn\">map</span>(u =&gt; <span class=\"str\">`&lt;li&gt;${u.name}&lt;/li&gt;`</span>).<span class=\"fn\">join</span>(<span class=\"str\">''</span>);\n}</div>\n      <div class=\"explain\">\n        <strong>import/export</strong> — базовая модульность: файл отдаёт наружу только то, что нужно другим частям приложения.<br>\n        <strong>Слои</strong> помогают не смешивать fetch, расчёты и DOM-отрисовку в одной функции. Такой код легче тестировать и переносить в React.<br>\n        <strong>Главная привычка:</strong> если функция одновременно ходит в API, считает данные и меняет HTML — её пора разделить.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb214a\" onchange=\"updateProgress(this)\"><span>Делю JS на модули через import/export</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb214b\" onchange=\"updateProgress(this)\"><span>Разделяю данные, бизнес-логику и отображение</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-ts","lessons":[{"id":"block-ts-strict-2026","title":"Строгая типизация реальных данных ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-ts-strict-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-ts-strict-2026')\">Строгая типизация реальных данных <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Типизируй аргументы, ответы API, props и состояние. Непроверенные внешние данные начинаются с unknown, а не any.</div><div class=\"code\">type Role = \"student\" | \"mentor\";\n\ninterface User {\n  id: number;\n  name: string;\n  role: Role;\n  skills: string[];\n}\n\nfunction getLabel(user: User): string {\n  return user.name + \" - \" + user.role;\n}\n\nfunction isUser(value: unknown): value is User {\n  if (typeof value !== \"object\" || value === null) return false;\n  return \"id\" in value &amp;&amp; \"name\" in value &amp;&amp; \"role\" in value;\n}</div><div class=\"explain\"><code>interface</code> удобен для контракта объекта, <code>type</code> - для объединений и составных типов. <code>unknown</code> требует проверку перед доступом. <code>any</code> отключает TypeScript именно там, где данные ненадёжны.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-strict-2026-1\" onchange=\"updateProgress(this)\"><span>Типизирую аргументы и return</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-strict-2026-2\" onchange=\"updateProgress(this)\"><span>Использую unknown вместо any</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-strict-2026-3\" onchange=\"updateProgress(this)\"><span>Описываю массивы объектов</span></label></div></div>"},{"id":"block-ts-basics","title":"Основы TypeScript — типы переменных основа 🔗","html":"<div class=\"block\" id=\"block-ts-basics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-basics')\">Основы TypeScript — типы переменных <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">TypeScript добавляет к JavaScript систему типов. После двоеточия пишем тип: <code>let name: string = \"Иван\"</code>.</div>\n      <div class=\"code\"><span class=\"cm\">// Базовые типы</span>\n<span class=\"kw\">let</span> name: <span class=\"str\">string</span> = <span class=\"str\">\"Иван\"</span>;\n<span class=\"kw\">let</span> age: <span class=\"num\">number</span> = 25;\n<span class=\"kw\">let</span> isActive: <span class=\"str\">boolean</span> = <span class=\"kw\">true</span>;\n<span class=\"kw\">let</span> tags: <span class=\"str\">string</span>[] = [<span class=\"str\">\"HTML\"</span>, <span class=\"str\">\"CSS\"</span>];\n\n<span class=\"cm\">// Union type — несколько допустимых типов</span>\n<span class=\"kw\">let</span> id: <span class=\"str\">string</span> | <span class=\"str\">number</span> = 42;\nid = <span class=\"str\">\"abc\"</span>; <span class=\"cm\">// тоже ок!</span>\n\n<span class=\"cm\">// Функция с типами параметров и возврата</span>\n<span class=\"kw\">function</span> <span class=\"fn\">greet</span>(name: <span class=\"str\">string</span>): <span class=\"str\">string</span> {\n  <span class=\"kw\">return</span> <span class=\"str\">`Привет, ${name}!`</span>;\n}\n\n<span class=\"cm\">// any — отключает проверку типов (избегай!)</span>\n<span class=\"kw\">let</span> data: <span class=\"str\">any</span> = <span class=\"str\">\"что угодно\"</span>;</div>\n      <div class=\"explain\">\n        <strong>Зачем типы?</strong> TS сообщит об ошибке ещё при написании кода, до запуска в браузере.<br>\n        <strong>string[]</strong> — массив строк. Можно также писать <code>Array&lt;string&gt;</code>.<br>\n        <strong>Union (|)</strong> — переменная может быть одним из нескольких типов.<br>\n        <strong>Избегай any!</strong> Он отключает всю пользу TypeScript.\n      </div>\n      <!-- МИНИ-ТЕСТ -->\n      <div class=\"quiz-block\" id=\"quiz-ts-basics\">\n        <div class=\"quiz-title\">🧪 Мини-тест — проверь знания</div>\n        <div class=\"quiz-question\">1. Как правильно указать тип массива строк в TypeScript?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-1\" value=\"a\"> <span>Array[string]</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-1\" value=\"b\"> <span>string[]</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-1\" value=\"c\"> <span>strings</span></label>\n        </div>\n        <div class=\"quiz-question\">2. Что такое Union type?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-2\" value=\"a\"> <span>Тип, который отключает проверку</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-2\" value=\"b\"> <span>Переменная, которая может быть одним из нескольких типов</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-2\" value=\"c\"> <span>Специальный тип для функций</span></label>\n        </div>\n        <!-- ПРАКТИКА -->\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Практика</div>\n          <div class=\"practice-task\">Напиши функцию <code>add(a, b)</code> с типами параметров <code>number</code> и типом возврата <code>number</code>.</div>\n          <textarea class=\"practice-input\" id=\"practice-ts-basics\" placeholder=\"function add(a: number, b: number): number { ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('ts-basics')\">✓ Проверить</button>\n        <div class=\"quiz-result\" id=\"result-ts-basics\"></div>\n      </div>\n      <div class=\"items\" id=\"items-ts-basics\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb612\" onchange=\"updateProgress(this)\" disabled><span>🔒 Базовые типы: string, number, boolean, string[]</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb613\" onchange=\"updateProgress(this)\" disabled><span>🔒 Union type: string | number — несколько допустимых типов</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb614\" onchange=\"updateProgress(this)\" disabled><span>🔒 Типизированные функции: (name: string): string</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Пройди тест и практику, чтобы разблокировать чекбоксы</div>\n    </div>\n\n    "},{"id":"block-ts-interfaces","title":"Интерфейсы и type alias важно 🔗","html":"<div class=\"block\" id=\"block-ts-interfaces\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-interfaces')\">Интерфейсы и type alias <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Interface — описывает форму объекта</span>\n<span class=\"kw\">interface</span> <span class=\"fn\">User</span> {\n  name: <span class=\"str\">string</span>;\n  age: <span class=\"num\">number</span>;\n  email?: <span class=\"str\">string</span>; <span class=\"cm\">// ? — необязательное поле</span>\n}\n\n<span class=\"kw\">const</span> user: <span class=\"fn\">User</span> = { name: <span class=\"str\">\"Иван\"</span>, age: 25 };\n\n<span class=\"cm\">// Type alias — похож на interface, но гибче</span>\n<span class=\"kw\">type</span> Status = <span class=\"str\">\"active\"</span> | <span class=\"str\">\"inactive\"</span> | <span class=\"str\">\"banned\"</span>;\n<span class=\"kw\">let</span> currentStatus: Status = <span class=\"str\">\"active\"</span>;\n\n<span class=\"cm\">// Расширение интерфейса</span>\n<span class=\"kw\">interface</span> <span class=\"fn\">Admin</span> <span class=\"kw\">extends</span> <span class=\"fn\">User</span> {\n  role: <span class=\"str\">string</span>;\n  permissions: <span class=\"str\">string</span>[];\n}</div>\n      <div class=\"explain\">\n        <strong>interface</strong> — контракт для объекта. Поля с <code>?</code> — необязательные.<br>\n        <strong>type</strong> — более гибкий. Лучше для Union, примитивов и функциональных типов.<br>\n        <strong>extends</strong> — наследует поля родительского интерфейса.\n      </div>\n      <div class=\"quiz-block\" id=\"quiz-ts-interfaces\">\n        <div class=\"quiz-title\">🧪 Мини-тест</div>\n        <div class=\"quiz-question\">1. Что означает <code>?</code> после имени поля в интерфейсе?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-1\" value=\"a\"> <span>Поле обязательное</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-1\" value=\"b\"> <span>Поле необязательное</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-1\" value=\"c\"> <span>Тип — boolean</span></label>\n        </div>\n        <div class=\"quiz-question\">2. Какой синтаксис используется для расширения интерфейса?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-2\" value=\"a\"> <span>interface Admin implements User</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-2\" value=\"b\"> <span>interface Admin extends User</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-2\" value=\"c\"> <span>interface Admin &lt;- User</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Практика</div>\n          <div class=\"practice-task\">Напиши интерфейс <code>Product</code> с полями: <code>id</code> (number), <code>name</code> (string), <code>price</code> (number), и необязательным <code>discount</code> (number).</div>\n          <textarea class=\"practice-input\" id=\"practice-ts-interfaces\" placeholder=\"interface Product { ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('ts-interfaces')\">✓ Проверить</button>\n        <div class=\"quiz-result\" id=\"result-ts-interfaces\"></div>\n      </div>\n      <div class=\"items\" id=\"items-ts-interfaces\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb615\" onchange=\"updateProgress(this)\" disabled><span>🔒 interface — описывает форму объекта</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb616\" onchange=\"updateProgress(this)\" disabled><span>🔒 ? — необязательное поле</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb617\" onchange=\"updateProgress(this)\" disabled><span>🔒 extends — наследование интерфейсов</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Пройди тест и практику, чтобы разблокировать чекбоксы</div>\n    </div>\n\n    "},{"id":"block-ts-generics","title":"Дженерики (Generics) важно 🔗","html":"<div class=\"block\" id=\"block-ts-generics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-generics')\">Дженерики (Generics) <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Дженерики — это «переменные для типов». Пишешь функцию один раз, она работает с любым типом без потери типизации.</div>\n      <div class=\"code\"><span class=\"cm\">// Без дженерика — нужно писать для каждого типа</span>\n<span class=\"kw\">function</span> <span class=\"fn\">firstNumber</span>(arr: <span class=\"str\">number</span>[]): <span class=\"str\">number</span> { <span class=\"kw\">return</span> arr[<span class=\"num\">0</span>]; }\n<span class=\"kw\">function</span> <span class=\"fn\">firstString</span>(arr: <span class=\"str\">string</span>[]): <span class=\"str\">string</span> { <span class=\"kw\">return</span> arr[<span class=\"num\">0</span>]; }\n\n<span class=\"cm\">// С дженериком — одна функция для всего</span>\n<span class=\"kw\">function</span> <span class=\"fn\">first</span>&lt;T&gt;(arr: T[]): T {\n  <span class=\"kw\">return</span> arr[<span class=\"num\">0</span>];\n}\n<span class=\"fn\">first</span>([<span class=\"num\">1</span>, <span class=\"num\">2</span>, <span class=\"num\">3</span>]);       <span class=\"cm\">// T = number</span>\n<span class=\"fn\">first</span>([<span class=\"str\">\"a\"</span>, <span class=\"str\">\"b\"</span>]);     <span class=\"cm\">// T = string</span>\n\n<span class=\"cm\">// Дженерики в интерфейсах</span>\n<span class=\"kw\">interface</span> <span class=\"fn\">ApiResponse</span>&lt;T&gt; {\n  data: T;\n  status: <span class=\"str\">number</span>;\n  message: <span class=\"str\">string</span>;\n}\n<span class=\"kw\">const</span> res: <span class=\"fn\">ApiResponse</span>&lt;<span class=\"fn\">User</span>&gt; = { data: user, status: <span class=\"num\">200</span>, message: <span class=\"str\">\"OK\"</span> };</div>\n      <div class=\"explain\">\n        <strong>&lt;T&gt;</strong> — «переменная типа». Называй T, U, K, V — любое имя.<br>\n        <strong>T[]</strong> — массив элементов типа T. При вызове T автоматически выводится.<br>\n        <strong>ApiResponse&lt;User&gt;</strong> — конкретизация: data будет типа User.\n      </div>\n      <div class=\"quiz-block\" id=\"quiz-ts-generics\">\n        <div class=\"quiz-title\">🧪 Мини-тест</div>\n        <div class=\"quiz-question\">1. Для чего используются дженерики?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-1\" value=\"a\"> <span>Для отключения проверки типов</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-1\" value=\"b\"> <span>Для написания универсального кода, работающего с любым типом</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-1\" value=\"c\"> <span>Только для работы с массивами</span></label>\n        </div>\n        <div class=\"quiz-question\">2. Что такое &lt;T&gt; в function first&lt;T&gt;(arr: T[])?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-2\" value=\"a\"> <span>HTML-тег</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-2\" value=\"b\"> <span>Переменная типа — TS подставит конкретный тип при вызове</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-2\" value=\"c\"> <span>Условный тип</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Практика</div>\n          <div class=\"practice-task\">Напиши дженерик-функцию <code>identity&lt;T&gt;</code>, которая принимает аргумент типа T и возвращает его же.</div>\n          <textarea class=\"practice-input\" id=\"practice-ts-generics\" placeholder=\"function identity&lt;T&gt;(arg: T): T { ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('ts-generics')\">✓ Проверить</button>\n        <div class=\"quiz-result\" id=\"result-ts-generics\"></div>\n      </div>\n      <div class=\"items\" id=\"items-ts-generics\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb618\" onchange=\"updateProgress(this)\" disabled><span>🔒 &lt;T&gt; — переменная типа, выводится автоматически</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb619\" onchange=\"updateProgress(this)\" disabled><span>🔒 Дженерики в функциях: function fn&lt;T&gt;(arg: T): T</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb620\" onchange=\"updateProgress(this)\" disabled><span>🔒 Дженерики в интерфейсах: interface Resp&lt;T&gt; { data: T }</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Пройди тест и практику, чтобы разблокировать чекбоксы</div>\n    </div>\n\n    "},{"id":"block-ts-generics-react-2026","title":"Generics и типы React ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-ts-generics-react-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-ts-generics-react-2026')\">Generics и типы React <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Generic сохраняет связь между входным и выходным типом. Он нужен, когда операция общая, а результат должен остаться точным.</div><div class=\"code\">type ApiResult&lt;T&gt; = { data: T; error: string | null };\n\nfunction firstItem&lt;T&gt;(items: T[]): T | undefined {\n  return items[0];\n}\n\ntype ProjectCardProps = {\n  title: string;\n  completed: boolean;\n  onToggle: (completed: boolean) =&gt; void;\n};\n\nfunction ProjectCard({ title, completed, onToggle }: ProjectCardProps) {\n  return &lt;button onClick={() =&gt; onToggle(!completed)}&gt;{title}&lt;/button&gt;;\n}</div><div class=\"explain\"><code>T</code> заполняется вызывающим кодом, поэтому <code>ApiResult&lt;User[]&gt;</code> сохраняет data как User[]. Props точно описывают компонент. Для tsconfig бери готовый preset Vite/Next.js с <code>strict: true</code>; не учи десятки флагов без задачи.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-generics-react-2026-1\" onchange=\"updateProgress(this)\"><span>Понимаю связь входа и выхода generic</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-generics-react-2026-2\" onchange=\"updateProgress(this)\"><span>Типизирую React props без any</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-generics-react-2026-3\" onchange=\"updateProgress(this)\"><span>Использую strict preset</span></label></div></div>"},{"id":"block-ts-react","title":"TypeScript + React — типизация компонентов часто на практике 🔗","html":"<div class=\"block\" id=\"block-ts-react\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-react')\">TypeScript + React — типизация компонентов <span class=\"badge must\">часто на практике</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Коммерческий React-код почти всегда на TypeScript. Главный вопрос новичков: как типизировать props с функциями и children?</div>\n      <div class=\"code\"><span class=\"cm\">// Типизация props через interface</span>\n<span class=\"kw\">interface</span> ButtonProps {\n  label: <span class=\"str\">string</span>;\n  onClick: (e: React.MouseEvent&lt;HTMLButtonElement&gt;) =&gt; <span class=\"kw\">void</span>; <span class=\"cm\">// обработчик получает событие кнопки</span>\n  children?: React.ReactNode;     <span class=\"cm\">// что угодно: текст, JSX, массив</span>\n  style?: React.CSSProperties;    <span class=\"cm\">// инлайн-стили объектом</span>\n}\n\n<span class=\"kw\">const</span> Button: React.FC&lt;ButtonProps&gt; = ({ label, onClick, children, style }) =&gt; {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={onClick} <span class=\"attr\">style</span>={style}&gt;\n      {label} {children}\n    &lt;/<span class=\"tag\">button</span>&gt;\n  );\n};\n\n<span class=\"cm\">// Типизация событий</span>\n<span class=\"kw\">function</span> <span class=\"fn\">handleClick</span>(e: React.MouseEvent&lt;HTMLButtonElement&gt;) {\n  console.<span class=\"fn\">log</span>(e.currentTarget);\n}\n\n<span class=\"kw\">function</span> <span class=\"fn\">handleSubmit</span>(e: React.FormEvent&lt;HTMLFormElement&gt;) {\n  e.<span class=\"fn\">preventDefault</span>();\n}\n\n<span class=\"cm\">// useRef для DOM-элементов</span>\n<span class=\"kw\">const</span> inputRef = <span class=\"fn\">useRef</span>&lt;HTMLInputElement&gt;(<span class=\"kw\">null</span>);\n<span class=\"cm\">// теперь inputRef.current типизирован как HTMLInputElement | null</span>\n<span class=\"cm\">// TS не ругается на .current.focus() после проверки на null</span></div>\n      <div class=\"explain\">\n        <strong>React.FC&lt;Props&gt;</strong> — тип для функциональных компонентов (хотя многие сейчас просто типизируют пропсы напрямую без FC).<br>\n        <strong>React.ReactNode</strong> — самый широкий тип для children: строка, число, JSX, массив, null.<br>\n        <strong>React.MouseEvent&lt;HTMLButtonElement&gt;</strong> — типизированное событие, точно знает что currentTarget это кнопка.<br>\n        <strong>useRef&lt;HTMLInputElement&gt;(null)</strong> — стандартный шаблон для рефов на DOM-элементы.<br>\n        <strong>React 19:</strong> ref можно передавать в компонент как обычный prop; <code>forwardRef</code> всё ещё встречается в старом коде, но для новых компонентов часто уже не нужен.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb232\" onchange=\"updateProgress(this)\"><span>Типизация props с функциями и children (React.ReactNode)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb233\" onchange=\"updateProgress(this)\"><span>React.MouseEvent, React.FormEvent — типизация событий</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb234\" onchange=\"updateProgress(this)\"><span>useRef&lt;HTMLInputElement&gt;(null) — типизация рефов на DOM</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-utility","title":"Utility Types важно 🔗","html":"<div class=\"block\" id=\"block-ts-utility\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-utility')\">Utility Types <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Utility Types — встроенные помощники TS для трансформации типов. Используются в каждом реальном проекте.</div>\n      <div class=\"code\"><span class=\"kw\">interface</span> <span class=\"fn\">User</span> { id: <span class=\"str\">number</span>; name: <span class=\"str\">string</span>; email: <span class=\"str\">string</span>; age: <span class=\"str\">number</span>; }\n\n<span class=\"cm\">// Partial — все поля необязательные</span>\n<span class=\"kw\">type</span> UserDraft = Partial&lt;<span class=\"fn\">User</span>&gt;;\n<span class=\"cm\">// { id?: number; name?: string; email?: string; age?: number }</span>\n\n<span class=\"cm\">// Required — все поля обязательные</span>\n<span class=\"kw\">type</span> StrictUser = Required&lt;<span class=\"fn\">User</span>&gt;;\n\n<span class=\"cm\">// Pick — берём только нужные поля</span>\n<span class=\"kw\">type</span> UserPreview = Pick&lt;<span class=\"fn\">User</span>, <span class=\"str\">\"id\"</span> | <span class=\"str\">\"name\"</span>&gt;;\n\n<span class=\"cm\">// Omit — исключаем поля</span>\n<span class=\"kw\">type</span> UserWithoutId = Omit&lt;<span class=\"fn\">User</span>, <span class=\"str\">\"id\"</span>&gt;;\n\n<span class=\"cm\">// Readonly — запрет изменений</span>\n<span class=\"kw\">type</span> FrozenUser = Readonly&lt;<span class=\"fn\">User</span>&gt;;</div>\n      <div class=\"explain\">\n        <strong>Partial&lt;T&gt;</strong> — все поля с ?. Удобно для форм редактирования.<br>\n        <strong>Pick&lt;T, K&gt;</strong> — выбирает только перечисленные поля.<br>\n        <strong>Omit&lt;T, K&gt;</strong> — убирает перечисленные поля.<br>\n        <strong>Readonly&lt;T&gt;</strong> — объект нельзя изменять после создания.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb215\" onchange=\"updateProgress(this)\"><span>Partial&lt;T&gt; — все поля необязательные</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb216\" onchange=\"updateProgress(this)\"><span>Pick&lt;T, K&gt; и Omit&lt;T, K&gt; — выбор/исключение полей</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb217\" onchange=\"updateProgress(this)\"><span>Readonly&lt;T&gt; — запрет изменений объекта</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-enums","title":"Enum и литеральные типы знать 🔗","html":"<div class=\"block\" id=\"block-ts-enums\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-enums')\">Enum и литеральные типы <span class=\"badge\">знать</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Enum — именованные константы</span>\n<span class=\"kw\">enum</span> <span class=\"fn\">Direction</span> { Up = <span class=\"str\">\"UP\"</span>, Down = <span class=\"str\">\"DOWN\"</span>, Left = <span class=\"str\">\"LEFT\"</span>, Right = <span class=\"str\">\"RIGHT\"</span> }\n<span class=\"kw\">const</span> move = <span class=\"fn\">Direction</span>.Up; <span class=\"cm\">// \"UP\"</span>\n\n<span class=\"cm\">// Литеральные типы (предпочтительнее enum в современном TS)</span>\n<span class=\"kw\">type</span> Theme = <span class=\"str\">\"light\"</span> | <span class=\"str\">\"dark\"</span> | <span class=\"str\">\"auto\"</span>;\n<span class=\"kw\">function</span> <span class=\"fn\">setTheme</span>(theme: Theme) { <span class=\"cm\">/* ... */</span> }\n<span class=\"fn\">setTheme</span>(<span class=\"str\">\"light\"</span>);  <span class=\"cm\">// ✓</span>\n<span class=\"fn\">setTheme</span>(<span class=\"str\">\"blue\"</span>);  <span class=\"cm\">// ✗ Ошибка TS!</span>\n\n<span class=\"cm\">// const assertion — объект как литерал</span>\n<span class=\"kw\">const</span> config = { env: <span class=\"str\">\"prod\"</span>, port: <span class=\"num\">3000</span> } <span class=\"kw\">as const</span>;</div>\n      <div class=\"explain\">\n        <strong>enum</strong> — группирует связанные константы. Но в современном TS чаще используют Union literals.<br>\n        <strong>Литеральный тип</strong> — конкретное значение как тип. TS проверит что передано именно оно.<br>\n        <strong>as const</strong> — делает все значения readonly-литералами.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb218\" onchange=\"updateProgress(this)\"><span>enum — именованные константы группой</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb219\" onchange=\"updateProgress(this)\"><span>Литеральные типы: \"light\" | \"dark\" | \"auto\"</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb220\" onchange=\"updateProgress(this)\"><span>as const — превращает значения в readonly-литералы</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-narrowing","title":"Type Narrowing и Type Guards важно 🔗","html":"<div class=\"block\" id=\"block-ts-narrowing\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-narrowing')\">Type Narrowing и Type Guards <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// typeof narrowing</span>\n<span class=\"kw\">function</span> <span class=\"fn\">printId</span>(id: <span class=\"str\">string</span> | <span class=\"str\">number</span>) {\n  <span class=\"kw\">if</span> (<span class=\"kw\">typeof</span> id === <span class=\"str\">\"string\"</span>) {\n    console.log(id.<span class=\"fn\">toUpperCase</span>()); <span class=\"cm\">// TS знает: id — строка</span>\n  } <span class=\"kw\">else</span> {\n    console.log(id.<span class=\"fn\">toFixed</span>(2));   <span class=\"cm\">// TS знает: id — число</span>\n  }\n}\n\n<span class=\"cm\">// instanceof narrowing</span>\n<span class=\"kw\">function</span> <span class=\"fn\">logError</span>(err: unknown) {\n  <span class=\"kw\">if</span> (err <span class=\"kw\">instanceof</span> Error) {\n    console.log(err.message); <span class=\"cm\">// теперь знаем что это Error</span>\n  }\n}\n\n<span class=\"cm\">// Custom type guard</span>\n<span class=\"kw\">function</span> <span class=\"fn\">isUser</span>(obj: <span class=\"str\">any</span>): obj <span class=\"kw\">is</span> <span class=\"fn\">User</span> {\n  <span class=\"kw\">return</span> obj &amp;&amp; <span class=\"kw\">typeof</span> obj.name === <span class=\"str\">\"string\"</span>;\n}</div>\n      <div class=\"explain\">\n        <strong>Narrowing</strong> — TS «сужает» тип после проверки. Внутри if(typeof x === \"string\") x точно строка.<br>\n        <strong>instanceof</strong> — сужение для классов и объектов.<br>\n        <strong>is</strong> — кастомный type guard, ты сам говоришь TS что за тип.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb221\" onchange=\"updateProgress(this)\"><span>typeof narrowing — сужение через проверку typeof</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb222\" onchange=\"updateProgress(this)\"><span>instanceof narrowing — для классов и объектов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb223\" onchange=\"updateProgress(this)\"><span>Custom type guard: function isX(v): v is Type</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-async","title":"Async/await с типами и работа с API важно 🔗","html":"<div class=\"block\" id=\"block-ts-async\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-async')\">Async/await с типами и работа с API <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Promise с типом возврата</span>\n<span class=\"kw\">async function</span> <span class=\"fn\">fetchUser</span>(id: <span class=\"str\">number</span>): Promise&lt;<span class=\"fn\">User</span>&gt; {\n  <span class=\"kw\">const</span> res = <span class=\"kw\">await</span> <span class=\"fn\">fetch</span>(<span class=\"str\">`/api/users/${id}`</span>);\n  <span class=\"kw\">if</span> (!res.ok) <span class=\"kw\">throw new</span> Error(<span class=\"str\">\"Not found\"</span>);\n  <span class=\"kw\">const</span> data: <span class=\"fn\">User</span> = <span class=\"kw\">await</span> res.<span class=\"fn\">json</span>();\n  <span class=\"kw\">return</span> data;\n}\n\n<span class=\"cm\">// Обработка ошибок с unknown</span>\n<span class=\"kw\">try</span> {\n  <span class=\"kw\">const</span> user = <span class=\"kw\">await</span> <span class=\"fn\">fetchUser</span>(<span class=\"num\">1</span>);\n  console.log(user.name);\n} <span class=\"kw\">catch</span> (err: unknown) {\n  <span class=\"kw\">if</span> (err <span class=\"kw\">instanceof</span> Error) console.error(err.message);\n}\n\n<span class=\"cm\">// Типизированный fetch-хелпер</span>\n<span class=\"kw\">async function</span> <span class=\"fn\">api</span>&lt;T&gt;(url: <span class=\"str\">string</span>): Promise&lt;T&gt; {\n  <span class=\"kw\">return</span> (<span class=\"kw\">await</span> <span class=\"fn\">fetch</span>(url)).<span class=\"fn\">json</span>();\n}</div>\n      <div class=\"explain\">\n        <strong>Promise&lt;User&gt;</strong> — говорит TS что async-функция вернёт User.<br>\n        <strong>catch (err: unknown)</strong> — правильный тип для пойманной ошибки. Никогда не any!<br>\n        <strong>api&lt;T&gt;</strong> — дженерик fetch: <code>api&lt;User&gt;('/api/me')</code> вернёт типизированный User.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb224\" onchange=\"updateProgress(this)\"><span>Promise&lt;T&gt; — тип возврата async-функции</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb225\" onchange=\"updateProgress(this)\"><span>catch (err: unknown) — не any для ошибок</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb226\" onchange=\"updateProgress(this)\"><span>Типизированный fetch-хелпер с дженериком</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-discriminated","title":"Discriminated Unions и advanced типы важно 🔗","html":"<div class=\"block\" id=\"block-ts-discriminated\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-discriminated')\">Discriminated Unions и advanced типы <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Discriminated Union — union с общим полем-дискриминатором</span>\n<span class=\"kw\">type</span> Action =\n  | { type: <span class=\"str\">'INCREMENT'</span>; amount: <span class=\"str\">number</span> }\n  | { type: <span class=\"str\">'SET_NAME'</span>; name: <span class=\"str\">string</span> }\n  | { type: <span class=\"str\">'RESET'</span> };\n\n<span class=\"kw\">function</span> <span class=\"fn\">reducer</span>(action: Action) {\n  <span class=\"kw\">switch</span> (action.type) {\n    <span class=\"kw\">case</span> <span class=\"str\">'INCREMENT'</span>: <span class=\"kw\">return</span> action.amount; <span class=\"cm\">// TS знает: есть amount</span>\n    <span class=\"kw\">case</span> <span class=\"str\">'SET_NAME'</span>:  <span class=\"kw\">return</span> action.name;   <span class=\"cm\">// TS знает: есть name</span>\n    <span class=\"kw\">case</span> <span class=\"str\">'RESET'</span>:     <span class=\"kw\">return</span> <span class=\"num\">0</span>;\n  }\n}\n\n<span class=\"cm\">// keyof и typeof — работа с типами объектов</span>\n<span class=\"kw\">const</span> config = { host: <span class=\"str\">'localhost'</span>, port: <span class=\"num\">3000</span> };\n<span class=\"kw\">type</span> ConfigKey = <span class=\"kw\">keyof typeof</span> config; <span class=\"cm\">// 'host' | 'port'</span>\n\n<span class=\"cm\">// ReturnType — тип возврата функции</span>\n<span class=\"kw\">function</span> <span class=\"fn\">getUser</span>() { <span class=\"kw\">return</span> { id: <span class=\"num\">1</span>, name: <span class=\"str\">'Ivan'</span> }; }\n<span class=\"kw\">type</span> User = <span class=\"kw\">ReturnType</span>&lt;<span class=\"kw\">typeof</span> <span class=\"fn\">getUser</span>&gt;; <span class=\"cm\">// { id: number, name: string }</span></div>\n      <div class=\"explain\">\n        <strong>Discriminated Union</strong> — TS автоматически сужает тип внутри switch/if по полю-дискриминатору.<br>\n        <strong>keyof typeof obj</strong> — часто используется для безопасного доступа к ключам объекта.<br>\n        <strong>ReturnType</strong> — не дублируй тип вручную, выведи его из функции.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb229\" onchange=\"updateProgress(this)\"><span>Discriminated Union — union с полем-дискриминатором</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb230\" onchange=\"updateProgress(this)\"><span>keyof, typeof — работа с типами существующих объектов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb231\" onchange=\"updateProgress(this)\"><span>ReturnType, Parameters — utility типы для функций</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-void-never","title":"void, never, unknown — отличия топ собесов 🔗","html":"<div class=\"block\" id=\"block-ts-void-never\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-void-never')\">void, never, unknown — отличия <span class=\"badge good\">топ собесов</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// void — функция ничего не возвращает</span>\n<span class=\"kw\">function</span> <span class=\"fn\">logMessage</span>(msg: <span class=\"str\">string</span>): <span class=\"kw\">void</span> {\n  console.<span class=\"fn\">log</span>(msg);\n  <span class=\"cm\">// нет return — или return; без значения</span>\n}\n\n<span class=\"cm\">// never — функция никогда не завершается нормально</span>\n<span class=\"kw\">function</span> <span class=\"fn\">throwError</span>(msg: <span class=\"str\">string</span>): <span class=\"kw\">never</span> {\n  <span class=\"kw\">throw new</span> <span class=\"fn\">Error</span>(msg); <span class=\"cm\">// всегда выбрасывает ошибку</span>\n}\n\n<span class=\"cm\">// never — для исчерпывающей проверки switch</span>\n<span class=\"kw\">type</span> Shape = { kind: <span class=\"str\">'circle'</span> } | { kind: <span class=\"str\">'square'</span> };\n\n<span class=\"kw\">function</span> <span class=\"fn\">area</span>(s: Shape) {\n  <span class=\"kw\">switch</span> (s.kind) {\n    <span class=\"kw\">case</span> <span class=\"str\">'circle'</span>: <span class=\"kw\">return</span> <span class=\"num\">1</span>;\n    <span class=\"kw\">case</span> <span class=\"str\">'square'</span>: <span class=\"kw\">return</span> <span class=\"num\">2</span>;\n    <span class=\"kw\">default</span>:\n      <span class=\"kw\">const</span> _exhaustive: <span class=\"kw\">never</span> = s; <span class=\"cm\">// ошибка TS если забыл case!</span>\n      <span class=\"kw\">return</span> _exhaustive;\n  }\n}\n\n<span class=\"cm\">// unknown vs any — оба \"любой тип\", но unknown безопаснее</span>\n<span class=\"kw\">let</span> a: <span class=\"kw\">any</span> = <span class=\"num\">5</span>;\na.<span class=\"fn\">toUpperCase</span>(); <span class=\"cm\">// ❌ компилируется, упадёт в runtime</span>\n\n<span class=\"kw\">let</span> u: unknown = <span class=\"num\">5</span>;\nu.<span class=\"fn\">toUpperCase</span>(); <span class=\"cm\">// ✅ TS требует проверку типа первой</span>\n<span class=\"kw\">if</span> (<span class=\"kw\">typeof</span> u === <span class=\"str\">'string'</span>) u.<span class=\"fn\">toUpperCase</span>(); <span class=\"cm\">// ✅ теперь можно</span></div>\n      <div class=\"explain\">\n        <strong>void</strong> — функция не возвращает значение (или возвращаемое значение игнорируется).<br>\n        <strong>never</strong> — функция никогда не завершается нормально (бросает ошибку, бесконечный цикл) или ветка кода недостижима.<br>\n        <strong>unknown vs any</strong> — <code>any</code> отключает проверки типов полностью, <code>unknown</code> заставляет сначала проверить тип перед использованием. Используй unknown вместо any.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb235\" onchange=\"updateProgress(this)\"><span>void — функция ничего не возвращает</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb236\" onchange=\"updateProgress(this)\"><span>never — недостижимый код или функция всегда бросает ошибку</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb237\" onchange=\"updateProgress(this)\"><span>unknown безопаснее any — требует проверку типа перед использованием</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-conditional-mapped","title":"Conditional Types и Mapped Types уровень middle 🔗","html":"<div class=\"block\" id=\"block-ts-conditional-mapped\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-conditional-mapped')\">Conditional Types и Mapped Types <span class=\"badge good\">уровень middle</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Без этих тем сложно читать исходники крупных библиотек (React, Redux, Zod), но для собственного кода они нужны не так часто — изучай когда почувствуешь уверенность в основах.</div>\n      <div class=\"code\"><span class=\"cm\">// Conditional Types — \"тип-тернарник\"</span>\n<span class=\"kw\">type</span> IsString&lt;T&gt; = T <span class=\"kw\">extends</span> <span class=\"str\">string</span> ? <span class=\"str\">true</span> : <span class=\"str\">false</span>;\n\n<span class=\"kw\">type</span> A = IsString&lt;<span class=\"str\">string</span>&gt;; <span class=\"cm\">// true</span>\n<span class=\"kw\">type</span> B = IsString&lt;<span class=\"str\">number</span>&gt;; <span class=\"cm\">// false</span>\n\n<span class=\"cm\">// Реальный пример — извлечь тип элемента массива</span>\n<span class=\"kw\">type</span> ElementType&lt;T&gt; = T <span class=\"kw\">extends</span> (infer U)[] ? U : T;\n<span class=\"kw\">type</span> Item = ElementType&lt;<span class=\"str\">string</span>[]&gt;; <span class=\"cm\">// string</span>\n\n<span class=\"cm\">// Mapped Types — создание нового типа на основе существующего</span>\n<span class=\"kw\">interface</span> User { name: <span class=\"str\">string</span>; age: <span class=\"str\">number</span>; }\n\n<span class=\"kw\">type</span> ReadonlyUser = {\n  [K <span class=\"kw\">in keyof</span> User]: readonly User[K];\n}; <span class=\"cm\">// все поля становятся readonly</span>\n\n<span class=\"kw\">type</span> OptionalUser = {\n  [K <span class=\"kw\">in keyof</span> User]?: User[K];\n}; <span class=\"cm\">// все поля становятся опциональными — так устроен Partial&lt;T&gt;!</span></div>\n      <div class=\"explain\">\n        <strong>T extends U ? X : Y</strong> — условный тип, работает как тернарный оператор, но на уровне типов.<br>\n        <strong>infer</strong> — \"извлекает\" тип из структуры, часто используется внутри conditional types.<br>\n        <strong>Mapped Types</strong> — проходят по всем ключам существующего типа и трансформируют их. Так устроены встроенные <code>Partial&lt;T&gt;</code>, <code>Readonly&lt;T&gt;</code>, <code>Pick&lt;T&gt;</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb238\" onchange=\"updateProgress(this)\"><span>T extends U ? X : Y — синтаксис условных типов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb239\" onchange=\"updateProgress(this)\"><span>Mapped Types — [K in keyof T] для трансформации типов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb240\" onchange=\"updateProgress(this)\"><span>Понимаю что Partial/Readonly/Pick — это просто Mapped Types</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-satisfies","title":"Type Assertions: as и satisfies современный TS 🔗","html":"<div class=\"block\" id=\"block-ts-satisfies\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-satisfies')\">Type Assertions: as и satisfies <span class=\"badge good\">современный TS</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// as — классическое приведение типа (говоришь TS \"поверь мне\")</span>\n<span class=\"kw\">const</span> input = document.<span class=\"fn\">getElementById</span>(<span class=\"str\">'email'</span>) <span class=\"kw\">as</span> HTMLInputElement;\ninput.value; <span class=\"cm\">// теперь доступно — но TS просто \"поверил\" нам</span>\n\n<span class=\"cm\">// Проблема as — можно случайно указать неправильный тип</span>\n<span class=\"kw\">const</span> wrong = <span class=\"str\">'hello'</span> <span class=\"kw\">as unknown as</span> <span class=\"str\">number</span>; <span class=\"cm\">// TS промолчит, но это баг</span>\n\n<span class=\"cm\">// satisfies (TS 4.9+) — проверяет совместимость БЕЗ изменения типа</span>\n<span class=\"kw\">type</span> Colors = Record&lt;<span class=\"str\">string</span>, [<span class=\"str\">number</span>, <span class=\"str\">number</span>, <span class=\"str\">number</span>]&gt;;\n\n<span class=\"kw\">const</span> palette = {\n  red:   [<span class=\"num\">255</span>, <span class=\"num\">0</span>, <span class=\"num\">0</span>],\n  green: [<span class=\"num\">0</span>, <span class=\"num\">255</span>, <span class=\"num\">0</span>]\n} <span class=\"kw\">satisfies</span> Colors;\n\n<span class=\"cm\">// ✅ TS проверяет что структура соответствует Colors,</span>\n<span class=\"cm\">// но palette.red остаётся точным типом [number,number,number],</span>\n<span class=\"cm\">// а не общим Colors — автодополнение работает точнее!</span>\n\npalette.red[<span class=\"num\">0</span>]; <span class=\"cm\">// TS знает что это именно red, не любой ключ</span></div>\n      <div class=\"explain\">\n        <strong>as MyType</strong> — принудительно говорит компилятору \"это именно такой тип\", без реальной проверки. Используй осторожно, легко создать баг.<br>\n        <strong>satisfies</strong> — проверяет что значение СООТВЕТСТВУЕТ типу, но сохраняет точный (более узкий) выведенный тип переменной. Лучшее из двух миров: безопасность + точная автодополнение.<br>\n        <strong>Когда что:</strong> satisfies предпочтительнее в современном TS (4.9+), as — когда работаешь со старым кодом или DOM API.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb241\" onchange=\"updateProgress(this)\"><span>as MyType — классическое приведение типа</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb242\" onchange=\"updateProgress(this)\"><span>satisfies — проверка типа с сохранением точного выведенного типа</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb243\" onchange=\"updateProgress(this)\"><span>Понимаю чем satisfies лучше as для объектов-констант</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-react","lessons":[{"id":"block-react-components","title":"Компоненты и JSX основа 🔗","html":"<div class=\"block\" id=\"block-react-components\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-components')\">Компоненты и JSX <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Компонент — это функция, которая возвращает JSX (HTML-подобный синтаксис). Каждый компонент — отдельная переиспользуемая деталь интерфейса.</div>\n      <div class=\"code\"><span class=\"cm\">// Функциональный компонент</span>\n<span class=\"kw\">function</span> <span class=\"fn\">Button</span>({ text, onClick }) {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={onClick} <span class=\"attr\">className</span>=<span class=\"str\">\"btn\"</span>&gt;\n      {text}\n    &lt;/<span class=\"tag\">button</span>&gt;\n  );\n}\n\n<span class=\"cm\">// Использование компонента</span>\n<span class=\"kw\">function</span> <span class=\"fn\">App</span>() {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">div</span>&gt;\n      &lt;<span class=\"fn\">Button</span> <span class=\"attr\">text</span>=<span class=\"str\">\"Нажми меня\"</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">alert</span>(<span class=\"str\">\"Клик!\"</span>)} /&gt;\n      &lt;<span class=\"fn\">Button</span> <span class=\"attr\">text</span>=<span class=\"str\">\"Ещё кнопка\"</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">console</span>.<span class=\"fn\">log</span>(<span class=\"str\">\"ok\"</span>)} /&gt;\n    &lt;/<span class=\"tag\">div</span>&gt;\n  );\n}</div>\n      <div class=\"explain\">\n        <strong>JSX</strong> — HTML внутри JS. Браузер его не понимает, Babel/Vite компилирует в JS.<br>\n        <strong>Props</strong> — параметры компонента. Как атрибуты HTML, только через {}.<br>\n        <strong>className вместо class</strong> — потому что class — зарезервированное слово JS.<br>\n        <strong>{}</strong> — JS-выражение внутри JSX. Можно переменные, функции, тернарные выражения.\n      </div>\n      <div class=\"quiz-block\" id=\"quiz-react-components\">\n        <div class=\"quiz-title\">🧪 Мини-тест</div>\n        <div class=\"quiz-question\">1. Как в JSX нужно писать атрибут class у HTML-элемента?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-1\" value=\"a\"> <span>class=\"btn\"</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-1\" value=\"b\"> <span>className=\"btn\"</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-1\" value=\"c\"> <span>cssClass=\"btn\"</span></label>\n        </div>\n        <div class=\"quiz-question\">2. Что такое props в React?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-2\" value=\"a\"> <span>Внутреннее состояние компонента</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-2\" value=\"b\"> <span>Параметры, которые передаются в компонент</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-2\" value=\"c\"> <span>Стили компонента</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Практика</div>\n          <div class=\"practice-task\">Напиши компонент <code>Card</code>, который принимает <code>title</code> и <code>description</code> как props и возвращает JSX с &lt;h2&gt; и &lt;p&gt;.</div>\n          <textarea class=\"practice-input\" id=\"practice-react-components\" placeholder=\"function Card({ title, description }) { return (...) }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('react-components')\">✓ Проверить</button>\n        <div class=\"quiz-result\" id=\"result-react-components\"></div>\n      </div>\n      <div class=\"items\" id=\"items-react-components\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb621\" onchange=\"updateProgress(this)\" disabled><span>🔒 Компонент — функция, возвращающая JSX</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb622\" onchange=\"updateProgress(this)\" disabled><span>🔒 Props — параметры компонента</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb623\" onchange=\"updateProgress(this)\" disabled><span>🔒 className вместо class в JSX</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Пройди тест и практику, чтобы разблокировать чекбоксы</div>\n    </div>\n\n    "},{"id":"block-react-hooks","title":"Хуки: useState и useEffect основа 🔗","html":"<div class=\"block\" id=\"block-react-hooks\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-hooks')\">Хуки: useState и useEffect <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Хуки — специальные функции React, начинаются с use. useState — для хранения данных, useEffect — для побочных эффектов.</div>\n      <div class=\"code\"><span class=\"kw\">import</span> { useState, useEffect } <span class=\"kw\">from</span> <span class=\"str\">'react'</span>;\n\n<span class=\"kw\">function</span> <span class=\"fn\">Counter</span>() {\n  <span class=\"cm\">// count — текущее значение, setCount — функция изменения</span>\n  <span class=\"kw\">const</span> [count, setCount] = <span class=\"fn\">useState</span>(<span class=\"num\">0</span>);\n\n  <span class=\"cm\">// useEffect: запустить когда count изменится</span>\n  <span class=\"fn\">useEffect</span>(() =&gt; {\n    document.title = <span class=\"str\">`Счётчик: ${count}`</span>;\n  }, [count]); <span class=\"cm\">// [count] — зависимость</span>\n\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">div</span>&gt;\n      &lt;<span class=\"tag\">p</span>&gt;Счётчик: {count}&lt;/<span class=\"tag\">p</span>&gt;\n      &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">setCount</span>(count + <span class=\"num\">1</span>)}&gt;+1&lt;/<span class=\"tag\">button</span>&gt;\n      &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">setCount</span>(<span class=\"num\">0</span>)}&gt;Сброс&lt;/<span class=\"tag\">button</span>&gt;\n    &lt;/<span class=\"tag\">div</span>&gt;\n  );\n}</div>\n      <div class=\"explain\">\n        <strong>useState(0)</strong> — начальное значение 0. Возвращает [значение, функцияИзменения].<br>\n        <strong>setCount</strong> — вызов перерисовывает компонент с новым значением.<br>\n        <strong>useEffect(fn, [deps])</strong> — fn вызывается после рендера при изменении deps.<br>\n        <strong>[] (пустой массив)</strong> — useEffect запустится один раз при монтировании.\n      </div>\n      <div class=\"quiz-block\" id=\"quiz-react-hooks\">\n        <div class=\"quiz-title\">🧪 Мини-тест</div>\n        <div class=\"quiz-question\">1. Что возвращает useState(0)?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-1\" value=\"a\"> <span>Только текущее значение</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-1\" value=\"b\"> <span>Массив: [текущее значение, функция изменения]</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-1\" value=\"c\"> <span>Объект с полем value</span></label>\n        </div>\n        <div class=\"quiz-question\">2. Что произойдёт если передать [] в useEffect?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-2\" value=\"a\"> <span>useEffect не запустится вообще</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-2\" value=\"b\"> <span>useEffect запустится один раз при монтировании компонента</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-2\" value=\"c\"> <span>useEffect будет запускаться при каждом рендере</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Практика</div>\n          <div class=\"practice-task\">Напиши компонент с состоянием <code>name</code> (строка), полем ввода и параграфом, который выводит <code>Привет, {name}!</code>.</div>\n          <textarea class=\"practice-input\" id=\"practice-react-hooks\" placeholder=\"function Greeter() { const [name, setName] = useState(''); ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('react-hooks')\">✓ Проверить</button>\n        <div class=\"quiz-result\" id=\"result-react-hooks\"></div>\n      </div>\n      <div class=\"items\" id=\"items-react-hooks\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb624\" onchange=\"updateProgress(this)\" disabled><span>🔒 useState — хранение состояния, setX вызывает рендер</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb625\" onchange=\"updateProgress(this)\" disabled><span>🔒 useEffect(fn, [deps]) — побочные эффекты после рендера</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb626\" onchange=\"updateProgress(this)\" disabled><span>🔒 [] в useEffect — один запуск при монтировании</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Пройди тест и практику, чтобы разблокировать чекбоксы</div>\n    </div>\n\n    "},{"id":"block-react-useref","title":"useRef — прямой доступ к DOM основа 🔗","html":"<div class=\"block\" id=\"block-react-useref\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-useref')\">useRef — прямой доступ к DOM <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">useRef — фундаментальный хук. Нужен когда нужно достать DOM-элемент напрямую (фокус, размеры) или сохранить значение которое НЕ должно вызывать перерисовку.</div>\n      <div class=\"code\"><span class=\"kw\">import</span> { useRef, useEffect } <span class=\"kw\">from</span> <span class=\"str\">'react'</span>;\n\n<span class=\"kw\">function</span> <span class=\"fn\">SearchInput</span>() {\n  <span class=\"kw\">const</span> inputRef = <span class=\"fn\">useRef</span>(<span class=\"kw\">null</span>);\n\n  <span class=\"fn\">useEffect</span>(() =&gt; {\n    inputRef.current.<span class=\"fn\">focus</span>(); <span class=\"cm\">// авто-фокус при монтировании</span>\n  }, []);\n\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">input</span> <span class=\"attr\">ref</span>={inputRef} <span class=\"attr\">type</span>=<span class=\"str\">\"text\"</span> /&gt;;\n}\n\n<span class=\"cm\">// useRef для значения которое не должно вызывать ре-рендер</span>\n<span class=\"kw\">function</span> <span class=\"fn\">Timer</span>() {\n  <span class=\"kw\">const</span> intervalId = <span class=\"fn\">useRef</span>(<span class=\"kw\">null</span>); <span class=\"cm\">// храним ID таймера</span>\n  <span class=\"kw\">const</span> [seconds, setSeconds] = <span class=\"fn\">useState</span>(<span class=\"num\">0</span>);\n\n  <span class=\"kw\">const</span> start = () =&gt; {\n    intervalId.current = <span class=\"fn\">setInterval</span>(() =&gt; <span class=\"fn\">setSeconds</span>(s =&gt; s + <span class=\"num\">1</span>), <span class=\"num\">1000</span>);\n  };\n  <span class=\"kw\">const</span> stop = () =&gt; <span class=\"fn\">clearInterval</span>(intervalId.current);\n\n  <span class=\"kw\">return</span> &lt;&gt;{seconds}s &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={start}&gt;Старт&lt;/<span class=\"tag\">button</span>&gt; &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={stop}&gt;Стоп&lt;/<span class=\"tag\">button</span>&gt;&lt;/&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>useRef(null)</strong> создаёт объект <code>{ current: null }</code>. Передаёшь его в <code>ref=</code> JSX-элемента — React сам положит туда DOM-ноду.<br>\n        <strong>Главное отличие от useState:</strong> изменение <code>ref.current</code> НЕ вызывает перерисовку компонента. Используй для значений которые \"за кадром\" (ID таймера, предыдущее значение, счётчик рендеров).<br>\n        <strong>Частые применения:</strong> фокус на input, измерение размеров блока, хранение ID setInterval/setTimeout, доступ к video/canvas элементам.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb263\" onchange=\"updateProgress(this)\"><span>useRef для доступа к DOM-элементу (focus, измерения)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb264\" onchange=\"updateProgress(this)\"><span>useRef для значения которое не должно вызывать ре-рендер</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb265\" onchange=\"updateProgress(this)\"><span>Понимаю разницу useRef vs useState</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-rhf-zod-2026","title":"React Hook Form + Zod ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-react-rhf-zod-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-react-rhf-zod-2026')\">React Hook Form + Zod <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">React Hook Form управляет формой без лишних ререндеров, а Zod проверяет данные и создаёт TypeScript-тип.</div><div class=\"code\">const schema = z.object({\n  email: z.string().email(\"Invalid email\"),\n  age: z.coerce.number().int().min(14)\n});\n\ntype FormData = z.infer&lt;typeof schema&gt;;\n\nfunction ProfileForm() {\n  const { register, handleSubmit, formState: { errors } } =\n    useForm&lt;FormData&gt;({ resolver: zodResolver(schema) });\n\n  return &lt;form onSubmit={handleSubmit(console.log)}&gt;\n    &lt;input {...register(\"email\")} /&gt;\n    &lt;span&gt;{errors.email?.message}&lt;/span&gt;\n    &lt;button&gt;Save&lt;/button&gt;\n  &lt;/form&gt;;\n}</div><div class=\"explain\"><code>register</code> подключает input, <code>handleSubmit</code> проверяет форму до твоей функции, <code>errors</code> хранит ошибки. <code>z.infer</code> не даёт схеме и типу разойтись. На сервере проверку повторяют.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-rhf-zod-2026-1\" onchange=\"updateProgress(this)\"><span>Регистрирую поля через RHF</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-rhf-zod-2026-2\" onchange=\"updateProgress(this)\"><span>Получаю тип через z.infer</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-rhf-zod-2026-3\" onchange=\"updateProgress(this)\"><span>Показываю ошибку у поля</span></label></div></div>"},{"id":"block-react-zustand-2026","title":"Общее состояние с Zustand ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-react-zustand-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-react-zustand-2026')\">Общее состояние с Zustand <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Локальное состояние оставляй в useState. Zustand нужен, когда несколько далёких компонентов делят состояние интерфейса.</div><div class=\"code\">type ThemeStore = {\n  theme: \"light\" | \"dark\";\n  toggleTheme: () =&gt; void;\n};\n\nconst useThemeStore = create&lt;ThemeStore&gt;((set) =&gt; ({\n  theme: \"dark\",\n  toggleTheme: () =&gt; set((state) =&gt; ({\n    theme: state.theme === \"dark\" ? \"light\" : \"dark\"\n  }))\n}));\n\nconst theme = useThemeStore((state) =&gt; state.theme);</div><div class=\"explain\">Store содержит данные и actions. Селектор подписывает компонент только на нужное поле и уменьшает ререндеры. Серверные данные лучше хранить на сервере или в кэше запросов, а не копировать в глобальный store.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-zustand-2026-1\" onchange=\"updateProgress(this)\"><span>Отличаю локальное и общее состояние</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-zustand-2026-2\" onchange=\"updateProgress(this)\"><span>Использую селектор Zustand</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-zustand-2026-3\" onchange=\"updateProgress(this)\"><span>Не копирую серверные данные в store</span></label></div></div>"},{"id":"block-react-ui-2026","title":"shadcn/ui + Radix UI ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-react-ui-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-react-ui-2026')\">shadcn/ui + Radix UI <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Radix даёт доступное поведение, shadcn/ui - готовый редактируемый код компонентов на Radix и Tailwind.</div><div class=\"code\">import { Button } from \"@/components/ui/button\";\nimport { Dialog, DialogContent, DialogTitle, DialogTrigger }\n  from \"@/components/ui/dialog\";\n\nexport function DeleteDialog() {\n  return &lt;Dialog&gt;\n    &lt;DialogTrigger asChild&gt;\n      &lt;Button variant=\"destructive\"&gt;Delete&lt;/Button&gt;\n    &lt;/DialogTrigger&gt;\n    &lt;DialogContent&gt;\n      &lt;DialogTitle&gt;Delete project?&lt;/DialogTitle&gt;\n      &lt;Button variant=\"destructive\"&gt;Confirm&lt;/Button&gt;\n    &lt;/DialogContent&gt;\n  &lt;/Dialog&gt;;\n}</div><div class=\"explain\">Диалог уже управляет фокусом, Escape, ролями и клавиатурой. Код находится в твоём проекте, его можно стилизовать. Не удаляй подписи, aria-атрибуты и focus-стили ради картинки.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-ui-2026-1\" onchange=\"updateProgress(this)\"><span>Отличаю Radix от shadcn/ui</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-ui-2026-2\" onchange=\"updateProgress(this)\"><span>Сохраняю keyboard и focus</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-ui-2026-3\" onchange=\"updateProgress(this)\"><span>Редактирую компоненты в своём проекте</span></label></div></div>"},{"id":"block-react-lists","title":"Списки и условный рендер основа 🔗","html":"<div class=\"block\" id=\"block-react-lists\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-lists')\">Списки и условный рендер <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Для списков используй .map() с обязательным key. Условный рендер — через &amp;&amp; или тернарный оператор.</div>\n      <div class=\"code\"><span class=\"kw\">const</span> todos = [\n  { id: <span class=\"num\">1</span>, text: <span class=\"str\">\"Учить React\"</span>, done: <span class=\"kw\">false</span> },\n  { id: <span class=\"num\">2</span>, text: <span class=\"str\">\"Сделать проект\"</span>, done: <span class=\"kw\">true</span> },\n];\n\n<span class=\"kw\">function</span> <span class=\"fn\">TodoList</span>() {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">ul</span>&gt;\n      {todos.<span class=\"fn\">map</span>(todo =&gt; (\n        &lt;<span class=\"tag\">li</span> <span class=\"attr\">key</span>={todo.id}&gt;  <span class=\"cm\">{/* key обязателен! */}</span>\n          {todo.text}\n          {todo.done &amp;&amp; &lt;<span class=\"tag\">span</span>&gt; ✓&lt;/<span class=\"tag\">span</span>&gt;}  <span class=\"cm\">{/* &amp;&amp; рендер */}</span>\n        &lt;/<span class=\"tag\">li</span>&gt;\n      ))}\n    &lt;/<span class=\"tag\">ul</span>&gt;\n  );\n}\n\n<span class=\"cm\">// Тернарный оператор</span>\n<span class=\"kw\">function</span> <span class=\"fn\">Status</span>({ isLoading }) {\n  <span class=\"kw\">return</span> isLoading ? &lt;<span class=\"tag\">p</span>&gt;Загрузка...&lt;/<span class=\"tag\">p</span>&gt; : &lt;<span class=\"tag\">p</span>&gt;Готово&lt;/<span class=\"tag\">p</span>&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>key</strong> — уникальный идентификатор для React при обновлении списка. Никогда не используй индекс массива как key.<br>\n        <strong>&amp;&amp;</strong> — рендерит правую часть только если левая true.<br>\n        <strong>? :</strong> — тернарный: одно или другое.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb244\" onchange=\"updateProgress(this)\"><span>.map() для рендера списков с обязательным key</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb245\" onchange=\"updateProgress(this)\"><span>Условный рендер: {condition &amp;&amp; &lt;Component /&gt;}</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb246\" onchange=\"updateProgress(this)\"><span>Тернарный рендер: condition ? &lt;A /&gt; : &lt;B /&gt;</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-forms","title":"React-формы: controlled input и масштабирование ВАЖНО #","html":"<div class=\"block wdg-quality-block\" id=\"block-react-forms\"><div class=\"block-title\" onclick=\"scrollToBlock('block-react-forms')\">React-формы: controlled input и масштабирование <span class=\"badge good\">ВАЖНО</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Controlled input получает <code>value</code> из state. Каждый символ обновляет state и планирует новый рендер этого компонента - это нормально, пока компонент не стал слишком тяжёлым.</div><div class=\"code\">function SearchForm() {\n  const [query, setQuery] = useState(\"\");\n\n  function handleSubmit(event) {\n    event.preventDefault();\n    if (!query.trim()) return;\n    console.log(query.trim());\n  }\n\n  return (\n    &lt;form onSubmit={handleSubmit}&gt;\n      &lt;input name=\"query\" value={query}\n        onChange={(event) =&gt; setQuery(event.target.value)} /&gt;\n      &lt;button type=\"submit\"&gt;Найти&lt;/button&gt;\n    &lt;/form&gt;\n  );\n}</div><div class=\"explain\">Держи state рядом с полем, чтобы не перерисовывать большой экран без причины. Для больших форм React Hook Form уменьшает ручной state и точнее подписывает поля. Zod проверяет структуру данных, но сам по себе не ускоряет ввод. Zustand нужен для общего состояния приложения, а не как автоматическая замена состоянию формы.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-forms-1\" onchange=\"updateProgress(this)\"><span>Понимаю value  ->  onChange  ->  state  ->  render</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-forms-2\" onchange=\"updateProgress(this)\"><span>Держу state ближе к полю</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-forms-3\" onchange=\"updateProgress(this)\"><span>Разделяю state, validation и shared state</span></label></div></div>"},{"id":"block-react-context","title":"React Context: область видимости и перерендеры ВАЖНО #","html":"<div class=\"block wdg-quality-block\" id=\"block-react-context\"><div class=\"block-title\" onclick=\"scrollToBlock('block-react-context')\">React Context: область видимости и перерендеры <span class=\"badge good\">ВАЖНО</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Когда <code>value</code> провайдера получает новую идентичность, React обновляет компоненты-потребители этого Context. Это не означает, что буквально каждый компонент внутри Provider обязан перерендериться.</div><div class=\"code\">const ThemeContext = createContext(null);\n\nfunction ThemeProvider({ children }) {\n  const [theme, setTheme] = useState(\"dark\");\n  const value = useMemo(() =&gt; ({ theme, setTheme }), [theme]);\n\n  return (\n    &lt;ThemeContext.Provider value={value}&gt;\n      {children}\n    &lt;/ThemeContext.Provider&gt;\n  );\n}\n\nfunction ThemeButton() {\n  const { theme, setTheme } = useContext(ThemeContext);\n  return &lt;button onClick={() =&gt; setTheme(theme === \"dark\" ? \"light\" : \"dark\")}&gt;Theme&lt;/button&gt;;\n}</div><div class=\"explain\">Context удобен для темы, локали и текущего пользователя. Не складывай в один Context всё приложение: разделяй независимые данные. <code>useMemo</code> не создаёт объект <code>value</code> без причины, но не отменяет обновление при изменении <code>theme</code>. Для часто меняющегося общего состояния пригодятся хранилища с селекторами, например Zustand.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-context-1\" onchange=\"updateProgress(this)\"><span>Разделяю независимые Context</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-context-2\" onchange=\"updateProgress(this)\"><span>Понимаю identity value</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-context-3\" onchange=\"updateProgress(this)\"><span>Использую selector-store по причине</span></label></div></div>"},{"id":"block-react-memo","title":"useMemo, useCallback и React.memo знать 🔗","html":"<div class=\"block\" id=\"block-react-memo\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-memo')\">useMemo, useCallback и React.memo <span class=\"badge\">знать</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// useMemo — кэшировать вычисление</span>\n<span class=\"kw\">const</span> total = <span class=\"fn\">useMemo</span>(() =&gt; {\n  <span class=\"kw\">return</span> items.<span class=\"fn\">reduce</span>((sum, i) =&gt; sum + i.price, <span class=\"num\">0</span>);\n}, [items]); <span class=\"cm\">// пересчитывать только при изменении items</span>\n\n<span class=\"cm\">// useCallback — кэшировать функцию</span>\n<span class=\"kw\">const</span> handleClick = <span class=\"fn\">useCallback</span>(() =&gt; {\n  <span class=\"fn\">doSomething</span>(id);\n}, [id]);\n\n<span class=\"cm\">// React.memo — не перерисовывать если props не изменились</span>\n<span class=\"kw\">const</span> ExpensiveCard = React.<span class=\"fn\">memo</span>(<span class=\"kw\">function</span> <span class=\"fn\">Card</span>({ title }) {\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">div</span>&gt;{title}&lt;/<span class=\"tag\">div</span>&gt;;\n});</div>\n      <div class=\"explain\">\n        <strong>useMemo</strong> — кэширует результат функции. Пересчитывает только при изменении зависимостей.<br>\n        <strong>useCallback</strong> — кэширует ссылку на функцию. Нужен при передаче коллбэков в React.memo-компоненты.<br>\n        <strong>React.memo</strong> — HOC-обёртка. Пропускает рендер если props не изменились.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb253\" onchange=\"updateProgress(this)\"><span>useMemo — кэширование вычислений с зависимостями</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb254\" onchange=\"updateProgress(this)\"><span>useCallback — стабильная ссылка на функцию</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb255\" onchange=\"updateProgress(this)\"><span>React.memo — пропуск ре-рендера при неизменных props</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-router","title":"React Router — навигация важно 🔗","html":"<div class=\"block\" id=\"block-react-router\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-router')\">React Router — навигация <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// npm install react-router-dom</span>\n<span class=\"kw\">import</span> { BrowserRouter, Routes, Route, Link, useNavigate, useParams } <span class=\"kw\">from</span> <span class=\"str\">'react-router-dom'</span>;\n\n<span class=\"kw\">function</span> <span class=\"fn\">App</span>() {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"fn\">BrowserRouter</span>&gt;\n      &lt;<span class=\"tag\">nav</span>&gt;\n        &lt;<span class=\"fn\">Link</span> <span class=\"attr\">to</span>=<span class=\"str\">\"/\"</span>&gt;Главная&lt;/<span class=\"fn\">Link</span>&gt;\n        &lt;<span class=\"fn\">Link</span> <span class=\"attr\">to</span>=<span class=\"str\">\"/about\"</span>&gt;О нас&lt;/<span class=\"fn\">Link</span>&gt;\n      &lt;/<span class=\"tag\">nav</span>&gt;\n      &lt;<span class=\"fn\">Routes</span>&gt;\n        &lt;<span class=\"fn\">Route</span> <span class=\"attr\">path</span>=<span class=\"str\">\"/\"</span> <span class=\"attr\">element</span>={&lt;<span class=\"fn\">Home</span> /&gt;} /&gt;\n        &lt;<span class=\"fn\">Route</span> <span class=\"attr\">path</span>=<span class=\"str\">\"/users/:id\"</span> <span class=\"attr\">element</span>={&lt;<span class=\"fn\">UserPage</span> /&gt;} /&gt;\n      &lt;/<span class=\"fn\">Routes</span>&gt;\n    &lt;/<span class=\"fn\">BrowserRouter</span>&gt;\n  );\n}\n\n<span class=\"kw\">function</span> <span class=\"fn\">UserPage</span>() {\n  <span class=\"kw\">const</span> { id } = <span class=\"fn\">useParams</span>(); <span class=\"cm\">// достаём :id из URL</span>\n  <span class=\"kw\">const</span> navigate = <span class=\"fn\">useNavigate</span>();\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">navigate</span>(<span class=\"str\">\"/\"</span>)}&gt;Назад&lt;/<span class=\"tag\">button</span>&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>BrowserRouter</strong> — оборачивает всё приложение, даёт доступ к роутингу.<br>\n        <strong>Routes + Route</strong> — декларативное описание маршрутов.<br>\n        <strong>Link</strong> — навигация без перезагрузки страницы.<br>\n        <strong>useParams</strong> — читает динамические части URL (:id).<br>\n        <strong>useNavigate</strong> — программный переход между страницами.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb256\" onchange=\"updateProgress(this)\"><span>BrowserRouter + Routes + Route — структура роутинга</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb257\" onchange=\"updateProgress(this)\"><span>Link — навигация без перезагрузки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb258\" onchange=\"updateProgress(this)\"><span>useParams — динамические параметры URL</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb259\" onchange=\"updateProgress(this)\"><span>useNavigate — программный переход</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-custom-hooks","title":"Кастомные хуки важно 🔗","html":"<div class=\"block\" id=\"block-react-custom-hooks\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-custom-hooks')\">Кастомные хуки <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Хук для fetch-запросов с отменой старого запроса</span>\n<span class=\"kw\">function</span> <span class=\"fn\">useFetch</span>&lt;T&gt;(url: <span class=\"str\">string</span>) {\n  <span class=\"kw\">const</span> [data, setData] = <span class=\"fn\">useState</span>&lt;T | <span class=\"kw\">null</span>&gt;(<span class=\"kw\">null</span>);\n  <span class=\"kw\">const</span> [loading, setLoading] = <span class=\"fn\">useState</span>(<span class=\"kw\">true</span>);\n  <span class=\"kw\">const</span> [error, setError] = <span class=\"fn\">useState</span>&lt;<span class=\"str\">string</span> | <span class=\"kw\">null</span>&gt;(<span class=\"kw\">null</span>);\n\n  <span class=\"fn\">useEffect</span>(() =&gt; {\n    <span class=\"kw\">const</span> controller = <span class=\"kw\">new</span> <span class=\"fn\">AbortController</span>();\n    <span class=\"fn\">setLoading</span>(<span class=\"kw\">true</span>);\n    <span class=\"fn\">setError</span>(<span class=\"kw\">null</span>);\n\n    <span class=\"fn\">fetch</span>(url, { signal: controller.signal })\n      .<span class=\"fn\">then</span>(r =&gt; {\n        <span class=\"kw\">if</span> (!r.ok) <span class=\"kw\">throw new</span> <span class=\"fn\">Error</span>(<span class=\"str\">`HTTP ${r.status}`</span>);\n        <span class=\"kw\">return</span> r.<span class=\"fn\">json</span>();\n      })\n      .<span class=\"fn\">then</span>(d =&gt; <span class=\"fn\">setData</span>(d))\n      .<span class=\"fn\">catch</span>(e =&gt; {\n        <span class=\"kw\">if</span> (e.name !== <span class=\"str\">'AbortError'</span>) <span class=\"fn\">setError</span>(e.message);\n      })\n      .<span class=\"fn\">finally</span>(() =&gt; {\n        <span class=\"kw\">if</span> (!controller.signal.aborted) <span class=\"fn\">setLoading</span>(<span class=\"kw\">false</span>);\n      });\n\n    <span class=\"kw\">return</span> () =&gt; controller.<span class=\"fn\">abort</span>();\n  }, [url]);\n\n  <span class=\"kw\">return</span> { data, loading, error };\n}</div>\n      <div class=\"explain\">\n        <strong>Кастомный хук</strong> — функция начинающаяся с use, которая инкапсулирует логику.<br>\n        <strong>AbortController</strong> отменяет старый запрос в cleanup. Без этого медленный ответ старого URL может перезаписать свежие данные — это race condition.<br>\n        <strong>useFetch</strong> — классический пример: данные + состояние загрузки + ошибка + отмена запроса.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb260\" onchange=\"updateProgress(this)\"><span>Кастомный хук — функция use*, инкапсулирует логику</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb261\" onchange=\"updateProgress(this)\"><span>useFetch — паттерн: data/loading/error</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb262\" onchange=\"updateProgress(this)\"><span>AbortController в cleanup защищает от race condition</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-cleanup","title":"useEffect: функция очистки (cleanup) частая ошибка новичков 🔗","html":"<div class=\"block\" id=\"block-react-cleanup\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-cleanup')\">useEffect: функция очистки (cleanup) <span class=\"badge must\">частая ошибка новичков</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Новички часто забывают очищать за собой ресурсы в useEffect — это приводит к утечкам памяти и багам типа \"висящих\" обработчиков после ухода с компонента.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Без очистки — утечка памяти и баги</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"kw\">const</span> id = <span class=\"fn\">setInterval</span>(() =&gt; console.<span class=\"fn\">log</span>(<span class=\"str\">'tick'</span>), <span class=\"num\">1000</span>);\n  <span class=\"cm\">// таймер продолжит работать даже после ухода с компонента!</span>\n}, []);\n\n<span class=\"cm\">// ✅ С функцией очистки — return внутри useEffect</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"kw\">const</span> id = <span class=\"fn\">setInterval</span>(() =&gt; console.<span class=\"fn\">log</span>(<span class=\"str\">'tick'</span>), <span class=\"num\">1000</span>);\n\n  <span class=\"kw\">return</span> () =&gt; <span class=\"fn\">clearInterval</span>(id); <span class=\"cm\">// вызовется при размонтировании</span>\n}, []);\n\n<span class=\"cm\">// ✅ Отписка от событий</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"kw\">const</span> handleResize = () =&gt; console.<span class=\"fn\">log</span>(window.innerWidth);\n  window.<span class=\"fn\">addEventListener</span>(<span class=\"str\">'resize'</span>, handleResize);\n\n  <span class=\"kw\">return</span> () =&gt; window.<span class=\"fn\">removeEventListener</span>(<span class=\"str\">'resize'</span>, handleResize);\n}, []);</div>\n      <div class=\"explain\">\n        <strong>return внутри useEffect</strong> — функция которая выполнится перед следующим запуском эффекта ИЛИ при размонтировании компонента.<br>\n        <strong>Что обязательно чистить:</strong> setInterval/setTimeout, addEventListener, подписки (WebSocket, observers), запросы которые можно отменить.<br>\n        <strong>Правило:</strong> если в useEffect что-то \"запускаешь\" (таймер, подписку) — почти всегда нужно его \"остановить\" в cleanup.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb266\" onchange=\"updateProgress(this)\"><span>return () =&gt; {} внутри useEffect — функция очистки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb267\" onchange=\"updateProgress(this)\"><span>clearInterval/removeEventListener в cleanup</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb268\" onchange=\"updateProgress(this)\"><span>Понимаю когда забытый cleanup приводит к утечке памяти</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-effect-loop","title":"useEffect: бесконечный цикл частая ошибка 🔗","html":"<div class=\"block\" id=\"block-react-effect-loop\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-effect-loop')\">useEffect: бесконечный цикл <span class=\"badge must\">частая ошибка</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Если эффект меняет состояние и запускается после каждого рендера, компонент может уйти в бесконечный цикл обновлений.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Нет массива зависимостей — эффект запускается после каждого рендера</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"fn\">setCount</span>(count + <span class=\"num\">1</span>);\n});\n\n<span class=\"cm\">// ❌ Зависимость от count + изменение count внутри эффекта</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"fn\">setCount</span>(count + <span class=\"num\">1</span>);\n}, [count]);\n\n<span class=\"cm\">// ✅ Если нужно выполнить один раз при монтировании</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"fn\">setCount</span>(c =&gt; c + <span class=\"num\">1</span>);\n}, []);</div>\n      <div class=\"explain\">\n        <strong>useEffect без второго аргумента</strong> запускается после каждого рендера.<br>\n        <strong>setState внутри эффекта</strong> вызывает новый рендер. Если эффект снова запускается и снова делает setState — вкладка начинает зависать.<br>\n        <strong>Правило:</strong> зависимости должны описывать внешние данные эффекта, а не быть случайным списком переменных.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb268a\" onchange=\"updateProgress(this)\"><span>Понимаю почему setState в useEffect может зациклить компонент</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-data-fetching","title":"TanStack Query — правильная работа с сервером стандарт индустрии 🔗","html":"<div class=\"block\" id=\"block-react-data-fetching\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-data-fetching')\">TanStack Query — правильная работа с сервером <span class=\"badge good\">стандарт индустрии</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Писать сырой fetch внутри useEffect — устаревший подход. Это приводит к race conditions, отсутствию кэширования и тоннам шаблонного кода для loading/error состояний.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Старый способ — fetch в useEffect</span>\n<span class=\"kw\">function</span> <span class=\"fn\">UserProfile</span>({ id }) {\n  <span class=\"kw\">const</span> [user, setUser] = <span class=\"fn\">useState</span>(<span class=\"kw\">null</span>);\n  <span class=\"kw\">const</span> [loading, setLoading] = <span class=\"fn\">useState</span>(<span class=\"kw\">true</span>);\n\n  <span class=\"fn\">useEffect</span>(() =&gt; {\n    <span class=\"fn\">fetch</span>(<span class=\"str\">`/api/users/${id}`</span>)\n      .<span class=\"fn\">then</span>(r =&gt; r.<span class=\"fn\">json</span>())\n      .<span class=\"fn\">then</span>(data =&gt; { <span class=\"fn\">setUser</span>(data); <span class=\"fn\">setLoading</span>(<span class=\"kw\">false</span>); });\n    <span class=\"cm\">// нет отмены запроса, нет кэша, нет обработки ошибок...</span>\n  }, [id]);\n}\n\n<span class=\"cm\">// ✅ TanStack Query — кэш, повторные запросы, отмена — из коробки</span>\n<span class=\"kw\">import</span> { useQuery } <span class=\"kw\">from</span> <span class=\"str\">'@tanstack/react-query'</span>;\n\n<span class=\"kw\">function</span> <span class=\"fn\">UserProfile</span>({ id }) {\n  <span class=\"kw\">const</span> { data: user, isLoading, error } = <span class=\"fn\">useQuery</span>({\n    queryKey: [<span class=\"str\">'user'</span>, id],\n    queryFn: () =&gt; <span class=\"fn\">fetch</span>(<span class=\"str\">`/api/users/${id}`</span>).<span class=\"fn\">then</span>(r =&gt; r.<span class=\"fn\">json</span>())\n  });\n\n  <span class=\"kw\">if</span> (isLoading) <span class=\"kw\">return</span> &lt;<span class=\"tag\">p</span>&gt;Загрузка...&lt;/<span class=\"tag\">p</span>&gt;;\n  <span class=\"kw\">if</span> (error) <span class=\"kw\">return</span> &lt;<span class=\"tag\">p</span>&gt;Ошибка&lt;/<span class=\"tag\">p</span>&gt;;\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">p</span>&gt;{user.name}&lt;/<span class=\"tag\">p</span>&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>TanStack Query (React Query)</strong> — автоматическое кэширование, повторные запросы при ошибке, отмена ненужных запросов при размонтировании.<br>\n        <strong>queryKey</strong> — уникальный идентификатор запроса, по нему строится кэш. Изменился id → автоматически новый запрос.<br>\n        <strong>RTK Query</strong> — аналог от Redux Toolkit, если проект уже использует Redux.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb272\" onchange=\"updateProgress(this)\"><span>Понимаю проблемы сырого fetch в useEffect (race conditions, кэш)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb273\" onchange=\"updateProgress(this)\"><span>useQuery — queryKey, queryFn, isLoading, error</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb274\" onchange=\"updateProgress(this)\"><span>Знаю что TanStack Query — стандарт для работы с серверным состоянием</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-advanced-hooks","title":"useReducer и useLayoutEffect для кругозора 🔗","html":"<div class=\"block\" id=\"block-react-advanced-hooks\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-advanced-hooks')\">useReducer и useLayoutEffect <span class=\"badge\">для кругозора</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// useReducer — альтернатива useState для сложной логики обновлений</span>\n<span class=\"kw\">function</span> <span class=\"fn\">reducer</span>(state, action) {\n  <span class=\"kw\">switch</span> (action.type) {\n    <span class=\"kw\">case</span> <span class=\"str\">'increment'</span>: <span class=\"kw\">return</span> { count: state.count + <span class=\"num\">1</span> };\n    <span class=\"kw\">case</span> <span class=\"str\">'decrement'</span>: <span class=\"kw\">return</span> { count: state.count - <span class=\"num\">1</span> };\n    <span class=\"kw\">case</span> <span class=\"str\">'reset'</span>: <span class=\"kw\">return</span> { count: <span class=\"num\">0</span> };\n    <span class=\"kw\">default</span>: <span class=\"kw\">return</span> state;\n  }\n}\n\n<span class=\"kw\">function</span> <span class=\"fn\">Counter</span>() {\n  <span class=\"kw\">const</span> [state, dispatch] = <span class=\"fn\">useReducer</span>(reducer, { count: <span class=\"num\">0</span> });\n  <span class=\"kw\">return</span> (\n    &lt;&gt;\n      {state.count}\n      &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">dispatch</span>({ type: <span class=\"str\">'increment'</span> })}&gt;+&lt;/<span class=\"tag\">button</span>&gt;\n    &lt;/&gt;\n  );\n}\n\n<span class=\"cm\">// useLayoutEffect — как useEffect, но выполняется ДО отрисовки на экране</span>\n<span class=\"fn\">useLayoutEffect</span>(() =&gt; {\n  <span class=\"cm\">// измерить элемент и сразу применить стиль — без \"мигания\"</span>\n  <span class=\"kw\">const</span> height = ref.current.offsetHeight;\n  ref.current.style.marginTop = height + <span class=\"str\">'px'</span>;\n}, []);</div>\n      <div class=\"explain\">\n        <strong>useReducer</strong> — удобен когда логика обновления состояния сложная (много action-типов) или зависит от предыдущего состояния.<br>\n        <strong>useLayoutEffect</strong> — выполняется синхронно ДО того как браузер отрисует изменения. Используй только для измерений DOM, которые должны быть видны мгновенно (иначе будет \"мигание\").\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb275\" onchange=\"updateProgress(this)\"><span>useReducer — альтернатива useState для сложной логики</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb276\" onchange=\"updateProgress(this)\"><span>useLayoutEffect — выполняется до отрисовки, для DOM-измерений</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-fsd","title":"Архитектура FSD — стандарт крупных проектов стандарт рынка 🔗","html":"<div class=\"block\" id=\"block-react-fsd\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-fsd')\">Архитектура FSD — стандарт крупных проектов <span class=\"badge good\">стандарт рынка</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">В маленьких проектах файлы делят по типу: components/, hooks/, pages/. В крупных проектах этот подход превращается в кашу. Современный стандарт на рынке — методология FSD (Feature-Sliced Design).</div>\n      <div class=\"code\"><span class=\"cm\">// Архитектура делится на 3 главных понятия:</span>\n<span class=\"cm\">// Слой (Layer) → Слайс (Slice) → Сегмент (Segment)</span>\n\n<span class=\"cm\">// Структура папок FSD:</span>\nsrc/\n  ├── app/         <span class=\"cm\">// Инициализация приложения (провайдеры, глобальные стили, роутинг)</span>\n  ├── pages/       <span class=\"cm\">// Страницы приложения (компоненты страниц, собирают виджеты)</span>\n  ├── widgets/     <span class=\"cm\">// Крупные самостоятельные блоки (Шапка, Сайдбар, Грид товаров)</span>\n  ├── features/    <span class=\"cm\">// Интерактивные действия пользователя (Лайк, Добавить в корзину, Поиск)</span>\n  ├── entities/    <span class=\"cm\">// Бизнес-сущности (Пользователь, Товар, Статья — их карточки и логика)</span>\n  ├── shared/      <span class=\"cm\">// Переиспользуемый фундамент (UI-kit: Button, Input, API-клиенты, хелперы)</span>\n\n<span class=\"cm\">// Главное правило FSD:</span>\n<span class=\"cm\">// Вышележащие слои могут импортировать только то, что находится</span>\n<span class=\"cm\">// на НИЖЕлежащих слоях. Но никогда наоборот!</span>\n<span class=\"cm\">// Например, компонент из shared/ не может импортировать что-то из features/</span></div>\n      <div class=\"explain\">\n        <strong>FSD избавляет от «спагетти-кода»</strong> и переплетённых импортов — каждый слой знает своё место.<br>\n        <strong>Иерархия:</strong> app → pages → widgets → features → entities → shared. Каждый следующий слой строится только из предыдущих.<br>\n        <strong>Главное правило:</strong> нижние слои никогда не знают о верхних. shared/ ничего не знает про features/, а features/ ничего не знает про widgets/.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb277\" onchange=\"updateProgress(this)\"><span>FSD избавляет от «спагетти-кода» и переплетённых импортов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb278\" onchange=\"updateProgress(this)\"><span>Понимаю иерархию: app → pages → widgets → features → entities → shared</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb279\" onchange=\"updateProgress(this)\"><span>Знаю правило: нижние слои никогда не знают о верхних</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-zustand-selectors","title":"Zustand: селекторы — без них смысла нет критично 🔗","html":"<div class=\"block\" id=\"block-react-zustand-selectors\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-zustand-selectors')\">Zustand: селекторы — без них смысла нет <span class=\"badge must\">критично</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Без селекторов Zustand перерисовывает компонент на ЛЮБОЕ изменение стора — это стирает его главное преимущество перед useContext.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Без селектора — компонент ре-рендерится при ЛЮБОМ изменении стора</span>\n<span class=\"kw\">const</span> { meals, user, theme } = <span class=\"fn\">useStore</span>(); <span class=\"cm\">// подписан на ВСЁ</span>\n<span class=\"cm\">// Изменилась тема? Компонент перерисуется, даже если использует только meals!</span>\n\n<span class=\"cm\">// ✅ С селектором — подписка только на нужное поле</span>\n<span class=\"kw\">const</span> meals = <span class=\"fn\">useStore</span>(state =&gt; state.meals);\n<span class=\"cm\">// Теперь компонент перерисуется ТОЛЬКО когда meals изменится</span>\n\n<span class=\"cm\">// Несколько полей — несколько отдельных селекторов</span>\n<span class=\"kw\">const</span> user = <span class=\"fn\">useStore</span>(state =&gt; state.user);\n<span class=\"kw\">const</span> addMeal = <span class=\"fn\">useStore</span>(state =&gt; state.addMeal);\n\n<span class=\"cm\">// Если нужно несколько полей сразу — useShallow для Zustand 5+</span>\n<span class=\"kw\">import</span> { useShallow } <span class=\"kw\">from</span> <span class=\"str\">'zustand/react/shallow'</span>;\n\n<span class=\"kw\">const</span> { meals, user } = <span class=\"fn\">useStore</span>(\n  <span class=\"fn\">useShallow</span>(state =&gt; ({ meals: state.meals, user: state.user }))\n);</div>\n      <div class=\"explain\">\n        <strong>useStore()</strong> без аргумента — подписка на весь стор целиком. Любое изменение в любом поле вызывает ре-рендер.<br>\n        <strong>useStore(state =&gt; state.field)</strong> — подписка только на конкретное поле. Это и есть селектор.<br>\n        <strong>useShallow</strong> — современный способ для Zustand 5+: оборачивает селектор и поверхностно сравнивает поля объекта, а не ссылку целиком.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb280\" onchange=\"updateProgress(this)\"><span>useStore(state =&gt; state.field) — селектор подписки на одно поле</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb281\" onchange=\"updateProgress(this)\"><span>Понимаю что без селектора теряется главное преимущество Zustand</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb282\" onchange=\"updateProgress(this)\"><span>shallow — для селекторов возвращающих несколько полей</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-zustand-persist","title":"Zustand middleware: persist и devtools коммерческий код 🔗","html":"<div class=\"block\" id=\"block-react-zustand-persist\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-zustand-persist')\">Zustand middleware: persist и devtools <span class=\"badge must\">коммерческий код</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">В реальных проектах стор часто должен переживать перезагрузку страницы: тема, корзина, настройки, токен-состояние интерфейса. Для этого в Zustand есть middleware.</div>\n      <div class=\"code\"><span class=\"kw\">import</span> { create } <span class=\"kw\">from</span> <span class=\"str\">'zustand'</span>;\n<span class=\"kw\">import</span> { persist, devtools } <span class=\"kw\">from</span> <span class=\"str\">'zustand/middleware'</span>;\n\n<span class=\"kw\">const</span> useSettingsStore = <span class=\"fn\">create</span>()(\n  <span class=\"fn\">devtools</span>(\n    <span class=\"fn\">persist</span>(\n      (set) =&gt; ({\n        theme: <span class=\"str\">'dark'</span>,\n        setTheme: (theme) =&gt; <span class=\"fn\">set</span>({ theme })\n      }),\n      { name: <span class=\"str\">'settings-storage'</span> } <span class=\"cm\">// ключ в localStorage</span>\n    )\n  )\n);\n\n<span class=\"cm\">// После перезагрузки theme восстановится автоматически</span>\n<span class=\"kw\">const</span> theme = <span class=\"fn\">useSettingsStore</span>(s =&gt; s.theme);</div>\n      <div class=\"explain\">\n        <strong>persist</strong> сохраняет часть стора в localStorage/sessionStorage и поднимает её при старте приложения.<br>\n        <strong>devtools</strong> подключает стор к Redux DevTools — удобно смотреть изменения состояния по шагам.<br>\n        <strong>partialize</strong> можно использовать, если нужно сохранять не весь стор, а только безопасные поля.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-react-zustand-persist-1\" onchange=\"updateProgress(this)\"><span>persist — автоматическое сохранение стора в localStorage</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-react-zustand-persist-2\" onchange=\"updateProgress(this)\"><span>devtools — отладка Zustand через Redux DevTools</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-19-compiler-actions","title":"React 19: Compiler, useActionState, useFormStatus modern 🔗","html":"<div class=\"block\" id=\"block-react-19-compiler-actions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-19-compiler-actions')\">React 19: Compiler, useActionState, useFormStatus <span class=\"badge good\">modern</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">React движется к меньшему количеству ручной оптимизации и более удобной работе с формами. Старые хуки не исчезли, но новые проекты пишутся иначе.</div>\n      <div class=\"code\"><span class=\"cm\">// React Compiler снижает потребность в ручном useMemo/useCallback</span>\n<span class=\"cm\">// Идея: компилятор сам понимает, что можно мемоизировать безопасно.</span>\n\n<span class=\"cm\">// useActionState — состояние формы вокруг action</span>\n<span class=\"kw\">function</span> <span class=\"fn\">Signup</span>() {\n  <span class=\"kw\">const</span> [state, formAction, pending] = <span class=\"fn\">useActionState</span>(signupAction, {\n    error: <span class=\"kw\">null</span>\n  });\n\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">form</span> <span class=\"attr\">action</span>={formAction}&gt;\n      &lt;<span class=\"tag\">input</span> <span class=\"attr\">name</span>=<span class=\"str\">\"email\"</span> /&gt;\n      {state.error &amp;&amp; &lt;<span class=\"tag\">p</span>&gt;{state.error}&lt;/<span class=\"tag\">p</span>&gt;}\n      &lt;<span class=\"tag\">button</span> <span class=\"attr\">disabled</span>={pending}&gt;Создать&lt;/<span class=\"tag\">button</span>&gt;\n    &lt;/<span class=\"tag\">form</span>&gt;\n  );\n}\n\n<span class=\"cm\">// useFormStatus читают дочерние кнопки формы</span>\n<span class=\"kw\">function</span> <span class=\"fn\">SubmitButton</span>() {\n  <span class=\"kw\">const</span> { pending } = <span class=\"fn\">useFormStatus</span>();\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">button</span> <span class=\"attr\">disabled</span>={pending}&gt;{pending ? <span class=\"str\">'Ждём...'</span> : <span class=\"str\">'Отправить'</span>}&lt;/<span class=\"tag\">button</span>&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>React Compiler</strong> автоматизирует часть мемоизации. Но в легаси-коде <code>useMemo</code>, <code>useCallback</code> и <code>React.memo</code> всё ещё встречаются постоянно.<br>\n        <strong>useActionState</strong> связывает action формы с состоянием результата: ошибка, успех, pending.<br>\n        <strong>useFormStatus</strong> удобен для кнопки отправки внутри формы: она может знать, что форма сейчас отправляется.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-react19-1\" onchange=\"updateProgress(this)\"><span>React Compiler — идея автоматической мемоизации</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-react19-2\" onchange=\"updateProgress(this)\"><span>useActionState — состояние результата формы</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-react19-3\" onchange=\"updateProgress(this)\"><span>useFormStatus — pending-состояние внутри формы</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-testing","title":"Тестирование: Vitest + React Testing Library уровень middle 🔗","html":"<div class=\"block\" id=\"block-react-testing\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-testing')\">Тестирование: Vitest + React Testing Library <span class=\"badge good\">уровень middle</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Vitest — современная и быстрая замена Jest, особенно для проектов на Vite (использует тот же движок и конфиг). React Testing Library — стандарт для тестирования React-компонентов.</div>\n      <div class=\"code\"><span class=\"cm\">// Установка</span>\n<span class=\"kw\">npm install</span> -D vitest @testing-library/react @testing-library/jest-dom jsdom\n\n<span class=\"cm\">// Button.test.jsx</span>\n<span class=\"kw\">import</span> { render, screen, fireEvent } <span class=\"kw\">from</span> <span class=\"str\">'@testing-library/react'</span>;\n<span class=\"kw\">import</span> { describe, it, expect, vi } <span class=\"kw\">from</span> <span class=\"str\">'vitest'</span>;\n<span class=\"kw\">import</span> Button <span class=\"kw\">from</span> <span class=\"str\">'./Button'</span>;\n\n<span class=\"fn\">describe</span>(<span class=\"str\">'Button'</span>, () =&gt; {\n  <span class=\"fn\">it</span>(<span class=\"str\">'отображает переданный текст'</span>, () =&gt; {\n    <span class=\"fn\">render</span>(&lt;<span class=\"tag\">Button</span> <span class=\"attr\">label</span>=<span class=\"str\">\"Купить\"</span> /&gt;);\n    <span class=\"fn\">expect</span>(screen.<span class=\"fn\">getByText</span>(<span class=\"str\">'Купить'</span>)).<span class=\"fn\">toBeInTheDocument</span>();\n  });\n\n  <span class=\"fn\">it</span>(<span class=\"str\">'вызывает onClick при клике'</span>, () =&gt; {\n    <span class=\"kw\">const</span> handleClick = vi.<span class=\"fn\">fn</span>(); <span class=\"cm\">// мок-функция</span>\n    <span class=\"fn\">render</span>(&lt;<span class=\"tag\">Button</span> <span class=\"attr\">label</span>=<span class=\"str\">\"Купить\"</span> <span class=\"attr\">onClick</span>={handleClick} /&gt;);\n\n    fireEvent.<span class=\"fn\">click</span>(screen.<span class=\"fn\">getByText</span>(<span class=\"str\">'Купить'</span>));\n    <span class=\"fn\">expect</span>(handleClick).<span class=\"fn\">toHaveBeenCalledTimes</span>(<span class=\"num\">1</span>);\n  });\n});</div>\n      <div class=\"explain\">\n        <strong>render()</strong> — монтирует компонент в виртуальный DOM для теста.<br>\n        <strong>screen.getByText/getByRole</strong> — находит элементы так же, как их видит пользователь (по тексту, роли), а не по CSS-классам.<br>\n        <strong>vi.fn()</strong> — создаёт функцию-заглушку (мок), которую можно проверить: вызвалась ли, сколько раз, с какими аргументами.<br>\n        <strong>Философия RTL:</strong> \"тестируй как пользователь\" — не проверяй внутреннее состояние компонента, проверяй что видно и что происходит на экране.<br>\n        <strong>Playwright / Cypress</strong> — E2E-тесты: запускают настоящий браузер, кликают по интерфейсу и проверяют целый пользовательский сценарий, например логин → корзина → оплата.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb283\" onchange=\"updateProgress(this)\"><span>Vitest — быстрая замена Jest для Vite-проектов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb284\" onchange=\"updateProgress(this)\"><span>render, screen.getByText/getByRole — базовые методы RTL</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb285\" onchange=\"updateProgress(this)\"><span>vi.fn() и fireEvent — мок-функции и симуляция событий</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb285a\" onchange=\"updateProgress(this)\"><span>Playwright или Cypress — E2E-тесты реальных пользовательских сценариев</span></label>\n      </div>\n    </div>\n"},{"id":"block-react-enterprise-architecture","title":"React в крупных продуктах: микрофронтенды enterprise 🔗","html":"<div class=\"block\" id=\"block-react-enterprise-architecture\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-enterprise-architecture')\">React в крупных продуктах: микрофронтенды <span class=\"badge opt\">enterprise</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">В больших компаниях React-приложение часто делят на независимые части: команды выпускают свои модули отдельно, а оболочка собирает их вместе.</div>\n      <div class=\"explain\">\n        <strong>Module Federation</strong> — способ подключать части приложения из разных сборок во время выполнения. Часто встречается вместе с Webpack или Rspack.<br>\n        <strong>Rspack и Turbopack</strong> — сборщики на Rust: Rspack часто заменяет Webpack в enterprise React/Vue, Turbopack развивается внутри Next.js.<br>\n        <strong>Монорепозиторий</strong> — один репозиторий для нескольких пакетов или приложений; часто используют Turborepo, pnpm workspaces, Nx.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb285b\" onchange=\"updateProgress(this)\"><span>Module Federation — понимаю идею микрофронтендов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb285c\" onchange=\"updateProgress(this)\"><span>Rspack/Turbopack — знаю что такое сборщики на Rust</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb285d\" onchange=\"updateProgress(this)\"><span>Монорепозитории и Turborepo — базовая концепция разделения кода</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-linux","lessons":[{"id":"block-linux-basics","title":"Базовые команды терминала основа 🔗","html":"<div class=\"block\" id=\"block-linux-basics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-basics')\">Базовые команды терминала <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Терминал — это текстовый интерфейс к системе. Работает быстрее мыши для большинства задач разработчика.</div>\n      <div class=\"code\"><span class=\"cm\"># Навигация</span>\n<span class=\"kw\">pwd</span>              <span class=\"cm\"># где я сейчас?</span>\n<span class=\"kw\">ls</span> -la           <span class=\"cm\"># список файлов (с скрытыми)</span>\n<span class=\"kw\">cd</span> projects      <span class=\"cm\"># перейти в папку</span>\n<span class=\"kw\">cd</span> ..            <span class=\"cm\"># на уровень выше</span>\n<span class=\"kw\">cd</span> ~             <span class=\"cm\"># домашняя папка</span>\n\n<span class=\"cm\"># Файлы и папки</span>\n<span class=\"kw\">mkdir</span> my-app     <span class=\"cm\"># создать папку</span>\n<span class=\"kw\">touch</span> index.html  <span class=\"cm\"># создать файл</span>\n<span class=\"kw\">cp</span> file.txt copy.txt   <span class=\"cm\"># копировать</span>\n<span class=\"kw\">mv</span> old.txt new.txt     <span class=\"cm\"># переименовать/переместить</span>\n<span class=\"kw\">rm</span> file.txt      <span class=\"cm\"># удалить файл</span>\n<span class=\"kw\">rm</span> -rf folder/   <span class=\"cm\"># удалить папку (осторожно!)</span>\n\n<span class=\"cm\"># Просмотр файлов</span>\n<span class=\"kw\">cat</span> file.txt     <span class=\"cm\"># вывести содержимое</span>\n<span class=\"kw\">less</span> file.txt    <span class=\"cm\"># постраничный просмотр (q — выход)</span>\n<span class=\"kw\">head</span> -20 file.txt <span class=\"cm\"># первые 20 строк</span>\n<span class=\"kw\">tail</span> -f log.txt  <span class=\"cm\"># следить за файлом в реальном времени</span></div>\n      <div class=\"explain\">\n        <strong>pwd</strong> — Print Working Directory. Всегда знай где находишься.<br>\n        <strong>ls -la</strong> — показывает скрытые файлы (начинаются с .) и права доступа.<br>\n        <strong>rm -rf</strong> — опасная команда! Удаляет всё без подтверждения и без корзины.<br>\n        <strong>tail -f</strong> — незаменим для просмотра логов в реальном времени.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb286\" onchange=\"updateProgress(this)\"><span>pwd, ls, cd — навигация по файловой системе</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb287\" onchange=\"updateProgress(this)\"><span>mkdir, touch, cp, mv, rm — управление файлами</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb288\" onchange=\"updateProgress(this)\"><span>cat, less, head, tail — просмотр содержимого</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-linux-permissions","title":"Права доступа и пользователи важно 🔗","html":"<div class=\"block\" id=\"block-linux-permissions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-permissions')\">Права доступа и пользователи <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># chmod — изменить права</span>\n<span class=\"kw\">chmod</span> 755 script.sh  <span class=\"cm\"># rwxr-xr-x</span>\n<span class=\"kw\">chmod</span> +x script.sh   <span class=\"cm\"># добавить право выполнения</span>\n<span class=\"kw\">chmod</span> 644 file.txt   <span class=\"cm\"># rw-r--r-- (типично для файлов)</span>\n\n<span class=\"cm\"># Расшифровка прав: rwxrwxrwx</span>\n<span class=\"cm\"># r=4 w=2 x=1 | владелец | группа | остальные</span>\n<span class=\"cm\"># 755 = 7(rwx) 5(r-x) 5(r-x)</span>\n\n<span class=\"cm\"># sudo — выполнить от имени root</span>\n<span class=\"kw\">sudo</span> apt install nginx\n<span class=\"kw\">sudo</span> systemctl start nginx\n\n<span class=\"cm\"># Смена владельца</span>\n<span class=\"kw\">chown</span> user:group file.txt\n\n<span class=\"cm\"># Текущий пользователь</span>\n<span class=\"kw\">whoami</span>\n<span class=\"kw\">id</span></div>\n      <div class=\"explain\">\n        <strong>chmod 755</strong> — владелец может всё (7=rwx), остальные только читать и запускать (5=r-x).<br>\n        <strong>chmod +x</strong> — быстро добавить право запуска скрипту.<br>\n        <strong>sudo</strong> — Superuser DO. Нужен для системных операций. Не злоупотребляй.<br>\n        <strong>644</strong> — стандартные права для файлов. 755 — для папок и скриптов.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb289\" onchange=\"updateProgress(this)\"><span>chmod — изменение прав (числовой и буквенный формат)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb290\" onchange=\"updateProgress(this)\"><span>sudo — выполнение от root, apt install</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb291\" onchange=\"updateProgress(this)\"><span>Расшифровка rwx: r=4, w=2, x=1</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-linux-processes","title":"Процессы и системный мониторинг важно 🔗","html":"<div class=\"block\" id=\"block-linux-processes\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-processes')\">Процессы и системный мониторинг <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># Просмотр процессов</span>\n<span class=\"kw\">ps</span> aux            <span class=\"cm\"># все процессы</span>\n<span class=\"kw\">ps</span> aux | <span class=\"kw\">grep</span> node <span class=\"cm\"># найти Node процессы</span>\n<span class=\"kw\">top</span>               <span class=\"cm\"># мониторинг в реальном времени</span>\n<span class=\"kw\">htop</span>              <span class=\"cm\"># удобная версия top (нужно установить)</span>\n\n<span class=\"cm\"># Управление процессами</span>\n<span class=\"kw\">kill</span> 1234          <span class=\"cm\"># завершить процесс по PID</span>\n<span class=\"kw\">kill</span> -9 1234       <span class=\"cm\"># принудительно убить</span>\n<span class=\"kw\">pkill</span> node         <span class=\"cm\"># убить по имени</span>\nCtrl+C             <span class=\"cm\"># прервать текущий процесс</span>\nCtrl+Z             <span class=\"cm\"># приостановить (bg/fg для управления)</span>\n\n<span class=\"cm\"># Фоновый запуск</span>\n<span class=\"kw\">npm</span> start &amp;       <span class=\"cm\"># запустить в фоне</span>\n<span class=\"kw\">nohup</span> node app.js &amp; <span class=\"cm\"># запустить и отвязать от терминала</span>\n\n<span class=\"cm\"># Порты</span>\n<span class=\"kw\">lsof</span> -i :3000     <span class=\"cm\"># что слушает порт 3000?</span>\n<span class=\"kw\">netstat</span> -tulpn    <span class=\"cm\"># все открытые порты</span></div>\n      <div class=\"explain\">\n        <strong>ps aux | grep node</strong> — pipe (|) передаёт вывод одной команды в другую. Ключевой паттерн bash.<br>\n        <strong>kill -9</strong> — SIGKILL, нельзя перехватить. Используй только если обычный kill не помогает.<br>\n        <strong>lsof -i :3000</strong> — спасение когда «порт уже занят» при запуске dev-сервера.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb292\" onchange=\"updateProgress(this)\"><span>ps aux, top — просмотр и мониторинг процессов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb293\" onchange=\"updateProgress(this)\"><span>kill, pkill — завершение процессов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb294\" onchange=\"updateProgress(this)\"><span>lsof -i — проверка занятых портов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb295\" onchange=\"updateProgress(this)\"><span>Pipe (|) — передача вывода между командами</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-linux-ssh","title":"SSH — подключение к серверам важно 🔗","html":"<div class=\"block\" id=\"block-linux-ssh\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-ssh')\">SSH — подключение к серверам <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># Подключение по SSH</span>\n<span class=\"kw\">ssh</span> user@server.com\n<span class=\"kw\">ssh</span> -p 2222 user@server.com  <span class=\"cm\"># нестандартный порт</span>\n<span class=\"kw\">ssh</span> -i ~/.ssh/id_rsa user@server.com  <span class=\"cm\"># с ключом</span>\n\n<span class=\"cm\"># Генерация SSH ключей</span>\n<span class=\"kw\">ssh-keygen</span> -t ed25519 -C \"email@example.com\"\n<span class=\"cm\"># Приватный: ~/.ssh/id_ed25519 (НИКОМУ!)</span>\n<span class=\"cm\"># Публичный: ~/.ssh/id_ed25519.pub (на сервер)</span>\n\n<span class=\"cm\"># Копирование ключа на сервер</span>\n<span class=\"kw\">ssh-copy-id</span> user@server.com\n\n<span class=\"cm\"># Копирование файлов</span>\n<span class=\"kw\">scp</span> file.txt user@server:/home/user/\n<span class=\"kw\">scp</span> -r folder/ user@server:/home/user/\n\n<span class=\"cm\"># ~/.ssh/config — сохраняем настройки</span>\nHost myserver\n  HostName 192.168.1.1\n  User ubuntu\n  IdentityFile ~/.ssh/id_ed25519</div>\n      <div class=\"explain\">\n        <strong>ed25519</strong> — современный алгоритм ключей. Лучше чем rsa.<br>\n        <strong>Приватный ключ</strong> — никогда не передавай! Публичный (.pub) — можно везде.<br>\n        <strong>~/.ssh/config</strong> — после настройки можно подключаться просто: <code>ssh myserver</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb296\" onchange=\"updateProgress(this)\"><span>ssh user@host — подключение к удалённому серверу</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb297\" onchange=\"updateProgress(this)\"><span>ssh-keygen — генерация пары ключей ed25519</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb298\" onchange=\"updateProgress(this)\"><span>scp — копирование файлов по SSH</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb299\" onchange=\"updateProgress(this)\"><span>~/.ssh/config — сохранение настроек подключений</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-linux-bash","title":"Bash-скрипты и автоматизация знать 🔗","html":"<div class=\"block\" id=\"block-linux-bash\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-bash')\">Bash-скрипты и автоматизация <span class=\"badge\">знать</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">#!/bin/bash</span>\n<span class=\"cm\"># Переменные</span>\n<span class=\"kw\">NAME</span>=<span class=\"str\">\"World\"</span>\n<span class=\"kw\">echo</span> <span class=\"str\">\"Hello, $NAME!\"</span>\n\n<span class=\"cm\"># Условия</span>\n<span class=\"kw\">if</span> [ -f \"package.json\" ]; <span class=\"kw\">then</span>\n  <span class=\"kw\">echo</span> \"Node проект найден\"\n<span class=\"kw\">else</span>\n  <span class=\"kw\">echo</span> \"package.json не найден\"\n<span class=\"kw\">fi</span>\n\n<span class=\"cm\"># Цикл</span>\n<span class=\"kw\">for</span> file <span class=\"kw\">in</span> *.html; <span class=\"kw\">do</span>\n  <span class=\"kw\">echo</span> \"Файл: $file\"\n<span class=\"kw\">done</span>\n\n<span class=\"cm\"># Полезные алиасы в ~/.bashrc или ~/.zshrc</span>\n<span class=\"kw\">alias</span> gs=<span class=\"str\">\"git status\"</span>\n<span class=\"kw\">alias</span> gp=<span class=\"str\">\"git push\"</span>\n<span class=\"kw\">alias</span> ll=<span class=\"str\">\"ls -la\"</span>\n<span class=\"kw\">alias</span> dev=<span class=\"str\">\"npm run dev\"</span></div>\n      <div class=\"explain\">\n        <strong>#!/bin/bash</strong> — shebang. Первая строка говорит системе чем выполнять скрипт.<br>\n        <strong>[ -f file ]</strong> — проверка существования файла. [ -d ] — папки.<br>\n        <strong>alias</strong> — сокращения для частых команд. Сохрани в ~/.bashrc или ~/.zshrc и применяй: <code>source ~/.bashrc</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb300\" onchange=\"updateProgress(this)\"><span>#!/bin/bash — shebang и запуск скриптов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb301\" onchange=\"updateProgress(this)\"><span>if/for в bash — условия и циклы</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb302\" onchange=\"updateProgress(this)\"><span>alias — сокращения команд в ~/.bashrc</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-linux-packagemanagers","title":"Пакетные менеджеры и npm-инструменты основа 🔗","html":"<div class=\"block\" id=\"block-linux-packagemanagers\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-packagemanagers')\">Пакетные менеджеры и npm-инструменты <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># apt (Debian/Ubuntu)</span>\n<span class=\"kw\">sudo apt update</span>        <span class=\"cm\"># обновить список пакетов</span>\n<span class=\"kw\">sudo apt install</span> curl git\n<span class=\"kw\">sudo apt remove</span> nginx\n\n<span class=\"cm\"># brew (macOS)</span>\n<span class=\"kw\">brew install</span> node\n<span class=\"kw\">brew update &amp;&amp; brew upgrade</span>\n\n<span class=\"cm\"># npm глобальные пакеты</span>\n<span class=\"kw\">npm install -g</span> typescript\n<span class=\"kw\">npm install -g</span> vite\n<span class=\"kw\">corepack enable</span>       <span class=\"cm\"># включает pnpm/yarn через Node</span>\n<span class=\"kw\">pnpm create vite</span> my-app\n<span class=\"kw\">bun create vite</span> my-app\n<span class=\"kw\">npm list -g --depth=0</span>  <span class=\"cm\"># список установленных</span>\n\n<span class=\"cm\"># nvm — менеджер версий Node</span>\n<span class=\"kw\">nvm install</span> 20\n<span class=\"kw\">nvm use</span> 20\n<span class=\"kw\">nvm ls</span>               <span class=\"cm\"># список версий</span></div>\n      <div class=\"explain\">\n        <strong>apt update</strong> — всегда запускай перед install, иначе поставишь устаревшую версию.<br>\n        <strong>nvm</strong> — Node Version Manager. Позволяет иметь несколько версий Node одновременно.<br>\n        <strong>pnpm</strong> — быстрый менеджер пакетов, экономит место на диске за счёт общего хранилища.<br>\n        <strong>Bun</strong> — современный рантайм и пакетный менеджер для локальной разработки, часто быстрее Node/npm на типовых задачах.<br>\n        Разные проекты могут требовать разные версии Node — nvm решает эту проблему.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb303\" onchange=\"updateProgress(this)\"><span>apt/brew — системные пакетные менеджеры</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb304\" onchange=\"updateProgress(this)\"><span>npm install -g — глобальные npm пакеты</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb304a\" onchange=\"updateProgress(this)\"><span>pnpm и Bun — современные альтернативы npm для фронтенд-проектов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb305\" onchange=\"updateProgress(this)\"><span>nvm — управление версиями Node.js</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-vite","lessons":[{"id":"block-vite-basics","title":"Vite — быстрый dev-сервер и сборка основа 🔗","html":"<div class=\"block\" id=\"block-vite-basics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vite-basics')\">Vite — быстрый dev-сервер и сборка <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Vite — инструмент сборки нового поколения. Dev-сервер запускается мгновенно, HMR обновляет модули без перезагрузки страницы.</div>\n      <div class=\"code\"><span class=\"cm\"># Создать новый проект</span>\n<span class=\"kw\">npm create vite@latest</span> my-app\n<span class=\"cm\"># Выбрать: React / Vue / Vanilla + TypeScript</span>\n\n<span class=\"kw\">cd</span> my-app\n<span class=\"kw\">npm install</span>\n<span class=\"kw\">npm run dev</span>     <span class=\"cm\"># dev-сервер на http://localhost:5173</span>\n<span class=\"kw\">npm run build</span>   <span class=\"cm\"># сборка в папку dist/</span>\n<span class=\"kw\">npm run preview</span> <span class=\"cm\"># превью production-сборки</span>\n\n<span class=\"cm\">// vite.config.ts</span>\n<span class=\"kw\">import</span> { defineConfig } <span class=\"kw\">from</span> <span class=\"str\">'vite'</span>\n<span class=\"kw\">import</span> react <span class=\"kw\">from</span> <span class=\"str\">'@vitejs/plugin-react'</span>\n\n<span class=\"kw\">export default</span> <span class=\"fn\">defineConfig</span>({\n  plugins: [<span class=\"fn\">react</span>()],\n  server: { port: <span class=\"num\">3000</span> },\n  build: { outDir: <span class=\"str\">'dist'</span> }\n})</div>\n      <div class=\"explain\">\n        <strong>HMR</strong> — Hot Module Replacement. Изменил файл — браузер обновляет только этот модуль, не перезагружая страницу.<br>\n        <strong>npm run build</strong> — минифицирует, разбивает на чанки, оптимизирует. Готово для деплоя.<br>\n        <strong>dist/</strong> — именно эту папку загружаешь на хостинг или GitHub Pages.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb306\" onchange=\"updateProgress(this)\"><span>npm create vite@latest — создание проекта с шаблоном</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb307\" onchange=\"updateProgress(this)\"><span>dev/build/preview — три ключевых команды Vite</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb308\" onchange=\"updateProgress(this)\"><span>vite.config.ts — настройка плагинов и сервера</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-vite-eslint","title":"ESLint + Prettier — качество кода важно 🔗","html":"<div class=\"block\" id=\"block-vite-eslint\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vite-eslint')\">ESLint + Prettier — качество кода <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># Установка</span>\n<span class=\"kw\">npm install -D eslint prettier stylelint stylelint-config-standard</span>\n<span class=\"kw\">npm install -D eslint-config-prettier</span>\n<span class=\"kw\">npm install -D @typescript-eslint/eslint-plugin</span>\n\n<span class=\"cm\">// .eslintrc.json</span>\n{\n  <span class=\"str\">\"extends\"</span>: [<span class=\"str\">\"eslint:recommended\"</span>, <span class=\"str\">\"prettier\"</span>],\n  <span class=\"str\">\"rules\"</span>: {\n    <span class=\"str\">\"no-unused-vars\"</span>: <span class=\"str\">\"warn\"</span>,\n    <span class=\"str\">\"no-console\"</span>: <span class=\"str\">\"off\"</span>\n  }\n}\n\n<span class=\"cm\">// .prettierrc</span>\n{\n  <span class=\"str\">\"semi\"</span>: <span class=\"kw\">true</span>,\n  <span class=\"str\">\"singleQuote\"</span>: <span class=\"kw\">true</span>,\n  <span class=\"str\">\"tabWidth\"</span>: <span class=\"num\">2</span>,\n  <span class=\"str\">\"printWidth\"</span>: <span class=\"num\">100</span>\n}\n\n<span class=\"cm\"># package.json scripts</span>\n<span class=\"str\">\"lint\"</span>: <span class=\"str\">\"eslint src --ext .ts,.tsx\"</span>,\n<span class=\"str\">\"format\"</span>: <span class=\"str\">\"prettier --write src/\"</span>,\n<span class=\"str\">\"lint:css\"</span>: <span class=\"str\">\"stylelint \\\"src/**/*.css\\\"\"</span></div>\n      <div class=\"explain\">\n        <strong>ESLint</strong> — находит ошибки и антипаттерны в коде. Можно настроить под команду.<br>\n        <strong>Prettier</strong> — автоформатирование. Конец споров о табах и запятых в команде.<br>\n        <strong>Stylelint</strong> — линтер для CSS/SCSS: ловит дубли, неизвестные свойства, неправильный порядок и случайные ошибки в стилях.<br>\n        <strong>-D</strong> — devDependency. Эти пакеты нужны только при разработке, не в продакшне.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb309\" onchange=\"updateProgress(this)\"><span>ESLint — линтер, находит ошибки и антипаттерны</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb310\" onchange=\"updateProgress(this)\"><span>Prettier — автоформатирование, .prettierrc конфиг</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb310a\" onchange=\"updateProgress(this)\"><span>Stylelint — линтер для CSS/SCSS, дополняет ESLint</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb311\" onchange=\"updateProgress(this)\"><span>npm scripts — lint и format в package.json</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-vite-env","title":"Переменные окружения (.env) важно 🔗","html":"<div class=\"block\" id=\"block-vite-env\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vite-env')\">Переменные окружения (.env) <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># .env файл (в корне проекта)</span>\nVITE_API_URL=https://api.example.com\nVITE_APP_NAME=MyApp\n<span class=\"cm\"># Всё что начинается с VITE_ — доступно в браузере</span>\n\n<span class=\"cm\"># .env.local — для локальных секретов (добавь в .gitignore!)</span>\nVITE_API_KEY=super_secret_key\n\n<span class=\"cm\">// Использование в коде</span>\n<span class=\"kw\">const</span> apiUrl = import.meta.env.VITE_API_URL;\n<span class=\"kw\">const</span> isDev = import.meta.env.DEV;   <span class=\"cm\">// true в dev режиме</span>\n<span class=\"kw\">const</span> isProd = import.meta.env.PROD; <span class=\"cm\">// true в production</span>\n\n<span class=\"cm\"># .gitignore — обязательно исключи!</span>\n.env.local\n.env.*.local\nnode_modules/\ndist/</div>\n      <div class=\"explain\">\n        <strong>VITE_</strong> — префикс обязателен! Без него переменная не попадёт в браузерный код.<br>\n        <strong>.env.local</strong> — никогда не коммить в git! Здесь хранятся API-ключи и токены.<br>\n        <strong>import.meta.env</strong> — специфика Vite. В старых Webpack-проектах часто встретишь <code>process.env.*</code>, но в новых Vite-проектах ориентируйся на <code>VITE_</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb312\" onchange=\"updateProgress(this)\"><span>VITE_ префикс — только такие переменные попадают в браузер</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb313\" onchange=\"updateProgress(this)\"><span>import.meta.env — доступ к env переменным в Vite</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb314\" onchange=\"updateProgress(this)\"><span>.env.local в .gitignore — защита секретов</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-vite-ssr-islands","title":"SSR, Islands и новые сборщики обзор 🔗","html":"<div class=\"block\" id=\"block-vite-ssr-islands\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vite-ssr-islands')\">SSR, Islands и новые сборщики <span class=\"badge rec\">обзор</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Это не надо учить первым делом. Но полезно понимать слова из вакансий: SSR, SSG, Islands, Rspack, Turbopack.</div>\n      <div class=\"code\"><span class=\"cm\">// CSR — обычный React/Vite в браузере</span>\nБраузер скачал JS → React построил страницу\n\n<span class=\"cm\">// SSR — сервер сразу отдаёт готовый HTML</span>\nЗапрос → сервер рендерит страницу → браузер быстрее видит контент\n\n<span class=\"cm\">// SSG — страницы собраны заранее</span>\nnpm run build → готовые HTML-файлы → очень быстрый хостинг\n\n<span class=\"cm\">// Islands Architecture — JS только там, где нужен</span>\nHeader = HTML\nArticle = HTML\nCartButton = интерактивный JS-остров\n\n<span class=\"cm\">// Современные инструменты</span>\nVite      — быстрый dev-сервер\nAstro     — islands + контентные сайты\nRspack    — быстрый webpack-compatible сборщик\nTurbopack — сборщик в экосистеме Next.js</div>\n      <div class=\"explain\">\n        <strong>CSR</strong> проще всего для старта: Vite + React. Минус — первый экран может ждать JS.<br>\n        <strong>SSR</strong> помогает SEO и скорости первого контента, но требует серверной части.<br>\n        <strong>Islands</strong> — идея Astro: большая часть страницы статичная, интерактивными становятся только нужные куски.<br>\n        <strong>Не прыгай слишком рано:</strong> сначала уверенный JS/React, потом SSR и архитектуры.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-vite-ssr-1\" onchange=\"updateProgress(this)\"><span>Понимаю разницу CSR, SSR и SSG</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-vite-ssr-2\" onchange=\"updateProgress(this)\"><span>Понимаю идею Islands: JS только для интерактивных частей</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-vite-ssr-3\" onchange=\"updateProgress(this)\"><span>Слышал про Astro, Rspack, Turbopack и понимаю зачем они нужны</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-career","lessons":[{"id":"block-career-stack","title":"Что реально требуют на рынке основа 🔗","html":"<div class=\"block\" id=\"block-career-stack\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-career-stack')\">Что реально требуют на рынке <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Анализ 500+ вакансий junior frontend на hh.ru — вот что работодатели пишут чаще всего.</div>\n      <div class=\"code\"><span class=\"cm\">// Требуется в 90%+ вакансий junior</span>\nHTML5 + CSS3 (Flexbox, Grid)\nJavaScript (ES6+)\nReact или Vue\nGit + GitHub\nАдаптивная вёрстка\n\n<span class=\"cm\">// Требуется в 60-80% вакансий</span>\nTypeScript\nnpm / Webpack / Vite\nREST API + fetch / axios\nБазовые знания Node.js\n\n<span class=\"cm\">// Плюс к резюме (не обязательно)</span>\nNext.js / Nuxt\nRedux / Zustand\nDocker (базово)\nUnit-тесты (Jest)</div>\n      <div class=\"explain\">\n        <strong>Главный совет:</strong> не учи всё сразу. Закрой HTML+CSS+JS+React+Git — этого хватит для первого оффера.<br>\n        <strong>TypeScript</strong> — добавь сразу после того как почувствуешь уверенность в JS. Это +20-30% к зарплате.<br>\n        <strong>Next.js</strong> — логичный следующий шаг после React. Очень востребован в 2024-2025.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb315\" onchange=\"updateProgress(this)\"><span>Знаю свой целевой стек для первой работы</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb316\" onchange=\"updateProgress(this)\"><span>Понимаю разницу между junior/middle требованиями</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-career-salary","title":"Зарплаты frontend-разработчиков важно 🔗","html":"<div class=\"block\" id=\"block-career-salary\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-career-salary')\">Зарплаты frontend-разработчиков <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Россия (Москва/удалёнка), 2024-2025</span>\nJunior (0-1 год):     50 000 — 120 000 ₽\nMiddle (1-3 года):   120 000 — 250 000 ₽\nSenior (3+ лет):     250 000 — 500 000+ ₽\n\n<span class=\"cm\">// Международный рынок (удалёнка, USD)</span>\nJunior:    $1 000 — $2 500/мес\nMiddle:    $2 500 — $5 000/мес\nSenior:    $5 000 — $12 000+/мес\n\n<span class=\"cm\">// Что поднимает зарплату быстрее всего</span>\n+ TypeScript          → +15-25%\n+ React + Next.js     → +20-30%\n+ Английский B2+      → +50-100% (международный рынок)\n+ Open Source вклад   → сильный сигнал для найма\n+ Pet-проекты с кодом → показывает реальный уровень</div>\n      <div class=\"explain\">\n        <strong>Важно:</strong> цифры примерные, сильно зависят от компании, города и конъюнктуры рынка.<br>\n        <strong>Английский</strong> — самый быстрый способ кратно увеличить доход. Даже B1 открывает международные вакансии.<br>\n        <strong>Смотри актуальные данные</strong> на hh.ru (раздел \"Зарплата\"), levels.fyi, glassdoor.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb317\" onchange=\"updateProgress(this)\"><span>Знаю рыночный диапазон для своего уровня</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb318\" onchange=\"updateProgress(this)\"><span>Знаю что конкретно поднимает мою стоимость</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-career-portfolio","title":"Портфолио — что реально работает основа 🔗","html":"<div class=\"block\" id=\"block-career-portfolio\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-career-portfolio')\">Портфолио — что реально работает <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// 3 проекта лучше чем 10 слабых</span>\n\n<span class=\"cm\">// Проект 1 — вёрстка (показывает базу)</span>\nТочная вёрстка макета из Figma\nАдаптивность на 3 брейкпоинтах\nАнимации, hover-эффекты\n→ Покажи: GitHub + живой деплой\n\n<span class=\"cm\">// Проект 2 — JS/React приложение</span>\nTodo / погода / новости / фильмы\nРабота с API (fetch + async/await)\nСостояние, роутинг, компоненты\n→ Покажи: GitHub + Vercel/Netlify\n\n<span class=\"cm\">// Проект 3 — что-то своё</span>\nРеальная проблема которую решаешь\nНеважно насколько просто — важна идея\n→ Покажи: GitHub + ссылка + README</div>\n      <div class=\"explain\">\n        <strong>Главная ошибка</strong> — портфолио без живых ссылок. Деплой на Vercel или GitHub Pages — обязательно.<br>\n        <strong>README</strong> — напиши что это, какие технологии, как запустить. Это показывает культуру разработки.<br>\n        <strong>Качество кода важнее количества</strong> — работодатели открывают GitHub и смотрят код.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb319\" onchange=\"updateProgress(this)\"><span>Есть минимум 2 проекта на GitHub с живыми ссылками</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb320\" onchange=\"updateProgress(this)\"><span>Каждый проект имеет нормальный README</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb321\" onchange=\"updateProgress(this)\"><span>Проекты задеплоены и открываются по ссылке</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-career-resume","title":"Резюме frontend-разработчика важно 🔗","html":"<div class=\"block\" id=\"block-career-resume\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-career-resume')\">Резюме frontend-разработчика <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Структура резюме (1 страница)</span>\n\n1. Имя + контакты\n   Email, GitHub, Telegram, город (или \"удалённо\")\n\n2. Стек (без воды)\n   JavaScript, TypeScript, React, HTML/CSS,\n   Git, REST API, Vite\n\n3. Опыт / Проекты (если нет работы)\n   Название проекта\n   Что сделал + какие технологии\n   Ссылка на GitHub и деплой\n\n4. Образование\n   Коротко, без лишнего\n\n<span class=\"cm\">// Частые ошибки в резюме</span>\n✗ \"Ответственный, коммуникабельный...\"  ← никто не читает\n✗ Фото в деловом костюме               ← необязательно\n✗ \"Знаю HTML/CSS\" без уточнения        ← слишком расплывчато\n✗ Резюме на 3 страницы                 ← максимум 1\n\n<span class=\"cm\">// Что работает</span>\n✓ Конкретные технологии и проекты\n✓ Ссылка на GitHub прямо в шапке\n✓ \"React, TypeScript — 1 год коммерческого опыта\"</div>\n      <div class=\"explain\">\n        <strong>Сервисы для резюме:</strong> hh.ru, LinkedIn, Notion (публичная страница).<br>\n        <strong>Главное правило</strong> — конкретика. Не \"знаю JavaScript\", а \"React + TypeScript, написал 3 проекта\".<br>\n        <strong>GitHub важнее резюме</strong> для junior — если там есть код, многие HR-ры даже не смотрят на остальное.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb322\" onchange=\"updateProgress(this)\"><span>Резюме готово, умещается на 1 страницу</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb323\" onchange=\"updateProgress(this)\"><span>В резюме есть ссылка на GitHub с проектами</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb324\" onchange=\"updateProgress(this)\"><span>Нет воды — только стек, проекты, контакты</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-career-interview","title":"Собеседование — как проходит и что спрашивают важно 🔗","html":"<div class=\"block\" id=\"block-career-interview\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-career-interview')\">Собеседование — как проходит и что спрашивают <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Типичные вопросы junior frontend</span>\n\n<span class=\"cm\">// HTML/CSS</span>\n- Разница между display:none и visibility:hidden?\n- Как работает специфичность CSS?\n- Что такое БЭМ?\n- Flexbox vs Grid — когда что?\n\n<span class=\"cm\">// JavaScript</span>\n- Разница let/const/var?\n- Что такое замыкание (closure)?\n- Event loop — как работает?\n- Promise vs async/await?\n- Разница == и ===?\n\n<span class=\"cm\">// React</span>\n- Жизненный цикл компонента\n- Зачем key в списках?\n- useState vs useReducer?\n- Что такое props drilling?\n\n<span class=\"cm\">// Практика (живое кодирование)</span>\n- Реверс строки\n- Убрать дубли из массива\n- Написать простой компонент\n- Сделать fetch и показать данные</div>\n      <div class=\"explain\">\n        <strong>Живое кодирование</strong> — не паникуй если не знаешь ответ. Думай вслух — это важнее правильного ответа.<br>\n        <strong>Вопросы к компании</strong> — всегда готовь 2-3 вопроса: стек, код-ревью, как выглядит типичный день.<br>\n        <strong>После отказа</strong> — попроси фидбек. Это лучший способ понять что подтянуть.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb325\" onchange=\"updateProgress(this)\"><span>Могу ответить на базовые вопросы по JS без гугла</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb326\" onchange=\"updateProgress(this)\"><span>Практиковал живое кодирование (leetcode easy / codewars)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb327\" onchange=\"updateProgress(this)\"><span>Готовил вопросы к компании</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-nexus","lessons":[{"id":"block-nexus-main","title":"Nexus Notes база знаний 🔗","html":"<div class=\"block\" id=\"block-nexus-main\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nexus-main')\">Nexus Notes <span class=\"badge good\">база знаний</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Используй для заметок по фронтенду: DOM, localStorage, идеи для Kwork, куски проектов. Чтобы связать заметки, пиши <code>[[DOM]]</code> или <code>[[Мой проект]]</code>.</div>\n      <div class=\"nexus-shell\">\n        <aside class=\"nexus-panel\">\n          <div class=\"nexus-actions\"><button class=\"nexus-btn primary\" onclick=\"nexusCreateNote()\">+ Заметка</button><button class=\"nexus-btn\" onclick=\"nexusExportNotes()\">Экспорт</button><button class=\"nexus-btn\" onclick=\"nexusImportNotes()\">Импорт</button></div>\n          <input class=\"nexus-search\" id=\"nexusSearch\" placeholder=\"Поиск заметок...\" oninput=\"nexusRenderList()\">\n          <div class=\"nexus-list\" id=\"nexusList\"></div>\n        </aside>\n        <main class=\"nexus-panel\">\n          <div class=\"nexus-actions\"><button class=\"nexus-btn primary\" onclick=\"nexusSaveActive()\">Сохранить</button><button class=\"nexus-btn\" onclick=\"nexusCreateLinkedNotes()\">Создать недостающие связи</button><button class=\"nexus-btn danger\" onclick=\"nexusDeleteActive()\">Удалить</button></div>\n          <input class=\"nexus-title-input\" id=\"nexusTitle\" placeholder=\"Название заметки\" oninput=\"nexusUpdateDraft()\">\n          <div class=\"nexus-editor-grid\" style=\"margin-top:12px;\"><textarea class=\"nexus-textarea\" id=\"nexusBody\" placeholder=\"Напиши заметку. Пример: сегодня я понял [[localStorage]] и [[DOM]].\" oninput=\"nexusUpdateDraft()\"></textarea><div class=\"nexus-preview\" id=\"nexusPreview\"></div></div>\n          <div class=\"nexus-graph\" id=\"nexusGraph\"></div>\n        </main>\n      </div>\n    </div>\n  "}]},{"id":"sec-ai","lessons":[{"id":"block-ai-default","title":"По умолчанию: Llama 3.3 70B встроено","html":"<div class=\"block\" id=\"block-ai-default\">\n      <div class=\"block-title\">По умолчанию: Llama 3.3 70B <span class=\"badge must\">встроено</span></div>\n      <div class=\"tip\">Без какой-либо настройки ИИ-помощник уже работает на бесплатной модели Llama 3.3 70B (через Groq). Просто открой чат кнопкой 💬 в правом нижнем углу или выдели текст на странице.</div>\n    </div>\n\n    "},{"id":"block-ai-custom","title":"⚙ Своя модель и API ключ опционально 🔗","html":"<div class=\"block\" id=\"block-ai-custom\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ai-custom')\">⚙ Своя модель и API ключ <span class=\"badge good\">опционально</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Поддерживаются любые OpenAI-совместимые провайдеры: <b>Groq</b>, <b>OpenRouter</b>, <b>OpenAI</b>, <b>Together.ai</b>, <b>Mistral</b> и другие. Ключ хранится локально в твоём браузере (localStorage) и никуда не отправляется кроме выбранного провайдера.</div>\n\n      <div style=\"background:#0d1117;border-radius:12px;padding:20px;margin-top:12px;border:1px solid #30363d;\">\n\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🔌 Провайдер</label>\n          <select id=\"ai-provider\" onchange=\"aiProviderPreset()\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;cursor:pointer;\">\n            <option value=\"https://api.groq.com/openai/v1\">Groq</option>\n            <option value=\"https://openrouter.ai/api/v1\">OpenRouter</option>\n            <option value=\"https://api.openai.com/v1\">OpenAI</option>\n            <option value=\"https://api.together.xyz/v1\">Together.ai</option>\n            <option value=\"https://api.mistral.ai/v1\">Mistral</option>\n            <option value=\"custom\">Другой (укажу URL вручную)</option>\n          </select>\n        </div>\n\n        <div style=\"margin-bottom:12px;\" id=\"ai-baseurl-wrap\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🌐 Base URL</label>\n          <input id=\"ai-baseurl\" type=\"text\" placeholder=\"https://api.groq.com/openai/v1\" value=\"https://api.groq.com/openai/v1\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n        </div>\n\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🔑 API ключ</label>\n          <input id=\"ai-apikey\" type=\"password\" placeholder=\"sk-... / gsk_... / sk-or-v1-...\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n        </div>\n\n        <div style=\"margin-bottom:16px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🤖 Название модели</label>\n          <input id=\"ai-modelname\" type=\"text\" placeholder=\"например: llama-3.3-70b-versatile, gpt-4o-mini, deepseek/deepseek-r1:free\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n          <div style=\"font-size:11px;color:#6e7681;margin-top:4px;\">Точное имя модели как требует выбранный провайдер (смотри его документацию)</div>\n        </div>\n\n        <div style=\"display:flex;gap:8px;\">\n          <button onclick=\"aiSaveCustomConfig()\" style=\"flex:1;padding:11px;background:linear-gradient(135deg,#7c3aed,#a855f7);color:#fff;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:opacity .2s;\" onmouseover=\"this.style.opacity='.85'\" onmouseout=\"this.style.opacity='1'\">\n            💾 Сохранить\n          </button>\n          <button onclick=\"aiClearCustomConfig()\" style=\"padding:11px 16px;background:#30363d;color:#e6edf3;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:background .2s;\" onmouseover=\"this.style.background='#3d444d'\" onmouseout=\"this.style.background='#30363d'\">\n            🗑 Очистить\n          </button>\n        </div>\n\n        <div id=\"ai-config-status\" style=\"margin-top:12px;font-size:13px;display:none;padding:10px 14px;border-radius:8px;\"></div>\n\n        <div id=\"ai-saved-models-wrap\" style=\"margin-top:16px;display:none;\">\n          <div style=\"font-size:12px;color:#8b949e;margin-bottom:8px;font-weight:600;\">💾 Сохранённые модели</div>\n          <div id=\"ai-saved-models-list\" style=\"display:flex;flex-direction:column;gap:6px;\"></div>\n        </div>\n      </div>\n    </div>\n\n    "},{"id":"block-ai-examples","title":"Примеры настроек по провайдерам справка 🔗","html":"<div class=\"block\" id=\"block-ai-examples\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ai-examples')\">Примеры настроек по провайдерам <span class=\"badge\">справка</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Groq — бесплатно, очень быстро</span>\nBase URL: https://api.groq.com/openai/v1\nМодель:   llama-3.3-70b-versatile\nКлюч:     console.groq.com/keys\n\n<span class=\"cm\">// OpenRouter — много моделей, есть бесплатные</span>\nBase URL: https://openrouter.ai/api/v1\nМодель:   deepseek/deepseek-r1:free\nКлюч:     openrouter.ai/keys\n\n<span class=\"cm\">// OpenAI — платно</span>\nBase URL: https://api.openai.com/v1\nМодель:   gpt-4o-mini\nКлюч:     platform.openai.com/api-keys\n\n<span class=\"cm\">// Mistral — есть бесплатный тариф</span>\nBase URL: https://api.mistral.ai/v1\nМодель:   mistral-small-latest\nКлюч:     console.mistral.ai/api-keys</div>\n      <div class=\"explain\">\n        <strong>Где взять ключ:</strong> зарегистрируйся у провайдера → раздел API Keys → создай новый ключ.<br>\n        <strong>Безопасность:</strong> ключ хранится в localStorage только твоего браузера. Никому не передаётся кроме выбранного провайдера напрямую.<br>\n        <strong>После сохранения</strong> выбери «⚙ Своя модель» в выпадающем списке в окне чата.\n      </div>\n    </div>\n\n    "},{"id":"block-ai-prompt-engineering","title":"Prompt Engineering для обучения коду практика 🔗","html":"<div class=\"block\" id=\"block-ai-prompt-engineering\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ai-prompt-engineering')\">Prompt Engineering для обучения коду <span class=\"badge good\">практика</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Хороший промпт — это не \"сделай красиво\", а понятная задача: роль, контекст, ограничения, формат ответа и критерий проверки.</div>\n      <div class=\"code\"><span class=\"cm\">// Плохой запрос</span>\nСделай мне сайт.\n\n<span class=\"cm\">// Хороший запрос</span>\nТы frontend-ментор. Я учу HTML/CSS/JS.\nЗадача: помоги сделать адаптивную карточку товара.\nОграничения: без фреймворков, только HTML/CSS, объясняй коротко.\nФормат: сначала план на 3 шага, потом маленький кусок кода.\nПроверка: скажи, какие ошибки чаще всего бывают в такой верстке.\n\n<span class=\"cm\">// Для проверки своего кода</span>\nПроверь этот код как mentor: найди баги, лишнюю сложность,\nпроблемы адаптива и предложи улучшения без полного переписывания.</div>\n      <div class=\"explain\">\n        <strong>Роль</strong> задаёт стиль ответа: ментор, ревьюер, интервьюер, заказчик.<br>\n        <strong>Контекст</strong> экономит время: что ты уже сделал, какие файлы есть, что именно не работает.<br>\n        <strong>Ограничения</strong> защищают от лишней сложности: без React, без библиотек, только подсказки, не полный ответ.<br>\n        <strong>Проверка</strong> заставляет ИИ искать ошибки, а не просто соглашаться.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-ai-prompt-1\" onchange=\"updateProgress(this)\"><span>Умею давать ИИ роль, контекст и ограничения</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-ai-prompt-2\" onchange=\"updateProgress(this)\"><span>Прошу проверку кода без полного переписывания</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-ai-prompt-3\" onchange=\"updateProgress(this)\"><span>Использую ИИ как ментора, а не как кнопку \"сделай всё\"</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-refactor","lessons":[{"id":"block-refactor-smells","title":"Code Smells — признаки что пора рефакторить основа 🔗","html":"<div class=\"block\" id=\"block-refactor-smells\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-refactor-smells')\">Code Smells — признаки что пора рефакторить <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Code Smell — не баг, код работает. Но это сигнал что структура плохая и в будущем создаст проблемы.</div>\n      <div class=\"code\"><span class=\"cm\">// 1. Long Method — слишком длинная функция</span>\n<span class=\"kw\">function</span> <span class=\"fn\">processOrder</span>(order) {\n  <span class=\"cm\">// 80 строк кода делающих validation + calculation + saving + email...</span>\n} <span class=\"cm\">// ❌ Слишком много обязанностей</span>\n\n<span class=\"cm\">// 2. Duplicate Code — повторяющийся код</span>\n<span class=\"kw\">function</span> <span class=\"fn\">getUserName</span>(u) { <span class=\"kw\">return</span> u.first + <span class=\"str\">' '</span> + u.last; }\n<span class=\"kw\">function</span> <span class=\"fn\">getFullName</span>(u)  { <span class=\"kw\">return</span> u.first + <span class=\"str\">' '</span> + u.last; } <span class=\"cm\">// ❌ Дубликат</span>\n\n<span class=\"cm\">// 3. Magic Numbers — числа без объяснения</span>\n<span class=\"kw\">if</span> (user.age &gt; <span class=\"num\">17</span>) { <span class=\"cm\">/* ... */</span> } <span class=\"cm\">// ❌ Что значит 17?</span>\n<span class=\"kw\">if</span> (user.age &gt;= ADULT_AGE) { <span class=\"cm\">/* ... */</span> } <span class=\"cm\">// ✅ Понятно</span>\n\n<span class=\"cm\">// 4. Large Class — класс делает слишком много</span>\n<span class=\"kw\">class</span> <span class=\"fn\">User</span> { <span class=\"cm\">/* auth + profile + orders + notifications + ... */</span> }\n\n<span class=\"cm\">// 5. Long Parameter List</span>\n<span class=\"kw\">function</span> <span class=\"fn\">createUser</span>(name, email, age, city, country, phone, role) {} <span class=\"cm\">// ❌</span>\n<span class=\"kw\">function</span> <span class=\"fn\">createUser</span>(userData) {} <span class=\"cm\">// ✅ Передавай объект</span></div>\n      <div class=\"explain\">\n        <strong>Long Method</strong> — если функция не помещается на экран, скорее всего делает слишком много. Раздели на части.<br>\n        <strong>Magic Numbers</strong> — выноси в именованные константы. Код должен объяснять сам себя.<br>\n        <strong>Long Parameter List</strong> — больше 3 параметров — повод передавать объект.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb328\" onchange=\"updateProgress(this)\"><span>Long Method — слишком длинные функции делающие много всего</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb329\" onchange=\"updateProgress(this)\"><span>Duplicate Code — повторяющийся код в разных местах</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb330\" onchange=\"updateProgress(this)\"><span>Magic Numbers — числа без объяснения, нужны константы</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-refactor-dry-kiss","title":"DRY, KISS, YAGNI — главные принципы основа 🔗","html":"<div class=\"block\" id=\"block-refactor-dry-kiss\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-refactor-dry-kiss')\">DRY, KISS, YAGNI — главные принципы <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// DRY — Don't Repeat Yourself</span>\n<span class=\"cm\">// ❌ До</span>\n<span class=\"kw\">const</span> tax1 = price1 * <span class=\"num\">0.2</span>;\n<span class=\"kw\">const</span> tax2 = price2 * <span class=\"num\">0.2</span>;\n\n<span class=\"cm\">// ✅ После</span>\n<span class=\"kw\">const</span> calculateTax = price =&gt; price * TAX_RATE;\n\n<span class=\"cm\">// KISS — Keep It Simple, Stupid</span>\n<span class=\"cm\">// ❌ Слишком умно</span>\n<span class=\"kw\">const</span> isEven = n =&gt; !(n &amp; <span class=\"num\">1</span>);\n\n<span class=\"cm\">// ✅ Просто и понятно</span>\n<span class=\"kw\">const</span> isEven = n =&gt; n % <span class=\"num\">2</span> === <span class=\"num\">0</span>;\n\n<span class=\"cm\">// YAGNI — You Aren't Gonna Need It</span>\n<span class=\"cm\">// ❌ \"А вдруг понадобится в будущем\"</span>\n<span class=\"kw\">function</span> <span class=\"fn\">processData</span>(data, options = {}) {\n  <span class=\"kw\">const</span> { format, validate, transform, cache, retry, timeout, logger } = options;\n  <span class=\"cm\">// 7 опций, используется только format</span>\n}\n\n<span class=\"cm\">// ✅ Добавляй сложность когда она РЕАЛЬНО нужна</span>\n<span class=\"kw\">function</span> <span class=\"fn\">processData</span>(data, format) { <span class=\"cm\">/* ... */</span> }</div>\n      <div class=\"explain\">\n        <strong>DRY</strong> — если копируешь код больше одного раза, выноси в функцию.<br>\n        <strong>KISS</strong> — пиши код для людей, не для компьютера. Читаемость важнее \"крутости\".<br>\n        <strong>YAGNI</strong> — не добавляй функциональность \"на будущее\". Когда понадобится — добавишь.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb331\" onchange=\"updateProgress(this)\"><span>DRY — не повторяй один и тот же код</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb332\" onchange=\"updateProgress(this)\"><span>KISS — простой код лучше \"умного\"</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb333\" onchange=\"updateProgress(this)\"><span>YAGNI — не пиши код \"на будущее\" заранее</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-refactor-extract","title":"Extract Function и Extract Variable важно 🔗","html":"<div class=\"block\" id=\"block-refactor-extract\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-refactor-extract')\">Extract Function и Extract Variable <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// ❌ До рефакторинга</span>\n<span class=\"kw\">function</span> <span class=\"fn\">printInvoice</span>(order) {\n  console.<span class=\"fn\">log</span>(<span class=\"str\">`Заказ #${order.id}`</span>);\n  <span class=\"kw\">let</span> total = <span class=\"num\">0</span>;\n  <span class=\"kw\">for</span> (<span class=\"kw\">const</span> item <span class=\"kw\">of</span> order.items) {\n    total += item.price * item.qty * (<span class=\"num\">1</span> - item.discount);\n  }\n  console.<span class=\"fn\">log</span>(<span class=\"str\">`Итого: ${total}`</span>);\n}\n\n<span class=\"cm\">// ✅ После — Extract Function + Extract Variable</span>\n<span class=\"kw\">function</span> <span class=\"fn\">calculateItemTotal</span>(item) {\n  <span class=\"kw\">const</span> discountMultiplier = <span class=\"num\">1</span> - item.discount; <span class=\"cm\">// Extract Variable</span>\n  <span class=\"kw\">return</span> item.price * item.qty * discountMultiplier;\n}\n\n<span class=\"kw\">function</span> <span class=\"fn\">calculateOrderTotal</span>(order) { <span class=\"cm\">// Extract Function</span>\n  <span class=\"kw\">return</span> order.items.<span class=\"fn\">reduce</span>((sum, item) =&gt; sum + <span class=\"fn\">calculateItemTotal</span>(item), <span class=\"num\">0</span>);\n}\n\n<span class=\"kw\">function</span> <span class=\"fn\">printInvoice</span>(order) {\n  console.<span class=\"fn\">log</span>(<span class=\"str\">`Заказ #${order.id}`</span>);\n  console.<span class=\"fn\">log</span>(<span class=\"str\">`Итого: ${calculateOrderTotal(order)}`</span>);\n} <span class=\"cm\">// Теперь каждая функция делает ровно одну вещь</span></div>\n      <div class=\"explain\">\n        <strong>Extract Function</strong> — выноси кусок логики в отдельную функцию с понятным именем.<br>\n        <strong>Extract Variable</strong> — давай имя сложному выражению, чтобы было понятно что оно значит.<br>\n        <strong>Результат</strong> — каждая функция читается как предложение и легко тестируется отдельно.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb334\" onchange=\"updateProgress(this)\"><span>Extract Function — выделение логики в отдельную функцию</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb335\" onchange=\"updateProgress(this)\"><span>Extract Variable — именование сложных выражений</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb336\" onchange=\"updateProgress(this)\"><span>Каждая функция делает одну вещь (Single Responsibility)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-refactor-conditionals","title":"Рефакторинг условий важно 🔗","html":"<div class=\"block\" id=\"block-refactor-conditionals\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-refactor-conditionals')\">Рефакторинг условий <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Вложенные if — сложно читать</span>\n<span class=\"kw\">function</span> <span class=\"fn\">getDiscount</span>(user) {\n  <span class=\"kw\">if</span> (user.isPremium) {\n    <span class=\"kw\">if</span> (user.years &gt; <span class=\"num\">2</span>) {\n      <span class=\"kw\">return</span> <span class=\"num\">0.3</span>;\n    } <span class=\"kw\">else</span> {\n      <span class=\"kw\">return</span> <span class=\"num\">0.2</span>;\n    }\n  } <span class=\"kw\">else</span> {\n    <span class=\"kw\">return</span> <span class=\"num\">0</span>;\n  }\n}\n\n<span class=\"cm\">// ✅ Early Return — выходим сразу, без вложенности</span>\n<span class=\"kw\">function</span> <span class=\"fn\">getDiscount</span>(user) {\n  <span class=\"kw\">if</span> (!user.isPremium) <span class=\"kw\">return</span> <span class=\"num\">0</span>;\n  <span class=\"kw\">if</span> (user.years &gt; <span class=\"num\">2</span>) <span class=\"kw\">return</span> <span class=\"num\">0.3</span>;\n  <span class=\"kw\">return</span> <span class=\"num\">0.2</span>;\n}\n\n<span class=\"cm\">// ✅ Replace Conditional with Polymorphism (когда условий много)</span>\n<span class=\"kw\">const</span> discountStrategies = {\n  premium2years: () =&gt; <span class=\"num\">0.3</span>,\n  premium: () =&gt; <span class=\"num\">0.2</span>,\n  regular: () =&gt; <span class=\"num\">0</span>\n};</div>\n      <div class=\"explain\">\n        <strong>Early Return</strong> — избавляет от вложенных if-else. Код становится плоским и читаемым.<br>\n        <strong>Guard Clauses</strong> — проверки в начале функции, которые сразу выходят если условие не выполнено.<br>\n        <strong>Полиморфизм вместо if/switch</strong> — когда условий становится много (5+), таблица/объект чище.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb337\" onchange=\"updateProgress(this)\"><span>Early Return — убираем вложенность через ранний выход</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb338\" onchange=\"updateProgress(this)\"><span>Guard Clauses — проверки в начале функции</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb339\" onchange=\"updateProgress(this)\"><span>Замена больших if/switch на объект-словарь</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-refactor-when","title":"Когда рефакторить (и когда не стоит) знать 🔗","html":"<div class=\"block\" id=\"block-refactor-when\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-refactor-when')\">Когда рефакторить (и когда не стоит) <span class=\"badge\">знать</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// ✅ Хорошее время для рефакторинга:</span>\n- Перед добавлением новой фичи в грязный код\n- Когда видишь Code Smell дважды (Rule of Three)\n- После того как тесты зелёные (рефактори с уверенностью)\n- Code review — коллега указал на проблему\n\n<span class=\"cm\">// ❌ Плохое время для рефакторинга:</span>\n- Прямо перед дедлайном\n- Когда нет тестов и нельзя проверить что не сломал\n- \"Просто потому что не нравится стиль\" без причины\n- Если код работает и трогать его не нужно (legacy без изменений)\n\n<span class=\"cm\">// Правило трёх (Rule of Three)</span>\n<span class=\"cm\">// 1-й раз: просто напиши код</span>\n<span class=\"cm\">// 2-й раз: скопировал похожее — это ОК, отметь дубликат</span>\n<span class=\"cm\">// 3-й раз: повторилось → теперь рефактори в общую функцию</span></div>\n      <div class=\"explain\">\n        <strong>Rule of Three</strong> — не торопись абстрагировать с первого повторения. На третий раз — точно рефактори.<br>\n        <strong>Маленькие шаги</strong> — рефактори небольшими безопасными изменениями, тестируя после каждого.<br>\n        <strong>Тесты — твоя защита</strong> — без тестов рефакторинг превращается в русскую рулетку.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb340\" onchange=\"updateProgress(this)\"><span>Rule of Three — рефактори после третьего повторения</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb341\" onchange=\"updateProgress(this)\"><span>Понимаю когда НЕ стоит рефакторить</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb342\" onchange=\"updateProgress(this)\"><span>Рефакторю маленькими шагами с проверкой</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-links","lessons":[{"id":"block-links-animation","title":"Анимации и визуальные эффекты 🔗 ссылки","html":"<div class=\"block\" id=\"block-links-animation\">\n      <div class=\"block-title\">Анимации и визуальные эффекты <span class=\"badge good\">🔗 ссылки</span></div>\n      <div style=\"display:flex;flex-direction:column;gap:10px;margin-top:8px;\">\n\n        <a href=\"https://animejs.com\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#6366f1'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">⚡</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Anime.js — animejs.com</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Лучшая JS-библиотека для анимаций. Лёгкая, мощная, понятный API. Анимируй CSS, SVG, DOM и JS объекты одинаково просто.</div>\n            <div style=\"margin-top:6px;display:flex;gap:6px;flex-wrap:wrap;\">\n              <span style=\"background:#4f46e5;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">JavaScript</span>\n              <span style=\"background:#0891b2;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">Анимации</span>\n              <span style=\"background:#16a34a;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">Бесплатно</span>\n            </div>\n          </div>\n        </a>\n\n        <a href=\"https://gsap.com\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#22c55e'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">🟢</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">GSAP — gsap.com</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Профессиональный стандарт анимаций. Используется на крупнейших сайтах. Timeline, ScrollTrigger, морфинг SVG.</div>\n            <div style=\"margin-top:6px;display:flex;gap:6px;flex-wrap:wrap;\">\n              <span style=\"background:#15803d;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">JavaScript</span>\n              <span style=\"background:#0891b2;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">Scroll</span>\n              <span style=\"background:#9333ea;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">SVG</span>\n            </div>\n          </div>\n        </a>\n\n        <a href=\"https://motion.dev\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#f59e0b'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">🎭</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Motion — motion.dev</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Framer Motion для React. Декларативные анимации прямо в JSX. Стандарт для React-проектов.</div>\n            <div style=\"margin-top:6px;display:flex;gap:6px;flex-wrap:wrap;\">\n              <span style=\"background:#0891b2;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">React</span>\n              <span style=\"background:#4f46e5;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">Декларативно</span>\n            </div>\n          </div>\n        </a>\n      </div>\n    </div>\n\n    "},{"id":"block-links-css-tools","title":"CSS инструменты 🔗 ссылки","html":"<div class=\"block\" id=\"block-links-css-tools\">\n      <div class=\"block-title\">CSS инструменты <span class=\"badge good\">🔗 ссылки</span></div>\n      <div style=\"display:flex;flex-direction:column;gap:10px;margin-top:8px;\">\n\n        <a href=\"https://uiverse.io\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#8b5cf6'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">🎨</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">UIverse — uiverse.io</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Огромная библиотека CSS компонентов — кнопки, карточки, инпуты, лоадеры. Всё бесплатно и с кодом.</div>\n          </div>\n        </a>\n\n        <a href=\"https://cssgradient.io\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#ec4899'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">🌈</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">CSS Gradient — cssgradient.io</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Визуальный генератор градиентов. Копируешь готовый CSS в один клик.</div>\n          </div>\n        </a>\n\n        <a href=\"https://cubic-bezier.com\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#06b6d4'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">📐</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Cubic Bezier — cubic-bezier.com</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Визуальный редактор кривых анимации. Незаменим для настройки transition и animation timing.</div>\n          </div>\n        </a>\n      </div>\n    </div>\n\n    "},{"id":"block-links-dev-tools","title":"Инструменты разработчика 🔗 ссылки","html":"<div class=\"block\" id=\"block-links-dev-tools\">\n      <div class=\"block-title\">Инструменты разработчика <span class=\"badge good\">🔗 ссылки</span></div>\n      <div style=\"display:flex;flex-direction:column;gap:10px;margin-top:8px;\">\n\n        <a href=\"https://caniuse.com\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#f97316'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">🌐</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Can I Use — caniuse.com</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Проверяй поддержку CSS и JS фич в браузерах. Открывай перед тем как использовать что-то новое.</div>\n          </div>\n        </a>\n\n        <a href=\"https://bundlephobia.com\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#ef4444'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">📦</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Bundlephobia — bundlephobia.com</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Узнай вес npm-пакета до установки. Помогает не раздувать бандл лишними зависимостями.</div>\n          </div>\n        </a>\n\n        <a href=\"https://ray.so\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#8b5cf6'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">📸</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Ray.so — ray.so</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Красивые скриншоты кода для портфолио, README и соцсетей. Бесплатно, без регистрации.</div>\n          </div>\n        </a>\n      </div>\n    </div>\n\n\n\n\n  "}]},{"id":"sec-algo","lessons":[{"id":"block-algo-complexity","title":"Big O — сложность алгоритмов основа 🔗","html":"<div class=\"block\" id=\"block-algo-complexity\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-complexity')\">Big O — сложность алгоритмов <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Big O описывает как растёт время выполнения при росте данных. Это язык на котором говорят про эффективность алгоритмов.</div>\n      <div class=\"code\"><span class=\"cm\">// O(1) — константное время (лучшее)</span>\n<span class=\"kw\">const</span> getFirst = arr =&gt; arr[<span class=\"num\">0</span>]; <span class=\"cm\">// всегда 1 операция</span>\n\n<span class=\"cm\">// O(n) — линейное время</span>\n<span class=\"kw\">const</span> findMax = arr =&gt; {\n  <span class=\"kw\">let</span> max = arr[<span class=\"num\">0</span>];\n  <span class=\"kw\">for</span> (<span class=\"kw\">const</span> x <span class=\"kw\">of</span> arr) <span class=\"kw\">if</span> (x &gt; max) max = x;\n  <span class=\"kw\">return</span> max;\n}; <span class=\"cm\">// n операций при n элементах</span>\n\n<span class=\"cm\">// O(n²) — квадратичное (плохо для больших данных)</span>\n<span class=\"kw\">function</span> <span class=\"fn\">bubbleSort</span>(arr) {\n  <span class=\"kw\">for</span> (<span class=\"kw\">let</span> i = <span class=\"num\">0</span>; i &lt; arr.length; i++)\n    <span class=\"kw\">for</span> (<span class=\"kw\">let</span> j = <span class=\"num\">0</span>; j &lt; arr.length - i; j++)\n      <span class=\"kw\">if</span> (arr[j] &gt; arr[j+<span class=\"num\">1</span>]) [arr[j], arr[j+<span class=\"num\">1</span>]] = [arr[j+<span class=\"num\">1</span>], arr[j]];\n  <span class=\"kw\">return</span> arr;\n}\n\n<span class=\"cm\">// O(log n) — логарифмическое (очень быстро)</span>\n<span class=\"cm\">// Бинарный поиск: делим пополам на каждом шаге</span>\n\n<span class=\"cm\">// Шпаргалка сложностей</span>\n<span class=\"cm\">// Array.push/pop     → O(1)</span>\n<span class=\"cm\">// Array.includes     → O(n)</span>\n<span class=\"cm\">// Array.sort         → O(n log n)</span>\n<span class=\"cm\">// Object lookup      → O(1)</span></div>\n      <div class=\"explain\">\n        <strong>O(1)</strong> — идеально. Не зависит от размера данных.<br>\n        <strong>O(n)</strong> — нормально. Растёт линейно с данными.<br>\n        <strong>O(n²)</strong> — осторожно. При 1000 элементах = 1 000 000 операций.<br>\n        <strong>Главное правило:</strong> если видишь цикл внутри цикла — это скорее всего O(n²).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb343\" onchange=\"updateProgress(this)\"><span>O(1), O(n), O(n²), O(log n) — понимаю разницу</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb344\" onchange=\"updateProgress(this)\"><span>Знаю сложность базовых операций с массивами и объектами</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-algo-array","title":"Задачи на массивы — топ на собесах основа 🔗","html":"<div class=\"block\" id=\"block-algo-array\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-array')\">Задачи на массивы — топ на собесах <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// 1. Убрать дубликаты</span>\n<span class=\"kw\">const</span> unique = arr =&gt; [...<span class=\"kw\">new</span> Set(arr)];\n<span class=\"fn\">unique</span>([<span class=\"num\">1</span>,<span class=\"num\">2</span>,<span class=\"num\">2</span>,<span class=\"num\">3</span>]); <span class=\"cm\">// [1,2,3]</span>\n\n<span class=\"cm\">// 2. Сумма элементов</span>\n<span class=\"kw\">const</span> sum = arr =&gt; arr.<span class=\"fn\">reduce</span>((a, b) =&gt; a + b, <span class=\"num\">0</span>);\n\n<span class=\"cm\">// 3. Развернуть массив (без reverse)</span>\n<span class=\"kw\">const</span> rev = arr =&gt; arr.<span class=\"fn\">reduceRight</span>((acc, x) =&gt; [...acc, x], []);\n\n<span class=\"cm\">// 4. Найти два числа с суммой N (Two Sum)</span>\n<span class=\"kw\">function</span> <span class=\"fn\">twoSum</span>(nums, target) {\n  <span class=\"kw\">const</span> map = <span class=\"kw\">new</span> Map();\n  <span class=\"kw\">for</span> (<span class=\"kw\">let</span> i = <span class=\"num\">0</span>; i &lt; nums.length; i++) {\n    <span class=\"kw\">const</span> diff = target - nums[i];\n    <span class=\"kw\">if</span> (map.<span class=\"fn\">has</span>(diff)) <span class=\"kw\">return</span> [map.<span class=\"fn\">get</span>(diff), i];\n    map.<span class=\"fn\">set</span>(nums[i], i);\n  }\n} <span class=\"cm\">// O(n) вместо O(n²) — используем Map</span>\n\n<span class=\"cm\">// 5. Группировка по свойству</span>\n<span class=\"kw\">const</span> users = [{role:<span class=\"str\">'admin'</span>},{role:<span class=\"str\">'user'</span>},{role:<span class=\"str\">'admin'</span>}];\n<span class=\"kw\">const</span> grouped = users.<span class=\"fn\">reduce</span>((acc, u) =&gt; {\n  (acc[u.role] ??= []).<span class=\"fn\">push</span>(u);\n  <span class=\"kw\">return</span> acc;\n}, {});</div>\n      <div class=\"explain\">\n        <strong>Set</strong> — структура данных без дубликатов. Lookup O(1).<br>\n        <strong>Map</strong> — как объект, но ключом может быть что угодно. Используй для оптимизации поиска.<br>\n        <strong>TwoSum с Map</strong> — классический пример как Map превращает O(n²) в O(n).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb345\" onchange=\"updateProgress(this)\"><span>Set — убрать дубликаты из массива</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb346\" onchange=\"updateProgress(this)\"><span>reduce — сумма, группировка, накопление</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb347\" onchange=\"updateProgress(this)\"><span>Map для оптимизации — O(n) вместо O(n²)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-algo-string","title":"Задачи на строки важно 🔗","html":"<div class=\"block\" id=\"block-algo-string\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-string')\">Задачи на строки <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// 1. Палиндром</span>\n<span class=\"kw\">const</span> isPalin = s =&gt; s === [...s].<span class=\"fn\">reverse</span>().<span class=\"fn\">join</span>(<span class=\"str\">''</span>);\n\n<span class=\"cm\">// 2. Анаграммы</span>\n<span class=\"kw\">const</span> isAnagram = (a, b) =&gt;\n  [...a].<span class=\"fn\">sort</span>().<span class=\"fn\">join</span>(<span class=\"str\">''</span>) === [...b].<span class=\"fn\">sort</span>().<span class=\"fn\">join</span>(<span class=\"str\">''</span>);\n\n<span class=\"cm\">// 3. Реверс строки</span>\n<span class=\"kw\">const</span> reverse = s =&gt; [...s].<span class=\"fn\">reverse</span>().<span class=\"fn\">join</span>(<span class=\"str\">''</span>);\n\n<span class=\"cm\">// 4. Количество каждого символа</span>\n<span class=\"kw\">const</span> <span class=\"fn\">charCount</span> = s =&gt;\n  [...s].<span class=\"fn\">reduce</span>((acc, c) =&gt; ({ ...acc, [c]: (acc[c] || <span class=\"num\">0</span>) + <span class=\"num\">1</span> }), {});\n\n<span class=\"cm\">// 5. Первый неповторяющийся символ</span>\n<span class=\"kw\">const</span> <span class=\"fn\">firstUniq</span> = s =&gt; {\n  <span class=\"kw\">const</span> cnt = <span class=\"fn\">charCount</span>(s);\n  <span class=\"kw\">return</span> [...s].<span class=\"fn\">find</span>(c =&gt; cnt[c] === <span class=\"num\">1</span>) ?? <span class=\"str\">''</span>;\n};</div>\n      <div class=\"explain\">\n        <strong>[...s]</strong> — spread строки в массив символов. Нужно для корректной работы с Unicode.<br>\n        <strong>Анаграмма через sort</strong> — простое O(n log n) решение. Существует O(n) через Map.<br>\n        <strong>charCount</strong> — паттерн частотного анализа. Используется в десятках задач.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb348\" onchange=\"updateProgress(this)\"><span>Палиндром, реверс строки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb349\" onchange=\"updateProgress(this)\"><span>Анаграммы — сортировка или Map</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb350\" onchange=\"updateProgress(this)\"><span>Частотный анализ символов через reduce</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-algo-recursion","title":"Рекурсия важно 🔗","html":"<div class=\"block\" id=\"block-algo-recursion\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-recursion')\">Рекурсия <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Рекурсия = функция вызывает сама себя</span>\n<span class=\"cm\">// Обязательно: базовый случай (выход из рекурсии)</span>\n\n<span class=\"cm\">// Факториал</span>\n<span class=\"kw\">function</span> <span class=\"fn\">factorial</span>(n) {\n  <span class=\"kw\">if</span> (n &lt;= <span class=\"num\">1</span>) <span class=\"kw\">return</span> <span class=\"num\">1</span>;  <span class=\"cm\">// базовый случай</span>\n  <span class=\"kw\">return</span> n * <span class=\"fn\">factorial</span>(n - <span class=\"num\">1</span>);\n}\n\n<span class=\"cm\">// Числа Фибоначчи (с мемоизацией)</span>\n<span class=\"kw\">const</span> memo = {};\n<span class=\"kw\">function</span> <span class=\"fn\">fib</span>(n) {\n  <span class=\"kw\">if</span> (n &lt;= <span class=\"num\">1</span>) <span class=\"kw\">return</span> n;\n  <span class=\"kw\">if</span> (memo[n]) <span class=\"kw\">return</span> memo[n];\n  <span class=\"kw\">return</span> memo[n] = <span class=\"fn\">fib</span>(n-<span class=\"num\">1</span>) + <span class=\"fn\">fib</span>(n-<span class=\"num\">2</span>);\n}\n\n<span class=\"cm\">// Обход вложенного объекта (реальная задача)</span>\n<span class=\"kw\">function</span> <span class=\"fn\">deepSum</span>(obj) {\n  <span class=\"kw\">return</span> Object.<span class=\"fn\">values</span>(obj).<span class=\"fn\">reduce</span>((sum, val) =&gt;\n    sum + (<span class=\"kw\">typeof</span> val === <span class=\"str\">'object'</span> ? <span class=\"fn\">deepSum</span>(val) : val), <span class=\"num\">0</span>\n  );\n}</div>\n      <div class=\"explain\">\n        <strong>Базовый случай</strong> — без него бесконечная рекурсия и Stack Overflow.<br>\n        <strong>Мемоизация</strong> — кэшируем результаты. fib(40) без memo = миллиарды вызовов, с memo = 40.<br>\n        <strong>Рекурсия для деревьев</strong> — обход DOM, файловой системы, вложенных объектов.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb351\" onchange=\"updateProgress(this)\"><span>Рекурсия — базовый случай + рекурсивный вызов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb352\" onchange=\"updateProgress(this)\"><span>Мемоизация — кэш для дорогих рекурсий</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb353\" onchange=\"updateProgress(this)\"><span>Обход вложенных структур через рекурсию</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-algo-data-structures","title":"Структуры данных: Stack, Queue, Tree, Graph важно 🔗","html":"<div class=\"block\" id=\"block-algo-data-structures\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-data-structures')\">Структуры данных: Stack, Queue, Tree, Graph <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Структура данных — это способ хранить данные так, чтобы нужные операции были удобными и быстрыми.</div>\n      <div class=\"code\"><span class=\"cm\">// Stack — стопка: последний вошёл, первый вышел</span>\nconst stack = [];\nstack.push('modal-open');\nstack.push('tooltip-open');\nstack.pop(); <span class=\"cm\">// tooltip-open</span>\n\n<span class=\"cm\">// Queue — очередь: первый вошёл, первый вышел</span>\nconst queue = [];\nqueue.push('task-1');\nqueue.push('task-2');\nqueue.shift(); <span class=\"cm\">// task-1</span>\n\n<span class=\"cm\">// Tree — дерево: DOM, меню, файловая система</span>\nconst menu = {\n  title: 'Frontend',\n  children: [\n    { title: 'HTML', children: [] },\n    { title: 'CSS', children: [] }\n  ]\n};\n\n<span class=\"cm\">// Graph — граф: связи между сущностями</span>\nconst graph = new Map([\n  ['home', ['about', 'catalog']],\n  ['catalog', ['product']],\n  ['product', ['cart']]\n]);</div>\n      <div class=\"explain\">\n        <strong>Stack</strong> нужен для undo/redo, истории переходов, закрытия вложенных окон.<br>\n        <strong>Queue</strong> нужна для очередей задач, загрузок, сообщений.<br>\n        <strong>Tree</strong> встречается постоянно: DOM, комментарии, категории, меню.<br>\n        <strong>Graph</strong> — связи: маршруты, друзья, зависимости пакетов, ссылки между страницами.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-algo-ds-1\" onchange=\"updateProgress(this)\"><span>Stack и Queue — понимаю разницу LIFO/FIFO</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-algo-ds-2\" onchange=\"updateProgress(this)\"><span>Tree — понимаю на примере DOM и меню</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-algo-ds-3\" onchange=\"updateProgress(this)\"><span>Graph — понимаю как набор узлов и связей</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-algo-advanced-concepts","title":"AST и Bloom Filter на будущее 🔗","html":"<div class=\"block\" id=\"block-algo-advanced-concepts\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-advanced-concepts')\">AST и Bloom Filter <span class=\"badge rec\">на будущее</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Это не база для старта, но эти слова часто встречаются в инструментах: линтеры, сборщики, поиск, антиспам, кэш.</div>\n      <div class=\"code\"><span class=\"cm\">// AST — дерево кода</span>\nconst x = 2 + 3;\n\n<span class=\"cm\">// Упрощённо парсер видит так:</span>\nVariableDeclaration\n  name: \"x\"\n  value:\n    BinaryExpression\n      left: 2\n      operator: \"+\"\n      right: 3\n\n<span class=\"cm\">// Bloom Filter — быстрый \"возможно есть / точно нет\"</span>\nif (bloom.has(email)) {\n  <span class=\"cm\">// возможно уже встречался, проверим в базе</span>\n} else {\n  <span class=\"cm\">// точно не встречался</span>\n}</div>\n      <div class=\"explain\">\n        <strong>AST</strong> используют Babel, ESLint, TypeScript, Prettier: они читают код как дерево и могут его проверять или переписывать.<br>\n        <strong>Bloom Filter</strong> экономит память и быстро отвечает: \"точно нет\" или \"возможно да\". Минус — бывают ложные срабатывания.<br>\n        <strong>Смысл блока:</strong> не учить глубоко сейчас, а понимать, что происходит под капотом инструментов.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-algo-advanced-1\" onchange=\"updateProgress(this)\"><span>Понимаю AST как дерево кода для линтеров и сборщиков</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-algo-advanced-2\" onchange=\"updateProgress(this)\"><span>Понимаю Bloom Filter на уровне \"точно нет / возможно да\"</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-mistakes","lessons":[{"id":"mistakes-lesson-1","title":"HTML — что делают новички не так читай!","html":"<div class=\"block\">\n      <div class=\"block-title\">HTML — что делают новички не так <span class=\"badge must\">читай!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ &lt;div onclick=\"...\"&gt;Кнопка&lt;/div&gt;\n✅ &lt;button onclick=\"...\"&gt;Кнопка&lt;/button&gt;</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb367\" onchange=\"updateProgress(this)\"><span>Не пропускай alt у &lt;img&gt;</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb368\" onchange=\"updateProgress(this)\"><span>Не используй &lt;br&gt; для отступов — для этого CSS margin/padding</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb369\" onchange=\"updateProgress(this)\"><span>Один h1 на страницу!</span></label>\n      </div>\n    </div>\n    "},{"id":"mistakes-lesson-2","title":"CSS — что делают новички не так читай!","html":"<div class=\"block\">\n      <div class=\"block-title\">CSS — что делают новички не так <span class=\"badge must\">читай!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ .box { width: 300px; padding: 20px; }   → реальная ширина 340px!\n✅ * { box-sizing: border-box; }\n   .box { width: 300px; padding: 20px; }  → ширина 300px</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb370\" onchange=\"updateProgress(this)\"><span>* { box-sizing: border-box; } — первая строка CSS!</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb371\" onchange=\"updateProgress(this)\"><span>Не используй !important — разберись со специфичностью</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb372\" onchange=\"updateProgress(this)\"><span>position: absolute без position: relative у родителя = беда</span></label>\n      </div>\n    </div>\n    "},{"id":"mistakes-lesson-3","title":"JavaScript — что делают новички не так читай!","html":"<div class=\"block\">\n      <div class=\"block-title\">JavaScript — что делают новички не так <span class=\"badge must\">читай!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ if (x = 5)   → это ПРИСВАИВАНИЕ, не сравнение!\n✅ if (x === 5) → это СРАВНЕНИЕ\n\n❌ \"5\" + 3 = \"53\"      → строка + число = склеивание\n✅ Number(\"5\") + 3 = 8 → сначала конвертируй</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb373\" onchange=\"updateProgress(this)\"><span>=== (строгое) вместо == (нестрогое)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb374\" onchange=\"updateProgress(this)\"><span>Всегда const или let. Без них — глобальная переменная!</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb375\" onchange=\"updateProgress(this)\"><span>F12 → Console — туда выводятся ВСЕ ошибки</span></label>\n      </div>\n    </div>\n    "},{"id":"block-mistakes-async","title":"async/await и Promise — типичные ловушки читай!","html":"<div class=\"block\" id=\"block-mistakes-async\">\n      <div class=\"block-title\">async/await и Promise — типичные ловушки <span class=\"badge must\">читай!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ async function getData() {\n  const data = fetch('/api/users');  // забыл await!\n  console.log(data);                 // [object Promise], не данные\n}\n\n❌ async function getData() {\n  const data = await fetch('/api/users');  // нет try/catch\n  return data.json();                       // падает тихо если сеть недоступна\n}\n\n✅ async function getData() {\n  try {\n    const res = await fetch('/api/users');\n    if (!res.ok) throw new Error('HTTP ' + res.status);\n    return await res.json();\n  } catch (err) {\n    console.error('Ошибка:', err.message);\n  }\n}</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb384\" onchange=\"updateProgress(this)\"><span>await обязателен перед fetch(), иначе получишь Promise, а не данные</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb385\" onchange=\"updateProgress(this)\"><span>Всегда оборачивай async-код в try/catch — сеть может упасть</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb386\" onchange=\"updateProgress(this)\"><span>Проверяй res.ok — fetch не выбрасывает ошибку на 404 или 500!</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-mistakes-scope","title":"z-index, position, overflow — три мушкетёра читай!","html":"<div class=\"block\" id=\"block-mistakes-scope\">\n      <div class=\"block-title\">z-index, position, overflow — три мушкетёра <span class=\"badge must\">читай!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ .tooltip { position: static; z-index: 9999; }\n   /* z-index НЕ работает без position: relative/absolute/fixed/sticky */\n\n✅ .tooltip { position: relative; z-index: 9999; }\n\n❌ .card { overflow: hidden; }\n   .card .dropdown { position: absolute; }\n   /* дропдаун обрежется родителем! */\n\n✅ /* Либо убери overflow: hidden с .card,\n      либо перенеси дропдаун в конец body через JS */\n\n❌ .modal { position: fixed; top: 50%; left: 50%; }\n   /* не по центру — угол, а не центр */\n✅ .modal { position: fixed; top: 50%; left: 50%;\n             transform: translate(-50%, -50%); }</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb387\" onchange=\"updateProgress(this)\"><span>z-index работает только при position: relative/absolute/fixed/sticky</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb388\" onchange=\"updateProgress(this)\"><span>overflow: hidden на родителе обрезает absolute-дочернего — осторожно с дропдаунами</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb389\" onchange=\"updateProgress(this)\"><span>Центрирование fixed-элемента: top/left 50% + transform: translate(-50%,-50%)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-mistakes-events","title":"EventListener — утечки памяти и дубли читай!","html":"<div class=\"block\" id=\"block-mistakes-events\">\n      <div class=\"block-title\">EventListener — утечки памяти и дубли <span class=\"badge must\">читай!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ // Каждый клик добавляет ЕЩЁ один обработчик:\nfunction render() {\n  document.getElementById('btn').addEventListener('click', handler);\n}\nrender(); render(); render(); // теперь 3 одинаковых обработчика!\n\n✅ // Вариант 1 — убирать перед добавлением:\nbtn.removeEventListener('click', handler);\nbtn.addEventListener('click', handler);\n\n✅ // Вариант 2 — делегирование (один обработчик на родителя):\ndocument.getElementById('list').addEventListener('click', (e) =&gt; {\n  if (e.target.matches('.item')) handleItem(e.target);\n});\n\n❌ // Анонимная функция — нельзя удалить!\nbtn.addEventListener('click', () =&gt; doSomething());\nbtn.removeEventListener('click', () =&gt; doSomething()); // НЕ работает!\n\n✅ function handler() { doSomething(); }\nbtn.addEventListener('click', handler);\nbtn.removeEventListener('click', handler); // ✓</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb390\" onchange=\"updateProgress(this)\"><span>Не добавляй addEventListener повторно без removeEventListener — будут дубли</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb391\" onchange=\"updateProgress(this)\"><span>Делегирование событий — один обработчик на родителя вместо 100 на детей</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb392\" onchange=\"updateProgress(this)\"><span>Анонимную функцию нельзя удалить через removeEventListener — давай имена</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-mistakes-specificity","title":"CSS специфичность — почему стили не применяются важно","html":"<div class=\"block\" id=\"block-mistakes-specificity\">\n      <div class=\"block-title\">CSS специфичность — почему стили не применяются <span class=\"badge good\">важно</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">/* Специфичность считается как (ID, класс, тег) */\n/* Выигрывает более специфичный, не тот что написан ниже! */\n\n❌ .nav a { color: blue; }   /* специфичность: 0-1-1 */\n   a { color: red; }          /* специфичность: 0-0-1 — ПРОИГРЫВАЕТ */\n   /* Красного не будет, хотя написано после! */\n\n❌ /* \"Решение\" через !important — создаёт хаос */\n   a { color: red !important; }\n\n✅ /* Правильное решение — выровнять специфичность */\n   .nav a { color: blue; }\n   .content a { color: red; } /* тоже 0-1-1, побеждает порядок */\n\n/* Таблица специфичности:\n   Инлайн style=\"\"     → 1-0-0-0  (самый сильный)\n   #id                 → 0-1-0-0\n   .class, [attr], :hover → 0-0-1-0\n   div, p, span        → 0-0-0-1  (самый слабый) */</div>\n      <div class=\"specificity-tool\">\n        <div class=\"tool-row\">\n          <input class=\"tool-input\" id=\"specSelectorA\" value=\".nav ul li a:hover\" oninput=\"updateSpecificityTool()\" aria-label=\"Первый CSS-селектор\">\n          <input class=\"tool-input\" id=\"specSelectorB\" value=\"#header a\" oninput=\"updateSpecificityTool()\" aria-label=\"Второй CSS-селектор\">\n        </div>\n        <div class=\"tool-result\" id=\"specResult\">Калькулятор покажет очки специфичности.</div>\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb393\" onchange=\"updateProgress(this)\"><span>Понимаю как считается специфичность: ID &gt; класс &gt; тег</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb394\" onchange=\"updateProgress(this)\"><span>!important — последнее средство, не первое решение</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb395\" onchange=\"updateProgress(this)\"><span>Инлайновый style перебивает любой CSS в файле</span></label>\n      </div>\n    </div>\n\n    "}]},{"id":"sec-resources","lessons":[{"id":"resources-lesson-1","title":"Бесплатные курсы и учебники must have","html":"<div class=\"block\">\n      <div class=\"block-title\">Бесплатные курсы и учебники <span class=\"badge must\">must have</span></div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb396\" onchange=\"updateProgress(this)\"><span>📖 <a href=\"https://developer.mozilla.org/ru/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">MDN Web Docs</a> — официальная документация HTML/CSS/JS</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb397\" onchange=\"updateProgress(this)\"><span>🎓 <a href=\"https://www.freecodecamp.org/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">freeCodeCamp.org</a> — бесплатные уроки с практикой и сертификатами</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb398\" onchange=\"updateProgress(this)\"><span>📘 <a href=\"https://learn.javascript.ru/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">learn.javascript.ru</a> — лучший учебник по JS на русском</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb399\" onchange=\"updateProgress(this)\"><span>🏫 <a href=\"https://htmlacademy.ru/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">HTML Academy</a> — бесплатные тренажёры HTML/CSS</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb400\" onchange=\"updateProgress(this)\"><span>🎮 <a href=\"https://css-tricks.com/snippets/css/a-guide-to-flexbox/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">CSS-Tricks Flexbox Guide</a> — лучшая шпаргалка по Flexbox</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb401\" onchange=\"updateProgress(this)\"><span>🕹️ <a href=\"https://flexboxfroggy.com/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Flexbox Froggy</a> — учи Flexbox играючи</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb402\" onchange=\"updateProgress(this)\"><span>🌐 <a href=\"https://codepen.io/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">CodePen</a> / <a href=\"https://jsfiddle.net/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">JSFiddle</a> — онлайн-песочница</span></label>\n      </div>\n    </div>\n    "},{"id":"resources-lesson-2","title":"YouTube-каналы и подкасты контент","html":"<div class=\"block\">\n      <div class=\"block-title\">YouTube-каналы и подкасты <span class=\"badge good\">контент</span></div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb403\" onchange=\"updateProgress(this)\"><span>▶️ <a href=\"https://www.youtube.com/@VladilenMinin\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Владилен Минин</a> — React, TypeScript, Node.js на русском</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb404\" onchange=\"updateProgress(this)\"><span>▶️ <a href=\"https://www.youtube.com/@UlbiTV\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Ulbi TV</a> — фронтенд, бэкенд, архитектура</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb405\" onchange=\"updateProgress(this)\"><span>▶️ <a href=\"https://www.youtube.com/@TraversyMedia\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Traversy Media</a> — практичные туториалы на английском</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb406\" onchange=\"updateProgress(this)\"><span>▶️ <a href=\"https://www.youtube.com/@KevinPowell\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Kevin Powell</a> — король CSS, советы и трюки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb407\" onchange=\"updateProgress(this)\"><span>▶️ <a href=\"https://www.youtube.com/@Fireship\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Fireship</a> — 100 секунд о технологиях, коротко и чётко</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb408\" onchange=\"updateProgress(this)\"><span>🎙️ <a href=\"https://syntax.fm/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Syntax.fm</a> — подкаст фронтендеров, eng, всё актуальное</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb409\" onchange=\"updateProgress(this)\"><span>🎙️ <a href=\"https://www.youtube.com/c/DevChatsTV\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Веб-стандарты</a> — русскоязычный подкаст о вебе</span></label>\n      </div>\n    </div>\n    "},{"id":"resources-lesson-3","title":"Инструменты важно","html":"<div class=\"block\">\n      <div class=\"block-title\">Инструменты <span class=\"badge good\">важно</span></div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb410\" onchange=\"updateProgress(this)\"><span><a href=\"https://code.visualstudio.com/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">VS Code</a> + расширение Live Server + Prettier</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb411\" onchange=\"updateProgress(this)\"><span>Chrome DevTools (F12) — консоль, инспектор, вкладка сеть</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb412\" onchange=\"updateProgress(this)\"><span><a href=\"https://github.com/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">GitHub</a> — храни код, показывай портфолио работодателю</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb413\" onchange=\"updateProgress(this)\"><span><a href=\"https://www.figma.com/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Figma</a> (бесплатно) — дизайн и макеты для верстки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb414\" onchange=\"updateProgress(this)\"><span><a href=\"https://caniuse.com/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">CanIUse.com</a> — проверить поддержку CSS/JS свойства в браузерах</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb415\" onchange=\"updateProgress(this)\"><span><a href=\"https://roadmap.sh/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">roadmap.sh</a> — карта развития фронтенд/бэкенд разработчика</span></label>\n      </div>\n    </div>\n    "}]},{"id":"sec-roadmap","lessons":[{"id":"roadmap-lesson-1","title":"🗺️ Карта: от нуля до первого проекта план","html":"<div class=\"block\">\n      <div class=\"block-title\">🗺️ Карта: от нуля до первого проекта <span class=\"badge must\">план</span></div>\n      <div class=\"tip\">Иди по шагам. Не перескакивай! Отмечай каждый пройденный этап.</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb416\" onchange=\"updateProgress(this)\"><span>📌 Этап 0: HTML — структура, теги, формы, семантика (1–2 недели)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb417\" onchange=\"updateProgress(this)\"><span>📌 Этап 1: CSS — цвета, текст, блочная модель (1–2 недели)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb418\" onchange=\"updateProgress(this)\"><span>📌 Этап 2: Flexbox + Grid + адаптивность (2 недели)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb419\" onchange=\"updateProgress(this)\"><span>📌 Этап 3: JS — переменные, условия, циклы, массивы (3 недели)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb420\" onchange=\"updateProgress(this)\"><span>📌 Этап 4: JS — функции, DOM, события (2 недели)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb421\" onchange=\"updateProgress(this)\"><span>📌 Этап 5: fetch + async/await + localStorage (1–2 недели)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb422\" onchange=\"updateProgress(this)\"><span>📌 Этап 6: Git + GitHub (1 неделя)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb423\" onchange=\"updateProgress(this)\"><span>📌 Этап 7: Первый проект (2–3 недели)</span></label>\n      </div>\n    </div>\n    "},{"id":"roadmap-lesson-2","title":"Что учить ПОСЛЕ основ следующий шаг","html":"<div class=\"block\">\n      <div class=\"block-title\"><iconify-icon icon=\"tabler:rocket\" width=\"18\" height=\"18\" style=\"vertical-align:middle\"></iconify-icon> Что учить ПОСЛЕ основ <span class=\"badge good\">следующий шаг</span></div>\n      <div class=\"code\">HTML → CSS → JS → Git\n     ↓\nReact → TypeScript\n     ↓\nNext.js → Node.js\n     ↓\nФриланс / Стажировка / Работа</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb424\" onchange=\"updateProgress(this)\"><span>React — самый востребованный фреймворк</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb425\" onchange=\"updateProgress(this)\"><span>TypeScript — JS с типами. Меньше ошибок</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb426\" onchange=\"updateProgress(this)\"><span>Не учи фреймворки, пока не знаешь чистый JS!</span></label>\n      </div>\n    </div>\n    "}]},{"id":"sec-git","lessons":[{"id":"block-git-init","title":"Установка и первая настройка начало 🔗","html":"<div class=\"block\" id=\"block-git-init\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-init')\">Установка и первая настройка <span class=\"badge must\">начало</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Git нужно установить один раз и настроить имя и email — они будут в каждом коммите.</div>\n      <div class=\"code\">\n# Проверить установлен ли Git\ngit --version        # git version 2.x.x\n\n# Настроить имя и email (один раз)\ngit config --global user.name  \"Твоё Имя\"\ngit config --global user.email \"you@example.com\"\n\n# Проверить настройки\ngit config --list\n\n# Создать новый репозиторий в текущей папке\ngit init\n\n# Склонировать существующий репозиторий с GitHub\ngit clone https://github.com/user/repo.git\ngit clone https://github.com/user/repo.git my-folder  # в папку my-folder</div>\n      <div class=\"explain\">\n        <strong>git init</strong> — создаёт скрытую папку .git. Теперь папка — репозиторий.<br>\n        <strong>git clone</strong> — скачивает чужой репозиторий и автоматически настраивает remote.<br>\n        <strong>--global</strong> — настройка для всего компьютера, не только для одного проекта.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb454\" onchange=\"updateProgress(this)\"><span>Установил Git и настроил user.name и user.email</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb455\" onchange=\"updateProgress(this)\"><span>git init — создать репо, git clone [url] — скачать</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-status","title":"Статус и добавление файлов основа 🔗","html":"<div class=\"block\" id=\"block-git-status\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-status')\">Статус и добавление файлов <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">\n# Посмотреть что изменилось\ngit status            # список изменённых / новых файлов\ngit status -s         # короткий вариант\n\n# Посмотреть разницу в строках\ngit diff              # что изменилось в рабочей папке\ngit diff --staged     # что уже добавлено (staged)\n\n# Добавить файлы в staging (индекс)\ngit add index.html    # один файл\ngit add css/          # всё в папке\ngit add .             # ВСЕ изменения (используй осторожно!)\ngit add -p            # интерактивно — выбирать куски изменений\n\n# Убрать файл из staging (не удаляет изменения!)\ngit restore --staged index.html</div>\n      <div class=\"explain\">\n        <strong>git status</strong> — твой главный инструмент. Смотри перед каждым коммитом.<br>\n        <strong>Staging area (индекс)</strong> — «корзина», куда ты собираешь изменения перед коммитом. Позволяет коммитить частями.<br>\n        <strong>git diff</strong> — показывает именно что изменилось в файлах (построчно).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb456\" onchange=\"updateProgress(this)\"><span>git status — смотрю что изменилось перед каждым коммитом</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb457\" onchange=\"updateProgress(this)\"><span>git add . — добавить всё; git add файл — добавить один</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb458\" onchange=\"updateProgress(this)\"><span>git diff — вижу конкретные изменённые строки</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-commit","title":"Коммиты — сохраняем историю основа 🔗","html":"<div class=\"block\" id=\"block-git-commit\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-commit')\">Коммиты — сохраняем историю <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">\n# Создать коммит\ngit commit -m \"feat: добавить форму регистрации\"\n\n# Добавить все изменённые (не новые!) + коммит за 1 шаг\ngit commit -am \"fix: исправить ошибку в валидации\"\n\n# Посмотреть историю коммитов\ngit log               # подробно\ngit log --oneline     # по одной строке на коммит\ngit log --oneline --graph --all  # дерево всех веток\n\n# Изменить последний коммит (ОСТОРОЖНО: только если не отправлен!)\ngit commit --amend -m \"Новый текст коммита\"\n\n# Вернуться к коммиту (создаёт новый «отменяющий» коммит)\ngit revert abc1234\n\n# Отменить коммиты (ОПАСНО: стирает историю!)\ngit reset --soft HEAD~1   # откат 1 коммита, изменения сохранены в staged\ngit reset --hard HEAD~1   # откат 1 коммита, изменения УДАЛЕНЫ</div>\n      <div class=\"explain\">\n        <strong>Соглашение по именам коммитов (Conventional Commits):</strong><br>\n        <code>feat:</code> — новая функция. <code>fix:</code> — исправление бага. <code>docs:</code> — документация. <code>refactor:</code> — рефакторинг. <code>style:</code> — форматирование.<br><br>\n        <strong>git revert</strong> — безопасная отмена. <strong>git reset --hard</strong> — стирает историю, не используй на shared ветках.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb459\" onchange=\"updateProgress(this)\"><span>git commit -m \"сообщение\" — создать коммит</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb460\" onchange=\"updateProgress(this)\"><span>git log --oneline — смотреть историю коммитов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb461\" onchange=\"updateProgress(this)\"><span>feat:, fix:, docs: — пишу понятные сообщения коммитов</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-branches","title":"Ветки — работаем параллельно основа 🔗","html":"<div class=\"block\" id=\"block-git-branches\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-branches')\">Ветки — работаем параллельно <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Ветка — это независимая копия кода. Делаешь новую фичу? Создай ветку — main остаётся нетронутым.</div>\n      <div class=\"code\">\n# Посмотреть ветки\ngit branch            # локальные\ngit branch -a         # все (включая remote)\n\n# Создать и переключиться\ngit checkout -b feature/login     # старый способ\ngit switch -c feature/login       # новый (Git 2.23+)\n\n# Переключиться на существующую\ngit checkout main\ngit switch main\n\n# Удалить ветку\ngit branch -d feature/login   # после merge\ngit branch -D feature/login   # принудительно\n\n# Слить ветку в текущую (merge)\ngit checkout main\ngit merge feature/login\n\n# Перебазировать (rebase — для чистой истории)\ngit checkout feature/login\ngit rebase main        # \"переклей\" коммиты поверх main</div>\n      <div class=\"explain\">\n        <strong>Типичный flow:</strong> main (стабильный) → develop (разработка) → feature/* (фичи).<br>\n        <strong>merge</strong> — сохраняет всю историю. <strong>rebase</strong> — делает историю линейной.<br>\n        В командах обычно используют Pull Request / Merge Request на GitHub вместо прямого merge.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb462\" onchange=\"updateProgress(this)\"><span>git switch -c имя — создать и переключиться на ветку</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb463\" onchange=\"updateProgress(this)\"><span>git merge ветка — влить изменения из ветки в текущую</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb464\" onchange=\"updateProgress(this)\"><span>Понимаю разницу merge vs rebase</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-remote","title":"Remote — работа с GitHub основа 🔗","html":"<div class=\"block\" id=\"block-git-remote\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-remote')\">Remote — работа с GitHub <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">\n# Посмотреть подключённые remote\ngit remote -v\n\n# Добавить remote (после git init)\ngit remote add origin https://github.com/user/repo.git\n\n# Отправить ветку на GitHub\ngit push origin main\ngit push origin feature/login\n\n# Первый push новой ветки\ngit push -u origin feature/login    # -u — запомнит связь\n\n# Получить изменения с GitHub\ngit fetch             # скачать, но не применять\ngit pull              # fetch + merge (применить)\ngit pull --rebase     # fetch + rebase (чистая история)\n\n# Работа с PR (Pull Request)\n# 1. git switch -c feature/my-feature\n# 2. ... делаешь изменения и коммитишь ...\n# 3. git push -u origin feature/my-feature\n# 4. На GitHub создаёшь Pull Request\n# 5. После ревью — merge в main</div>\n      <div class=\"explain\">\n        <strong>origin</strong> — стандартное имя remote. Можно добавить несколько remotes.<br>\n        <strong>git fetch vs pull</strong>: fetch — только скачает, не изменит твои файлы. pull — скачает и применит.<br>\n        <strong>-u</strong> — устанавливает upstream, после этого можно просто писать <code>git push</code> без origin и имени ветки.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb465\" onchange=\"updateProgress(this)\"><span>git push origin ветка — отправить на GitHub</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb466\" onchange=\"updateProgress(this)\"><span>git pull — получить изменения от команды</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb467\" onchange=\"updateProgress(this)\"><span>Знаю как создать Pull Request на GitHub</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-conflicts","title":"Конфликты и их решение важно 🔗","html":"<div class=\"block\" id=\"block-git-conflicts\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-conflicts')\">Конфликты и их решение <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Конфликт = двое изменили одну строку. Git не знает чью версию взять — спрашивает тебя.</div>\n      <div class=\"code\">\n# Конфликт выглядит так в файле:\n&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD\n    Твой код (текущая ветка)\n=======\n    Чужой код (входящие изменения)\n&gt;&gt;&gt;&gt;&gt;&gt;&gt; feature/login\n\n# Шаги разрешения:\n# 1. Открой файл в редакторе\n# 2. Выбери нужную версию (или объедини обе)\n# 3. Удали маркеры &lt;&lt;&lt;, ===, &gt;&gt;&gt;\n# 4. git add файл_с_конфликтом\n# 5. git commit\n\n# Если запутался — отменить merge полностью:\ngit merge --abort\ngit rebase --abort\n\n# Полезные инструменты\ngit log --merge       # коммиты, вызвавшие конфликт\ngit diff              # посмотреть все конфликтные места</div>\n      <div class=\"explain\">\n        <strong>Не паникуй</strong> — конфликты это нормально. Они случаются у всех.<br>\n        VS Code подсвечивает конфликты и показывает кнопки: «Accept Current», «Accept Incoming», «Accept Both».<br>\n        После разрешения всех конфликтов — <code>git add .</code> и <code>git commit</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb468\" onchange=\"updateProgress(this)\"><span>Понимаю маркеры &lt;&lt;&lt;HEAD / ======= / &gt;&gt;&gt;&gt;ветка</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb469\" onchange=\"updateProgress(this)\"><span>Умею разрешать конфликты вручную или через VS Code</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb470\" onchange=\"updateProgress(this)\"><span>git merge --abort — знаю как выйти если всё сломалось</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-gitignore","title":".gitignore — что НЕ добавлять в репо важно 🔗","html":"<div class=\"block\" id=\"block-git-gitignore\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-gitignore')\">.gitignore — что НЕ добавлять в репо <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">\n# Файл .gitignore — в корне проекта\n# Git не будет отслеживать перечисленные файлы и папки\n\n# Зависимости (ставятся командой, не нужны в репо)\nnode_modules/\n\n# Сборки (генерируются автоматически)\ndist/\nbuild/\n.cache/\n\n# Секреты (НИКОГДА не добавляй в репо!)\n.env\n.env.local\n*.key\nsecrets.json\n\n# Системные файлы\n.DS_Store          # macOS\nThumbs.db          # Windows\n\n# Логи\n*.log\nlogs/\n\n# IDE настройки (зависит от команды)\n.vscode/\n.idea/</div>\n      <div class=\"explain\">\n        <strong>Золотое правило:</strong> secrets (пароли, ключи API) НИКОГДА не должны попасть в Git. Даже если удалишь потом — история сохранит их. Используй переменные окружения (.env).<br>\n        <strong>node_modules</strong> — всегда в .gitignore. Вместо неё в репо лежит package.json, и команда делает npm install.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb471\" onchange=\"updateProgress(this)\"><span>node_modules/ и .env — всегда в .gitignore</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb472\" onchange=\"updateProgress(this)\"><span>Никогда не коммичу пароли, ключи API, секреты</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-stash","title":"Stash и cherry-pick продвинуто 🔗","html":"<div class=\"block\" id=\"block-git-stash\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-stash')\">Stash и cherry-pick <span class=\"badge pro\">продвинуто</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">\n# STASH — «отложить» незакомиченные изменения\ngit stash             # прячет все изменения\ngit stash push -m \"работа над формой\"  # с именем\n\ngit stash list        # список спрятанного\ngit stash pop         # восстановить последний и удалить из списка\ngit stash apply stash@{0}  # восстановить конкретный\ngit stash drop stash@{0}   # удалить из списка\n\n# CHERRY-PICK — взять один коммит из другой ветки\ngit cherry-pick abc1234   # скопировать коммит в текущую ветку\n\n# TAGS — пометить версию\ngit tag v1.0.0\ngit tag -a v1.0.0 -m \"Первый релиз\"   # annotated тег\ngit push origin v1.0.0                 # отправить тег на GitHub\ngit push origin --tags                 # все теги\n\n# Найти когда появился баг (бинарный поиск!)\ngit bisect start\ngit bisect bad          # текущий коммит — плохой\ngit bisect good v1.0.0  # эта версия была рабочей\n# Git переключает на середину, ты тестируешь...\ngit bisect good / git bisect bad\ngit bisect reset        # завершить поиск</div>\n      <div class=\"explain\">\n        <strong>git stash</strong> — временный карман для незакомиченных изменений. Удобно когда нужно срочно переключить ветку.<br>\n        <strong>cherry-pick</strong> — берёт один конкретный коммит и применяет его к текущей ветке. Без всего остального из той ветки.<br>\n        <strong>bisect</strong> — бинарный поиск бага в истории. Экономит часы поиска.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb473\" onchange=\"updateProgress(this)\"><span>git stash / git stash pop — «положить и достать» незакомиченные изменения</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb474\" onchange=\"updateProgress(this)\"><span>git cherry-pick [хэш] — взять один коммит из другой ветки</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-viz","title":"Визуализация веток — как это выглядит схема 🔗","html":"<div class=\"block\" id=\"block-git-viz\" style=\"margin-top:1.25rem;\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-viz')\">Визуализация веток — как это выглядит <span class=\"badge good\">схема</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Каждый кружок — коммит. Стрелка — от нового к старому. Ветки — параллельные линии истории.</div>\n      <div class=\"git-viz\">\n        <svg viewbox=\"0 0 640 220\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;min-width:480px;\">\n          <!-- main branch line -->\n          <line x1=\"40\" y1=\"60\" x2=\"560\" y2=\"60\" stroke=\"#4ade80\" stroke-width=\"2\"></line>\n          <!-- feature branch line -->\n          <line x1=\"220\" y1=\"60\" x2=\"320\" y2=\"140\" stroke=\"#818cf8\" stroke-width=\"2\"></line>\n          <line x1=\"320\" y1=\"140\" x2=\"440\" y2=\"140\" stroke=\"#818cf8\" stroke-width=\"2\"></line>\n          <line x1=\"440\" y1=\"140\" x2=\"480\" y2=\"60\" stroke=\"#818cf8\" stroke-width=\"2\"></line>\n          <!-- hotfix branch -->\n          <line x1=\"340\" y1=\"60\" x2=\"380\" y2=\"30\" stroke=\"#f87171\" stroke-width=\"2\"></line>\n          <line x1=\"380\" y1=\"30\" x2=\"420\" y2=\"60\" stroke=\"#f87171\" stroke-width=\"2\" stroke-dasharray=\"4,3\"></line>\n          <!-- main commits -->\n          <circle cx=\"80\" cy=\"60\" r=\"12\" fill=\"#4ade80\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <circle cx=\"160\" cy=\"60\" r=\"12\" fill=\"#4ade80\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <circle cx=\"240\" cy=\"60\" r=\"12\" fill=\"#4ade80\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <circle cx=\"340\" cy=\"60\" r=\"12\" fill=\"#4ade80\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <circle cx=\"480\" cy=\"60\" r=\"14\" fill=\"#4ade80\" stroke=\"#22c55e\" stroke-width=\"3\"></circle>\n          <circle cx=\"560\" cy=\"60\" r=\"14\" fill=\"#fbbf24\" stroke=\"#f59e0b\" stroke-width=\"3\"></circle>\n          <!-- feature commits -->\n          <circle cx=\"320\" cy=\"140\" r=\"12\" fill=\"#818cf8\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <circle cx=\"400\" cy=\"140\" r=\"12\" fill=\"#818cf8\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <!-- hotfix commit -->\n          <circle cx=\"380\" cy=\"30\" r=\"10\" fill=\"#f87171\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <!-- labels -->\n          <text x=\"80\" y=\"90\" text-anchor=\"middle\" fill=\"#94a3b8\" font-size=\"10\" font-family=\"monospace\">init</text>\n          <text x=\"160\" y=\"90\" text-anchor=\"middle\" fill=\"#94a3b8\" font-size=\"10\" font-family=\"monospace\">feat</text>\n          <text x=\"240\" y=\"90\" text-anchor=\"middle\" fill=\"#94a3b8\" font-size=\"10\" font-family=\"monospace\">fork</text>\n          <text x=\"340\" y=\"90\" text-anchor=\"middle\" fill=\"#94a3b8\" font-size=\"10\" font-family=\"monospace\">fix</text>\n          <text x=\"480\" y=\"90\" text-anchor=\"middle\" fill=\"#86efac\" font-size=\"10\" font-family=\"monospace\">merge</text>\n          <text x=\"560\" y=\"90\" text-anchor=\"middle\" fill=\"#fcd34d\" font-size=\"10\" font-family=\"monospace\">HEAD</text>\n          <text x=\"320\" y=\"165\" text-anchor=\"middle\" fill=\"#a5b4fc\" font-size=\"10\" font-family=\"monospace\">feat/A</text>\n          <text x=\"400\" y=\"165\" text-anchor=\"middle\" fill=\"#a5b4fc\" font-size=\"10\" font-family=\"monospace\">feat/B</text>\n          <text x=\"380\" y=\"20\" text-anchor=\"middle\" fill=\"#fca5a5\" font-size=\"10\" font-family=\"monospace\">hotfix</text>\n          <!-- branch badges -->\n          <rect x=\"10\" y=\"50\" width=\"42\" height=\"20\" rx=\"6\" fill=\"#166534\" opacity=\".8\"></rect>\n          <text x=\"31\" y=\"64\" text-anchor=\"middle\" fill=\"#4ade80\" font-size=\"10\" font-weight=\"bold\">main</text>\n          <rect x=\"266\" y=\"130\" width=\"56\" height=\"20\" rx=\"6\" fill=\"#312e81\" opacity=\".8\"></rect>\n          <text x=\"294\" y=\"144\" text-anchor=\"middle\" fill=\"#818cf8\" font-size=\"10\" font-weight=\"bold\">feature</text>\n          <rect x=\"345\" y=\"18\" width=\"46\" height=\"18\" rx=\"6\" fill=\"#450a0a\" opacity=\".8\"></rect>\n          <text x=\"368\" y=\"31\" text-anchor=\"middle\" fill=\"#f87171\" font-size=\"10\" font-weight=\"bold\">hotfix</text>\n        </svg>\n      </div>\n      <div class=\"explain\">\n        <strong>main</strong> (зелёный) — стабильная ветка с рабочим кодом.<br>\n        <strong>feature</strong> (фиолетовый) — новая функциональность разрабатывается отдельно, не ломая main.<br>\n        <strong>hotfix</strong> (красный) — срочное исправление прямо в main, потом вливается обратно.<br>\n        <strong>HEAD</strong> (жёлтый) — указатель на текущий коммит, где ты сейчас находишься.\n      </div>\n    </div>\n\n    "},{"id":"block-git-scenarios","title":"Типичные сценарии — пошаговые команды практика 🔗","html":"<div class=\"block\" id=\"block-git-scenarios\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-scenarios')\">Типичные сценарии — пошаговые команды <span class=\"badge must\">практика</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Сохрани или запомни — это 90% реальной работы с Git.</div>\n\n      <div class=\"git-scenario\">\n        <div class=\"git-scenario-title\"><iconify-icon icon=\"tabler:rocket\" width=\"18\" height=\"18\" style=\"vertical-align:middle\"></iconify-icon> Сценарий 1: Новый проект с нуля → GitHub</div>\n        <div class=\"code\" style=\"margin:0;\">cd my-project\ngit init\ngit add .\ngit commit -m \"feat: initial commit\"\ngit branch -M main\ngit remote add origin https://github.com/you/repo.git\ngit push -u origin main</div>\n      </div>\n\n      <div class=\"git-scenario\">\n        <div class=\"git-scenario-title\">✨ Сценарий 2: Feature branch (стандартный flow)</div>\n        <div class=\"code\" style=\"margin:0;\">git switch main\ngit pull                          # синхронизируемся с командой\ngit switch -c feature/auth        # создаём ветку\n# ... пишем код ...\ngit add .\ngit commit -m \"feat: add login form\"\ngit push -u origin feature/auth   # пушим ветку\n# → создаём Pull Request на GitHub\n# → после ревью и approve делаем merge</div>\n      </div>\n\n      <div class=\"git-scenario\">\n        <div class=\"git-scenario-title\">🔥 Сценарий 3: Срочный hotfix в production</div>\n        <div class=\"code\" style=\"margin:0;\">git stash                         # прячем текущую работу\ngit switch main\ngit pull\ngit switch -c hotfix/null-pointer\n# ... правим баг ...\ngit commit -am \"fix: null pointer on empty cart\"\ngit switch main\ngit merge hotfix/null-pointer\ngit push\ngit branch -d hotfix/null-pointer\ngit switch -                      # возвращаемся назад\ngit stash pop                     # достаём отложенную работу</div>\n      </div>\n\n      <div class=\"git-scenario\">\n        <div class=\"git-scenario-title\">⏪ Сценарий 4: Откатить ошибочный коммит</div>\n        <div class=\"code\" style=\"margin:0;\"># Безопасно — создаёт новый «отменяющий» коммит:\ngit log --oneline                 # смотрим историю\ngit revert abc1234                # отменяем конкретный коммит\n\n# Если коммит ещё не запушен (ОСТОРОЖНО):\ngit reset --soft HEAD~1           # убрать коммит, сохранить изменения\ngit reset --hard HEAD~1           # убрать коммит И изменения</div>\n      </div>\n\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb475\" onchange=\"updateProgress(this)\"><span>Умею создавать проект и подключать к GitHub</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb476\" onchange=\"updateProgress(this)\"><span>Работаю через feature branches + Pull Request</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb477\" onchange=\"updateProgress(this)\"><span>Знаю как сделать hotfix не прерывая основную работу</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb478\" onchange=\"updateProgress(this)\"><span>Умею откатить ошибочный коммит через git revert</span></label>\n      </div>\n    </div>\n\n\n    "},{"id":"block-git-push","title":"Push — отправка изменений на GitHub основа 🔗","html":"<div class=\"block\" id=\"block-git-push\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-push')\">Push — отправка изменений на GitHub <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Три команды которые ты будешь писать каждый день: <code>git add</code> → <code>git commit</code> → <code>git push</code>. Это и есть \"залить на GitHub\".</div>\n      <div class=\"code\"><span class=\"cm\"># Смотришь что изменилось</span>\n<span class=\"kw\">git status</span>\n\n<span class=\"cm\"># Добавляешь файлы в коммит</span>\n<span class=\"kw\">git add .</span>             <span class=\"cm\"># все изменения сразу</span>\n<span class=\"kw\">git add index.html</span>    <span class=\"cm\"># или конкретный файл</span>\n\n<span class=\"cm\"># Создаёшь коммит с описанием</span>\n<span class=\"kw\">git commit -m</span> <span class=\"str\">\"fix: поправил стили кнопок\"</span>\n\n<span class=\"cm\"># Отправляешь на GitHub</span>\n<span class=\"kw\">git push</span>                    <span class=\"cm\"># если ветка уже привязана</span>\n<span class=\"kw\">git push origin main</span>        <span class=\"cm\"># явно: remote=origin, ветка=main</span>\n<span class=\"kw\">git push -u origin main</span>     <span class=\"cm\"># первый раз: -u запоминает связь</span></div>\n      <div class=\"explain\">\n        <strong>git add .</strong> — добавляет все изменённые файлы в \"очередь\" для коммита.<br>\n        <strong>git commit -m</strong> — фиксирует снимок. Без коммита нечего отправлять.<br>\n        <strong>origin</strong> — это просто псевдоним для адреса твоего репозитория на GitHub.<br>\n        <strong>-u</strong> — запоминает связь ветки с remote. После этого достаточно просто <code>git push</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb479\" onchange=\"updateProgress(this)\"><span>git add . → git commit -m → git push — полный цикл</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb480\" onchange=\"updateProgress(this)\"><span>git push -u origin main — первый push с привязкой ветки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb481\" onchange=\"updateProgress(this)\"><span>git status — проверяй перед каждым коммитом</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-pull-conflict","title":"Конфликт при git pull — что делать часто встречается 🔗","html":"<div class=\"block\" id=\"block-git-pull-conflict\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-pull-conflict')\">Конфликт при git pull — что делать <span class=\"badge must\">часто встречается</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">90% конфликтов у новичков случаются не при merge веток, а в простой ситуации: ты поменял файл локально, написал <code>git pull</code> — и Git ругается, отказываясь обновлять.</div>\n      <div class=\"code\"><span class=\"cm\">// Ситуация:</span>\n<span class=\"kw\">git pull</span>\n<span class=\"cm\">// error: Your local changes to the following files would be overwritten by merge:</span>\n<span class=\"cm\">//   index.html</span>\n<span class=\"cm\">// Please commit your changes or stash them before you merge.</span>\n\n<span class=\"cm\">// Решение — спрячь изменения, подтяни обновления, верни изменения:</span>\n<span class=\"kw\">git stash</span>          <span class=\"cm\">// прячет твои незакоммиченные изменения \"в карман\"</span>\n<span class=\"kw\">git pull</span>           <span class=\"cm\">// теперь pull проходит без конфликта</span>\n<span class=\"kw\">git stash pop</span>      <span class=\"cm\">// возвращаешь свои изменения обратно</span>\n\n<span class=\"cm\">// Если после stash pop Git показал конфликт —</span>\n<span class=\"cm\">// значит твои изменения и обновления задели одни и те же строки.</span>\n<span class=\"cm\">// Тогда открываешь файл, ищешь &lt;&lt;&lt;&lt;&lt;&lt;&lt; и решаешь как при обычном merge-конфликте.</span></div>\n      <div class=\"explain\">\n        <strong>git stash</strong> — временно убирает несохранённые изменения, возвращая рабочую копию к последнему коммиту (изменения не теряются, просто прячутся).<br>\n        <strong>git stash pop</strong> — достаёт спрятанные изменения и применяет их обратно. Если конфликтов нет — применяется мгновенно.<br>\n        <strong>Альтернатива</strong> — если изменения уже готовы, можно просто закоммитить их (<code>git add . &amp;&amp; git commit</code>) перед pull вместо stash.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb482\" onchange=\"updateProgress(this)\"><span>git stash → git pull → git stash pop — цикл для безопасного pull</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb483\" onchange=\"updateProgress(this)\"><span>Понимаю почему Git блокирует pull при несохранённых изменениях</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb484\" onchange=\"updateProgress(this)\"><span>Знаю альтернативу: закоммитить вместо stash</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-node","lessons":[{"id":"block-node-next-overview-2026","title":"Node.js, Next.js и отдельный API КАРТА #","html":"<div class=\"block wdg-quality-block\" id=\"block-node-next-overview-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-node-next-overview-2026')\">Node.js, Next.js и отдельный API <span class=\"badge good\">КАРТА</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Node.js - среда выполнения JavaScript на сервере. Next.js - фреймворк поверх Node.js, который закрывает большинство задач junior fullstack-приложения без отдельного Express-сервера.</div><div class=\"code\">// Next.js: страницы, Route Handlers и Server Actions в одном проекте\nexport async function GET() {\n  return Response.json({ ok: true });\n}\n\n// Express/Fastify полезны для независимого API:\n// - сервис для нескольких клиентов\n// - WebSocket, очереди, особая архитектура\n// - backend с отдельным циклом релизов</div><div class=\"explain\">Для учебного fullstack-проекта начни с Next App Router: Server Components читают данные, Route Handlers создают HTTP API, Server Actions обрабатывают формы. Express или Fastify изучай обзорно и подключай, когда API должен жить независимо. Next.js не заменяет любой возможный backend, но отдельный сервер заранее добавляет лишнюю сложность.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-node-next-overview-2026-1\" onchange=\"updateProgress(this)\"><span>Отличаю runtime от framework</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-node-next-overview-2026-2\" onchange=\"updateProgress(this)\"><span>Начинаю типовой fullstack с Next.js</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-node-next-overview-2026-3\" onchange=\"updateProgress(this)\"><span>Отдельный API создаю по причине</span></label></div></div>"},{"id":"block-next-app-router-2026","title":"Next.js App Router: современная архитектура ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-next-app-router-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-next-app-router-2026')\">Next.js App Router: современная архитектура <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Страницы - Server Components по умолчанию. Добавляй use client только для state, effects и браузерных событий.</div><div class=\"code\">// app/projects/page.tsx - Server Component\nexport default async function ProjectsPage() {\n  const projects = await db.project.findMany();\n  return &lt;ProjectList projects={projects} /&gt;;\n}\n\n// app/projects/actions.ts\n\"use server\";\nexport async function createProject(formData: FormData) {\n  const data = schema.parse({ title: formData.get(\"title\") });\n  await db.project.create({ data });\n  revalidatePath(\"/projects\");\n}</div><div class=\"explain\">Server Component читает базу без передачи секретов в браузер. Server Action изменяет данные на сервере, валидирует вход и обновляет страницу. Route Handler оставь для webhook или публичного API. Отдельный Express-бэкенд обычно не нужен.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-app-router-2026-1\" onchange=\"updateProgress(this)\"><span>Отличаю Server и Client Components</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-app-router-2026-2\" onchange=\"updateProgress(this)\"><span>Проверяю данные в Server Action</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-app-router-2026-3\" onchange=\"updateProgress(this)\"><span>Не создаю Express без причины</span></label></div><div class=\"wdg-quality-extension\"><div class=\"tip\"><strong>Server Action прямо в форме</strong>: поле всё равно должно иметь <code>name</code>, потому что action читает его из <code>FormData</code>.</div><div class=\"code\">async function createUser(formData) {\n  \"use server\";\n  const name = String(formData.get(\"name\") ?? \"\").trim();\n  if (!name) return;\n  await db.user.create({ data: { name } });\n}\n\nexport default function NewUserForm() {\n  return (\n    &lt;form action={createUser}&gt;\n      &lt;input name=\"name\" required /&gt;\n      &lt;button type=\"submit\"&gt;Создать&lt;/button&gt;\n    &lt;/form&gt;\n  );\n}</div><div class=\"explain\">Server Action выполняется на сервере, но входные данные всё равно недоверенные: нормализуй и валидируй их до записи в базу.</div></div></div>"},{"id":"block-node-nextjs-intro","title":"Next.js + Node.js — почему вместе лучше важно 🔗","html":"<div class=\"block\" id=\"block-node-nextjs-intro\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-nextjs-intro')\">Next.js + Node.js — почему вместе лучше <span class=\"badge must\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Next.js — фреймворк поверх React, который сам является Node.js приложением. Понимание Node.js — обязательное условие чтобы по-настоящему понимать Next.js, а не просто копировать код.</div>\n      <div class=\"code\"><span class=\"cm\">// Чистый React (CRA/Vite) — только клиент</span>\nБраузер запрашивает index.html\n  → загружает пустой div#root\n  → JS скачивается и рендерит всё на клиенте (CSR)\n  → SEO страдает, первая загрузка медленнее\n\n<span class=\"cm\">// Next.js — Node.js сервер рендерит React</span>\nБраузер запрашивает страницу\n  → Next.js (запущен на Node.js!) рендерит React в HTML на сервере\n  → Браузер получает готовый HTML с контентом (SSR)\n  → JS подгружается и \"оживляет\" страницу (hydration)\n  → SEO работает из коробки, первая загрузка быстрее\n\n<span class=\"cm\">// Структура Next.js проекта (App Router)</span>\napp/\n  page.tsx        <span class=\"cm\">→ главная страница (\"/\")</span>\n  layout.tsx       <span class=\"cm\">→ общий layout для всех страниц</span>\n  api/\n    users/route.ts <span class=\"cm\">→ это Node.js backend! Без Express</span>\n  blog/[slug]/\n    page.tsx        <span class=\"cm\">→ динамический маршрут /blog/my-post</span></div>\n      <div class=\"explain\">\n        <strong>Next.js = React + Node.js сервер в одном фреймворке.</strong> Без Node.js под капотом Next.js просто не существовал бы — рендеринг на сервере, API routes, middleware — всё это выполняется в Node.js окружении.<br>\n        <strong>Зачем учить раздельно?</strong> Если ты понимаешь чистый Node.js (как работает сервер, event loop, модули), то код Next.js перестаёт быть \"магией\" — ты понимаешь что происходит при каждом запросе.<br>\n        <strong>API Routes в Next.js</strong> — это полноценный Node.js backend без необходимости поднимать отдельный Express-сервер. Один проект — и фронтенд, и бэкенд.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb511\" onchange=\"updateProgress(this)\"><span>Понимаю что Next.js работает на Node.js сервере</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb512\" onchange=\"updateProgress(this)\"><span>SSR (Server-Side Rendering) — рендер React на сервере</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb513\" onchange=\"updateProgress(this)\"><span>Понимаю разницу CSR vs SSR и зачем нужен SSR</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-nextjs-routing","title":"App Router — файловая система как роутинг основа 🔗","html":"<div class=\"block\" id=\"block-nextjs-routing\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nextjs-routing')\">App Router — файловая система как роутинг <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Создание проекта</span>\n<span class=\"kw\">npx create-next-app@latest</span> my-app\n<span class=\"kw\">cd</span> my-app &amp;&amp; <span class=\"kw\">npm run dev</span>\n\n<span class=\"cm\">// app/page.tsx — главная страница</span>\n<span class=\"kw\">export default function</span> <span class=\"fn\">Home</span>() {\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">h1</span>&gt;Главная страница&lt;/<span class=\"tag\">h1</span>&gt;;\n}\n\n<span class=\"cm\">// app/about/page.tsx → доступна на /about</span>\n<span class=\"kw\">export default function</span> <span class=\"fn\">About</span>() {\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">h1</span>&gt;О нас&lt;/<span class=\"tag\">h1</span>&gt;;\n}\n\n<span class=\"cm\">// app/blog/[slug]/page.tsx → динамический маршрут</span>\n<span class=\"kw\">export default function</span> <span class=\"fn\">BlogPost</span>({ params }: { params: { slug: <span class=\"str\">string</span> } }) {\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">h1</span>&gt;Пост: {params.slug}&lt;/<span class=\"tag\">h1</span>&gt;;\n}\n<span class=\"cm\">// /blog/hello-world → params.slug = \"hello-world\"</span>\n\n<span class=\"cm\">// app/layout.tsx — общий каркас (header, footer)</span>\n<span class=\"kw\">export default function</span> <span class=\"fn\">RootLayout</span>({ children }) {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">html</span>&gt;&lt;<span class=\"tag\">body</span>&gt;\n      &lt;<span class=\"fn\">Header</span> /&gt;\n      {children}\n      &lt;<span class=\"fn\">Footer</span> /&gt;\n    &lt;/<span class=\"tag\">body</span>&gt;&lt;/<span class=\"tag\">html</span>&gt;\n  );\n}</div>\n      <div class=\"explain\">\n        <strong>Файл = маршрут.</strong> Папка <code>app/about/page.tsx</code> автоматически становится страницей <code>/about</code>. Никакого ручного роутера.<br>\n        <strong>[slug]</strong> — квадратные скобки создают динамический параметр URL.<br>\n        <strong>layout.tsx</strong> — оборачивает все вложенные страницы, не перерендеривается при навигации между ними.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb514\" onchange=\"updateProgress(this)\"><span>app/page.tsx — файловый роутинг Next.js</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb515\" onchange=\"updateProgress(this)\"><span>[slug] — динамические маршруты</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb516\" onchange=\"updateProgress(this)\"><span>layout.tsx — общий каркас страниц</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-nextjs-data","title":"Server Components и загрузка данных важно 🔗","html":"<div class=\"block\" id=\"block-nextjs-data\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nextjs-data')\">Server Components и загрузка данных <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Server Component (по умолчанию в App Router!)</span>\n<span class=\"cm\">// Выполняется на Node.js сервере, НЕ попадает в JS bundle браузера</span>\n<span class=\"kw\">export default async function</span> <span class=\"fn\">ProductList</span>() {\n  <span class=\"kw\">const</span> products = <span class=\"kw\">await</span> db.product.<span class=\"fn\">findMany</span>(); <span class=\"cm\">// прямой доступ к БД!</span>\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">ul</span>&gt;\n      {products.<span class=\"fn\">map</span>(p =&gt; &lt;<span class=\"tag\">li</span> <span class=\"attr\">key</span>={p.id}&gt;{p.name}&lt;/<span class=\"tag\">li</span>&gt;)}\n    &lt;/<span class=\"tag\">ul</span>&gt;\n  );\n}\n\n<span class=\"cm\">// Client Component — нужен для интерактивности</span>\n<span class=\"str\">'use client'</span>; <span class=\"cm\">// обязательная директива!</span>\n<span class=\"kw\">import</span> { useState } <span class=\"kw\">from</span> <span class=\"str\">'react'</span>;\n\n<span class=\"kw\">export default function</span> <span class=\"fn\">LikeButton</span>() {\n  <span class=\"kw\">const</span> [liked, setLiked] = <span class=\"fn\">useState</span>(<span class=\"kw\">false</span>);\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">setLiked</span>(!liked)}&gt;{liked ? <span class=\"str\">'❤️'</span> : <span class=\"str\">'🤍'</span>}&lt;/<span class=\"tag\">button</span>&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>Server Component</strong> — может напрямую общаться с БД, читать файлы, использовать секретные ключи. Код никогда не попадает в браузер.<br>\n        <strong>'use client'</strong> — нужен только когда требуется useState, useEffect, onClick и другая интерактивность.<br>\n        <strong>Главное правило</strong> — по умолчанию всё Server Component. Добавляй 'use client' только когда реально нужно.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb520\" onchange=\"updateProgress(this)\"><span>Server Components — выполняются на сервере, прямой доступ к БД</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb521\" onchange=\"updateProgress(this)\"><span>'use client' — когда нужна интерактивность (useState, onClick)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb522\" onchange=\"updateProgress(this)\"><span>Понимаю что Server Components не увеличивают размер JS bundle</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-nextjs-api","title":"API Routes — Node.js backend внутри Next.js важно 🔗","html":"<div class=\"block\" id=\"block-nextjs-api\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nextjs-api')\">API Routes — Node.js backend внутри Next.js <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// app/api/users/route.ts — это Node.js! Без Express</span>\n<span class=\"kw\">import</span> { NextResponse } <span class=\"kw\">from</span> <span class=\"str\">'next/server'</span>;\n\n<span class=\"kw\">export async function</span> <span class=\"fn\">GET</span>() {\n  <span class=\"kw\">const</span> users = <span class=\"kw\">await</span> db.user.<span class=\"fn\">findMany</span>();\n  <span class=\"kw\">return</span> NextResponse.<span class=\"fn\">json</span>(users);\n}\n\n<span class=\"kw\">export async function</span> <span class=\"fn\">POST</span>(request: Request) {\n  <span class=\"kw\">const</span> body = <span class=\"kw\">await</span> request.<span class=\"fn\">json</span>();\n  <span class=\"kw\">const</span> user = <span class=\"kw\">await</span> db.user.<span class=\"fn\">create</span>({ data: body });\n  <span class=\"kw\">return</span> NextResponse.<span class=\"fn\">json</span>(user, { status: <span class=\"num\">201</span> });\n}\n\n<span class=\"cm\">// Вызов с клиента — обычный fetch на свой же домен</span>\n<span class=\"kw\">const</span> res = <span class=\"kw\">await fetch</span>(<span class=\"str\">'/api/users'</span>);\n<span class=\"kw\">const</span> users = <span class=\"kw\">await</span> res.<span class=\"fn\">json</span>();\n\n<span class=\"cm\">// Server Actions — ещё проще, без route.ts вообще</span>\n<span class=\"str\">'use server'</span>;\n<span class=\"kw\">export async function</span> <span class=\"fn\">createUser</span>(formData: FormData) {\n  <span class=\"kw\">await</span> db.user.<span class=\"fn\">create</span>({ data: { name: formData.<span class=\"fn\">get</span>(<span class=\"str\">'name'</span>) } });\n}</div>\n      <div class=\"explain\">\n        <strong>route.ts</strong> — каждый экспорт (GET, POST, PUT, DELETE) это отдельный HTTP handler. Это полноценный Node.js код.<br>\n        <strong>Server Actions</strong> — новый способ в Next.js вызывать серверный код прямо из формы, без ручного fetch.<br>\n        ⚠️ <strong>Безопасность:</strong> Server Actions — это скрытые API-эндпоинты. Проверяй авторизацию и права пользователя прямо внутри action, не только в UI.<br>\n        <strong>Один проект, один деплой</strong> — фронтенд и бэкенд живут вместе, не нужно поднимать Express отдельно.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb517\" onchange=\"updateProgress(this)\"><span>API Routes — GET/POST в route.ts</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb518\" onchange=\"updateProgress(this)\"><span>Server Actions — серверные функции без route.ts</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb519\" onchange=\"updateProgress(this)\"><span>Понимаю что не нужен отдельный Express для простых API</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-next-auth-2026","title":"Auth.js / Clerk и защита маршрутов ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-next-auth-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-next-auth-2026')\">Auth.js / Clerk и защита маршрутов <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Auth.js даёт больше контроля, Clerk - готовую облачную систему аккаунтов. Проверка доступа в любом случае выполняется на сервере.</div><div class=\"code\">import { auth } from \"@/auth\";\nimport { redirect } from \"next/navigation\";\n\nexport default async function DashboardPage() {\n  const session = await auth();\n  if (!session?.user) redirect(\"/sign-in\");\n  return &lt;Dashboard user={session.user} /&gt;;\n}\n\n// middleware.ts\nexport { auth as middleware } from \"@/auth\";\nexport const config = { matcher: [\"/dashboard/:path*\"] };</div><div class=\"explain\">Скрытая кнопка - не безопасность. Проверяй сессию внутри приватной серверной страницы и action. Clerk удобен для быстрого готового профиля, Auth.js - для гибкости. Секреты провайдеров хранятся в env.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-auth-2026-1\" onchange=\"updateProgress(this)\"><span>Проверяю сессию на сервере</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-auth-2026-2\" onchange=\"updateProgress(this)\"><span>Защищаю группу маршрутов</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-auth-2026-3\" onchange=\"updateProgress(this)\"><span>Не коммичу секреты</span></label></div></div>"},{"id":"block-node-zod-validation","title":"Валидация данных через Zod база коммерческого кода 🔗","html":"<div class=\"block\" id=\"block-node-zod-validation\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-zod-validation')\">Валидация данных через Zod <span class=\"badge must\">база коммерческого кода</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">В коммерческом бэкенде никто не проверяет req.body вручную через if/else. Используется библиотека валидации — Zod самая популярная в TypeScript-проектах.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Ручная валидация — много кода, легко забыть проверку</span>\napp.<span class=\"fn\">post</span>(<span class=\"str\">'/users'</span>, (req, res) =&gt; {\n  <span class=\"kw\">if</span> (!req.body.email || <span class=\"kw\">typeof</span> req.body.email !== <span class=\"str\">'string'</span>) {\n    <span class=\"kw\">return</span> res.<span class=\"fn\">status</span>(<span class=\"num\">400</span>).<span class=\"fn\">send</span>(<span class=\"str\">'Invalid email'</span>);\n  }\n  <span class=\"cm\">// ... ещё 10 проверок для каждого поля</span>\n});\n\n<span class=\"cm\">// ✅ Zod — описываешь схему один раз, валидация автоматическая</span>\n<span class=\"kw\">import</span> { z } <span class=\"kw\">from</span> <span class=\"str\">'zod'</span>;\n\n<span class=\"kw\">const</span> userSchema = z.<span class=\"fn\">object</span>({\n  email: z.<span class=\"fn\">string</span>().<span class=\"fn\">email</span>(),\n  age: z.<span class=\"fn\">number</span>().<span class=\"fn\">min</span>(<span class=\"num\">18</span>).<span class=\"fn\">max</span>(<span class=\"num\">120</span>),\n  name: z.<span class=\"fn\">string</span>().<span class=\"fn\">min</span>(<span class=\"num\">2</span>)\n});\n\napp.<span class=\"fn\">post</span>(<span class=\"str\">'/users'</span>, (req, res) =&gt; {\n  <span class=\"kw\">const</span> result = userSchema.<span class=\"fn\">safeParse</span>(req.body);\n  <span class=\"kw\">if</span> (!result.success) {\n    <span class=\"kw\">return</span> res.<span class=\"fn\">status</span>(<span class=\"num\">400</span>).<span class=\"fn\">json</span>(result.error.issues);\n  }\n  <span class=\"cm\">// result.data — гарантированно валидные и типизированные данные</span>\n  <span class=\"kw\">const</span> user = <span class=\"kw\">await</span> db.user.<span class=\"fn\">create</span>({ data: result.data });\n});\n\n<span class=\"cm\">// Бонус — TypeScript тип выводится из схемы автоматически</span>\n<span class=\"kw\">type</span> UserInput = z.infer&lt;<span class=\"kw\">typeof</span> userSchema&gt;;</div>\n      <div class=\"explain\">\n        <strong>safeParse</strong> — не бросает ошибку, возвращает <code>{success, data}</code> или <code>{success, error}</code> — удобно для обработки.<br>\n        <strong>z.infer&lt;typeof schema&gt;</strong> — TypeScript тип автоматически выводится из Zod-схемы, не нужно дублировать вручную.<br>\n        <strong>Где используется:</strong> валидация body запросов в Express/Next.js API Routes, валидация форм на фронтенде (часто вместе с react-hook-form).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb535\" onchange=\"updateProgress(this)\"><span>z.object() — описание схемы валидации</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb536\" onchange=\"updateProgress(this)\"><span>safeParse — безопасная валидация без try/catch</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb537\" onchange=\"updateProgress(this)\"><span>z.infer — автоматический TypeScript тип из схемы</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-what","title":"Что такое Node.js и зачем он основа 🔗","html":"<div class=\"block\" id=\"block-node-what\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-what')\">Что такое Node.js и зачем он <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Браузер умеет запускать JS. Но JS «снаружи» браузера — на компьютере, на сервере — запускает <strong>Node.js</strong>. Это «движок» V8 (тот же что в Chrome), вынутый из браузера и поставленный отдельно.</div>\n      <div class=\"explain\">\n        <strong>Зачем это нужно:</strong><br>\n        • <strong>Сервер</strong> — программа которая принимает запросы от пользователей и отдаёт данные (страницы, ответы API)<br>\n        • <strong>Один язык везде</strong> — фронтенд на JS, бэкенд на JS. Не надо учить второй язык для сервера<br>\n        • <strong>Быстрый старт</strong> — раз ты уже знаешь JS, Node даётся легче чем Python или PHP с нуля<br>\n        • <strong>Гигантская экосистема</strong> — миллионы готовых пакетов (npm), почти всё уже написано до тебя<br><br>\n        <strong>Где используется:</strong> чаты (WhatsApp Web), стриминг (часть Netflix), API, сервера реального времени, инструменты разработки.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb485\" onchange=\"updateProgress(this)\"><span>Понимаю: Node.js — это JS вне браузера (на сервере/компьютере)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb486\" onchange=\"updateProgress(this)\"><span>Знаю что одним языком (JS) можно писать и фронт, и бэк</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb487\" onchange=\"updateProgress(this)\"><span>Понимаю что сервер — это программа отвечающая на запросы</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-install","title":"Установка и первый запуск основа 🔗","html":"<div class=\"block\" id=\"block-node-install\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-install')\">Установка и первый запуск <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Node ставится с официального сайта <strong>nodejs.org</strong>. Бери версию <strong>LTS</strong> (Long Term Support — стабильная). Вместе с Node ставится <strong>npm</strong> — менеджер пакетов.</div>\n      <div class=\"code\">// Проверить что установлено (в терминале):\nnode -v      // покажет версию, например v20.11.0\nnpm -v       // версия npm\n\n// Создай файл hello.js:\nconsole.log(\"Привет с сервера!\");\n\n// Запусти в терминале:\nnode hello.js\n// → выведет: Привет с сервера!</div>\n      <div class=\"explain\">\n        <strong>node hello.js</strong> — запускает твой JS-файл <em>напрямую</em>, без браузера. Никакого HTML не нужно!<br>\n        <strong>console.log</strong> — работает так же как в браузере, но выводит в <em>терминал</em>, а не в консоль браузера.<br>\n        <strong>LTS-версия</strong> — выбирай её, не «Current». LTS стабильнее, реже ломается.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb488\" onchange=\"updateProgress(this)\"><span>Установил Node.js (LTS) с nodejs.org</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb489\" onchange=\"updateProgress(this)\"><span>Проверил node -v и npm -v в терминале</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb490\" onchange=\"updateProgress(this)\"><span>Запустил первый .js файл через node имя_файла.js</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-npm","title":"npm — менеджер пакетов основа 🔗","html":"<div class=\"block\" id=\"block-node-npm\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-npm')\">npm — менеджер пакетов <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\"><strong>npm</strong> — это как магазин готового кода. Нужна библиотека? Устанавливаешь одной командой, а не пишешь сам. Миллионы пакетов.</div>\n      <div class=\"code\">// Создать проект (создаёт package.json — «паспорт» проекта):\nnpm init -y\n\n// Установить пакет (например, express — фреймворк для серверов):\nnpm install express\n\n// Установить и запомнить как dev-зависимость:\nnpm install --save-dev nodemon\n\n// Запустить скрипт из package.json:\nnpm run start</div>\n      <div class=\"explain\">\n        <strong>package.json</strong> — файл со списком всех пакетов которые использует твой проект. Как список ингредиентов рецепта.<br>\n        <strong>node_modules</strong> — папка куда скачиваются пакеты. Огромная. <em>Никогда не заливай её на GitHub</em> — добавь в <code>.gitignore</code>.<br>\n        <strong>npm install</strong> (без названия) — установит ВСЕ пакеты из package.json. Удобно когда скачал чужой проект.<br>\n        <strong>nodemon</strong> — перезапускает сервер автоматически когда меняешь код. Очень удобно при разработке.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb491\" onchange=\"updateProgress(this)\"><span>Понимаю что npm — менеджер готовых пакетов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb492\" onchange=\"updateProgress(this)\"><span>Знаю что package.json — список зависимостей проекта</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb493\" onchange=\"updateProgress(this)\"><span>node_modules НЕ заливаю на GitHub (добавляю в .gitignore)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-next","title":"Куда двигаться дальше потом 🔗","html":"<div class=\"block\" id=\"block-node-next\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-next')\">Куда двигаться дальше <span class=\"badge opt\">потом</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"explain\">\n        Когда освоишь базовый Express-сервер — следующие темы:<br>\n        • <strong>POST/PUT/DELETE</strong> — не только получать данные, но и создавать, менять, удалять<br>\n        • <strong>Middleware</strong> — промежуточные обработчики (проверка авторизации, логи)<br>\n        • <strong>Подключение базы данных</strong> — чтобы данные хранились (см. раздел SQL)<br>\n        • <strong>Авторизация</strong> — логин/регистрация с токенами (JWT)<br>\n        • <strong>Переменные окружения</strong> (.env) — хранить пароли и ключи отдельно от кода<br><br>\n        💡 Лучший способ учиться: <strong>переделай свой TodoList на сервер</strong>. Сейчас он хранит задачи в localStorage (только в браузере). Сделай чтобы задачи хранились на сервере — и тогда они будут доступны с любого устройства.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb500\" onchange=\"updateProgress(this)\"><span>Узнал про POST/PUT/DELETE (методы для изменения данных)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb501\" onchange=\"updateProgress(this)\"><span>Понимаю зачем нужны переменные окружения (.env)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb502\" onchange=\"updateProgress(this)\"><span>Цель: переделать TodoList на серверное хранение</span></label>\n      </div>\n    </div>\n\n\n    "},{"id":"block-node-env","title":"Переменные окружения и .env основа 🔗","html":"<div class=\"block\" id=\"block-node-env\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-env')\">Переменные окружения и .env <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># .env файл</span>\nPORT=3000\nDB_URL=postgresql://localhost:5432/mydb\nJWT_SECRET=supersecretkey123\nNODE_ENV=development\n\n<span class=\"cm\">// Использование через dotenv</span>\n<span class=\"kw\">import</span> dotenv <span class=\"kw\">from</span> <span class=\"str\">'dotenv'</span>;\ndotenv.<span class=\"fn\">config</span>();\n\n<span class=\"kw\">const</span> port = process.env.PORT || <span class=\"num\">3000</span>;\n<span class=\"kw\">const</span> dbUrl = process.env.DB_URL;\n\n<span class=\"cm\">// Никогда не коммить .env!</span>\n<span class=\"cm\"># .gitignore</span>\n.env\n.env.local\nnode_modules/</div>\n      <div class=\"explain\">\n        <strong>process.env</strong> — глобальный объект Node.js с переменными окружения.<br>\n        <strong>dotenv</strong> — загружает .env файл в process.env. Установка: <code>npm i dotenv</code>.<br>\n        <strong>.env в .gitignore</strong> — обязательно! Иначе секреты попадут в публичный репозиторий.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb506\" onchange=\"updateProgress(this)\"><span>process.env — переменные окружения в Node</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb507\" onchange=\"updateProgress(this)\"><span>dotenv — загрузка .env файла</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb508\" onchange=\"updateProgress(this)\"><span>.env в .gitignore — защита секретов</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-fs","title":"Работа с файловой системой (fs) знать 🔗","html":"<div class=\"block\" id=\"block-node-fs\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-fs')\">Работа с файловой системой (fs) <span class=\"badge\">знать</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"kw\">import</span> fs <span class=\"kw\">from</span> <span class=\"str\">'fs/promises'</span>; <span class=\"cm\">// async версия</span>\n<span class=\"kw\">import</span> path <span class=\"kw\">from</span> <span class=\"str\">'path'</span>;\n\n<span class=\"cm\">// Чтение файла</span>\n<span class=\"kw\">const</span> data = <span class=\"kw\">await</span> fs.<span class=\"fn\">readFile</span>(<span class=\"str\">'data.json'</span>, <span class=\"str\">'utf-8'</span>);\n<span class=\"kw\">const</span> json = JSON.<span class=\"fn\">parse</span>(data);\n\n<span class=\"cm\">// Запись файла</span>\n<span class=\"kw\">await</span> fs.<span class=\"fn\">writeFile</span>(<span class=\"str\">'output.json'</span>, JSON.<span class=\"fn\">stringify</span>(json, <span class=\"kw\">null</span>, <span class=\"num\">2</span>));\n\n<span class=\"cm\">// Создание папки</span>\n<span class=\"kw\">await</span> fs.<span class=\"fn\">mkdir</span>(<span class=\"str\">'uploads'</span>, { recursive: <span class=\"kw\">true</span> });\n\n<span class=\"cm\">// Путь к файлу — используй path.join!</span>\n<span class=\"kw\">const</span> filePath = path.<span class=\"fn\">join</span>(__dirname, <span class=\"str\">'data'</span>, <span class=\"str\">'file.json'</span>);\n<span class=\"cm\">// НЕ делай: './data/' + filename (уязвимость path traversal)</span></div>\n      <div class=\"explain\">\n        <strong>fs/promises</strong> — используй вместо callback-версии. Работает с async/await.<br>\n        <strong>path.join</strong> — всегда собирай пути через path.join, не через конкатенацию строк.<br>\n        <strong>recursive: true</strong> — создаст все вложенные папки, не упадёт если уже существует.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb509\" onchange=\"updateProgress(this)\"><span>fs/promises — readFile, writeFile, mkdir</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb510\" onchange=\"updateProgress(this)\"><span>path.join — безопасная сборка путей</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-nextjs-ssg-isr","title":"SSG и ISR — статическая генерация сила Next.js 🔗","html":"<div class=\"block\" id=\"block-nextjs-ssg-isr\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nextjs-ssg-isr')\">SSG и ISR — статическая генерация <span class=\"badge good\">сила Next.js</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Помимо CSR и SSR, у Next.js есть ещё два режима рендеринга — именно они делают Next.js таким быстрым и популярным для контентных сайтов (блоги, магазины, документация).</div>\n      <div class=\"code\"><span class=\"cm\">// SSG (Static Site Generation) — страница генерируется ОДИН РАЗ при сборке</span>\n<span class=\"kw\">export default async function</span> <span class=\"fn\">BlogPost</span>({ params }) {\n  <span class=\"kw\">const</span> post = <span class=\"kw\">await</span> <span class=\"fn\">getPost</span>(params.slug);\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">article</span>&gt;{post.title}&lt;/<span class=\"tag\">article</span>&gt;;\n}\n\n<span class=\"cm\">// Указываем какие страницы генерировать заранее (на этапе npm run build)</span>\n<span class=\"kw\">export async function</span> <span class=\"fn\">generateStaticParams</span>() {\n  <span class=\"kw\">const</span> posts = <span class=\"kw\">await</span> <span class=\"fn\">getAllPosts</span>();\n  <span class=\"kw\">return</span> posts.<span class=\"fn\">map</span>(p =&gt; ({ slug: p.slug }));\n}\n<span class=\"cm\">// Результат: готовый HTML для каждого поста, отдаётся мгновенно — как обычный файл</span>\n\n<span class=\"cm\">// ISR (Incremental Static Regeneration) — статика, которая обновляется сама</span>\n<span class=\"kw\">export const</span> revalidate = <span class=\"num\">60</span>; <span class=\"cm\">// пересобрать страницу не чаще раза в 60 секунд</span>\n\n<span class=\"kw\">export default async function</span> <span class=\"fn\">ProductPage</span>({ params }) {\n  <span class=\"kw\">const</span> product = <span class=\"kw\">await</span> <span class=\"fn\">getProduct</span>(params.id); <span class=\"cm\">// данные могут меняться (цена, наличие)</span>\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">div</span>&gt;{product.price}&lt;/<span class=\"tag\">div</span>&gt;;\n}\n<span class=\"cm\">// Первый посетитель после истечения 60 сек получает старую версию,</span>\n<span class=\"cm\">// но в фоне Next.js пересобирает страницу — следующие посетители видят новую</span></div>\n      <div class=\"explain\">\n        <strong>SSG</strong> — лучший вариант для контента который редко меняется (блог, документация, лендинг). Страница уже готова заранее — отдаётся мгновенно, как статический файл.<br>\n        <strong>ISR</strong> — компромисс между SSG и SSR: страница статическая (быстрая), но автоматически обновляется через заданный интервал без полной пересборки всего сайта.<br>\n        <strong>PPR (Partial Prerendering)</strong> — современный подход Next.js: статический каркас отдаётся мгновенно, а динамические зоны догружаются стримингом через Suspense.<br>\n        <strong>Edge Runtime</strong> — выполнение части серверного кода ближе к пользователю, когда важна минимальная задержка и нет зависимости от Node-only API.<br>\n        <strong>Когда что выбрать:</strong> SSG — контент почти не меняется; ISR — меняется иногда (цены, остатки); SSR — меняется на каждый запрос (личный кабинет, дашборд).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb523\" onchange=\"updateProgress(this)\"><span>SSG — generateStaticParams, страницы готовы при сборке</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb524\" onchange=\"updateProgress(this)\"><span>ISR — revalidate, автообновление статики в фоне</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb525\" onchange=\"updateProgress(this)\"><span>Понимаю когда выбрать SSG, ISR или SSR</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb525a\" onchange=\"updateProgress(this)\"><span>PPR и Edge Runtime — понимаю современные режимы рендеринга Next.js</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-auth-types","title":"Session vs JWT — два подхода к авторизации критично 🔗","html":"<div class=\"block\" id=\"block-node-auth-types\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-auth-types')\">Session vs JWT — два подхода к авторизации <span class=\"badge must\">критично</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Это основа основ для бэкенда. Понимание разницы между Session-based и Token-based авторизацией спрашивают на каждом собеседовании.</div>\n      <div class=\"code\"><span class=\"cm\">// ===== Session-based (классический подход) =====</span>\n<span class=\"cm\">// 1. Пользователь логинится → сервер создаёт сессию в БД/памяти</span>\n<span class=\"cm\">// 2. Сервер отдаёт cookie с session ID</span>\n<span class=\"cm\">// 3. Каждый запрос → сервер ищет сессию по ID в своём хранилище</span>\n\napp.<span class=\"fn\">post</span>(<span class=\"str\">'/login'</span>, (req, res) =&gt; {\n  req.session.userId = user.id; <span class=\"cm\">// сохраняется на сервере (Redis/БД)</span>\n  res.<span class=\"fn\">send</span>(<span class=\"str\">'OK'</span>);\n});\n<span class=\"cm\">// Сервер ДОЛЖЕН хранить состояние сессий — это stateful</span>\n\n<span class=\"cm\">// ===== JWT (Token-based, современный подход) =====</span>\n<span class=\"cm\">// 1. Пользователь логинится → сервер подписывает токен и отдаёт его</span>\n<span class=\"cm\">// 2. Сервер НЕ хранит токен — вся инфа уже внутри самого токена</span>\n<span class=\"cm\">// 3. Каждый запрос → сервер просто проверяет подпись токена</span>\n\n<span class=\"kw\">const</span> token = jwt.<span class=\"fn\">sign</span>({ userId: user.id }, SECRET, { expiresIn: <span class=\"str\">'15m'</span> });\nres.<span class=\"fn\">json</span>({ token });\n<span class=\"cm\">// Сервер НИЧЕГО не хранит — это stateless, легко масштабируется</span></div>\n      <div class=\"explain\">\n        <strong>Session</strong> — сервер хранит состояние (stateful). Просто отозвать доступ (удалить сессию), но сложнее масштабировать на много серверов.<br>\n        <strong>JWT</strong> — сервер ничего не хранит (stateless). Легко масштабируется, но сложнее досрочно \"отозвать\" токен пока он не истёк.<br>\n        <strong>На практике:</strong> JWT — стандарт для API и SPA/мобильных приложений. Session — иногда используется в классических серверных приложениях (Django, Rails).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb526\" onchange=\"updateProgress(this)\"><span>Session-based — сервер хранит состояние (stateful)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb527\" onchange=\"updateProgress(this)\"><span>JWT — вся информация внутри токена, сервер stateless</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb528\" onchange=\"updateProgress(this)\"><span>Понимаю плюсы/минусы каждого подхода</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-access-refresh","title":"Access и Refresh токены критично 🔗","html":"<div class=\"block\" id=\"block-node-access-refresh\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-access-refresh')\">Access и Refresh токены <span class=\"badge must\">критично</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Почему нельзя выдать один токен навечно? Потому что если его украдут (XSS, перехват) — злоумышленник получит доступ навсегда. Решение — короткоживущий Access + долгоживущий Refresh.</div>\n      <div class=\"code\"><span class=\"cm\">// Access Token — живёт КОРОТКО (минуты), используется в каждом запросе</span>\n<span class=\"kw\">const</span> accessToken = jwt.<span class=\"fn\">sign</span>({ userId }, ACCESS_SECRET, { expiresIn: <span class=\"str\">'15m'</span> });\n\n<span class=\"cm\">// Refresh Token — живёт ДОЛГО (дни/недели), хранится безопасно (httpOnly cookie)</span>\n<span class=\"kw\">const</span> refreshToken = jwt.<span class=\"fn\">sign</span>({ userId }, REFRESH_SECRET, { expiresIn: <span class=\"str\">'7d'</span> });\n\n<span class=\"cm\">// Когда Access Token истекает — клиент использует Refresh для получения нового</span>\napp.<span class=\"fn\">post</span>(<span class=\"str\">'/refresh'</span>, (req, res) =&gt; {\n  <span class=\"kw\">const</span> { refreshToken } = req.cookies;\n  <span class=\"kw\">try</span> {\n    <span class=\"kw\">const</span> payload = jwt.<span class=\"fn\">verify</span>(refreshToken, REFRESH_SECRET);\n    <span class=\"kw\">const</span> newAccessToken = jwt.<span class=\"fn\">sign</span>({ userId: payload.userId }, ACCESS_SECRET, { expiresIn: <span class=\"str\">'15m'</span> });\n    res.<span class=\"fn\">json</span>({ accessToken: newAccessToken }); <span class=\"cm\">// ротация — выдаём новый</span>\n  } <span class=\"kw\">catch</span> {\n    res.<span class=\"fn\">status</span>(<span class=\"num\">401</span>).<span class=\"fn\">send</span>(<span class=\"str\">'Refresh token невалиден — нужен повторный логин'</span>);\n  }\n});</div>\n      <div class=\"explain\">\n        <strong>Зачем два токена:</strong> Access живёт мало — даже если украден, окно для атаки маленькое (15 минут). Refresh живёт долго, но хранится только в httpOnly cookie, недоступной для JS/XSS.<br>\n        <strong>Ротация токенов</strong> — каждый раз когда Refresh используется для получения нового Access, иногда выдают и новый Refresh, инвалидируя старый.<br>\n        <strong>Если Refresh украден</strong> — у сервера есть возможность отозвать его (хранить blacklist), в отличие от чистого stateless JWT.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb529\" onchange=\"updateProgress(this)\"><span>Access Token — короткоживущий, используется в каждом запросе</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb530\" onchange=\"updateProgress(this)\"><span>Refresh Token — долгоживущий, для получения нового Access</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb531\" onchange=\"updateProgress(this)\"><span>Понимаю зачем нужна ротация токенов</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-cookies-security","title":"Безопасные куки: httpOnly, Secure, SameSite критично для фронтенда 🔗","html":"<div class=\"block\" id=\"block-node-cookies-security\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-cookies-security')\">Безопасные куки: httpOnly, Secure, SameSite <span class=\"badge must\">критично для фронтенда</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Хранить токены в localStorage в реальных проектах небезопасно — любой встроенный на страницу скрипт (XSS-атака) может их прочитать. httpOnly cookie решает эту проблему.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ localStorage — доступен из ЛЮБОГО JS на странице</span>\nlocalStorage.<span class=\"fn\">setItem</span>(<span class=\"str\">'token'</span>, accessToken);\n<span class=\"cm\">// Если на сайт попадёт вредоносный script (XSS) — он украдёт токен</span>\n\n<span class=\"cm\">// ✅ httpOnly cookie — JavaScript НЕ МОЖЕТ её прочитать</span>\nres.<span class=\"fn\">cookie</span>(<span class=\"str\">'refreshToken'</span>, refreshToken, {\n  httpOnly: <span class=\"kw\">true</span>,   <span class=\"cm\">// недоступна через document.cookie / JS</span>\n  secure: <span class=\"kw\">true</span>,     <span class=\"cm\">// передаётся только по HTTPS</span>\n  sameSite: <span class=\"str\">'strict'</span>, <span class=\"cm\">// защита от CSRF — не отправляется с других сайтов</span>\n  maxAge: <span class=\"num\">7</span> * <span class=\"num\">24</span> * <span class=\"num\">60</span> * <span class=\"num\">60</span> * <span class=\"num\">1000</span> <span class=\"cm\">// 7 дней в миллисекундах</span>\n});</div>\n      <div class=\"explain\">\n        <strong>httpOnly</strong> — куки недоступна через <code>document.cookie</code>, защищает от XSS (вредоносных скриптов на странице).<br>\n        <strong>Secure</strong> — куки передаётся только по HTTPS, не по обычному HTTP.<br>\n        <strong>SameSite: strict/lax</strong> — браузер не отправляет куки если запрос пришёл с другого домена, защита от CSRF-атак.<br>\n        <strong>Практика:</strong> Refresh Token — в httpOnly cookie. Access Token — можно держать в памяти приложения (переменная JS), не в localStorage.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb532\" onchange=\"updateProgress(this)\"><span>httpOnly — куки недоступна для JavaScript, защита от XSS</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb533\" onchange=\"updateProgress(this)\"><span>Secure и SameSite — защита передачи и от CSRF</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb534\" onchange=\"updateProgress(this)\"><span>Понимаю почему localStorage небезопасен для токенов</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-cors-security","title":"CORS и Security Headers часто ломается 🔗","html":"<div class=\"block\" id=\"block-node-cors-security\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-cors-security')\">CORS и Security Headers <span class=\"badge must\">часто ломается</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Когда фронтенд на одном домене, а API на другом, браузер включает CORS-проверку. Это не ошибка JS, а защита браузера.</div>\n      <div class=\"code\"><span class=\"cm\">// Express + cors</span>\n<span class=\"kw\">import</span> cors <span class=\"kw\">from</span> <span class=\"str\">'cors'</span>;\n<span class=\"kw\">import</span> helmet <span class=\"kw\">from</span> <span class=\"str\">'helmet'</span>;\n\napp.<span class=\"fn\">use</span>(<span class=\"fn\">cors</span>({\n  origin: <span class=\"str\">'https://my-frontend.ru'</span>,\n  credentials: <span class=\"kw\">true</span>,\n  methods: [<span class=\"str\">'GET'</span>, <span class=\"str\">'POST'</span>, <span class=\"str\">'PUT'</span>, <span class=\"str\">'DELETE'</span>]\n}));\n\napp.<span class=\"fn\">use</span>(<span class=\"fn\">helmet</span>({\n  contentSecurityPolicy: {\n    directives: {\n      defaultSrc: [<span class=\"str\">\"'self'\"</span>],\n      scriptSrc: [<span class=\"str\">\"'self'\"</span>]\n    }\n  }\n}));</div>\n      <div class=\"explain\">\n        <strong>Access-Control-Allow-Origin</strong> говорит браузеру, какому фронтенду можно читать ответ API.<br>\n        <strong>credentials: true</strong> нужен, если запросы ходят с cookie. Тогда нельзя ставить <code>origin: '*'</code>.<br>\n        <strong>CSP, HSTS, X-Content-Type-Options</strong> — security headers. В Express их часто ставят через <code>helmet</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-cors-1\" onchange=\"updateProgress(this)\"><span>CORS — понимаю почему браузер блокирует чужой origin</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-cors-2\" onchange=\"updateProgress(this)\"><span>credentials + cookie требуют точный origin, не *</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-cors-3\" onchange=\"updateProgress(this)\"><span>Helmet — базовые security headers для Express</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-zod-advanced","title":"Zod: refine и transform практика 🔗","html":"<div class=\"block\" id=\"block-node-zod-advanced\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-zod-advanced')\">Zod: refine и transform <span class=\"badge good\">практика</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Базовая схема проверяет типы. В реальном коде часто нужны дополнительные правила: совпадение паролей, очистка строк, превращение строки в число.</div>\n      <div class=\"code\"><span class=\"kw\">const</span> registerSchema = z.<span class=\"fn\">object</span>({\n  email: z.<span class=\"fn\">string</span>().<span class=\"fn\">trim</span>().<span class=\"fn\">toLowerCase</span>().<span class=\"fn\">email</span>(),\n  password: z.<span class=\"fn\">string</span>().<span class=\"fn\">min</span>(<span class=\"num\">8</span>),\n  confirm: z.<span class=\"fn\">string</span>(),\n  age: z.<span class=\"fn\">string</span>().<span class=\"fn\">transform</span>(Number)\n}).<span class=\"fn\">refine</span>(\n  data =&gt; data.password === data.confirm,\n  { path: [<span class=\"str\">'confirm'</span>], message: <span class=\"str\">'Пароли не совпадают'</span> }\n);\n\n<span class=\"kw\">const</span> result = registerSchema.<span class=\"fn\">safeParse</span>(req.body);</div>\n      <div class=\"explain\">\n        <strong>transform</strong> меняет значение после проверки: например, строку <code>\"18\"</code> превращает в число <code>18</code>.<br>\n        <strong>refine</strong> добавляет правило, которое зависит от нескольких полей сразу.<br>\n        <strong>path</strong> показывает, к какому полю привязать ошибку, чтобы фронтенд подсветил правильный input.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-zod-advanced-1\" onchange=\"updateProgress(this)\"><span>transform — преобразование данных после проверки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-zod-advanced-2\" onchange=\"updateProgress(this)\"><span>refine — кастомная проверка, например совпадение паролей</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-api-styles","title":"REST, GraphQL, gRPC, tRPC и SSE архитектура API 🔗","html":"<div class=\"block\" id=\"block-node-api-styles\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-api-styles')\">REST, GraphQL, gRPC, tRPC и SSE <span class=\"badge good\">архитектура API</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">REST — база. Но в командах встречаются и другие подходы: GraphQL для гибких запросов, gRPC для микросервисов, tRPC для TypeScript fullstack, SSE для стриминга.</div>\n      <div class=\"explain\">\n        <strong>REST</strong> — ресурсы и HTTP-методы: GET, POST, PUT/PATCH, DELETE. Лучший старт для новичка.<br>\n        <strong>GraphQL</strong> — клиент сам выбирает поля через Query/Mutation, а сервер описывает resolver-функции.<br>\n        <strong>gRPC + Protobuf</strong> — бинарный протокол для общения сервисов между собой. Быстрее JSON, но сложнее старт.<br>\n        <strong>tRPC</strong> — сквозная типизация между frontend и backend в TypeScript-проектах без ручной OpenAPI-схемы.<br>\n        <strong>SSE</strong> — Server-Sent Events. Нативный поток с сервера к клиенту: ленты, прогресс, генерация текста ИИ. Для чата чаще WebSocket.\n      </div>\n      <div class=\"code\"><span class=\"cm\">// SSE: сервер отправляет поток событий</span>\napp.<span class=\"fn\">get</span>(<span class=\"str\">'/events'</span>, (req, res) =&gt; {\n  res.<span class=\"fn\">setHeader</span>(<span class=\"str\">'Content-Type'</span>, <span class=\"str\">'text/event-stream'</span>);\n  res.<span class=\"fn\">write</span>(<span class=\"str\">'data: hello\\\\n\\\\n'</span>);\n});\n\n<span class=\"cm\">// Клиент</span>\n<span class=\"kw\">const</span> events = <span class=\"kw\">new</span> <span class=\"fn\">EventSource</span>(<span class=\"str\">'/events'</span>);\nevents.<span class=\"fn\">onmessage</span> = (e) =&gt; console.<span class=\"fn\">log</span>(e.data);</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-api-styles-1\" onchange=\"updateProgress(this)\"><span>REST — база API через HTTP-методы</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-api-styles-2\" onchange=\"updateProgress(this)\"><span>GraphQL, gRPC и tRPC — понимаю где применяются</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-api-styles-3\" onchange=\"updateProgress(this)\"><span>SSE — односторонний поток событий с сервера</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-websockets","title":"WebSockets — реальное время (Socket.io) важно 🔗","html":"<div class=\"block\" id=\"block-node-websockets\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-websockets')\">WebSockets — реальное время (Socket.io) <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">REST API работает по принципу \"запрос → ответ\". Но чаты, уведомления в реальном времени и live-обновления (например, совместное редактирование) требуют постоянного соединения — для этого WebSockets.</div>\n      <div class=\"code\"><span class=\"cm\">// Сервер (Node.js + Socket.io)</span>\n<span class=\"kw\">import</span> { Server } <span class=\"kw\">from</span> <span class=\"str\">'socket.io'</span>;\n\n<span class=\"kw\">const</span> io = <span class=\"kw\">new</span> <span class=\"fn\">Server</span>(httpServer);\n\nio.<span class=\"fn\">on</span>(<span class=\"str\">'connection'</span>, (socket) =&gt; {\n  console.<span class=\"fn\">log</span>(<span class=\"str\">'Клиент подключился'</span>);\n\n  socket.<span class=\"fn\">on</span>(<span class=\"str\">'message'</span>, (text) =&gt; {\n    io.<span class=\"fn\">emit</span>(<span class=\"str\">'message'</span>, text); <span class=\"cm\">// рассылаем ВСЕМ подключённым клиентам</span>\n  });\n\n  socket.<span class=\"fn\">on</span>(<span class=\"str\">'disconnect'</span>, () =&gt; console.<span class=\"fn\">log</span>(<span class=\"str\">'Клиент отключился'</span>));\n});\n\n<span class=\"cm\">// Клиент (React)</span>\n<span class=\"kw\">import</span> { io } <span class=\"kw\">from</span> <span class=\"str\">'socket.io-client'</span>;\n\n<span class=\"kw\">const</span> socket = <span class=\"fn\">io</span>(<span class=\"str\">'http://localhost:3000'</span>);\n\nsocket.<span class=\"fn\">on</span>(<span class=\"str\">'message'</span>, (text) =&gt; {\n  <span class=\"fn\">setMessages</span>(prev =&gt; [...prev, text]); <span class=\"cm\">// новое сообщение появляется мгновенно</span>\n});\n\nsocket.<span class=\"fn\">emit</span>(<span class=\"str\">'message'</span>, <span class=\"str\">'Привет всем!'</span>); <span class=\"cm\">// отправка сообщения на сервер</span></div>\n      <div class=\"explain\">\n        <strong>Главное отличие от HTTP:</strong> соединение остаётся открытым — сервер может сам отправлять данные клиенту без того, чтобы клиент сначала запросил.<br>\n        <strong>socket.emit</strong> — отправить событие. <strong>socket.on</strong> — подписаться на событие.<br>\n        <strong>Где используется:</strong> чаты, live-уведомления, совместное редактирование документов, онлайн-игры, биржевые котировки в реальном времени.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb538\" onchange=\"updateProgress(this)\"><span>Понимаю разницу WebSocket vs обычный REST запрос</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb539\" onchange=\"updateProgress(this)\"><span>socket.emit / socket.on — базовый API Socket.io</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb540\" onchange=\"updateProgress(this)\"><span>Знаю типичные применения: чаты, уведомления, real-time доски</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-sql","lessons":[{"id":"block-sql-practice","title":"Где практиковаться совет 🔗","html":"<div class=\"block\" id=\"block-sql-practice\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-practice')\">Где практиковаться <span class=\"badge opt\">совет</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"explain\">\n        <strong>Без установки (в браузере):</strong><br>\n        • <strong>sqlbolt.com</strong> — интерактивный учебник SQL с нуля, лучший для старта<br>\n        • <strong>sql-ex.ru</strong> — задачи на русском<br>\n        • <strong>db-fiddle.com</strong> — песочница, пробуй запросы онлайн<br><br>\n        <strong>Для проекта:</strong><br>\n        • <strong>SQLite</strong> — простейшая БД, целая база в одном файле. Идеально для старта с Node.js<br>\n        • <strong>PostgreSQL</strong> — серьёзная БД для реальных проектов. Бесплатная, мощная<br><br>\n        💡 С Node.js базу подключают через пакеты: <code>better-sqlite3</code> (для SQLite) или <code>pg</code> (для PostgreSQL).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb553\" onchange=\"updateProgress(this)\"><span>Прошёл интерактивный курс на sqlbolt.com</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb554\" onchange=\"updateProgress(this)\"><span>Попробовал SQLite (база в одном файле)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb555\" onchange=\"updateProgress(this)\"><span>Цель: подключить БД к своему Node.js серверу</span></label>\n      </div>\n    </div>\n\n\n    "},{"id":"block-sql-aggregate","title":"Агрегатные функции и GROUP BY основа 🔗","html":"<div class=\"block\" id=\"block-sql-aggregate\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-aggregate')\">Агрегатные функции и GROUP BY <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- Агрегатные функции</span>\n<span class=\"kw\">SELECT</span>\n  <span class=\"fn\">COUNT</span>(*) <span class=\"kw\">AS</span> total_orders,\n  <span class=\"fn\">SUM</span>(amount) <span class=\"kw\">AS</span> revenue,\n  <span class=\"fn\">AVG</span>(amount) <span class=\"kw\">AS</span> avg_order,\n  <span class=\"fn\">MAX</span>(amount) <span class=\"kw\">AS</span> max_order,\n  <span class=\"fn\">MIN</span>(amount) <span class=\"kw\">AS</span> min_order\n<span class=\"kw\">FROM</span> orders;\n\n<span class=\"cm\">-- GROUP BY — группировка</span>\n<span class=\"kw\">SELECT</span> user_id, <span class=\"fn\">COUNT</span>(*) <span class=\"kw\">AS</span> orders_count, <span class=\"fn\">SUM</span>(amount)\n<span class=\"kw\">FROM</span> orders\n<span class=\"kw\">GROUP BY</span> user_id\n<span class=\"kw\">ORDER BY</span> orders_count <span class=\"kw\">DESC</span>;\n\n<span class=\"cm\">-- HAVING — фильтр после группировки (не WHERE!)</span>\n<span class=\"kw\">SELECT</span> user_id, <span class=\"fn\">SUM</span>(amount) <span class=\"kw\">AS</span> total\n<span class=\"kw\">FROM</span> orders\n<span class=\"kw\">GROUP BY</span> user_id\n<span class=\"kw\">HAVING</span> <span class=\"fn\">SUM</span>(amount) &gt; <span class=\"num\">1000</span>; <span class=\"cm\">-- только крупные покупатели</span></div>\n      <div class=\"explain\">\n        <strong>COUNT(*)</strong> — считает все строки. COUNT(column) — только не-NULL значения.<br>\n        <strong>GROUP BY</strong> — обязателен когда используешь агрегатные функции с другими колонками.<br>\n        <strong>HAVING vs WHERE</strong> — WHERE фильтрует строки ДО группировки, HAVING — ПОСЛЕ.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb559\" onchange=\"updateProgress(this)\"><span>COUNT, SUM, AVG, MAX, MIN — агрегатные функции</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb560\" onchange=\"updateProgress(this)\"><span>GROUP BY — группировка результатов</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb561\" onchange=\"updateProgress(this)\"><span>HAVING — фильтрация после группировки</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-indexes","title":"Индексы и оптимизация важно 🔗","html":"<div class=\"block\" id=\"block-sql-indexes\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-indexes')\">Индексы и оптимизация <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- Индекс ускоряет поиск (B-tree структура)</span>\n<span class=\"kw\">CREATE INDEX</span> idx_users_email <span class=\"kw\">ON</span> users(email);\n<span class=\"kw\">CREATE INDEX</span> idx_orders_user_id <span class=\"kw\">ON</span> orders(user_id);\n\n<span class=\"cm\">-- Уникальный индекс</span>\n<span class=\"kw\">CREATE UNIQUE INDEX</span> idx_unique_email <span class=\"kw\">ON</span> users(email);\n\n<span class=\"cm\">-- EXPLAIN ANALYZE — смотрим план запроса</span>\n<span class=\"kw\">EXPLAIN ANALYZE</span>\n<span class=\"kw\">SELECT</span> * <span class=\"kw\">FROM</span> users <span class=\"kw\">WHERE</span> email = <span class=\"str\">'test@test.com'</span>;\n<span class=\"cm\">-- Без индекса: Seq Scan (перебор всех строк)</span>\n<span class=\"cm\">-- С индексом:  Index Scan (мгновенно)</span>\n\n<span class=\"cm\">-- Когда создавать индекс:</span>\n<span class=\"cm\">-- ✓ Колонки в WHERE, JOIN ON, ORDER BY</span>\n<span class=\"cm\">-- ✗ Колонки которые часто обновляются</span>\n<span class=\"cm\">-- ✗ Маленькие таблицы (&lt; 1000 строк)</span></div>\n      <div class=\"explain\">\n        <strong>Индекс</strong> — как оглавление в книге. Без него БД читает все строки (Seq Scan).<br>\n        <strong>PRIMARY KEY</strong> автоматически создаёт индекс.<br>\n        <strong>EXPLAIN ANALYZE</strong> — главный инструмент оптимизации. Показывает как выполняется запрос.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb562\" onchange=\"updateProgress(this)\"><span>CREATE INDEX — ускорение поиска по колонке</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb563\" onchange=\"updateProgress(this)\"><span>EXPLAIN ANALYZE — анализ плана выполнения</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb564\" onchange=\"updateProgress(this)\"><span>Знаю когда индекс помогает, а когда нет</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-transactions-isolation","title":"Транзакции и уровни изоляции важно 🔗","html":"<div class=\"block\" id=\"block-sql-transactions-isolation\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-transactions-isolation')\">Транзакции и уровни изоляции <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Транзакция — это группа запросов, которые должны выполниться целиком. Если один шаг сломался, всё откатывается назад.</div>\n      <div class=\"code\"><span class=\"cm\">-- Перевод денег: либо оба запроса, либо ни одного</span>\n<span class=\"kw\">BEGIN</span>;\n\n<span class=\"kw\">UPDATE</span> accounts\n<span class=\"kw\">SET</span> balance = balance - <span class=\"num\">1000</span>\n<span class=\"kw\">WHERE</span> id = <span class=\"num\">1</span>;\n\n<span class=\"kw\">UPDATE</span> accounts\n<span class=\"kw\">SET</span> balance = balance + <span class=\"num\">1000</span>\n<span class=\"kw\">WHERE</span> id = <span class=\"num\">2</span>;\n\n<span class=\"kw\">COMMIT</span>;   <span class=\"cm\">-- сохранить изменения</span>\n<span class=\"cm\">-- ROLLBACK; -- отменить всё внутри транзакции</span>\n\n<span class=\"cm\">-- Уровень изоляции: насколько транзакции видят друг друга</span>\n<span class=\"kw\">BEGIN</span>;\n<span class=\"kw\">SET TRANSACTION ISOLATION LEVEL</span> SERIALIZABLE;\n<span class=\"cm\">-- важные запросы...</span>\n<span class=\"kw\">COMMIT</span>;</div>\n      <div class=\"explain\">\n        <strong>ACID</strong> — база защищает данные: атомарность, согласованность, изоляция, надёжность.<br>\n        <strong>Read Committed</strong> — дефолт в PostgreSQL: видишь только закоммиченные данные.<br>\n        <strong>Repeatable Read / Serializable</strong> — строже, но дороже по производительности. Нужны для денег, бронирований, остатков товара.<br>\n        <strong>PgBouncer</strong> — пулер соединений перед PostgreSQL. Помогает не убить базу тысячами подключений.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-tx-1\" onchange=\"updateProgress(this)\"><span>BEGIN / COMMIT / ROLLBACK — понимаю базовый цикл транзакции</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-tx-2\" onchange=\"updateProgress(this)\"><span>Понимаю зачем нужны уровни изоляции</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-tx-3\" onchange=\"updateProgress(this)\"><span>Слышал про PgBouncer как пулер соединений</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-nosql-redis","title":"Redis и NoSQL — когда не только SQL обзор 🔗","html":"<div class=\"block\" id=\"block-sql-nosql-redis\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-nosql-redis')\">Redis и NoSQL — когда не только SQL <span class=\"badge rec\">обзор</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">SQL остаётся базой для большинства проектов. Redis и MongoDB добавляют рядом, когда появляется конкретная задача: кэш, сессии, очереди или гибкие документы.</div>\n      <div class=\"code\"><span class=\"cm\"># Redis — быстрые данные в памяти</span>\nSET user:42 \"Alex\"\nGET user:42\nEXPIRE user:42 3600       <span class=\"cm\"># удалить через час</span>\n\n<span class=\"cm\"># Список как простая очередь задач</span>\nLPUSH jobs \"send-email\"\nRPOP jobs\n\n<span class=\"cm\"># Частые сценарии</span>\ncache:homepage\nsession:user:42\nrate-limit:ip:127.0.0.1\nqueue:emails</div>\n      <div class=\"explain\">\n        <strong>Redis</strong> — супербыстрое key-value хранилище в памяти. Часто используют для кэша, сессий, лимитов запросов и очередей.<br>\n        <strong>MongoDB</strong> — документо-ориентированная база. Удобна, когда структура данных часто меняется.<br>\n        <strong>Главное правило:</strong> сначала PostgreSQL/SQL. NoSQL добавляй не «потому что модно», а когда есть реальная причина.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-redis-1\" onchange=\"updateProgress(this)\"><span>Понимаю Redis как быстрый key-value кэш</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-redis-2\" onchange=\"updateProgress(this)\"><span>Знаю сценарии: сессии, rate limit, очереди, кэш</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-redis-3\" onchange=\"updateProgress(this)\"><span>Понимаю: NoSQL не заменяет SQL по умолчанию</span></label>\n      </div>\n    </div>\n"},{"id":"block-sql-select","title":"SELECT — получить данные основа 🔗","html":"<div class=\"block\" id=\"block-sql-select\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-select')\">SELECT — получить данные <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\"><strong>SELECT</strong> — самая частая команда. «Выбери (покажи) мне данные».</div>\n      <div class=\"code\">-- Получить все столбцы всех пользователей\nSELECT * FROM users;\n\n-- Только имя и email\nSELECT name, email FROM users;\n\n-- С условием: только взрослые\nSELECT * FROM users WHERE age &gt;= 18;\n\n-- Сортировка по имени\nSELECT * FROM users ORDER BY name;\n\n-- Только первые 10\nSELECT * FROM users LIMIT 10;</div>\n      <div class=\"explain\">\n        <strong>SELECT</strong> — что показать (* = всё, или перечисли столбцы).<br>\n        <strong>FROM</strong> — из какой таблицы.<br>\n        <strong>WHERE</strong> — условие (фильтр). Как <code>filter()</code> в JS!<br>\n        <strong>ORDER BY</strong> — сортировка.<br>\n        <strong>LIMIT</strong> — ограничить количество.<br>\n        💡 Заметь: <code>WHERE age &gt;= 18</code> — это та же логика что <code>tasks.filter(t =&gt; t.age &gt;= 18)</code> в твоём JS.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb544\" onchange=\"updateProgress(this)\"><span>Умею SELECT * FROM таблица</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb545\" onchange=\"updateProgress(this)\"><span>Понимаю WHERE (фильтр, как filter в JS)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb546\" onchange=\"updateProgress(this)\"><span>Знаю ORDER BY (сортировка) и LIMIT (ограничение)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-crud","title":"INSERT, UPDATE, DELETE основа 🔗","html":"<div class=\"block\" id=\"block-sql-crud\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-crud')\">INSERT, UPDATE, DELETE <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Это «CRUD» — Create, Read, Update, Delete. Базовые операции с данными. SELECT — это Read, остальные три — здесь.</div>\n      <div class=\"code\">-- CREATE: добавить нового пользователя\nINSERT INTO users (name, email, age)\nVALUES ('sweety', 'sweety@mail.ru', 16);\n\n-- UPDATE: изменить данные\nUPDATE users\nSET age = 17\nWHERE name = 'sweety';\n\n-- DELETE: удалить\nDELETE FROM users\nWHERE id = 5;</div>\n      <div class=\"explain\">\n        <strong>INSERT INTO ... VALUES</strong> — добавить новую строку (запись).<br>\n        <strong>UPDATE ... SET ... WHERE</strong> — изменить. <em>ВСЕГДА с WHERE!</em> Без WHERE обновишь ВСЕ строки!<br>\n        <strong>DELETE FROM ... WHERE</strong> — удалить. <em>Тоже всегда с WHERE!</em> Без WHERE удалишь всю таблицу!<br><br>\n        ⚠️ <strong>Главная ошибка новичков:</strong> забыть WHERE в UPDATE или DELETE. Это удалит/изменит ВСЁ. В реальной работе это катастрофа. Всегда сначала проверь WHERE через SELECT.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb547\" onchange=\"updateProgress(this)\"><span>Знаю CRUD: Create, Read, Update, Delete</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb548\" onchange=\"updateProgress(this)\"><span>Умею INSERT, UPDATE, DELETE</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb549\" onchange=\"updateProgress(this)\"><span>ВСЕГДА пишу WHERE в UPDATE/DELETE (иначе изменю всё!)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-keys","title":"Ключи и связи таблиц важно 🔗","html":"<div class=\"block\" id=\"block-sql-keys\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-keys')\">Ключи и связи таблиц <span class=\"badge rec\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Таблицы умеют <strong>связываться</strong> друг с другом. Например: таблица «посты» связана с таблицей «пользователи» — каждый пост знает кто его автор.</div>\n      <div class=\"code\">-- У каждой таблицы есть PRIMARY KEY (уникальный id)\nCREATE TABLE users (\n  id SERIAL PRIMARY KEY,    -- уникальный номер, авто-растёт\n  name TEXT,\n  email TEXT,\n  age INTEGER\n);\n\nCREATE TABLE posts (\n  id SERIAL PRIMARY KEY,\n  title TEXT,\n  user_id INTEGER REFERENCES users(id)  -- связь!\n);</div>\n      <div class=\"explain\">\n        <strong>PRIMARY KEY</strong> — уникальный идентификатор строки. Обычно <code>id</code>. Двух одинаковых не бывает.<br>\n        <strong>SERIAL</strong> — авто-увеличение. Первая запись = 1, вторая = 2, и т.д. Сам не задаёшь.<br>\n        <strong>FOREIGN KEY (REFERENCES)</strong> — «внешний ключ», ссылка на другую таблицу. <code>user_id</code> в постах указывает на <code>id</code> в users.<br>\n        💡 Это позволяет не дублировать данные. Имя пользователя хранится <em>один раз</em> в users, а посты просто ссылаются на него по id.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb550\" onchange=\"updateProgress(this)\"><span>Понимаю PRIMARY KEY (уникальный id строки)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb551\" onchange=\"updateProgress(this)\"><span>Понимаю связь таблиц через FOREIGN KEY</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb552\" onchange=\"updateProgress(this)\"><span>Понимаю зачем не дублировать данные (связи вместо копий)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-joins","title":"JOIN — объединение таблиц основа 🔗","html":"<div class=\"block\" id=\"block-sql-joins\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-joins')\">JOIN — объединение таблиц <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- Таблицы</span>\nusers:  id, name, email\norders: id, user_id, product, amount\n\n<span class=\"cm\">-- INNER JOIN — только совпадающие строки</span>\n<span class=\"kw\">SELECT</span> users.name, orders.product, orders.amount\n<span class=\"kw\">FROM</span> users\n<span class=\"kw\">INNER JOIN</span> orders <span class=\"kw\">ON</span> users.id = orders.user_id;\n\n<span class=\"cm\">-- LEFT JOIN — все пользователи, даже без заказов</span>\n<span class=\"kw\">SELECT</span> users.name, orders.product\n<span class=\"kw\">FROM</span> users\n<span class=\"kw\">LEFT JOIN</span> orders <span class=\"kw\">ON</span> users.id = orders.user_id;\n<span class=\"cm\">-- orders.product будет NULL если заказов нет</span>\n\n<span class=\"cm\">-- Несколько JOIN</span>\n<span class=\"kw\">SELECT</span> u.name, o.product, c.city\n<span class=\"kw\">FROM</span> users u\n<span class=\"kw\">JOIN</span> orders o <span class=\"kw\">ON</span> u.id = o.user_id\n<span class=\"kw\">JOIN</span> cities c <span class=\"kw\">ON</span> u.city_id = c.id;</div>\n      <div class=\"explain\">\n        <strong>INNER JOIN</strong> — пересечение. Строки без пары отбрасываются с обеих сторон.<br>\n        <strong>LEFT JOIN</strong> — все строки из левой таблицы + совпадения из правой (NULL если нет).<br>\n        <strong>Алиасы (u, o)</strong> — сокращают запись при многих JOIN'ах.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb556\" onchange=\"updateProgress(this)\"><span>INNER JOIN — только совпадающие строки</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb557\" onchange=\"updateProgress(this)\"><span>LEFT JOIN — все из левой + NULL из правой</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb558\" onchange=\"updateProgress(this)\"><span>Несколько JOIN в одном запросе</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-what","title":"Что такое база данных основа 🔗","html":"<div class=\"block\" id=\"block-sql-what\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-what')\">Что такое база данных <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">База данных (БД) — это место где хранятся данные так, чтобы их можно было <strong>быстро находить, добавлять, менять и удалять</strong>. Представь огромную таблицу Excel, но умную и быструю.</div>\n      <div class=\"explain\">\n        <strong>Реляционные БД (SQL)</strong> — данные в <em>таблицах</em> со строками и столбцами. PostgreSQL, MySQL, SQLite.<br>\n        <strong>Таблица</strong> — например «users». Столбцы: id, имя, email. Каждая строка — один пользователь.<br>\n        <strong>SQL</strong> (Structured Query Language) — язык которым ты «спрашиваешь» базу: «дай всех пользователей старше 18».<br><br>\n        <strong>Бывают ещё NoSQL базы</strong> (MongoDB) — там данные не в таблицах, а в виде объектов (как JSON). Для старта учи <strong>SQL</strong> — он более универсален и востребован.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb541\" onchange=\"updateProgress(this)\"><span>Понимаю что БД хранит данные для быстрого поиска</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb542\" onchange=\"updateProgress(this)\"><span>Знаю: таблица = строки (записи) + столбцы (поля)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb543\" onchange=\"updateProgress(this)\"><span>Понимаю разницу SQL (таблицы) и NoSQL (объекты)</span></label>\n      </div>\n    </div>\n\n    "}]},{"id":"sec-devops","lessons":[{"id":"block-devops-server","title":"Как устроен сервер обзор 🔗","html":"<div class=\"block\" id=\"block-devops-server\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-server')\">Как устроен сервер <span class=\"badge rec\">обзор</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\"><strong>Сервер</strong> — это просто компьютер, который всегда включён и отвечает на запросы из интернета. Когда ты открываешь сайт — твой браузер шлёт запрос на сервер, сервер отвечает.</div>\n      <div class=\"explain\">\n        <strong>Что происходит когда ты открываешь сайт:</strong><br>\n        1. Браузер шлёт <strong>запрос</strong> на сервер (по адресу/домену)<br>\n        2. <strong>DNS</strong> переводит домен (site.ru) в IP-адрес сервера (например 95.12.44.1)<br>\n        3. Сервер получает запрос, обрабатывает (может лезть в базу данных)<br>\n        4. Сервер отправляет <strong>ответ</strong> (HTML, JSON, картинку)<br>\n        5. Браузер показывает результат<br><br>\n        <strong>Чем больше людей</strong> — тем больше запросов одновременно. Один сервер может «захлебнуться». Дальше — про то как с этим бороться.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb565\" onchange=\"updateProgress(this)\"><span>Понимаю: сервер — это всегда включённый компьютер отвечающий на запросы</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb566\" onchange=\"updateProgress(this)\"><span>Знаю что DNS переводит домен в IP-адрес</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb567\" onchange=\"updateProgress(this)\"><span>Понимаю цикл: запрос → обработка → ответ</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-cache","title":"Кэширование — главный ускоритель обзор 🔗","html":"<div class=\"block\" id=\"block-devops-cache\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-cache')\">Кэширование — главный ускоритель <span class=\"badge rec\">обзор</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\"><strong>Кэш</strong> — это «запомнить результат, чтобы не считать заново». Самый важный приём для скорости и нагрузки.</div>\n      <div class=\"explain\">\n        <strong>Пример:</strong> на главной странице показываются «топ-10 постов». Чтобы их собрать — надо лезть в базу, считать, сортировать. Это <em>медленно</em>. Если 10000 человек открывают главную — база считает одно и то же 10000 раз. <strong>Глупо.</strong><br><br>\n        <strong>С кэшем:</strong> посчитали один раз → <em>запомнили</em> результат на 5 минут → следующие 10000 человек получают готовое <em>мгновенно</em>. База разгружена.<br><br>\n        <strong>Инструменты:</strong><br>\n        • <strong>Redis</strong> — хранилище в памяти, очень быстрое. Главный инструмент кэша<br>\n        • <strong>CDN</strong> (Cloudflare) — кэширует картинки/файлы на серверах по всему миру, ближе к пользователю<br>\n        • <strong>Кэш браузера</strong> — браузер запоминает картинки чтобы не качать заново\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb568\" onchange=\"updateProgress(this)\"><span>Понимаю идею кэша: посчитать раз, запомнить, отдавать готовое</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb569\" onchange=\"updateProgress(this)\"><span>Слышал про Redis (быстрый кэш в памяти)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb570\" onchange=\"updateProgress(this)\"><span>Понимаю что CDN раздаёт файлы ближе к пользователю</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-balance","title":"Балансировка нагрузки обзор 🔗","html":"<div class=\"block\" id=\"block-devops-balance\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-balance')\">Балансировка нагрузки <span class=\"badge rec\">обзор</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Когда людей слишком много для одного сервера — ставят <strong>несколько серверов</strong> и раскидывают запросы между ними. Это и есть балансировка.</div>\n      <div class=\"explain\">\n        <strong>Проблема:</strong> один сервер тянет, например, 1000 человек одновременно. Пришло 5000 — упал.<br><br>\n        <strong>Решение — горизонтальное масштабирование:</strong><br>\n        1. Ставим <strong>5 одинаковых серверов</strong> вместо одного<br>\n        2. Перед ними — <strong>балансировщик</strong> (load balancer, например Nginx)<br>\n        3. Балансировщик <em>распределяет</em> запросы: первого человека на сервер 1, второго на сервер 2, и т.д.<br>\n        4. Нагрузка делится — каждый сервер тянет свою долю<br><br>\n        <strong>Вертикальное масштабирование</strong> — это «сделать один сервер мощнее» (больше памяти, процессор). Проще, но есть потолок.<br>\n        <strong>Горизонтальное</strong> — «добавить ещё серверов». Сложнее, но масштабируется почти бесконечно (так работают Google, Яндекс).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb571\" onchange=\"updateProgress(this)\"><span>Понимаю что балансировщик раскидывает запросы по серверам</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb572\" onchange=\"updateProgress(this)\"><span>Знаю разницу: вертикальное (мощнее) vs горизонтальное (больше серверов)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb573\" onchange=\"updateProgress(this)\"><span>Слышал про Nginx как балансировщик/веб-сервер</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-docker","title":"Docker — контейнеры обзор 🔗","html":"<div class=\"block\" id=\"block-devops-docker\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-docker')\">Docker — контейнеры <span class=\"badge rec\">обзор</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\"><strong>Docker</strong> решает проблему «у меня на компе работает, а на сервере нет». Он упаковывает приложение со всем окружением в «контейнер», который работает одинаково везде.</div>\n      <div class=\"explain\">\n        <strong>Проблема без Docker:</strong> ты написал приложение. На твоём компе Node 20, у коллеги Node 18, на сервере Node 16. Версии библиотек разные. Где-то работает, где-то ломается. Ад.<br><br>\n        <strong>С Docker:</strong> ты описываешь в файле <code>Dockerfile</code> точное окружение (какой Node, какие пакеты). Docker создаёт <strong>контейнер</strong> — изолированную коробку где всё нужное уже внутри. Этот контейнер работает <em>одинаково</em> на твоём компе, у коллеги, на сервере.<br><br>\n        <strong>Аналогия:</strong> контейнер — как транспортный контейнер на корабле. Неважно что внутри — он стандартного размера и подходит к любому кораблю, крану, грузовику. Так же Docker-контейнер запускается на любом сервере одинаково.\n      </div>\n      <div class=\"code\"># Простой Dockerfile для Node-приложения\nFROM node:20            # берём готовое окружение с Node 20\nWORKDIR /app            # рабочая папка внутри контейнера\nCOPY package.json .     # копируем список зависимостей\nRUN npm install         # устанавливаем пакеты\nCOPY . .                # копируем весь код\nCMD [\"node\", \"server.js\"]  # команда запуска</div>\n      <div class=\"explain\">\n        <strong>FROM</strong> — на основе чего строим (базовый образ с Node).<br>\n        <strong>COPY</strong> — копируем файлы внутрь контейнера.<br>\n        <strong>RUN</strong> — выполнить команду при сборке (установка пакетов).<br>\n        <strong>CMD</strong> — что запустить когда контейнер стартует.<br>\n        💡 Это <em>обзор</em> — не пытайся освоить Docker сейчас. Просто пойми идею: «упаковать приложение чтобы работало везде одинаково».\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb574\" onchange=\"updateProgress(this)\"><span>Понимаю проблему «у меня работает, на сервере нет»</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb575\" onchange=\"updateProgress(this)\"><span>Понимаю идею Docker: упаковать приложение с окружением</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb576\" onchange=\"updateProgress(this)\"><span>Знаю что Dockerfile описывает как собрать контейнер</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-path","title":"Полная картина: путь к «много людей» карта 🔗","html":"<div class=\"block\" id=\"block-devops-path\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-path')\">Полная картина: путь к «много людей» <span class=\"badge opt\">карта</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"explain\">\n        Вот весь путь от новичка до «сайт выдерживает нагрузку», по порядку:<br><br>\n        <strong>1. Фронтенд</strong> (ты здесь) — HTML, CSS, JS<br>\n        <strong>2. Node.js</strong> — серверы на знакомом JS<br>\n        <strong>3. Базы данных</strong> — SQL, хранение данных<br>\n        <strong>4. Архитектура</strong> — как правильно строить приложение без «узких мест»<br>\n        <strong>5. Кэширование</strong> — Redis, CDN — ускорение<br>\n        <strong>6. Масштабирование</strong> — балансировка, несколько серверов<br>\n        <strong>7. Docker + облака</strong> — упаковка и развёртывание (AWS, Yandex Cloud)<br>\n        <strong>8. Мониторинг</strong> — следить за нагрузкой, логами, падениями<br><br>\n        💡 Это путь на <strong>годы</strong>, не на месяцы. Но каждый шаг логично следует за предыдущим. Сейчас твоя задача — <strong>пункт 1</strong>. Не прыгай вперёд. Всему своё время.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb577\" onchange=\"updateProgress(this)\"><span>Вижу полную карту пути к высоконагруженным системам</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb578\" onchange=\"updateProgress(this)\"><span>Понимаю что это путь на годы, шаг за шагом</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb579\" onchange=\"updateProgress(this)\"><span>Сейчас фокус на текущем шаге, не прыгаю вперёд</span></label>\n      </div>\n    </div>\n\n\n    "},{"id":"block-devops-github-actions","title":"CI/CD: GitHub Actions — автоматизация деплоя связывает Git + Серверы 🔗","html":"<div class=\"block\" id=\"block-devops-github-actions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-github-actions')\">CI/CD: GitHub Actions — автоматизация деплоя <span class=\"badge good\">связывает Git + Серверы</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">CI/CD автоматизирует то, что иначе делаешь руками: проверку кода и деплой. Один файл — и при каждом пуше в main линтер проверяет код, а проект автоматически деплоится.</div>\n      <div class=\"code\"><span class=\"cm\"># .github/workflows/deploy.yml</span>\nname: Deploy\n\n<span class=\"kw\">on</span>:\n  push:\n    branches: [main]   <span class=\"cm\"># запускается при пуше в main</span>\n\njobs:\n  build-and-deploy:\n    runs-on: ubuntu-latest\n\n    steps:\n      - <span class=\"kw\">uses</span>: actions/checkout@v4        <span class=\"cm\"># скачивает код репозитория</span>\n\n      - <span class=\"kw\">uses</span>: actions/setup-node@v4\n        <span class=\"kw\">with</span>:\n          node-version: <span class=\"str\">'20'</span>\n\n      - <span class=\"kw\">run</span>: npm install                  <span class=\"cm\"># устанавливает зависимости</span>\n      - <span class=\"kw\">run</span>: npm run lint                  <span class=\"cm\"># проверяет код линтером</span>\n      - <span class=\"kw\">run</span>: npm run build                 <span class=\"cm\"># собирает проект</span>\n\n      - <span class=\"kw\">name</span>: Deploy to server\n        <span class=\"kw\">run</span>: |\n          echo \"Деплоим на продакшен...\"\n          <span class=\"cm\"># здесь команда деплоя: rsync, scp, или action для Vercel/Netlify</span></div>\n      <div class=\"explain\">\n        <strong>on: push: branches: [main]</strong> — запускает workflow автоматически при каждом пуше в указанную ветку.<br>\n        <strong>jobs / steps</strong> — последовательность действий. Если хоть один шаг упал (например, lint нашёл ошибки) — деплой не произойдёт.<br>\n        <strong>actions/checkout, actions/setup-node</strong> — готовые \"кусочки\" от GitHub, которые делают типовые вещи (скачать код, поставить Node.js).<br>\n        <strong>Связь с карьерой:</strong> наличие настроенного CI/CD в твоём портфолио-проекте — сильный сигнал для работодателя, что ты понимаешь не только код, но и процесс разработки.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb580\" onchange=\"updateProgress(this)\"><span>.github/workflows/*.yml — где живут GitHub Actions</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb581\" onchange=\"updateProgress(this)\"><span>on: push — автоматический запуск при пуше в ветку</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb582\" onchange=\"updateProgress(this)\"><span>Настроил автоматический lint + build хотя бы в одном своём проекте</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-compose-nginx","title":"Docker Compose и Nginx reverse proxy обзор 🔗","html":"<div class=\"block\" id=\"block-devops-compose-nginx\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-compose-nginx')\">Docker Compose и Nginx reverse proxy <span class=\"badge rec\">обзор</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Dockerfile собирает один контейнер. Docker Compose запускает сразу несколько: сайт, сервер, базу, Redis. Nginx принимает запросы снаружи и прокидывает их внутрь.</div>\n      <div class=\"code\"><span class=\"cm\"># docker-compose.yml</span>\nservices:\n  app:\n    build: .\n    ports:\n      - \"3000:3000\"\n    env_file: .env\n    depends_on:\n      - db\n      - redis\n\n  db:\n    image: postgres:16\n    environment:\n      POSTGRES_PASSWORD: example\n\n  redis:\n    image: redis:7\n\n<span class=\"cm\"># nginx.conf — reverse proxy</span>\nserver {\n  listen 80;\n  server_name example.com;\n\n  location / {\n    proxy_pass http://app:3000;\n    proxy_set_header Host $host;\n    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n  }\n}</div>\n      <div class=\"explain\">\n        <strong>depends_on</strong> — показывает порядок запуска контейнеров.<br>\n        <strong>env_file</strong> — подключает переменные окружения без хардкода в коде.<br>\n        <strong>Reverse proxy</strong> — Nginx стоит перед приложением: принимает HTTP/HTTPS, отдаёт статику, проксирует запросы на Node-сервер.<br>\n        <strong>Пока цель простая:</strong> понять схему, не зубрить DevOps.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-compose-1\" onchange=\"updateProgress(this)\"><span>Понимаю: Compose запускает несколько сервисов одной командой</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-compose-2\" onchange=\"updateProgress(this)\"><span>Понимаю роль Nginx как reverse proxy перед приложением</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-compose-3\" onchange=\"updateProgress(this)\"><span>Знаю зачем env_file и почему секреты не пишут в коде</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-message-brokers","title":"Очереди сообщений: RabbitMQ и Kafka обзор 🔗","html":"<div class=\"block\" id=\"block-devops-message-brokers\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-message-brokers')\">Очереди сообщений: RabbitMQ и Kafka <span class=\"badge rec\">обзор</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Очередь нужна, когда задача тяжёлая или её можно сделать позже: письмо, генерация PDF, обработка картинки, уведомления.</div>\n      <div class=\"code\"><span class=\"cm\">// Без очереди: пользователь ждёт всё сразу</span>\nPOST /order\n  сохранить заказ\n  отправить письмо\n  пересчитать аналитику\n  ответить пользователю\n\n<span class=\"cm\">// С очередью: быстрый ответ, тяжёлое делает worker</span>\nPOST /order\n  сохранить заказ\n  addJob(\"send-email\", orderId)\n  addJob(\"update-analytics\", orderId)\n  ответить пользователю\n\n<span class=\"cm\">// Worker работает отдельно</span>\nwhile (true) {\n  const job = queue.take();\n  process(job);\n}</div>\n      <div class=\"explain\">\n        <strong>RabbitMQ</strong> — классические очереди задач: взять сообщение, обработать, подтвердить.<br>\n        <strong>Kafka</strong> — поток событий для больших систем: события хранятся, их могут читать разные сервисы.<br>\n        <strong>Для новичка:</strong> достаточно понять идею producer → queue → worker. Реально понадобится позже, когда будет backend-проект.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-queue-1\" onchange=\"updateProgress(this)\"><span>Понимаю зачем выносить тяжёлые задачи в очередь</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-queue-2\" onchange=\"updateProgress(this)\"><span>Знаю цепочку producer → queue → worker</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-queue-3\" onchange=\"updateProgress(this)\"><span>Отличаю RabbitMQ для задач и Kafka для потоков событий на базовом уровне</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-pg","lessons":[{"id":"block-pg-cloud-2026","title":"Облачный PostgreSQL: Neon или Supabase ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-pg-cloud-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-pg-cloud-2026')\">Облачный PostgreSQL: Neon или Supabase <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Облачная база убирает долгую локальную настройку. Для старта достаточно DATABASE_URL и базового CRUD.</div><div class=\"code\"># .env.local - never commit this file\nDATABASE_URL=\"postgresql://user:password@host/database?sslmode=require\"\n\nSELECT id, title FROM projects ORDER BY id DESC;\nINSERT INTO projects (title, author_id) VALUES ('Roadmap', 1);\nUPDATE projects SET title = 'WebDevGym' WHERE id = 1;\nDELETE FROM projects WHERE id = 1;</div><div class=\"explain\"><strong>Neon</strong> специализируется на serverless PostgreSQL и ветках базы. <strong>Supabase</strong> добавляет авторизацию, storage, realtime и панель. <code>DATABASE_URL</code> хранится в env, миграции запускаются через ORM.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-cloud-2026-1\" onchange=\"updateProgress(this)\"><span>Подключаюсь через DATABASE_URL</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-cloud-2026-2\" onchange=\"updateProgress(this)\"><span>Не отправляю URL базы в GitHub</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-cloud-2026-3\" onchange=\"updateProgress(this)\"><span>Выполняю SELECT/INSERT/UPDATE/DELETE</span></label></div></div>"},{"id":"block-pg-orm-2026","title":"Связи через Prisma или Drizzle ОСНОВА 2026 #","html":"<div class=\"block wdg-2026-block\" id=\"block-pg-orm-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-pg-orm-2026')\">Связи через Prisma или Drizzle <span class=\"badge must\">ОСНОВА 2026</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">ORM описывает схему, миграции и типизированные запросы. SQL остаётся нужен для понимания и отладки.</div><div class=\"code\">model User {\n  id       Int       @id @default(autoincrement())\n  email    String    @unique\n  projects Project[]\n}\n\nmodel Project {\n  id       Int    @id @default(autoincrement())\n  title    String\n  author   User   @relation(fields: [authorId], references: [id])\n  authorId Int\n}\n\nconst projects = await prisma.project.findMany({\n  where: { authorId: userId },\n  include: { author: true }\n});</div><div class=\"explain\"><strong>Prisma</strong> использует собственную схему и генерирует клиент. <strong>Drizzle</strong> ближе к SQL и описывает схему на TypeScript. Выбери один ORM. Внешний ключ создаёт one-to-many, промежуточная таблица - many-to-many.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-orm-2026-1\" onchange=\"updateProgress(this)\"><span>Моделирую one-to-many и many-to-many</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-orm-2026-2\" onchange=\"updateProgress(this)\"><span>Отличаю Prisma от Drizzle</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-orm-2026-3\" onchange=\"updateProgress(this)\"><span>Запускаю миграции</span></label></div></div>"},{"id":"block-pg-prisma","title":"Prisma ORM — работа с PostgreSQL из Node.js важно 🔗","html":"<div class=\"block\" id=\"block-pg-prisma\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-prisma')\">Prisma ORM — работа с PostgreSQL из Node.js <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># Установка</span>\n<span class=\"kw\">npm install</span> prisma @prisma/client\n<span class=\"kw\">npx prisma init</span>\n\n<span class=\"cm\">// schema.prisma</span>\ngenerator client {\n  provider = <span class=\"str\">\"prisma-client-js\"</span>\n}\ndatasource db {\n  provider = <span class=\"str\">\"postgresql\"</span>\n  url      = env(<span class=\"str\">\"DATABASE_URL\"</span>)\n}\nmodel User {\n  id        Int      @id @default(autoincrement())\n  name      String\n  email     String   @unique\n  posts     Post[]\n  createdAt DateTime @default(now())\n}\nmodel Post {\n  id      Int    @id @default(autoincrement())\n  title   String\n  user    User   @relation(fields: [userId], references: [id])\n  userId  Int\n}\n\n<span class=\"cm\">// Использование в коде</span>\n<span class=\"kw\">import</span> { PrismaClient } <span class=\"kw\">from</span> <span class=\"str\">'@prisma/client'</span>;\n<span class=\"kw\">const</span> prisma = <span class=\"kw\">new</span> <span class=\"fn\">PrismaClient</span>();\n\n<span class=\"cm\">// Создать пользователя</span>\n<span class=\"kw\">const</span> user = <span class=\"kw\">await</span> prisma.user.<span class=\"fn\">create</span>({\n  data: { name: <span class=\"str\">'Иван'</span>, email: <span class=\"str\">'ivan@mail.ru'</span> }\n});\n\n<span class=\"cm\">// Найти с отношениями</span>\n<span class=\"kw\">const</span> users = <span class=\"kw\">await</span> prisma.user.<span class=\"fn\">findMany</span>({\n  where: { email: { <span class=\"fn\">contains</span>: <span class=\"str\">'@mail.ru'</span> } },\n  include: { posts: <span class=\"kw\">true</span> },\n  orderBy: { createdAt: <span class=\"str\">'desc'</span> },\n  take: <span class=\"num\">10</span>\n});</div>\n      <div class=\"explain\">\n        <strong>Prisma</strong> — ORM который генерирует типизированный клиент из схемы. Популярен в TypeScript проектах.<br>\n        <strong>npx prisma migrate dev</strong> — создаёт миграцию и применяет к БД.<br>\n        <strong>include</strong> — подгружает связанные данные (аналог JOIN). <strong>take</strong> = LIMIT, <strong>skip</strong> = OFFSET.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb601\" onchange=\"updateProgress(this)\"><span>schema.prisma — описание моделей и связей</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb602\" onchange=\"updateProgress(this)\"><span>prisma.model.create/findMany/update/delete</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb603\" onchange=\"updateProgress(this)\"><span>include — загрузка связанных данных</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb604\" onchange=\"updateProgress(this)\"><span>npx prisma migrate dev — применение миграций</span></label>\n      </div>\n    </div>\n"},{"id":"block-pg-schema","title":"Схема БД и миграции важно 🔗","html":"<div class=\"block\" id=\"block-pg-schema\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-schema')\">Схема БД и миграции <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- Создание таблиц</span>\n<span class=\"kw\">CREATE TABLE</span> users (\n  id        <span class=\"str\">SERIAL PRIMARY KEY</span>,      <span class=\"cm\">-- автоинкремент</span>\n  name      <span class=\"str\">VARCHAR(100) NOT NULL</span>,\n  email     <span class=\"str\">VARCHAR(255) UNIQUE NOT NULL</span>,\n  role      <span class=\"str\">VARCHAR(20) DEFAULT</span> <span class=\"str\">'user'</span>,\n  created_at <span class=\"str\">TIMESTAMP DEFAULT NOW()</span>\n);\n\n<span class=\"kw\">CREATE TABLE</span> posts (\n  id      <span class=\"str\">SERIAL PRIMARY KEY</span>,\n  user_id <span class=\"str\">INT REFERENCES</span> users(id) <span class=\"kw\">ON DELETE CASCADE</span>,\n  title   <span class=\"str\">TEXT NOT NULL</span>,\n  body    <span class=\"str\">TEXT</span>,\n  tags    <span class=\"str\">TEXT[]</span>                    <span class=\"cm\">-- массив в PostgreSQL!</span>\n);\n\n<span class=\"cm\">-- Миграции через node-pg-migrate или Prisma</span>\n<span class=\"cm\">-- Никогда не меняй БД руками в production!</span>\n<span class=\"cm\">-- Всегда через миграционные файлы</span></div>\n      <div class=\"explain\">\n        <strong>SERIAL</strong> — автоинкрементный числовой ID. В PostgreSQL 10+ предпочитают GENERATED ALWAYS AS IDENTITY.<br>\n        <strong>ON DELETE CASCADE</strong> — при удалении пользователя удалятся все его посты.<br>\n        <strong>TEXT[]</strong> — нативный тип массива PostgreSQL. Очень удобно для тегов.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb589\" onchange=\"updateProgress(this)\"><span>SERIAL, VARCHAR, TEXT, TIMESTAMP — основные типы</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb590\" onchange=\"updateProgress(this)\"><span>REFERENCES + ON DELETE CASCADE — внешние ключи</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb591\" onchange=\"updateProgress(this)\"><span>Миграции — изменения схемы через файлы</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-pg-crud","title":"CRUD операции в PostgreSQL основа 🔗","html":"<div class=\"block\" id=\"block-pg-crud\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-crud')\">CRUD операции в PostgreSQL <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- CREATE</span>\n<span class=\"kw\">INSERT INTO</span> users (name, email)\n<span class=\"kw\">VALUES</span> (<span class=\"str\">'Иван'</span>, <span class=\"str\">'ivan@mail.ru'</span>)\n<span class=\"kw\">RETURNING</span> *; <span class=\"cm\">-- вернёт созданную строку</span>\n\n<span class=\"cm\">-- READ с фильтрами</span>\n<span class=\"kw\">SELECT</span> id, name, email <span class=\"kw\">FROM</span> users\n<span class=\"kw\">WHERE</span> role = <span class=\"str\">'admin'</span> <span class=\"kw\">AND</span> created_at &gt; <span class=\"str\">'2024-01-01'</span>\n<span class=\"kw\">ORDER BY</span> created_at <span class=\"kw\">DESC</span>\n<span class=\"kw\">LIMIT</span> <span class=\"num\">10</span> <span class=\"kw\">OFFSET</span> <span class=\"num\">20</span>; <span class=\"cm\">-- пагинация</span>\n\n<span class=\"cm\">-- UPDATE</span>\n<span class=\"kw\">UPDATE</span> users\n<span class=\"kw\">SET</span> name = <span class=\"str\">'Пётр'</span>, updated_at = <span class=\"kw\">NOW</span>()\n<span class=\"kw\">WHERE</span> id = <span class=\"num\">1</span>\n<span class=\"kw\">RETURNING</span> *;\n\n<span class=\"cm\">-- DELETE</span>\n<span class=\"kw\">DELETE FROM</span> users <span class=\"kw\">WHERE</span> id = <span class=\"num\">1</span> <span class=\"kw\">RETURNING</span> id;</div>\n      <div class=\"explain\">\n        <strong>RETURNING</strong> — убирает необходимость делать SELECT после INSERT/UPDATE/DELETE.<br>\n        <strong>OFFSET</strong> — пропустить N строк. Используй для пагинации: страница 2 = OFFSET 10 при LIMIT 10.<br>\n        <strong>NOW()</strong> — текущее время на сервере БД. Удобно для поля updated_at.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb592\" onchange=\"updateProgress(this)\"><span>INSERT INTO ... VALUES ... RETURNING *</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb593\" onchange=\"updateProgress(this)\"><span>SELECT с WHERE, ORDER BY, LIMIT, OFFSET</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb594\" onchange=\"updateProgress(this)\"><span>UPDATE ... SET ... WHERE RETURNING *</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-pg-queries","title":"Параметризованные запросы и безопасность основа 🔗","html":"<div class=\"block\" id=\"block-pg-queries\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-queries')\">Параметризованные запросы и безопасность <span class=\"badge must\">основа</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// ❌ НИКОГДА так — SQL injection!</span>\n<span class=\"kw\">const</span> query = <span class=\"str\">`SELECT * FROM users WHERE email = '${email}'`</span>;\n\n<span class=\"cm\">// ✅ Правильно — параметризованный запрос</span>\n<span class=\"kw\">const</span> { rows } = <span class=\"kw\">await</span> pool.<span class=\"fn\">query</span>(\n  <span class=\"str\">'SELECT * FROM users WHERE email = $1'</span>,\n  [email]  <span class=\"cm\">// $1 — первый параметр</span>\n);\n\n<span class=\"cm\">// Несколько параметров</span>\n<span class=\"kw\">await</span> pool.<span class=\"fn\">query</span>(\n  <span class=\"str\">'INSERT INTO users (name, email) VALUES ($1, $2) RETURNING *'</span>,\n  [name, email]\n);\n\n<span class=\"cm\">// Транзакция</span>\n<span class=\"kw\">const</span> client = <span class=\"kw\">await</span> pool.<span class=\"fn\">connect</span>();\n<span class=\"kw\">try</span> {\n  <span class=\"kw\">await</span> client.<span class=\"fn\">query</span>(<span class=\"str\">'BEGIN'</span>);\n  <span class=\"kw\">await</span> client.<span class=\"fn\">query</span>(<span class=\"str\">'UPDATE accounts SET balance = balance - $1 WHERE id = $2'</span>, [amount, fromId]);\n  <span class=\"kw\">await</span> client.<span class=\"fn\">query</span>(<span class=\"str\">'UPDATE accounts SET balance = balance + $1 WHERE id = $2'</span>, [amount, toId]);\n  <span class=\"kw\">await</span> client.<span class=\"fn\">query</span>(<span class=\"str\">'COMMIT'</span>);\n} <span class=\"kw\">catch</span> (e) {\n  <span class=\"kw\">await</span> client.<span class=\"fn\">query</span>(<span class=\"str\">'ROLLBACK'</span>);\n} <span class=\"kw\">finally</span> { client.<span class=\"fn\">release</span>(); }\n</div>\n      <div class=\"explain\">\n        <strong>SQL Injection</strong> — если подставлять данные в строку напрямую, злоумышленник может выполнить произвольный SQL.<br>\n        <strong>$1, $2...</strong> — PostgreSQL-синтаксис параметров. В MySQL используется ?.<br>\n        <strong>RETURNING *</strong> — возвращает вставленную/обновлённую строку без дополнительного SELECT.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb586\" onchange=\"updateProgress(this)\"><span>Параметризованные запросы $1, $2 — защита от SQL Injection</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb587\" onchange=\"updateProgress(this)\"><span>RETURNING * — получить результат после INSERT/UPDATE</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb588\" onchange=\"updateProgress(this)\"><span>Транзакции — BEGIN / COMMIT / ROLLBACK</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-pg-json","title":"JSON и JSONB в PostgreSQL важно 🔗","html":"<div class=\"block\" id=\"block-pg-json\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-json')\">JSON и JSONB в PostgreSQL <span class=\"badge good\">важно</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- JSONB — бинарный JSON (индексируемый, быстрее)</span>\n<span class=\"kw\">CREATE TABLE</span> products (\n  id    <span class=\"str\">SERIAL PRIMARY KEY</span>,\n  name  <span class=\"str\">TEXT NOT NULL</span>,\n  meta  <span class=\"str\">JSONB</span>   <span class=\"cm\">-- любые данные</span>\n);\n\n<span class=\"kw\">INSERT INTO</span> products (name, meta)\n<span class=\"kw\">VALUES</span> (<span class=\"str\">'Ноутбук'</span>, <span class=\"str\">'{\"brand\":\"Apple\",\"ram\":16,\"tags\":[\"tech\",\"sale\"]}'</span>);\n\n<span class=\"cm\">-- Доступ к полям JSONB</span>\n<span class=\"kw\">SELECT</span>\n  name,\n  meta-&gt;<span class=\"str\">'brand'</span>    <span class=\"kw\">AS</span> brand,   <span class=\"cm\">-- возвращает JSON</span>\n  meta-&gt;&gt;<span class=\"str\">'brand'</span>   <span class=\"kw\">AS</span> brand_text <span class=\"cm\">-- возвращает текст</span>\n<span class=\"kw\">FROM</span> products\n<span class=\"kw\">WHERE</span> meta-&gt;&gt;<span class=\"str\">'brand'</span> = <span class=\"str\">'Apple'</span>\n  <span class=\"kw\">AND</span> (meta-&gt;&gt;<span class=\"str\">'ram'</span>)::<span class=\"str\">int</span> &gt; <span class=\"num\">8</span>;\n\n<span class=\"cm\">-- Индекс по JSONB полю</span>\n<span class=\"kw\">CREATE INDEX</span> idx_products_brand\n  <span class=\"kw\">ON</span> products ((meta-&gt;&gt;<span class=\"str\">'brand'</span>));</div>\n      <div class=\"explain\">\n        <strong>JSONB vs JSON</strong> — JSONB хранится в бинарном формате, быстрее для поиска. Используй JSONB.<br>\n        <strong>-&gt;</strong> возвращает JSON тип, <strong>-&gt;&gt;</strong> возвращает текст. Для сравнения нужен -&gt;&gt;.<br>\n        <strong>::int</strong> — приведение типа (cast). JSONB всегда возвращает текст, кастуй для числовых сравнений.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb595\" onchange=\"updateProgress(this)\"><span>JSONB — хранение гибких данных</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb596\" onchange=\"updateProgress(this)\"><span>-&gt; и -&gt;&gt; — доступ к полям JSON</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb597\" onchange=\"updateProgress(this)\"><span>Индекс по JSONB полю для быстрого поиска</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-pg-functions","title":"Функции, триггеры и представления знать 🔗","html":"<div class=\"block\" id=\"block-pg-functions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-functions')\">Функции, триггеры и представления <span class=\"badge\">знать</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- VIEW — виртуальная таблица</span>\n<span class=\"kw\">CREATE VIEW</span> active_users <span class=\"kw\">AS</span>\n<span class=\"kw\">SELECT</span> id, name, email <span class=\"kw\">FROM</span> users\n<span class=\"kw\">WHERE</span> is_active = <span class=\"kw\">true</span>;\n\n<span class=\"cm\">-- Использование как обычной таблицы</span>\n<span class=\"kw\">SELECT</span> * <span class=\"kw\">FROM</span> active_users <span class=\"kw\">WHERE</span> name <span class=\"kw\">LIKE</span> <span class=\"str\">'И%'</span>;\n\n<span class=\"cm\">-- FUNCTION — хранимая функция</span>\n<span class=\"kw\">CREATE OR REPLACE FUNCTION</span> <span class=\"fn\">get_user_orders</span>(user_id <span class=\"str\">INT</span>)\n<span class=\"kw\">RETURNS TABLE</span>(order_id <span class=\"str\">INT</span>, product <span class=\"str\">TEXT</span>, amount <span class=\"str\">NUMERIC</span>) <span class=\"kw\">AS</span> $$\n  <span class=\"kw\">SELECT</span> id, product, amount <span class=\"kw\">FROM</span> orders\n  <span class=\"kw\">WHERE</span> orders.user_id = get_user_orders.user_id;\n$$ <span class=\"kw\">LANGUAGE</span> sql;\n\n<span class=\"kw\">SELECT</span> * <span class=\"kw\">FROM</span> <span class=\"fn\">get_user_orders</span>(<span class=\"num\">1</span>);\n\n<span class=\"cm\">-- TRIGGER — автоматически при изменении</span>\n<span class=\"kw\">CREATE OR REPLACE FUNCTION</span> <span class=\"fn\">update_timestamp</span>()\n<span class=\"kw\">RETURNS TRIGGER AS</span> $$\n<span class=\"kw\">BEGIN</span>\n  NEW.updated_at = <span class=\"kw\">NOW</span>();\n  <span class=\"kw\">RETURN</span> NEW;\n<span class=\"kw\">END</span>; $$ <span class=\"kw\">LANGUAGE</span> plpgsql;\n\n<span class=\"kw\">CREATE TRIGGER</span> set_timestamp\n  <span class=\"kw\">BEFORE UPDATE ON</span> users\n  <span class=\"kw\">FOR EACH ROW EXECUTE FUNCTION</span> <span class=\"fn\">update_timestamp</span>();</div>\n      <div class=\"explain\">\n        <strong>VIEW</strong> — сохранённый SELECT запрос. Упрощает сложные запросы и скрывает детали.<br>\n        <strong>Триггер</strong> — автоматически обновляет updated_at без изменения кода приложения.<br>\n        <strong>$$ ... $$</strong> — разделитель тела функции в PostgreSQL.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb598\" onchange=\"updateProgress(this)\"><span>CREATE VIEW — виртуальная таблица из SELECT</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb599\" onchange=\"updateProgress(this)\"><span>Хранимые функции — CREATE FUNCTION</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb600\" onchange=\"updateProgress(this)\"><span>Триггер — автоматическое обновление полей</span></label>\n      </div>\n    </div>\n\n    "}]},{"id":"sec-github","lessons":[{"id":"block-git-github-create","title":"🆕 Создать новый репозиторий практика 🔗","html":"<div class=\"block\" id=\"block-git-github-create\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-github-create')\">🆕 Создать новый репозиторий <span class=\"badge good\">практика</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Создай репозиторий прямо отсюда — без перехода на GitHub. Используй тот же токен что и для загрузки файлов (нужен scope <code>repo</code>).</div>\n\n      <div style=\"background:#0d1117;border-radius:12px;padding:20px;margin-top:12px;border:1px solid #30363d;\">\n\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🔑 Personal Access Token <a href=\"https://github.com/settings/tokens/new?scopes=repo&amp;description=Roadmap+Uploader\" target=\"_blank\" style=\"color:#58a6ff;text-decoration:none;margin-left:8px;font-weight:400;\">→ Создать токен</a></label>\n          <input id=\"ghc-token\" type=\"password\" placeholder=\"ghp_xxxxxxxxxxxxxxxxxxxx\" oninput=\"ghSaveField('ghc-token', this.value)\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n          <div style=\"font-size:11px;color:#6e7681;margin-top:4px;\">🔒 Тот же токен можно использовать ниже для загрузки файлов</div>\n        </div>\n\n        <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:12px;\">\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">📁 Имя репозитория</label>\n            <input id=\"ghc-name\" type=\"text\" placeholder=\"my-awesome-project\" oninput=\"ghSaveField('ghc-name', this.value)\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n          </div>\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">👁 Видимость</label>\n            <select id=\"ghc-visibility\" oninput=\"ghSaveField('ghc-visibility', this.value)\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;cursor:pointer;\">\n              <option value=\"false\">🌍 Публичный (Public)</option>\n              <option value=\"true\">🔒 Приватный (Private)</option>\n            </select>\n          </div>\n        </div>\n\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">📝 Описание (необязательно)</label>\n          <input id=\"ghc-desc\" type=\"text\" placeholder=\"Краткое описание проекта\" oninput=\"ghSaveField('ghc-desc', this.value)\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n        </div>\n\n        <label style=\"display:flex;align-items:center;gap:8px;margin-bottom:16px;font-size:13px;color:#c9d1d9;cursor:pointer;\">\n          <input type=\"checkbox\" id=\"ghc-readme\" checked style=\"width:16px;height:16px;cursor:pointer;accent-color:#238636;\">\n          Создать с README.md (рекомендуется)\n        </label>\n\n        <button onclick=\"githubCreateRepo()\" style=\"width:100%;padding:11px;background:linear-gradient(135deg,#238636,#2ea043);color:#fff;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:opacity .2s;\" onmouseover=\"this.style.opacity='.85'\" onmouseout=\"this.style.opacity='1'\">\n          🆕 Создать репозиторий\n        </button>\n\n        <div id=\"ghc-status\" style=\"margin-top:12px;font-size:13px;display:none;padding:10px 14px;border-radius:8px;\"></div>\n      </div>\n\n      <div class=\"items\" style=\"margin-top:14px;\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb605\" onchange=\"updateProgress(this)\"><span>Создал новый репозиторий через API</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb606\" onchange=\"updateProgress(this)\"><span>Понимаю разницу между публичным и приватным репо</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-github-upload","title":"🚀 Загрузить файл в репозиторий GitHub практика 🔗","html":"<div class=\"block\" id=\"block-git-github-upload\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-github-upload')\">🚀 Загрузить файл в репозиторий GitHub <span class=\"badge good\">практика</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Загрузи файл напрямую в твой GitHub репозиторий через API — прямо отсюда. Токен нигде не сохраняется.</div>\n\n      <div style=\"background:#0d1117;border-radius:12px;padding:20px;margin-top:12px;border:1px solid #30363d;\">\n        <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:12px;\">\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">👤 GitHub Username</label>\n            <input id=\"gh-username\" type=\"text\" placeholder=\"your-username\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\" oninput=\"ghSaveField('gh-username', this.value)\">\n          </div>\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">📁 Repository Name</label>\n            <input id=\"gh-repo\" type=\"text\" placeholder=\"your-repo-name\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\" oninput=\"ghSaveField('gh-repo', this.value)\">\n          </div>\n        </div>\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🔑 Personal Access Token <a href=\"https://github.com/settings/tokens/new?scopes=repo&amp;description=Roadmap+Uploader\" target=\"_blank\" style=\"color:#58a6ff;text-decoration:none;margin-left:8px;font-weight:400;\">→ Создать токен</a></label>\n          <input id=\"gh-token\" type=\"password\" placeholder=\"ghp_xxxxxxxxxxxxxxxxxxxx\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\" oninput=\"ghSaveField('gh-token', this.value)\">\n          <div style=\"font-size:11px;color:#6e7681;margin-top:4px;\">🔒 Токен не сохраняется — только в памяти вкладки</div>\n        </div>\n        <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:12px;\">\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">📄 Путь к файлу в репо</label>\n            <input id=\"gh-filepath\" type=\"text\" placeholder=\"index.html\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\" oninput=\"ghSaveField('gh-filepath', this.value)\">\n          </div>\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🌿 Ветка</label>\n            <input id=\"gh-branch\" type=\"text\" placeholder=\"main\" value=\"main\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\" oninput=\"ghSaveField('gh-branch', this.value)\">\n          </div>\n        </div>\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">💬 Сообщение коммита</label>\n          <input id=\"gh-message\" type=\"text\" placeholder=\"update: roadmap content\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n        </div>\n        <div style=\"margin-bottom:16px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">📎 Файл для загрузки</label>\n          <input id=\"gh-file-input\" type=\"file\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;cursor:pointer;box-sizing:border-box;\">\n        </div>\n        <button onclick=\"githubUpload()\" style=\"width:100%;padding:11px;background:linear-gradient(135deg,#238636,#2ea043);color:#fff;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:opacity .2s;\" onmouseover=\"this.style.opacity='.85'\" onmouseout=\"this.style.opacity='1'\">\n          ↑ Push на GitHub\n        </button>\n        <div id=\"gh-status\" style=\"margin-top:12px;font-size:13px;display:none;padding:10px 14px;border-radius:8px;\"></div>\n      </div>\n\n      <div class=\"items\" style=\"margin-top:14px;\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb607\" onchange=\"updateProgress(this)\"><span>Создал Personal Access Token на GitHub</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb608\" onchange=\"updateProgress(this)\"><span>Успешно загрузил файл через GitHub API</span></label>\n      </div>\n    </div>\n\n  "}]}]};
